function DriverRow({ setup, driver, stats }) {
  // Nur Farbe/Flaeche auf MC-Tokens, Layout und Logik unveraendert. Kein inline
  // background auf .mc-ride-card, sonst stirbt der :hover der Klasse.
  const dot = stats.active ? "var(--mc-st-enroute)" : "var(--mc-st-done)";
  const loc = setup.locations.find((l) => l.id === stats.locNow);
  const busyRide = stats.active;
  const van = driver.vehicleType === "Van";
  return (
    <div className="mc-ride-card px-3 py-2 flex items-center gap-3">
      <span className="w-2.5 h-2.5 rounded-full shrink-0" style={{ background: dot }} />
      <div className="min-w-0 flex-1">
        <div className="text-sm truncate flex items-center gap-1.5" style={{ color: "var(--mc-text)" }}>
          {driver.firstName} {driver.lastName}
          <span className="text-[10px] px-1" style={{ borderRadius: "var(--mc-r-sm)", fontFamily: "var(--mc-font-mono)", background: van ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: van ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>{van ? "Van" : "Car"}</span>
        </div>
        <div className="text-[11px] truncate" style={{ color: "var(--mc-text-muted)" }}>
          {busyRide ? <>unterwegs → {setup.locations.find((l) => l.id === busyRide.toId)?.short || "Ziel"}</>
            : <>frei{loc ? " · " + loc.short : ""}</>}
        </div>
      </div>
      <div className="text-right shrink-0">
        <div className="text-xs" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-secondary)" }}>{stats.count}×</div>
        <div className="text-[10px]" style={{ color: stats.drivingMin >= setup.config.softHoursMin ? "var(--mc-st-assigned)" : "var(--mc-text-muted)" }}>{fmtDur(stats.drivingMin)}</div>
      </div>
      {driver.phone && <a href={`tel:${driver.phone}`} title={`Anrufen: ${driver.phone}`} className="mc-iconbtn shrink-0 w-7 h-7"><Navigation className="w-4 h-4 rotate-90" /></a>}
    </div>
  );
}

/* ------------------------------ Zuteilen-Modal --------------------------- */
function AssignModal({ setup, dyn, ride, onClose, onAssign }) {
  const suggestions = useMemo(() => suggestDrivers(setup, dyn, ride), [setup, dyn, ride]);
  // Vor-Festival-Sicherheitsphase: solange die Personenzahl fehlt/ungültig ist,
  // kann grundsätzlich niemand als kapazitiv geprüft gelten (gilt für JEDEN
  // Fahrer gleich, deshalb einmal ride-bezogen prüfen statt pro Fahrer).
  const capacityUnknown = useMemo(() => validPassengerCount(ride.passengerCount) == null, [ride.passengerCount]);
  const locName = (id, txt) => setup.locations.find((l) => l.id === id)?.short || txt || "—";
  // Teilpaket B: operative Orte fuer die Anzeige (Abholung/Zone/Warnungen). Rein
  // presentational, aendert keine Ride-Daten. canonName: kurzer Name fuer eine
  // kanonische Orts-ID (Sheraton-Pickup etc.).
  const opLoc = useMemo(() => resolveOperationalRideLocations(ride, setup), [ride, setup]);
  const canonName = (canonId) => setup.locations.find((l) => l.id === (LOC_MATRIX_NODE[canonId] || canonId))?.short
    || (canonId === "sheraton" ? "Sheraton" : ZONE_LABEL[LOC_ZONE[canonId]] || canonId);
  const pickupRedirected = opLoc.appliedRules.length > 0
    && opLoc.operationalFrom.operationalLocation !== opLoc.requestedFrom.normalizedLocation;
  const current = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  // Teilpaket C2: einmalig normalisierte Timetable-Eintraege (rein lesend).
  const ttMatchEntries = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  // Teilpaket C3: Match nur EINMAL berechnen, an C2-Anzeige und C3-Bewertung teilen.
  const ttMatch = useMemo(() => matchRideToTimetable({ ride, timetableEntries: ttMatchEntries }), [ride, ttMatchEntries]);
  const [assigning, setAssigning] = useState(false); // Doppelklick-Schutz + Ladezustand
  const [assignErr, setAssignErr] = useState("");     // sichtbare Meldung, falls die Zuteilung nicht gespeichert wird

  // Alle Zuteilungs-Wege (Vorschlag, manuell, entfernen) laufen hier durch:
  // sperrt gegen Doppelklick, awaitet das Ergebnis, zeigt bei echtem Fehler eine
  // Meldung statt das Modal kommentarlos zu schliessen (Parent schliesst nur bei ok).
  const doAssign = async (driverId) => {
    if (assigning) return;
    // Slice 4: Rueckfrage, wenn Wechsel/Entfernen den Live-Status einer schon
    // laufenden Fahrt still auf "Geplant" zuruecksetzen wuerde (destruktiv).
    if (wouldResetLiveStatus(ride.status, ride.assignedDriverId, driverId)) {
      const verb = driverId ? "Fahrerwechsel" : "Zuteilung entfernen";
      if (!window.confirm(`Diese Fahrt läuft schon (Status: ${STATUS_LABEL[ride.status] || ride.status}).\n\n${verb} setzt sie zurück auf „Geplant“ und verwirft den aktuellen Stand. Trotzdem?`)) return;
    }
    setAssignErr("");
    setAssigning(true);
    try {
      const res = await onAssign(driverId);
      if (res && res.ok === false && !res.cancelled) {
        setAssignErr(res.error || "Die Zuteilung konnte nicht gespeichert werden. Bitte Verbindung prüfen und erneut versuchen.");
      }
    } catch (e) {
      console.error("AssignModal.doAssign", e);
      setAssignErr("Die Zuteilung konnte nicht gespeichert werden. Bitte erneut versuchen.");
    } finally {
      setAssigning(false);
    }
  };

  return (
    <Modal onClose={onClose} title="Fahrer zuteilen" wide mc>
      <div className="p-3 mb-4 text-sm" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
        <div className="flex items-center gap-3">
          <span className="text-lg" style={{ fontFamily: "var(--mc-font-mono)", fontVariantNumeric: "tabular-nums" }}>{ride.time}</span>
          <span style={{ color: "var(--mc-text-secondary)" }}>{locName(ride.fromId, ride.fromCustom)}</span>
          <ArrowRight className="w-4 h-4" style={{ color: "var(--mc-text-muted)" }} />
          <span className="font-medium" style={{ color: "var(--mc-text)" }}>{locName(ride.toId, ride.toCustom)}</span>
          {ride.zone && <span className="text-xs px-1.5 py-0.5" style={{ background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)", borderRadius: "var(--mc-r-sm)" }}>{ride.zone}</span>}
          <span className="flex items-center gap-1 ml-auto" style={{ color: capacityUnknown ? "var(--mc-st-problem)" : "var(--mc-text-muted)" }}><Users className="w-3.5 h-3.5" />{ride.passengerCount ?? "?"} Pers.</span>
        </div>
        {ride.djName && <div className="mt-1.5 text-base font-semibold truncate" style={{ color: "var(--mc-st-assigned)" }}>{ride.djName}</div>}
        {/* Teilpaket B: operativer Abholpunkt (nur wenn abweichend), Zone, Warnungen.
            Rein presentational; der urspruengliche Ort oben bleibt sichtbar. */}
        {pickupRedirected && (
          <div className="mt-1.5 text-xs flex items-center gap-1.5" style={{ color: "var(--mc-st-assigned)" }}>
            <MapPin className="w-3.5 h-3.5" />
            Abholung: <span className="font-medium">{canonName(opLoc.operationalFrom.operationalLocation)}</span>
            <span style={{ color: "var(--mc-text-muted)" }}>(Fahrgast-Ort: {locName(ride.fromId, ride.fromCustom)})</span>
          </div>
        )}
        {opLoc.requestedFrom.status === "unknown" && ride.fromId === "__custom" && (
          <div className="mt-1.5 text-xs flex items-center gap-1.5" style={{ color: "var(--mc-st-problem)" }}>
            <AlertTriangle className="w-3.5 h-3.5" />Abholort nicht erkannt – Fahrzeit unbekannt, bitte manuell prüfen.
          </div>
        )}
        {opLoc.requestedTo.status === "unknown" && ride.toId === "__custom" && (
          <div className="mt-1 text-xs flex items-center gap-1.5" style={{ color: "var(--mc-st-problem)" }}>
            <AlertTriangle className="w-3.5 h-3.5" />Zielort nicht erkannt – Fahrzeit unbekannt, bitte manuell prüfen.
          </div>
        )}
        {/* Teilpaket C2: rein lesende Timetable-Zuordnung (nur Anzeige, nichts gespeichert). */}
        <TimetableMatchInfo ride={ride} entries={ttMatchEntries} match={ttMatch} />
        {/* Teilpaket C3: rein lesende Planungsbewertung (Ankunft/Rueckfahrt vs. Set). */}
        <TimetableTimingInfo ride={ride} matchResult={ttMatch} setup={setup} />
      </div>

      {current && (
        <div className="text-xs mb-2" style={{ color: "var(--mc-text-muted)" }}>Aktuell zugeteilt: <span style={{ color: "var(--mc-text-secondary)" }}>{current.firstName} {current.lastName} ({current.vehicleType === "Van" ? "Van" : "Car"})</span></div>
      )}

      {capacityUnknown && (
        <div className="p-3 mb-4 text-sm" style={{ background: "var(--mc-st-problem-soft)", border: "1px solid var(--mc-st-problem)", borderRadius: "var(--mc-r)", color: "var(--mc-st-problem)" }}>
          <div className="font-medium mb-1">Personenzahl fehlt</div>
          <div>Kapazität kann nicht sicher geprüft werden.<br />Bitte ergänze die Personenzahl vor der Zuteilung.</div>
        </div>
      )}

      <div className="text-xs mb-2 flex items-center gap-1.5" style={{ color: "var(--mc-text-muted)" }}><Gauge className="w-3.5 h-3.5" />Vorschläge – Nähe &amp; Verfügbarkeit zuerst, Reisezeiten &amp; Fairness berücksichtigt</div>
      {/* Teilpaket A: Springer-Fallback nur, wenn kein regulaerer Fahrer geeignet war. */}
      {!capacityUnknown && suggestions.some((s) => s.emergencySpringer) && (
        <div className="p-2.5 mb-2 text-xs flex items-start gap-2" style={{ background: "var(--mc-st-problem-soft)", border: "1px solid var(--mc-st-problem)", borderRadius: "var(--mc-r)", color: "var(--mc-st-problem)" }}>
          <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
          <span><span className="font-medium">Kein regulärer Fahrer verfügbar</span> – Springer-Vorschläge (Notfall-Reserve).</span>
        </div>
      )}
      <div className="space-y-1.5 max-h-[46vh] overflow-y-auto pr-1">
        {capacityUnknown && <div className="text-sm py-6 text-center" style={{ color: "var(--mc-text-muted)" }}>Keine Vorschläge, solange die Personenzahl fehlt.</div>}
        {!capacityUnknown && suggestions.length === 0 && <div className="text-sm py-6 text-center" style={{ color: "var(--mc-text-muted)" }}>Kein passender Fahrer (Kapazität/Überschneidung). Manuell unten wählen.</div>}
        {!capacityUnknown && suggestions.slice(0, 8).map((x, i) => {
          const best = i === 0 && x.feasible;
          // Nur borderColor inline, damit der :hover aus .mc-ride-card (Flaeche +
          // Rahmen + 1px Lift) in allen drei Zustaenden lebt. Ein inline
          // background wuerde den Hover-Hintergrund ueberschreiben (inline > class).
          return (
            <button key={x.driver.id} onClick={() => doAssign(x.driver.id)} disabled={assigning}
              className="mc-ride-card w-full text-left px-3 py-2.5 flex items-center gap-3 disabled:opacity-50"
              style={best ? { borderColor: "var(--mc-brand)" } : !x.feasible ? { borderColor: "var(--mc-st-assigned)" } : undefined}>
              <span className="w-8 h-8 flex items-center justify-center text-xs shrink-0"
                style={{ borderRadius: "var(--mc-r-sm)", fontFamily: "var(--mc-font-mono)", background: x.driver.vehicleType === "Van" ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: x.driver.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>{x.driver.vehicleType === "Van" ? "Van" : "Car"}</span>
              <div className="min-w-0 flex-1">
                <div className="text-sm flex items-center gap-2 flex-wrap" style={{ color: "var(--mc-text)" }}>
                  {x.driver.firstName} {x.driver.lastName}
                  {best && <span className="mc-badge mc-badge--brand text-[10px]">beste Wahl</span>}
                  {!x.feasible && <span className="mc-badge mc-badge--assigned text-[10px]">knapp</span>}
                  {/* Teilpaket A: Springer- und Team-Kennzeichnung (rein informativ) */}
                  {x.emergencySpringer && <span className="mc-badge mc-badge--problem text-[10px]">Springer</span>}
                  {x.teamLabel && <span className="mc-badge mc-badge--assigned text-[10px]">Team: {x.teamLabel}</span>}
                </div>
                <div className="text-[11px]" style={{ color: "var(--mc-text-muted)" }}>{reasonText(setup, x)}</div>
              </div>
              <ChevronRight className="w-4 h-4 shrink-0" style={{ color: "var(--mc-text-muted)" }} />
            </button>
          );
        })}
      </div>

      {/* Manuell */}
      <div className="mt-4 pt-3" style={{ borderTop: "1px solid var(--mc-border)" }}>
        <div className="text-xs mb-2" style={{ color: "var(--mc-text-muted)" }}>Manuell zuweisen (alle Fahrer · mit Konfliktprüfung)</div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5 max-h-40 overflow-y-auto">
          {setup.drivers.map((d) => {
            const ev = evaluateInsertion(setup, dyn, d, ride);
            // Vor-Festival-Sicherheitsphase: bei fehlender/ungültiger Personenzahl gibt
            // es NICHTS zu bestätigen (kein "trotzdem zuweisen?"), der Button ist hart
            // gesperrt statt per confirm() übergehbar. Andere Konflikte (zu wenig Sitze
            // bei bekannter Zahl, Überschneidung, ...) bleiben wie bisher übergehbar.
            const assignManual = () => {
              if (ev.capacityUnknown) return; // Button ist ohnehin disabled, zusätzliche Sperre hier
              if (!ev.feasible) {
                const ok = window.confirm(`${d.firstName} ${d.lastName} (${d.vehicleType === "Van" ? "Van" : "Car"}) hat einen Konflikt:\n\n• ${ev.problems.join("\n• ")}\n\nTrotzdem zuweisen?`);
                if (!ok) return;
              }
              doAssign(d.id);
            };
            return (
              <button key={d.id} onClick={assignManual} disabled={assigning || ev.capacityUnknown}
                title={ev.capacityUnknown ? "Personenzahl fehlt – Kapazität kann nicht geprüft werden" : undefined}
                className="mc-ride-card text-xs px-2 py-1.5 text-left disabled:opacity-50"
                style={ev.capacityUnknown || !ev.eligible || !ev.available ? { borderColor: "var(--mc-st-problem)" } : !ev.feasible ? { borderColor: "var(--mc-st-assigned)" } : undefined}>
                <div className="truncate" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName[0]}.</div>
                <div className="flex items-center gap-1 flex-wrap">
                  <span className="text-[10px]" style={{ color: "var(--mc-text-muted)", fontFamily: "var(--mc-font-mono)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
                  {ev.capacityUnknown ? <span className="text-[9px]" style={{ color: "var(--mc-st-problem)" }}>Personenzahl fehlt</span>
                    : !ev.eligible ? <span className="text-[9px]" style={{ color: "var(--mc-st-problem)" }}>zu klein</span>
                    : !ev.available ? <span className="text-[9px]" style={{ color: "var(--mc-st-problem)" }}>noch nicht verfügbar</span>
                    : ev.overlap ? <span className="text-[9px]" style={{ color: "var(--mc-st-assigned)" }}>Überschneidung</span>
                      : !ev.feasible ? <span className="text-[9px]" style={{ color: "var(--mc-st-assigned)" }}>knapp</span> : null}
                  {/* Teilpaket A: Springer/Team als Info auch in der manuellen Liste */}
                  {ev.driverCategory === "springer" && <span className="text-[9px]" style={{ color: "var(--mc-st-problem)" }}>· Springer</span>}
                  {ev.teamLabel && <span className="text-[9px]" style={{ color: "var(--mc-st-assigned)" }}>· {ev.teamLabel}</span>}
                </div>
              </button>
            );
          })}
        </div>
        {ride.assignedDriverId && (
          <button onClick={() => doAssign(null)} disabled={assigning} className="mt-3 text-xs hover:opacity-80 disabled:opacity-40 flex items-center gap-1" style={{ color: "var(--mc-st-problem)" }}><X className="w-3.5 h-3.5" />Zuteilung entfernen</button>
        )}
      </div>

      {assignErr && (
        <div className="mt-4 text-sm px-3 py-2" style={{ color: "var(--mc-st-problem)", background: "var(--mc-st-problem-soft)", border: "1px solid var(--mc-st-problem)", borderRadius: "var(--mc-r)" }}>{assignErr}</div>
      )}
    </Modal>
  );
}

/* ------------------------------ Fahrt-Formular --------------------------- */
function RideForm({ setup, ride, onClose, onSave, onDelete }) {
  const isNew = ride._new;
  const [saving, setSaving] = useState(false);   // Doppelklick-Schutz + Ladezustand Speichern
  const [deleting, setDeleting] = useState(false); // Doppelklick-Schutz + Ladezustand Stornieren
  const [saveErr, setSaveErr] = useState("");     // sichtbare Fehlermeldung, falls Speichern/Stornieren scheitert
  const [f, setF] = useState({
    date: ride.date || ride.dayKey || todayISO(),
    time: ride.time || "12:00",
    fromId: ride.fromId || "airport",
    toId: ride.toId || "festival",
    fromCustom: ride.fromCustom || "",
    toCustom: ride.toCustom || "",
    zone: ride.zone || "",
    djName: ride.djName || "",
    // Vor-Festival-Sicherheitsphase: fehlende Zahl bleibt im Formular LEER statt
    // mit 1 vorbelegt zu werden – sonst würde blosses Öffnen+Speichern einer alten
    // Fahrt ohne Personenzahl sie unbemerkt auf "1" festschreiben (geschätzt).
    passengerCount: ride.passengerCount ?? "",
    passengers: ride.passengers || "",
    flightNo: ride.flightNo || "",
    airline: ride.airline || "",
    terminal: ride.terminal || "",
    scheduledArrival: ride.scheduledArrival || "",
    actualArrival: ride.actualArrival || "",
    estimatedArrival: ride.estimatedArrival || "",
    flightStatus: ride.flightStatus || "",
    meetingPoint: ride.meetingPoint || "",
    notes: ride.notes || "",
    guestNote: ride.guestNote || "",
    onDemand: ride.onDemand || false,
  });
  const [manualDur, setManualDur] = useState(ride.estDurationMin != null ? String(ride.estDurationMin) : "");
  const [flightBusy, setFlightBusy] = useState(false);
  const [flightMsg, setFlightMsg] = useState(null);
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  // Telefonnummern, die im Passagiere-Text stecken (z. B. "Name (+49…)") – live,
  // aktualisiert sich beim Tippen. Nur hier sichtbar (Fahrt geöffnet), nicht in Listen.
  const contacts = useMemo(() => extractContactPhones(f.passengers), [f.passengers]);

  // Punkt 6: Flugstatus über Provider (serverseitig) abrufen; im Artifact -> Fallback.
  // Abklingzeit (FLIGHT_REFRESH_COOLDOWN_MIN) gegen das begrenzte API-Kontingent,
  // siehe Hinweis bei der Konstante. Prüft gegen f.lastFlightCheck (falls in
  // dieser Sitzung schon einmal abgefragt) ODER ride.lastFlightCheck (falls
  // beim Öffnen des Formulars schon aktuell) — je nachdem, was neuer ist.
  // "force" überspringt sie bewusst (Link unten).
  const fetchFlight = async (force) => {
    if (!f.flightNo) return;
    const baseline = { lastFlightCheck: Math.max(f.lastFlightCheck || 0, ride.lastFlightCheck || 0) };
    if (!force && flightRefreshOnCooldown(baseline)) {
      setFlightMsg({ ok: true, cooldown: true, text: `vor ${FLIGHT_REFRESH_COOLDOWN_MIN - flightCooldownRemainingMin(baseline)} Min. abgefragt · noch ${flightCooldownRemainingMin(baseline)} Min. Abklingzeit` });
      return;
    }
    setFlightBusy(true); setFlightMsg(null);
    const res = await getFlightStatus(f.flightNo, f.date);
    setFlightBusy(false);
    if (!res.ok) { setFlightMsg({ ok: false, text: res.error || "nicht verfügbar – bitte manuell pflegen" }); return; }
    setF((p) => ({
      ...p,
      airline: res.airline || p.airline,
      terminal: res.terminal || p.terminal,
      scheduledArrival: res.scheduledArrival || p.scheduledArrival,
      estimatedArrival: res.estimatedArrival || p.estimatedArrival,
      actualArrival: res.actualArrival || p.actualArrival,
      flightStatus: res.flightStatus || p.flightStatus,
      lastFlightCheck: Date.now(),
    }));
    setFlightMsg({ ok: true, text: `aktualisiert (${res.source || FLIGHT_PROVIDER})` });
  };

  const toIsFestival = f.toId === "festival";
  // Teilpaket C2: rein lesende Timetable-Zuordnung. Live aus dem Formular-State
  // abgeleitete Ride-Ansicht (aktualisiert sich beim Tippen von Artist/Datum/
  // Richtung). Nur Anzeige, keine Speicherung des Ergebnisses am Ride.
  const ttEntries = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  const ttMatchRide = useMemo(() => ({
    djName: f.djName, date: f.date, time: f.time,
    fromId: f.fromId, toId: f.toId,
    fromCustom: f.fromCustom, toCustom: f.toCustom,
    dayKey: festDayKey(f.date, f.time),
  }), [f.djName, f.date, f.time, f.fromId, f.toId, f.fromCustom, f.toCustom]);
  // Teilpaket C3: Match nur EINMAL berechnen, an C2-Anzeige und C3-Bewertung teilen.
  const ttMatch = useMemo(() => matchRideToTimetable({ ride: ttMatchRide, timetableEntries: ttEntries }), [ttMatchRide, ttEntries]);
  const dur = travel(setup.matrix, f.fromId, f.toId);        // aus Matrix (null = unbekannt)
  const durKnown = dur != null;
  // Vor-Festival-Sicherheitsphase: keine stille 1 mehr. pax ist entweder eine
  // echte positive ganze Zahl oder null (= "fehlt/ungültig", wird so gespeichert).
  const pax = validPassengerCount(f.passengerCount);
  const tooBig = pax != null && pax > 7; // größer als jede V-Klasse

  // Slice 3: weiche Eingabe-Warnungen (warnen, NICHT blockieren) fuer Fehler,
  // die nie gewollt sind und heute kommentarlos durchgehen. Speichern bleibt
  // immer moeglich, das sind Hinweise wie tooBig oben, keine Sperre.
  const fromCustom = f.fromId === "__custom";
  const toCustom = f.toId === "__custom";
  const sameLoc = !fromCustom && f.fromId === f.toId; // gleicher hinterlegter Ort als Start und Ziel
  const bothCustomSame = fromCustom && toCustom && f.fromCustom.trim() && f.fromCustom.trim().toLowerCase() === f.toCustom.trim().toLowerCase();
  const fromCustomEmpty = fromCustom && !f.fromCustom.trim();
  const toCustomEmpty = toCustom && !f.toCustom.trim();
  // Datums-Tippfehler (falscher Monat/Tag) erkennen: der per Nachtmodus korrekt
  // aufgeloeste Festival-Tag der Fahrt wird gegen die eingetragenen Festivaltage
  // geprueft. Nur ein Hinweis - Abhol-/Rueckfahrten am Vor-/Nachtag sind legitim
  // und bleiben erlaubt. Guard: nur wenn ueberhaupt Festivaltage hinterlegt sind.
  const festDates = setup.config.festivalDates || [];
  const effDayKey = festDayKey(f.date, f.time);
  const dateOffFestival = festDates.length > 0 && effDayKey && !festDates.includes(effDayKey);
  const inputWarnings = [];
  if (sameLoc || bothCustomSame) inputWarnings.push("Start und Ziel sind identisch. Ist das so gewollt?");
  if (fromCustomEmpty) inputWarnings.push("Für „Von“ ist „Anderer Ort“ gewählt, aber kein Ort eingetragen.");
  if (toCustomEmpty) inputWarnings.push("Für „Nach“ ist „Anderer Ort“ gewählt, aber kein Ort eingetragen.");
  if (dateOffFestival) inputWarnings.push("Dieses Datum liegt außerhalb der eingetragenen Festivaltage. Bitte Datum prüfen (Vor-/Nachtag ist ok).");
  if (pax == null) inputWarnings.push("Personenzahl fehlt oder ungültig – Kapazität kann bei der Zuteilung nicht geprüft werden.");

  const save = async () => {
    // Doppelklick-Schutz: laeuft schon ein Speicher-/Stornier-Vorgang, nichts tun,
    // sonst wuerde eine neue Fahrt bei schnellem Doppelklick zweimal angelegt.
    if (saving || deleting) return;
    const dayKey = festDayKey(f.date, f.time);
    const est = durKnown ? dur.min : (manualDur.trim() !== "" ? Number(manualDur) : null);
    const { _new, ...clean } = ride;
    // Punkt 4: Flug-Update-Metadaten pflegen; manuelle Änderung als Override markieren
    const flightTouched = f.flightStatus !== (ride.flightStatus || "") || f.actualArrival !== (ride.actualArrival || "") || f.estimatedArrival !== (ride.estimatedArrival || "") || f.terminal !== (ride.terminal || "");
    const delay = f.scheduledArrival && (f.actualArrival || f.estimatedArrival)
      ? Math.max(0, sortMin(f.actualArrival || f.estimatedArrival) - sortMin(f.scheduledArrival)) : (ride.delayMinutes || 0);
    setSaveErr("");
    setSaving(true);
    try {
      // onSave gibt jetzt das Speicher-Ergebnis zurueck ({ ok, error, cancelled? }).
      // Bei Erfolg schliesst der Parent das Formular (setEditRide(null)); scheitert
      // es, bleibt das Formular offen und die Eingabe erhalten.
      const res = await onSave({
        ...clean, ...f,
        passengerCount: pax,
        zone: toIsFestival ? f.zone : "",
        dayKey,
        estDurationMin: Number.isFinite(est) ? est : null,
        type: classify(f.fromId, f.toId, f.fromCustom, f.toCustom),
        delayMinutes: delay,
        manualOverride: flightTouched ? true : (ride.manualOverride || false),
        lastFlightUpdate: flightTouched ? Date.now() : (ride.lastFlightUpdate || null),
        flightUpdateSource: flightTouched ? "manuell" : (ride.flightUpdateSource || null),
        contactPhones: extractContactPhones(f.passengers), // aus "Name (+49…)" im Passagiere-Text
        updatedAt: Date.now(),
      });
      // cancelled = Nutzer hat den Konflikt-Dialog bewusst abgebrochen -> keine Fehlermeldung.
      if (res && res.ok === false && !res.cancelled) {
        setSaveErr(res.error || "Die Fahrt konnte nicht gespeichert werden. Bitte Verbindung prüfen und erneut versuchen.");
      }
    } catch (e) {
      console.error("RideForm.save", e);
      setSaveErr("Die Fahrt konnte nicht gespeichert werden. Bitte erneut versuchen.");
    } finally {
      setSaving(false);
    }
  };

  // Stornieren mit gleichem Schutz: Doppelklick unkritisch (idempotent), aber das
  // Formular darf bei einem Schreibfehler nicht kommentarlos schliessen.
  const doDelete = async () => {
    if (!onDelete || saving || deleting) return;
    // Slice 4: Rueckfrage vor dem Stornieren (destruktiv, ein Fehlklick storniert
    // sonst eine Fahrt). Identifikation ueber die gespeicherten Werte der Fahrt.
    const who = (ride.djName || "").trim() || "diese Fahrt";
    if (!window.confirm(`Fahrt „${who}“${ride.time ? ` um ${ride.time}` : ""} wirklich stornieren?`)) return;
    setSaveErr("");
    setDeleting(true);
    try {
      const res = await onDelete();
      if (res && res.ok === false && !res.cancelled) {
        setSaveErr(res.error || "Die Fahrt konnte nicht storniert werden. Bitte erneut versuchen.");
      }
    } catch (e) {
      console.error("RideForm.delete", e);
      setSaveErr("Die Fahrt konnte nicht storniert werden. Bitte erneut versuchen.");
    } finally {
      setDeleting(false);
    }
  };

  return (
    <Modal onClose={onClose} title={isNew ? "Neue Fahrt" : "Fahrt bearbeiten"} wide mc>
      <div className="grid grid-cols-2 gap-3">
        <Field label="Datum" mc><input type="date" className={mcInp} value={f.date} onChange={(e) => set("date", e.target.value)} /></Field>
        <Field label="Uhrzeit" mc><input type="time" className={mcInp} value={f.time} onChange={(e) => set("time", e.target.value)} /></Field>
        <LocSelect setup={setup} label="Von" value={f.fromId} custom={f.fromCustom}
          onId={(v) => set("fromId", v)} onCustom={(v) => set("fromCustom", v)} />
        <LocSelect setup={setup} label="Nach" value={f.toId} custom={f.toCustom}
          onId={(v) => set("toId", v)} onCustom={(v) => set("toCustom", v)} />
        {toIsFestival && (
          <Field label="Abladezone" mc>
            <select className={mcInp} value={f.zone} onChange={(e) => set("zone", e.target.value)}>
              <option value="">– wählen –</option>
              {setup.zones.map((z) => <option key={z} value={z}>{z}</option>)}
            </select>
          </Field>
        )}
        <Field label="DJ / Artist" mc><input className={mcInp} value={f.djName} onChange={(e) => set("djName", e.target.value)} placeholder="z. B. Alok" /></Field>
        <div className="col-span-2"><TimetableMatchInfo ride={ttMatchRide} entries={ttEntries} match={ttMatch} /></div>
        <div className="col-span-2"><TimetableTimingInfo ride={ttMatchRide} matchResult={ttMatch} setup={setup} /></div>
        <Field label="Personen" mc><input type="number" min="1" max="8" className={mcInp} value={f.passengerCount} onChange={(e) => set("passengerCount", e.target.value)} /></Field>
        <Field label="Flugnummer" mc><input className={mcInp} value={f.flightNo} onChange={(e) => set("flightNo", e.target.value)} placeholder="z. B. KL1845" /></Field>
        {(f.fromId === "airport" || f.flightNo) && (
          <div className="col-span-2 p-3 mt-1" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
            <div className="text-xs font-medium mb-2 flex items-center justify-between" style={{ color: "var(--mc-st-new)" }}>
              <span className="flex items-center gap-1.5"><Plane className="w-3.5 h-3.5" />Flug-Details</span>
              {ride.manualOverride && <span className="mc-badge mc-badge--assigned text-[10px]">manuell überschrieben</span>}
            </div>
            <div className="grid grid-cols-2 gap-2.5">
              <Field label="Airline" mc><input className={mcInp} value={f.airline} onChange={(e) => set("airline", e.target.value)} placeholder="z. B. KLM" /></Field>
              <Field label="Terminal" mc><input className={mcInp} value={f.terminal} onChange={(e) => set("terminal", e.target.value)} placeholder="z. B. Terminal 1" /></Field>
              <Field label="Geplante Ankunft" mc><input type="time" className={mcInp} value={f.scheduledArrival} onChange={(e) => set("scheduledArrival", e.target.value)} /></Field>
              <Field label="Erwartete Ankunft" mc><input type="time" className={mcInp} value={f.estimatedArrival} onChange={(e) => set("estimatedArrival", e.target.value)} /></Field>
              <Field label="Echte Ankunft" mc><input type="time" className={mcInp} value={f.actualArrival} onChange={(e) => set("actualArrival", e.target.value)} /></Field>
              <Field label="Flugstatus" mc>
                <select className={mcInp} value={f.flightStatus} onChange={(e) => set("flightStatus", e.target.value)}>
                  {FLIGHT_STATUS.map((s) => <option key={s.k} value={s.k}>{s.k === "" ? "– unbekannt –" : s.l}</option>)}
                </select>
              </Field>
            </div>
            <div className="flex items-center gap-2 mt-2.5">
              <button type="button" onClick={() => fetchFlight(false)} disabled={flightBusy || !f.flightNo}
                className="mc-btn-primary text-xs disabled:opacity-40 px-2.5 py-1.5 flex items-center gap-1.5">
                <RefreshCw className={`w-3.5 h-3.5 ${flightBusy ? "animate-spin" : ""}`} />Flugstatus aktualisieren
              </button>
              {flightMsg && (
                <span className="text-[11px]" style={{ color: flightMsg.ok ? "var(--mc-st-done)" : "var(--mc-st-assigned)" }}>
                  {flightMsg.text}
                  {flightMsg.cooldown && (
                    <> · <button type="button" onClick={() => fetchFlight(true)} className="underline hover:opacity-80">trotzdem abfragen</button></>
                  )}
                </span>
              )}
            </div>
          </div>
        )}
        <div className="col-span-2">
          <Field label="Passagiere (Namen)" mc><input className={mcInp} value={f.passengers} onChange={(e) => set("passengers", e.target.value)} /></Field>
          {contacts.length > 0 && (
            <div className="mt-1.5 flex flex-wrap gap-1.5">
              {contacts.map((c, i) => (
                <a key={i} href={`tel:${c.phone}`} className="inline-flex items-center gap-1.5 text-xs px-2 py-1 hover:opacity-80"
                  style={{ background: "var(--mc-st-done-soft)", border: "1px solid var(--mc-st-done)", color: "var(--mc-st-done)", borderRadius: "var(--mc-r)" }}>
                  <Navigation className="w-3 h-3 rotate-90" />{c.name ? `${c.name}: ` : ""}{c.phone}
                </a>
              ))}
            </div>
          )}
        </div>
        <div className="col-span-2">
          <Field label="Treffpunkt" mc><input className={mcInp} value={f.meetingPoint} onChange={(e) => set("meetingPoint", e.target.value)} placeholder="z. B. Infront of the Hotel" /></Field>
        </div>
        <div className="col-span-2">
          <Field label="Notiz (intern)" mc><input className={mcInp} value={f.notes} onChange={(e) => set("notes", e.target.value)} /></Field>
        </div>
        <div className="col-span-2">
          <Field label="Hinweis für den Gast (Artist/Manager-Link)" mc>
            <input className={mcInp} value={f.guestNote} onChange={(e) => set("guestNote", e.target.value)} placeholder="z. B. Bitte Ausweis bereithalten" />
          </Field>
          <p className="text-[11px] mt-1" style={{ color: "var(--mc-text-muted)" }}>Getrennt von der internen Notiz oben — nur dieser Text erscheint im Gast-Link.</p>
        </div>
        <label className="col-span-2 flex items-center gap-2 text-sm mt-1" style={{ color: "var(--mc-text-secondary)" }}>
          <input type="checkbox" checked={f.onDemand} onChange={(e) => set("onDemand", e.target.checked)} className="w-4 h-4" style={{ accentColor: "var(--mc-st-new)" }} />
          Rückfahrt / on demand (Zeit flexibel)
        </label>
      </div>

      {tooBig && (
        <div className="mt-3 text-xs flex items-center gap-2" style={{ color: "var(--mc-st-assigned)" }}><AlertTriangle className="w-3.5 h-3.5" />{pax} Personen passen in kein einzelnes Fahrzeug (V-Klasse max. 7) – ggf. auf zwei Fahrten aufteilen.</div>
      )}

      {inputWarnings.map((w, i) => (
        <div key={i} className="mt-3 text-xs flex items-center gap-2" style={{ color: "var(--mc-st-assigned)" }}><AlertTriangle className="w-3.5 h-3.5 shrink-0" />{w}</div>
      ))}

      <div className="mt-3">
        {durKnown ? (
          <div className="text-xs flex items-center gap-2" style={{ color: "var(--mc-text-muted)" }}>
            <Route className="w-3.5 h-3.5" />Geschätzte Fahrzeit aus Matrix: <b style={{ color: "var(--mc-text-secondary)" }}>{fmtDur(dur.min)}</b> · {dur.km} km
          </div>
        ) : (
          <div className="flex items-center gap-2 text-xs">
            <AlertTriangle className="w-3.5 h-3.5" style={{ color: "var(--mc-st-assigned)" }} />
            <span style={{ color: "var(--mc-st-assigned)" }}>Fahrzeit für diese Strecke nicht hinterlegt – bitte manuell angeben:</span>
            <input type="number" min="1" className="mc-input w-20 px-2 py-1 text-center text-xs"
              style={{ fontFamily: "var(--mc-font-mono)" }}
              value={manualDur} onChange={(e) => setManualDur(e.target.value)} placeholder="min" />
            <span style={{ color: "var(--mc-text-muted)" }}>min</span>
          </div>
        )}
      </div>

      {!isNew && ((ride.issues && ride.issues.length > 0) || (ride.log && ride.log.length > 0)) && (
        <RideHistory ride={ride} />
      )}

      {saveErr && (
        <div className="mt-4 text-sm px-3 py-2 flex items-center justify-between gap-3"
          style={{ color: "var(--mc-st-problem)", background: "var(--mc-st-problem-soft)", border: "1px solid var(--mc-st-problem)", borderRadius: "var(--mc-r)" }}>
          <span>{saveErr}</span>
          <button onClick={save} disabled={saving || deleting} className="shrink-0 text-xs underline hover:opacity-80 disabled:opacity-40">Erneut versuchen</button>
        </div>
      )}

      <div className="flex items-center gap-2 mt-5">
        <button onClick={save} disabled={saving || deleting} className="mc-btn-primary disabled:opacity-50 px-4 py-2.5 text-sm">{saving ? "Speichere…" : "Speichern"}</button>
        <button onClick={onClose} disabled={saving || deleting} className="hover:opacity-80 disabled:opacity-40 px-4 py-2.5 text-sm" style={{ color: "var(--mc-text-secondary)" }}>Abbrechen</button>
        {onDelete && <button onClick={doDelete} disabled={saving || deleting} className="ml-auto hover:opacity-80 disabled:opacity-40 text-sm flex items-center gap-1" style={{ color: "var(--mc-st-problem)" }}><Ban className="w-4 h-4" />{deleting ? "Storniere…" : "Stornieren"}</button>}
      </div>
    </Modal>
  );
}

// Punkt 9: Verlauf/Audit-Log pro Fahrt + gemeldete Probleme mit Status.
const LOG_LABEL = { created: "Fahrt erstellt", assigned: "Fahrer zugeteilt", reassigned: "Fahrer geändert", time: "Uhrzeit geändert", route: "Route geändert", status: "Status geändert", problem: "Problem gemeldet", problem_progress: "Problem in Bearbeitung", problem_done: "Problem erledigt", whatsapp: "WhatsApp-Text kopiert", flight: "Flugstatus geändert" };
// Nur von RideForm aus erreichbar (transitiv gemessen, Session 27a), deshalb
// fest auf MC-Design statt mit Schalter. Sichtbar bei JEDER bestehenden Fahrt,
// weil logRide(nr, "created", ...) beim Anlegen schon einen Eintrag setzt.
function RideHistory({ ride }) {
  const [open, setOpen] = useState(false);
  const log = (ride.log || []).slice().sort((a, b) => b.at - a.at);
  const issues = (ride.issues || []).slice().sort((a, b) => b.at - a.at);
  return (
    <div className="mt-4 pt-3" style={{ borderTop: "1px solid var(--mc-border)" }}>
      <button onClick={() => setOpen((o) => !o)} className="text-xs hover:opacity-80 flex items-center gap-1.5" style={{ color: "var(--mc-text-secondary)" }}>
        <ChevronRight className={`w-3.5 h-3.5 transition ${open ? "rotate-90" : ""}`} />Verlauf &amp; Meldungen ({log.length + issues.length})
      </button>
      {open && (
        <div className="mt-2 space-y-2">
          {issues.length > 0 && (
            <div className="space-y-1">
              {issues.map((i, k) => (
                <div key={k} className="text-xs flex items-center gap-2 px-2 py-1" style={{ background: "var(--mc-inset)", borderRadius: "var(--mc-r-sm)" }}>
                  <span className={`mc-badge text-[10px] ${i.state === "done" ? "mc-badge--done" : i.state === "progress" ? "mc-badge--assigned" : "mc-badge--problem"}`}>{ISSUE_STATE_LABEL[i.state] || "offen"}</span>
                  <span style={{ color: "var(--mc-text-secondary)" }}>{i.type}{i.note ? `: ${i.note}` : ""}</span>
                  <span className="ml-auto" style={{ color: "var(--mc-text-muted)" }}>{fmtClock(i.at)}</span>
                </div>
              ))}
            </div>
          )}
          <div className="space-y-0.5 max-h-40 overflow-y-auto">
            {log.map((e, k) => (
              <div key={k} className="text-[11px] flex items-center gap-2" style={{ color: "var(--mc-text-muted)" }}>
                <span className="shrink-0" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-muted)" }}>{fmtClock(e.at)}</span>
                <span style={{ color: "var(--mc-text-secondary)" }}>{LOG_LABEL[e.event] || e.event}</span>
                {e.detail && <span className="truncate" style={{ color: "var(--mc-text-muted)" }}>· {e.detail}</span>}
                <span className="ml-auto shrink-0" style={{ color: "var(--mc-text-muted)" }}>{e.by}</span>
              </div>
            ))}
            {log.length === 0 && <div className="text-[11px]" style={{ color: "var(--mc-text-muted)" }}>Noch keine Einträge.</div>}
          </div>
        </div>
      )}
    </div>
  );
}

// Nur von RideForm aus erreichbar (transitiv gemessen, Session 27a), deshalb
// fest auf MC-Design statt mit Schalter. Kommt es je woanders hin, braucht es
// hier dieselbe mc-Prop wie bei Field/Modal.
function LocSelect({ setup, label, value, custom, onId, onCustom }) {
  return (
    <Field label={label} mc>
      <select className={mcInp} value={value} onChange={(e) => onId(e.target.value)}>
        {setup.locations.map((l) => <option key={l.id} value={l.id}>{l.short}</option>)}
        <option value="__custom">Anderer Ort…</option>
      </select>
      {value === "__custom" && <input className={mcInp + " mt-1.5"} value={custom} onChange={(e) => onCustom(e.target.value)} placeholder="Ort eingeben" />}
    </Field>
  );
}

/* -------- Mission-Control-Variante der Fahrer-Uebersicht (Session 8, Teil 1) --
 * Eigenstaendige Kopie von DriversTab, nur fuer uiMode === "mission-control".
 * DATENABLEITUNG + SORTIERUNG SIND VERBATIM aus DriversTab uebernommen
 * (computeDriverStats, maxMin, live, freeCount/busyCount, Sortierregel). Es wird
 * KEINE Fahrer-, Status-, Rollen-, Zuteilungs- oder GPS-SCHREIBLOGIK veraendert.
 * Neu ist ausschliesslich der Render (MC-Design). Online/Offline + letzter
 * Kontakt werden NUR GELESEN aus driverState[id].gps mit derselben Frische-Regel
 * wie die Live-Karte (GPS_MAX_AGE_MS, fmtAgo) - exakt wie an den bestehenden
 * Lesestellen. Der aktuelle Auftrag ist die von computeDriverStats ohnehin schon
 * berechnete laufende Fahrt (s.active), nur bisher nicht angezeigt. Classic
 * DriversTab bleibt byte-genau unveraendert. */
