/* ---- Teilpaket C1: Timetable-Normalisierung + Helfer (rein lesend) ------ *
 * Reine Funktionen ohne Nebenwirkung. Keine zweite Datumslogik: der
 * Betriebstag kommt aus dem BESTEHENDEN Helfer festDayKey (00:00-05:59 =>
 * Vortagsnacht), festival_day dient nur zur Gegenpruefe/Diagnose. Keine
 * Zufalls-IDs, keine geratenen Zeiten, Originaldaten werden nicht mutiert.
 * ----------------------------------------------------------------------- */
const TT_DT_RE = /^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2})$/;   // "YYYY-MM-DD HH:MM"
const TT_FD_RE = /^(\d{2})\/(\d{2})\/(\d{4})$/;                 // "DD/MM/YYYY"

// Deterministischer, stabiler String-Hash (FNV-1a, 32 Bit) -> 8-stelliger Hex.
// Gleiche Eingabe ergibt immer gleiche ID (Test 15/16), kein Math.random.
function ttHash(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h + ((h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24))) >>> 0;
  }
  return ("00000000" + h.toString(16)).slice(-8);
}

// "YYYY-MM-DD HH:MM" -> absolute Minuten (nur fuer Dauer/Vergleich, UTC-stabil).
function ttAbsMin(dateTime) {
  const m = TT_DT_RE.exec(dateTime);
  if (!m) return null;
  const days = Math.floor(Date.UTC(+m[1], +m[2] - 1, +m[3]) / 86400000);
  return days * 1440 + (+m[4]) * 60 + (+m[5]);
}

// B2B nur nach echten Namensmustern (b2b / vs.), Gross-/Kleinschreibung egal.
// Der Originalname bleibt IMMER unveraendert erhalten (Test 38).
function ttIsB2B(artist) {
  return /\bb2b\b/i.test(artist) || /\bvs\.?\b/i.test(artist);
}

// Suchnormalisierung: Umlaute/Diakritika weg, klein, Mehrfach-Leerzeichen zu eins.
function ttNorm(s) {
  return String(s == null ? "" : s)
    .normalize("NFKD").replace(/[\u0300-\u036f]/g, "")
    .toLowerCase().replace(/\s+/g, " ").trim();
}

// Deterministische Reihenfolge: Start, dann Stage, Artist, sourceIndex.
// startAt ist der kanonische "YYYY-MM-DD HH:MM"-String und damit lexikografisch
// korrekt sortierbar (Post-Mitternacht-Sets haben das echte spaetere Datum,
// landen also korrekt hinter den Abend-Sets desselben Betriebstags).
function ttCompare(a, b) {
  const sa = a.startAt || "", sb = b.startAt || "";
  if (sa !== sb) return sa < sb ? -1 : 1;
  if (a.stage !== b.stage) return a.stage.localeCompare(b.stage, "de");
  if (a.artist !== b.artist) return a.artist.localeCompare(b.artist, "de");
  return a.sourceIndex - b.sourceIndex;
}

/* Wandelt Rohdaten in ein einheitliches internes Format. Ungueltige Eintraege
 * werden NICHT still repariert, sondern mit nachvollziehbarem Diagnosegrund
 * gekennzeichnet; ihre Zeiten bleiben null statt geraten. */
function normalizeTimetableEntries(rawEntries) {
  const list = Array.isArray(rawEntries) ? rawEntries : [];
  return list.map((e, sourceIndex) => {
    const src = e || {};
    const artist = typeof src.artist === "string" ? src.artist : "";
    const stage  = typeof src.stage  === "string" ? src.stage  : "";
    const start  = typeof src.start  === "string" ? src.start  : "";
    const end    = typeof src.end    === "string" ? src.end    : "";
    const festivalDayRaw = typeof src.festival_day === "string" ? src.festival_day : "";

    const problems = [];
    if (!artist.trim()) problems.push({ field: "artist", reason: "Artist fehlt" });
    if (!stage.trim())  problems.push({ field: "stage",  reason: "Stage fehlt" });

    const startOk = TT_DT_RE.test(start);
    const endOk   = TT_DT_RE.test(end);
    if (!start.trim())      problems.push({ field: "start", reason: "Startzeit fehlt" });
    else if (!startOk)      problems.push({ field: "start", reason: "Startzeit ungueltig" });
    if (!end.trim())        problems.push({ field: "end",   reason: "Endzeit fehlt" });
    else if (!endOk)        problems.push({ field: "end",   reason: "Endzeit ungueltig" });

    // Betriebstag ausschliesslich ueber den bestehenden App-Helfer festDayKey.
    let dayKey = null, date = null, startsAfterMidnight = false, durationMin = null;
    if (startOk) {
      date = start.slice(0, 10);
      const startTime = start.slice(11);
      dayKey = festDayKey(date, startTime);
      startsAfterMidnight = toMin(startTime) < 360;
    }

    // festival_day nur zur Gegenpruefe (keine zweite Datumsquelle).
    if (TT_FD_RE.test(festivalDayRaw)) {
      const fm = TT_FD_RE.exec(festivalDayRaw);
      const festivalDayISO = `${fm[3]}-${fm[2]}-${fm[1]}`;
      if (dayKey && festivalDayISO !== dayKey) {
        problems.push({ field: "festival_day", reason: "festival_day weicht vom errechneten Betriebstag ab" });
      }
    } else if (festivalDayRaw.trim()) {
      problems.push({ field: "festival_day", reason: "festival_day-Format unbekannt" });
    }

    if (startOk && endOk) {
      const a = ttAbsMin(start), b = ttAbsMin(end);
      if (a != null && b != null) {
        durationMin = b - a;
        if (durationMin <= 0) problems.push({ field: "end", reason: "Endzeit liegt nicht nach der Startzeit" });
      }
    }

    const valid = problems.length === 0;
    // Stabile ID: Inhalt + sourceIndex als Tie-Breaker, deterministisch.
    const id = "tt-" + ttHash(`${festivalDayRaw}|${stage}|${artist}|${start}|${end}`) + "-" + sourceIndex;

    return {
      id, sourceIndex,
      artist, stage,
      startAt: startOk ? start : null,   // interner Wert = kanonischer, sortierbarer String
      endAt: endOk ? end : null,
      date, dayKey, startsAfterMidnight,
      durationMin,                       // null wenn nicht berechenbar; NIE geraten
      isB2B: ttIsB2B(artist),
      valid,
      problems,                          // [] wenn gueltig
      raw: { festival_day: festivalDayRaw, stage, artist, start, end }, // Original erhalten
    };
  });
}

/* ---- Timetable-Tab (nur Leitstelle, rein lesend) ----------------------- *
 * Keinerlei Schreibvorgang: kein updateDyn, kein Supabase, keine Ride-/Fahrer-
 * Aenderung. Suche und Filter aendern ausschliesslich lokalen useState.
 * Sichtbarkeit steuert allein MC_ROLE_TABS (dispo bekommt alle Tabs,
 * stage/driver ihre Allowlist ohne "timetable") - andere Rollen bleiben
 * dadurch strukturell unangetastet.
 * ----------------------------------------------------------------------- */
function TimetableTab() {
  // Einmalige Normalisierung (stabile Referenz, kein Neuparsen pro Render).
  const entries = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  const [query, setQuery] = useState("");
  const [dayFilter, setDayFilter] = useState("all");     // dayKey oder "all"
  const [stageFilter, setStageFilter] = useState("all"); // Stage-Name oder "all"

  const validEntries   = useMemo(() => entries.filter((e) => e.valid), [entries]);
  const invalidEntries = useMemo(() => entries.filter((e) => !e.valid), [entries]);

  // Dynamische Tag-Liste aus den echten Daten (sortiert), mit Wochentagslabel.
  const days = useMemo(() => {
    const keys = [...new Set(validEntries.map((e) => e.dayKey).filter(Boolean))].sort();
    return keys.map((k) => ({ key: k, label: fmtDate(k) }));
  }, [validEntries]);

  // Dynamische Stage-Liste aus den echten Daten, ohne Duplikate, alphabetisch.
  const stages = useMemo(
    () => [...new Set(validEntries.map((e) => e.stage).filter(Boolean))].sort((a, b) => a.localeCompare(b, "de")),
    [validEntries]
  );

  const sortedValid = useMemo(() => validEntries.slice().sort(ttCompare), [validEntries]);

  // Filter + Suche: nur lesend, nur lokaler State.
  const filtered = useMemo(() => {
    const qTokens = ttNorm(query).split(" ").filter(Boolean);
    return sortedValid.filter((e) => {
      if (dayFilter !== "all" && e.dayKey !== dayFilter) return false;
      if (stageFilter !== "all" && e.stage !== stageFilter) return false;
      if (qTokens.length) {
        const startHM = e.startAt ? e.startAt.slice(11) : "";
        const endHM = e.endAt ? e.endAt.slice(11) : "";
        const hay = ttNorm(`${e.artist} ${e.stage} ${fmtDate(e.dayKey)} ${startHM} ${endHM}`);
        if (!qTokens.every((t) => hay.includes(t))) return false;
      }
      return true;
    });
  }, [sortedValid, dayFilter, stageFilter, query]);

  // Gruppierung nach Betriebstag (Tagesreihenfolge), innerhalb chronologisch.
  const groups = useMemo(() => {
    const byDay = new Map();
    filtered.forEach((e) => {
      if (!byDay.has(e.dayKey)) byDay.set(e.dayKey, []);
      byDay.get(e.dayKey).push(e);
    });
    return [...byDay.entries()]
      .sort((a, b) => (a[0] || "").localeCompare(b[0] || ""))
      .map(([key, items]) => ({ key, label: fmtDate(key), items }));
  }, [filtered]);

  const anyFilter = query !== "" || dayFilter !== "all" || stageFilter !== "all";
  const reset = () => { setQuery(""); setDayFilter("all"); setStageFilter("all"); };

  const hmRange = (e) => {
    const s = e.startAt ? e.startAt.slice(11) : "?";
    const en = e.endAt ? e.endAt.slice(11) : "?";
    return `${s}-${en}`;
  };

  return (
    <div className="mc-scope space-y-3">
      <MissionPanel
        icon={Clock}
        title="Timetable"
        subtitle={`Open Beatz · ${validEntries.length} Sets${invalidEntries.length ? ` · ${invalidEntries.length} mit Hinweis` : ""}`}
      >
        {/* Diagnose nur wenn ungueltige Eintraege existieren (aufklappbar) */}
        {invalidEntries.length > 0 && (
          <details className="mb-3 rounded-lg" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
            <summary className="px-3 py-2 text-xs cursor-pointer flex items-center gap-2" style={{ color: "var(--mc-st-problem)" }}>
              <AlertTriangle className="w-3.5 h-3.5" />
              {invalidEntries.length} Eintrag{invalidEntries.length > 1 ? "e" : ""} konnte{invalidEntries.length > 1 ? "n" : ""} nicht vollständig verarbeitet werden
            </summary>
            <div className="px-3 pb-2 space-y-1">
              {invalidEntries.map((e) => (
                <div key={e.id} className="text-[11px]" style={{ color: "var(--mc-text-secondary)" }}>
                  #{e.sourceIndex} · {e.raw.artist || "(ohne Artist)"} · {e.problems.map((p) => p.reason).join(", ")}
                </div>
              ))}
            </div>
          </details>
        )}

        {/* Suche + Zuruecksetzen (rein lokaler UI-State) */}
        <div className="flex items-center gap-2 mb-3">
          <div className="relative flex-1">
            <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none" style={{ color: "var(--mc-text-muted)" }} />
            <input
              className="mc-input w-full pl-9 pr-3 py-2.5 text-base sm:text-sm"
              value={query}
              onChange={(ev) => setQuery(ev.target.value)}
              placeholder="Artist, Stage oder Uhrzeit suchen…"
              aria-label="Timetable durchsuchen"
            />
          </div>
          {anyFilter && (
            <button onClick={reset} aria-label="Filter zurücksetzen"
              className="text-xs px-3 py-2.5 rounded-lg shrink-0 inline-flex items-center gap-1"
              style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>
              <RotateCcw className="w-3.5 h-3.5" />Zurücksetzen
            </button>
          )}
        </div>

        {/* Filter: Festival-Tag (Chips) + Stage (Auswahl) */}
        <div className="flex flex-col sm:flex-row sm:items-center gap-2 mb-1">
          <div className="flex items-center gap-1.5 flex-wrap">
            {[{ key: "all", label: "Alle Tage" }, ...days].map((d) => {
              const on = dayFilter === d.key;
              return (
                <button key={d.key} onClick={() => setDayFilter(d.key)}
                  className="text-xs px-3 py-1.5 rounded-lg whitespace-nowrap transition"
                  style={on
                    ? { background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)", fontWeight: 600 }
                    : { background: "var(--mc-inset)", color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
                  {d.label}
                </button>
              );
            })}
          </div>
          <div className="sm:ml-auto">
            <select
              className="mc-input px-3 py-2 text-sm"
              value={stageFilter}
              onChange={(ev) => setStageFilter(ev.target.value)}
              aria-label="Stage filtern"
            >
              <option value="all">Alle Stages</option>
              {stages.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        </div>
      </MissionPanel>

      {/* Ergebnis: gruppiert nach Betriebstag, chronologisch */}
      {groups.length === 0 ? (
        <MissionPanel padded={false}>
          <EmptyState icon={Search} title="Keine Sets gefunden"
            hint="Suche oder Filter passen auf keinen Eintrag. Mit „Zurücksetzen“ wieder die komplette Liste anzeigen." />
        </MissionPanel>
      ) : (
        groups.map((g) => (
          <MissionPanel key={g.key} padded={false}>
            <div className="px-4 py-2.5 flex items-center justify-between" style={{ borderBottom: "1px solid var(--mc-border)" }}>
              <span className="text-sm font-semibold" style={{ color: "var(--mc-text)" }}>{g.label}</span>
              <span className="text-[11px]" style={{ color: "var(--mc-text-muted)" }}>{g.items.length} Set{g.items.length > 1 ? "s" : ""}</span>
            </div>
            <div>
              {g.items.map((e) => (
                <div key={e.id} className="px-4 py-2.5 flex items-start gap-3" style={{ borderTop: "1px solid var(--mc-border)" }}>
                  <div className="shrink-0 w-[92px]">
                    <div className="text-sm font-mono tabular-nums" style={{ color: "var(--mc-text)" }}>{hmRange(e)}</div>
                    {e.durationMin != null && (
                      <div className="text-[10px]" style={{ color: "var(--mc-text-muted)" }}>{e.durationMin} min</div>
                    )}
                  </div>
                  <div className="min-w-0 flex-1">
                    <div className="text-sm font-medium break-words" style={{ color: "var(--mc-text)" }} title={e.artist}>{e.artist}</div>
                    <div className="mt-0.5 flex items-center gap-1.5 flex-wrap">
                      <span className="mc-badge mc-badge--idle text-[10px]">{e.stage}</span>
                      {e.isB2B && <span className="mc-badge mc-badge--assigned text-[10px]">B2B</span>}
                      {e.startsAfterMidnight && <span className="mc-badge mc-badge--enroute text-[10px]">nach Mitternacht</span>}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </MissionPanel>
        ))
      )}
    </div>
  );
}

/* ---- Fahrtenliste: rein lesende Live-Uebersicht aller Shuttle-Fahrten ---- *
 * REIN LESEND. Keinerlei Schreibvorgang (kein updateDyn, kein onEdit/onAssign,
 * kein Storage/Supabase, keine Status-/Zeit-/Fahrer-Aenderung). Liest allein
 * aus dyn.rides und stellt sie als durchsuchbare, nach Betriebstag gruppierte
 * Tabelle dar. Live automatisch, weil dieselbe Datenquelle wie Board/Timeline.
 * Nur lokaler UI-State (Suche/Filter). Keine neuen Ride-Felder: alle Spalten
 * kommen aus vorhandenen Feldern (Zeit, djName, from/to, passengerCount,
 * assignedDriverId->Roster, flightNo, notes, status, type). Dispo-only ueber
 * MC_NAV (stage/driver-Allow-Listen enthalten den Tab nicht).
 * ------------------------------------------------------------------------- */
function ridesListDirection(type) {
  if (type === "return") return { key: "rueck", label: "Rückfahrt", st: "assigned" };
  if (type === "arrival" || type === "toVenue") return { key: "hin", label: "Hinfahrt", st: "new" };
  return { key: "transfer", label: "Transfer", st: "idle" };
}
const RIDESLIST_STATUS_ST = {
  planned: "idle", accepted: "new", enroute_pickup: "enroute",
  onboard: "enroute", done: "done", cancelled: "problem",
};
function RidesListTab({ setup, dyn, day }) {
  const [query, setQuery] = useState("");
  const [dayFilter, setDayFilter] = useState("all");   // dayKey oder "all"
  const [typeFilter, setTypeFilter] = useState("all");  // all|hin|rueck|transfer

  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const drvName = (id) => {
    const d = setup.drivers.find((x) => x.id === id);
    return d ? `${d.firstName} ${d.lastName}`.trim() : "";
  };
  const drvVehicle = (id) => {
    const d = setup.drivers.find((x) => x.id === id);
    return d ? (d.vehicleType === "Van" ? "Van" : "Car") : "";
  };

  // Echte Buehne (nur bei eindeutigem Timetable-Treffer). Index einmal bauen und
  // je Zeile wiederverwenden. Rein lesend, keine neue Ride-/DB-Struktur.
  const ttEntries = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  const ttIndex = useMemo(() => buildTimetableMatchIndex(ttEntries), [ttEntries]);

  const allRides = dyn.rides || [];

  // Tag-Liste dynamisch aus den echten Fahrten (sortiert), mit Wochentagslabel.
  const days = useMemo(() => {
    const keys = [...new Set(allRides.map((r) => r.dayKey).filter(Boolean))].sort();
    return keys.map((k) => ({ key: k, label: fmtDate(k) }));
  }, [allRides]);

  const norm = (s) => String(s || "").toLowerCase();

  const filtered = useMemo(() => {
    const qTokens = norm(query).split(" ").filter(Boolean);
    return allRides.filter((r) => {
      if (dayFilter !== "all" && r.dayKey !== dayFilter) return false;
      if (typeFilter !== "all" && ridesListDirection(r.type).key !== typeFilter) return false;
      if (qTokens.length) {
        const hay = norm(`${r.djName} ${ln(r.fromId, r.fromCustom)} ${ln(r.toId, r.toCustom)} ${drvName(r.assignedDriverId)} ${r.flightNo || ""} ${r.time || ""} ${r.notes || ""}`);
        if (!qTokens.every((t) => hay.includes(t))) return false;
      }
      return true;
    });
  }, [allRides, dayFilter, typeFilter, query, setup]);

  // Gruppierung nach Betriebstag, innerhalb chronologisch nach Uhrzeit.
  const groups = useMemo(() => {
    const byDay = new Map();
    filtered.forEach((r) => { if (!byDay.has(r.dayKey)) byDay.set(r.dayKey, []); byDay.get(r.dayKey).push(r); });
    return [...byDay.entries()]
      .sort((a, b) => (a[0] || "").localeCompare(b[0] || ""))
      .map(([key, items]) => ({ key, label: fmtDate(key), items: items.slice().sort((x, y) => sortMin(x.time) - sortMin(y.time)) }));
  }, [filtered]);

  const anyFilter = query !== "" || dayFilter !== "all" || typeFilter !== "all";
  const reset = () => { setQuery(""); setDayFilter("all"); setTypeFilter("all"); };

  const typeChips = [
    { key: "all", label: "Alle Typen" },
    { key: "hin", label: "Hinfahrt" },
    { key: "rueck", label: "Rückfahrt" },
    { key: "transfer", label: "Transfer" },
  ];

  const Th = ({ children, w }) => (
    <th className="text-left font-medium px-3 py-2 whitespace-nowrap"
      style={{ color: "var(--mc-text-muted)", width: w }}>{children}</th>
  );

  return (
    <div className="mc-scope space-y-3">
      <MissionPanel
        icon={Eye}
        title="Fahrtenliste"
        subtitle={`${filtered.length} von ${allRides.length} Fahrten`}
      >
        {/* Suche + Zuruecksetzen (rein lokaler UI-State) */}
        <div className="flex items-center gap-2 mb-3">
          <div className="relative flex-1">
            <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none" style={{ color: "var(--mc-text-muted)" }} />
            <input
              className="mc-input w-full pl-9 pr-3 py-2.5 text-base sm:text-sm"
              value={query}
              onChange={(ev) => setQuery(ev.target.value)}
              placeholder="Artist, Ort, Fahrer, Flug oder Uhrzeit suchen…"
              aria-label="Fahrtenliste durchsuchen"
            />
          </div>
          {anyFilter && (
            <button onClick={reset} aria-label="Filter zurücksetzen"
              className="text-xs px-3 py-2.5 rounded-lg shrink-0 inline-flex items-center gap-1"
              style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>
              <RotateCcw className="w-3.5 h-3.5" />Zurücksetzen
            </button>
          )}
        </div>

        {/* Filter: Festival-Tag (Chips) + Typ (Chips) */}
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-1.5 flex-wrap">
            {[{ key: "all", label: "Alle Tage" }, ...days].map((d) => {
              const on = dayFilter === d.key;
              return (
                <button key={d.key} onClick={() => setDayFilter(d.key)}
                  className="text-xs px-3 py-1.5 rounded-lg whitespace-nowrap transition"
                  style={on
                    ? { background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)", fontWeight: 600 }
                    : { background: "var(--mc-inset)", color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
                  {d.label}
                </button>
              );
            })}
          </div>
          <div className="flex items-center gap-1.5 flex-wrap">
            {typeChips.map((c) => {
              const on = typeFilter === c.key;
              return (
                <button key={c.key} onClick={() => setTypeFilter(c.key)}
                  className="text-xs px-3 py-1.5 rounded-lg whitespace-nowrap transition"
                  style={on
                    ? { background: "var(--mc-st-new-soft)", color: "var(--mc-st-new)", fontWeight: 600 }
                    : { background: "var(--mc-inset)", color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
                  {c.label}
                </button>
              );
            })}
          </div>
        </div>
      </MissionPanel>

      {groups.length === 0 ? (
        <MissionPanel padded={false}>
          <EmptyState icon={Search} title="Keine Fahrten gefunden"
            hint="Suche oder Filter passen auf keine Fahrt. Mit „Zurücksetzen“ wieder die komplette Liste anzeigen." />
        </MissionPanel>
      ) : (
        groups.map((g) => (
          <MissionPanel key={g.key} padded={false}>
            <div className="px-4 py-2.5 flex items-center justify-between" style={{ borderBottom: "1px solid var(--mc-border)" }}>
              <span className="text-sm font-semibold" style={{ color: "var(--mc-text)" }}>{g.label}</span>
              <span className="text-[11px]" style={{ color: "var(--mc-text-muted)" }}>{g.items.length} Fahrt{g.items.length > 1 ? "en" : ""}</span>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm" style={{ borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid var(--mc-border)" }}>
                    <Th w="72px">Zeit</Th>
                    <Th>Artist</Th>
                    <Th>Von → Nach</Th>
                    <Th w="56px">Pers.</Th>
                    <Th w="64px">Fahrzeug</Th>
                    <Th>Fahrer</Th>
                    <Th>Status</Th>
                    <Th w="88px">Flug</Th>
                    <Th>Notiz</Th>
                  </tr>
                </thead>
                <tbody>
                  {g.items.map((r) => {
                    const dir = ridesListDirection(r.type);
                    const stKey = RIDESLIST_STATUS_ST[r.status] || "idle";
                    const fahrer = drvName(r.assignedDriverId);
                    const veh = drvVehicle(r.assignedDriverId);
                    const ttSet = ttStageSet(r, ttEntries, ttIndex);
                    return (
                      <tr key={r.id} style={{ borderTop: "1px solid var(--mc-border)" }}>
                        <td className="px-3 py-2 align-top font-mono tabular-nums whitespace-nowrap" style={{ color: "var(--mc-text)" }}>{r.time || "—"}</td>
                        <td className="px-3 py-2 align-top" style={{ color: "var(--mc-text)" }}>
                          <div className="font-medium break-words" title={r.djName}>{r.djName || "—"}</div>
                          <span className="mc-badge text-[10px] mt-0.5 inline-block" style={{ background: `var(--mc-st-${dir.st}-soft)`, color: `var(--mc-st-${dir.st})` }}>{dir.label}</span>
                          {ttSet && (
                            <div className="text-[11px] mt-0.5 flex items-center gap-1" style={{ color: "var(--mc-text-muted)" }}>
                              <Clock className="w-3 h-3 shrink-0" />
                              <span>{ttSet.stage}{ttSet.start ? ` · ${ttSet.start}${ttSet.end ? "–" + ttSet.end : ""}` : ""}</span>
                            </div>
                          )}
                        </td>
                        <td className="px-3 py-2 align-top whitespace-nowrap" style={{ color: "var(--mc-text-secondary)" }}>{ln(r.fromId, r.fromCustom)} → {ln(r.toId, r.toCustom)}</td>
                        <td className="px-3 py-2 align-top tabular-nums" style={{ color: "var(--mc-text-secondary)" }}>{r.passengerCount != null && r.passengerCount !== "" ? r.passengerCount : "—"}</td>
                        <td className="px-3 py-2 align-top" style={{ color: "var(--mc-text-secondary)" }}>{veh || "—"}</td>
                        <td className="px-3 py-2 align-top whitespace-nowrap" style={{ color: fahrer ? "var(--mc-text)" : "var(--mc-text-muted)" }}>{fahrer || "offen"}</td>
                        <td className="px-3 py-2 align-top">
                          <span className="mc-badge text-[10px]" style={{ background: `var(--mc-st-${stKey}-soft)`, color: `var(--mc-st-${stKey})` }}>{STATUS_LABEL[r.status] || r.status || "—"}</span>
                        </td>
                        <td className="px-3 py-2 align-top font-mono whitespace-nowrap" style={{ color: r.flightNo ? "var(--mc-text-secondary)" : "var(--mc-text-muted)" }}>{r.flightNo || "—"}</td>
                        <td className="px-3 py-2 align-top" style={{ color: "var(--mc-text-secondary)", maxWidth: "260px" }}>{r.notes ? <span className="break-words" title={r.notes}>{r.notes}</span> : <span style={{ color: "var(--mc-text-muted)" }}>—</span>}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </MissionPanel>
        ))
      )}
    </div>
  );
}


/* ============================================================================
   Teilpaket C2: sicheres Artist-Matching zwischen Fahrten und Timetable
   ----------------------------------------------------------------------------
   REIN LESEND. Keinerlei Schreibvorgang (kein updateDyn, kein Supabase, kein
   Storage, keine Aenderung an ride/timetable/Status/Zeit). Berechnet nur
   moegliche Timetable-Zuordnungen und macht sie nachvollziehbar sichtbar.

   Bewusst NICHT enthalten (spaetere Teilpakete): farbliche/kritische Zeit-
   warnungen, automatische Zeit-/Status-/Fahrer-Aenderungen, Fuzzy-Matching,
   Levenshtein, phonetische Aehnlichkeit, Tippfehlerkorrektur.

   Kanonisches Ride-Artist-Feld: ride.djName (einzige Quelle laut Datenanalyse;
   passengers=Begleitnamen, notes=Freitext, type=Fahrttyp -> kein Fallback).
   Betriebstag ausschliesslich ueber den bestehenden Helfer festDayKey.
   Wiederverwendet aus C1: normalizeTimetableEntries (liefert artist, startAt,
   endAt, dayKey via festDayKey, durationMin, valid) sowie ttHash/toMin/sortMin.
   ========================================================================== */

/* Reine Normalisierung NUR fuer Vergleiche. Der sichtbare Originalname wird
 * NIEMALS veraendert. Setzt kein Fuzzy/Aehnlichkeit ein: gleicht nur Schreib-
 * weise an (Gross/Klein, Diakritika, ss/ß, dekorative Sonderzeichen). Zwei
 * verschiedene Kuenstler werden dadurch nicht gleichgesetzt. */
function normalizeArtistName(value) {
  let s = String(value == null ? "" : value);
  // typografische Apostrophe/Anfuehrungen auf ASCII vereinheitlichen (dann entfernt)
  s = s.replace(/[\u2018\u2019\u02BC\u2032]/g, "'").replace(/[\u201C\u201D]/g, '"');
  s = s.toLowerCase();
  // ß -> ss VOR der Diakritika-Entfernung (NFKD zerlegt ß nicht)
  s = s.replace(/\u00df/g, "ss").replace(/\u1e9e/g, "ss");
  // Deutsche Umlaute AUSGESCHRIEBEN transliterieren (ä->ae, ö->oe, ü->ue), damit
  // die Umlaut-Form UND die ausgeschriebene Form identisch normalisieren
  // ("Gestört" == "Gestoert"). Muss VOR der Diakritika-Entfernung passieren,
  // sonst wuerde ö sonst nur zu "o" (Diakritika weg) statt "oe".
  s = s.replace(/\u00e4/g, "ae").replace(/\u00f6/g, "oe").replace(/\u00fc/g, "ue");
  // uebrige Diakritika entfernen (é->e, á->a ...); Umlaute sind schon ersetzt.
  s = s.normalize("NFKD").replace(/[\u0300-\u036f]/g, "");
  // & in einheitliches Wort ueberfuehren, damit "W&W" == "W and W" == "W & W"
  s = s.replace(/&/g, " and ");
  // dekorative Sonderzeichen, Binde-/Unterstriche, Punkte, Kommas, Apostrophe
  // zu Leerzeichen. Buchstaben/Ziffern bleiben.
  s = s.replace(/[^a-z0-9]+/g, " ");
  return s.replace(/\s+/g, " ").trim();
}

/* Explizite Artist-Alias-Konfiguration.
 * Struktur: { "<kanonisch-normalisiert>": ["<alias-normalisiert>", ...] }.
 * NUR aus realen Fahrt-/Timetable-Daten belegte oder fachlich bestaetigte
 * Aliase eintragen - keine erfundenen. Die Datenanalyse (C2, Abschnitt 1)
 * ergab KEINE aus den vorhandenen Daten belegbare Alias-Regel (die grossen
 * Ride-Headliner stehen nicht im Timetable), deshalb ist die Tabelle bewusst
 * leer. Sie bleibt zentral erweiterbar, sobald bestaetigte Faelle vorliegen.
 * Regeln muessen deterministisch und eindeutig auf genau einen kanonischen
 * Artist zeigen; mehrdeutige Aliase (auf >1 Kanon) werden beim Aufbau
 * verworfen. Aliase gelten NUR fuer das Matching, nie fuer die Anzeige. */
const ARTIST_ALIASES = {
  // Beispiel (auskommentiert, NICHT aktiv - nur Formatdoku):
  // "kanonischer name": ["alternative schreibweise", "bekannte abkuerzung"],
};

/* Baut aus ARTIST_ALIASES eine flache, deterministische Lookup-Map
 * alias(normalisiert) -> kanonisch(normalisiert). Mehrdeutige Aliase (zeigen
 * auf mehr als einen Kanon) werden verworfen (als ungueltig markiert), damit
 * ein Alias niemals zwischen zwei Kuenstlern raten muss. Reine Funktion. */
function buildArtistAliasIndex(aliases) {
  const map = new Map();       // alias -> canon
  const rejected = new Set();  // alias, der mehrdeutig ist
  const src = aliases && typeof aliases === "object" ? aliases : {};
  for (const canonRaw of Object.keys(src)) {
    const canon = normalizeArtistName(canonRaw);
    if (!canon) continue;
    const list = Array.isArray(src[canonRaw]) ? src[canonRaw] : [];
    for (const aliasRaw of list) {
      const alias = normalizeArtistName(aliasRaw);
      if (!alias || alias === canon) continue;
      if (rejected.has(alias)) continue;
      if (map.has(alias) && map.get(alias) !== canon) {
        // mehrdeutig -> beide Richtungen verwerfen
        map.delete(alias);
        rejected.add(alias);
        continue;
      }
      map.set(alias, canon);
    }
  }
  return { map, rejected };
}

/* Kollaborations-Trenner. WICHTIG: "&" ist bewusst NICHT dabei, weil es Teil
 * eines einzelnen Kuenstlernamens sein kann (z. B. "Harris & Ford",
 * "2 Engel & Charlie"). Nur eindeutige B2B/Versus-Muster trennen. */
const TT_COLLAB_RE = /\s+(?:b2b|back\s+to\s+back|vs\.?)\s+/i;

/* Ermittelt aus dem Timetable-Namen die einzelnen Kuenstler eines B2B-/Versus-
 * Sets. Der Originalname (originalArtistLabel) bleibt IMMER vollstaendig und
 * unveraendert erhalten. Reine Funktion, keine Nebenwirkung.
 * Rueckgabe:
 *   { originalArtistLabel, normalizedArtists:[...], collaborationType, status }
 * status: "parsed" (eindeutig geteilt) | "unparsed" (nicht eindeutig teilbar). */
function extractTimetableArtists(entry) {
  const original = entry && typeof entry.artist === "string" ? entry.artist : "";
  const base = { originalArtistLabel: original, normalizedArtists: [], collaborationType: null, status: "unparsed" };
  if (!original.trim()) return base;

  // Kollaborationstyp bestimmen (nur echte Muster).
  let collaborationType = null;
  if (/\bb2b\b|\bback\s+to\s+back\b/i.test(original)) collaborationType = "b2b";
  else if (/\bvs\.?\b/i.test(original)) collaborationType = "vs";

  if (!collaborationType) {
    // Einzel-Artist: als genau ein normalisierter Name, sauber "parsed".
    const n = normalizeArtistName(original);
    return { originalArtistLabel: original, normalizedArtists: n ? [n] : [], collaborationType: null, status: n ? "parsed" : "unparsed" };
  }

  // B2B/vs.: entlang der eindeutigen Trenner splitten.
  const parts = original.split(TT_COLLAB_RE).map((p) => normalizeArtistName(p)).filter(Boolean);
  // Nur akzeptieren, wenn mindestens zwei nichtleere, unterscheidbare Teile
  // herauskommen. Sonst nicht eindeutig teilbar -> unparsed (kein Raten).
  const uniq = [...new Set(parts)];
  if (uniq.length < 2) return { originalArtistLabel: original, normalizedArtists: [], collaborationType, status: "unparsed" };
  return { originalArtistLabel: original, normalizedArtists: uniq, collaborationType, status: "parsed" };
}

/* Fahrtrichtung aus den Ride-Endpunkten. Rein aus fromId/toId (die operative
 * Umleitung Leonardo/HBF -> Sheraton-Pickup aendert nur den Abholpunkt, nicht,
 * ob es zum/vom Festival geht). "toFestival" = Hinfahrt, "fromFestival" =
 * Rueckfahrt, sonst "other". Reine Funktion. */
function rideFestivalDirection(ride) {
  const from = ride && ride.fromId;
  const to = ride && ride.toId;
  if (to === "festival" && from !== "festival") return "toFestival";
  if (from === "festival" && to !== "festival") return "fromFestival";
  return "other";
}

/* Kanonischer Ride-Artist-Eingabewert. Nur ride.djName (Datenanalyse: einzige
 * verlaessliche Quelle). Kein Erraten aus passengers/notes/type. Reine Funktion. */
function rideCanonicalArtist(ride) {
  const raw = ride && typeof ride.djName === "string" ? ride.djName : "";
  return { original: raw, normalized: normalizeArtistName(raw), present: !!raw.trim() };
}

/* Baut memo-isierbare Indizes ueber die (bereits aus C1 normalisierten)
 * Timetable-Eintraege: pro normalisiertem Artist (inkl. B2B-Mitglieder) und
 * pro Betriebstag. Wiederverwendung der C1-Normalisierung, kein Neuparsen der
 * Zeiten. Reine Funktion; erwartet die Ausgabe von normalizeTimetableEntries. */
function buildTimetableMatchIndex(entries) {
  const list = Array.isArray(entries) ? entries : [];
  const valid = list.filter((e) => e && e.valid);
  // artistNorm -> [{ entry, memberOf(null|originalLabel), collaborationType }]
  const byArtist = new Map();
  const byDay = new Map();
  for (const entry of valid) {
    if (entry.dayKey) {
      if (!byDay.has(entry.dayKey)) byDay.set(entry.dayKey, []);
      byDay.get(entry.dayKey).push(entry);
    }
    const ex = extractTimetableArtists(entry);
    if (ex.status !== "parsed") continue;
    const isCollab = !!ex.collaborationType;
    for (const nName of ex.normalizedArtists) {
      if (!byArtist.has(nName)) byArtist.set(nName, []);
      byArtist.get(nName).push({
        entry,
        memberOf: isCollab ? ex.originalArtistLabel : null,
        collaborationType: ex.collaborationType,
      });
    }
  }
  return { byArtist, byDay };
}

/* Zeitliche Auswahl unter mehreren Kandidaten desselben Tages, abhaengig von
 * der Fahrtrichtung. Erzeugt NIEMALS einen Artist-Match (der ist bereits
 * erfolgt), nur die Auswahl des plausibelsten Sets. Gibt den ausgewaehlten
 * Kandidaten zurueck oder null (bei verbleibender Mehrdeutigkeit). Reine
 * Funktion, ohne Warnung/Farbe. */
function pickByTime(candidates, direction, ride) {
  if (!candidates.length) return null;
  if (candidates.length === 1) return candidates[0];

  const rideMin = ride && ride.time ? sortMin(ride.time) : null;
  const startMin = (e) => (e.startAt ? sortMin(e.startAt.slice(11)) : null);
  const endMin = (e) => (e.endAt ? sortMin(e.endAt.slice(11)) : null);

  if (rideMin == null) return null; // ohne Fahrtzeit keine zeitliche Aufloesung

  if (direction === "toFestival") {
    // relevantestes Set: Beginn nach geplanter Ankunft, sonst zeitlich naechster
    const withStart = candidates.filter((e) => startMin(e) != null);
    if (!withStart.length) return null;
    const after = withStart.filter((e) => startMin(e) >= rideMin);
    const pool = after.length ? after : withStart;
    let best = null, bestDist = Infinity;
    for (const e of pool) {
      const d = Math.abs(startMin(e) - rideMin);
      if (d < bestDist) { bestDist = d; best = e; }
      else if (d === bestDist) { best = null; } // Gleichstand -> nicht eindeutig
    }
    return best;
  }

  if (direction === "fromFestival") {
    // relevantestes Set: Ende vor/nahe geplanter Rueckfahrt, sonst naechstes
    const withEnd = candidates.filter((e) => endMin(e) != null);
    if (!withEnd.length) return null;
    const before = withEnd.filter((e) => endMin(e) <= rideMin);
    const pool = before.length ? before : withEnd;
    let best = null, bestDist = Infinity;
    for (const e of pool) {
      const d = Math.abs(endMin(e) - rideMin);
      if (d < bestDist) { bestDist = d; best = e; }
      else if (d === bestDist) { best = null; }
    }
    return best;
  }

  // andere Richtungen: keinen zeitlichen Hauptkandidaten erzwingen
  return null;
}

/* Zentrale reine Matching-Funktion. Veraendert NICHTS. Reihenfolge streng:
 *   1) exakter normalisierter Name  -> "exact"
 *   2) expliziter Alias             -> "alias"
 *   3) eindeutiges B2B-Mitglied     -> "b2b_member"
 * Zeit wird NUR danach zur Kandidatenauswahl genutzt (nie zur Match-Erzeugung).
 * Statuswerte (nur berechnete Rueckgabe): exact | alias | b2b_member |
 * multiple_candidates | no_match | missing_artist | invalid_artist. */
function matchRideToTimetable({ ride, timetableEntries, aliases, index, aliasIndex }) {
  const idx = index || buildTimetableMatchIndex(timetableEntries);
  const aIdx = aliasIndex || buildArtistAliasIndex(aliases || ARTIST_ALIASES);
  const direction = rideFestivalDirection(ride);
  const dayKey = ride && ride.dayKey ? ride.dayKey : (ride && ride.date ? festDayKey(ride.date, ride.time || "12:00") : null);
  const art = rideCanonicalArtist(ride);

  const diagnosticBase = {
    rideArtistOriginal: art.original,
    rideArtistNormalized: art.normalized,
    festivalDay: dayKey,
    direction,
    candidates: [],
    excluded: [],
    selected: null,
  };

  // Fehlender Artist.
  if (!art.present) {
    return { ...diagnosticBase, status: "missing_artist", reason: "Kein Artist für Timetable-Zuordnung hinterlegt", matchStage: null };
  }
  // Nur-Sonderzeichen / nicht verarbeitbar.
  if (!art.normalized) {
    return { ...diagnosticBase, status: "invalid_artist", reason: "Artist-Angabe kann nicht verarbeitet werden", matchStage: null };
  }

  // Kandidaten-Herkunft bestimmen: exakt -> alias -> b2b_member (erste greifende Stufe gewinnt).
  let hits = idx.byArtist.get(art.normalized) || [];
  let matchStage = null;
  let usedName = art.normalized;

  const exactHits = hits.filter((h) => h.memberOf === null);
  const b2bHits = hits.filter((h) => h.memberOf !== null);

  if (exactHits.length) {
    matchStage = "exact";
    hits = exactHits;
  } else {
    // Stufe 2: expliziter Alias -> auf kanonischen Namen umlenken, dann exakt suchen.
    const canon = aIdx.map.get(art.normalized);
    if (canon) {
      const canonHits = (idx.byArtist.get(canon) || []).filter((h) => h.memberOf === null);
      if (canonHits.length) {
        matchStage = "alias";
        usedName = canon;
        hits = canonHits;
      }
    }
    if (!matchStage && b2bHits.length) {
      matchStage = "b2b_member";
      hits = b2bHits;
    }
  }

  if (!matchStage || !hits.length) {
    return { ...diagnosticBase, status: "no_match", reason: "Kein passendes Timetable-Set gefunden", matchStage: null };
  }

  // Kandidaten (bereits Artist-gematcht). Diagnose je Kandidat.
  const candidateEntries = hits.map((h) => h.entry);

  // Tag beruecksichtigen: gleicher festDayKey bevorzugt.
  const excluded = [];
  let dayScoped = candidateEntries;
  if (dayKey) {
    const sameDay = candidateEntries.filter((e) => e.dayKey === dayKey);
    candidateEntries.forEach((e) => {
      if (e.dayKey !== dayKey) excluded.push({ id: e.id, reason: `anderer Festival-Tag (${e.dayKey || "?"})` });
    });
    if (sameDay.length) dayScoped = sameDay;
    // Wenn kein Set am gleichen Tag: keine tagesfremde Einzelauswahl erzwingen.
    else dayScoped = candidateEntries;
  }

  // Sortierte Kandidatenliste (zeitliche Plausibilitaet, Start, Stage, Artist, ID).
  const sortedCandidates = dayScoped.slice().sort((a, b) => {
    const sa = a.startAt || "", sb = b.startAt || "";
    if (sa !== sb) return sa < sb ? -1 : 1;
    if (a.stage !== b.stage) return a.stage.localeCompare(b.stage, "de");
    if (a.artist !== b.artist) return a.artist.localeCompare(b.artist, "de");
    return (a.sourceIndex || 0) - (b.sourceIndex || 0);
  });

  const collabLabelFor = (entry) => {
    const h = hits.find((x) => x.entry === entry);
    return h ? h.memberOf : null;
  };

  const result = {
    ...diagnosticBase,
    matchStage,
    matchedNormalized: usedName,
    candidates: sortedCandidates.map((e) => ({
      id: e.id, artist: e.artist, stage: e.stage, dayKey: e.dayKey,
      startAt: e.startAt, endAt: e.endAt,
      collaborationLabel: collabLabelFor(e),
    })),
    excluded,
  };

  // Eindeutig genau ein Kandidat (nach Tagesfilter).
  if (sortedCandidates.length === 1) {
    const e = sortedCandidates[0];
    return { ...result, status: matchStage, selected: candOut(e, collabLabelFor(e)), reason: reasonFor(matchStage) };
  }

  // Mehrere gleicher Tag -> zeitliche Auswahlregel versuchen.
  const sameDaySet = dayKey ? sortedCandidates.filter((e) => e.dayKey === dayKey) : sortedCandidates;
  if (sameDaySet.length > 1) {
    const picked = pickByTime(sameDaySet, direction, ride);
    if (picked) {
      return { ...result, status: matchStage, selected: candOut(picked, collabLabelFor(picked)), reason: reasonFor(matchStage) + " · zeitlich ausgewählt" };
    }
    return { ...result, status: "multiple_candidates", selected: null, reason: "Mehrere plausible Sets gefunden" };
  }

  // sonst (kein Set am Tag, mehrere tagesfremd) -> keine Einzelauswahl erzwingen.
  return { ...result, status: "multiple_candidates", selected: null, reason: "Mehrere plausible Sets gefunden" };
}

function candOut(e, collaborationLabel) {
  return { id: e.id, artist: e.artist, stage: e.stage, dayKey: e.dayKey, startAt: e.startAt, endAt: e.endAt, collaborationLabel: collaborationLabel || null };
}
function reasonFor(stage) {
  if (stage === "exact") return "Exakter Artist-Name";
  if (stage === "alias") return "Treffer über Alias";
  if (stage === "b2b_member") return "Mitglied eines B2B-Sets";
  return "";
}

/* ---- C2 UI: neutrale, rein lesende Timetable-Match-Anzeige --------------- *
 * Nur Leitstellenansicht (eingebunden in RideForm / AssignModal). Keine roten/
 * gelben/gruenen Zeitwarnungen (kommt erst in C3). Keine Schreibaktion.
 * ------------------------------------------------------------------------- */
function ttSetLine(setup, cand) {
  const day = cand.dayKey ? fmtDate(cand.dayKey) : "";
  const s = cand.startAt ? cand.startAt.slice(11) : "?";
  const en = cand.endAt ? cand.endAt.slice(11) : "?";
  return `${day ? day + " · " : ""}${cand.stage} · ${s}–${en}`;
}

/* Rein lesend: liefert fuer eine Fahrt NUR bei eindeutigem Timetable-Treffer die
 * echte Buehne + Set-Zeit ({ stage, start, end }), sonst null. Baut auf der schon
 * vorhandenen matchRideToTimetable-Logik auf (kein neues Matching, kein neues
 * Feld, keine Schreibaktion). Bewusst null bei mehreren/ohne Treffer, damit die
 * Fahrer-Ansicht nicht mit Mehrdeutigkeiten verwirrt wird. Genutzt in Fahrer-App
 * und Leitstellen-Fahrtenliste; matchRideToTimetable bleibt unveraendert. */
function ttStageSet(ride, timetableEntries, index) {
  const m = matchRideToTimetable({ ride, timetableEntries, index });
  if (!m || !m.selected || !m.selected.stage) return null;
  const s = m.selected.startAt ? m.selected.startAt.slice(11) : "";
  const en = m.selected.endAt ? m.selected.endAt.slice(11) : "";
  return { stage: m.selected.stage, start: s, end: en };
}

function TimetableMatchInfo({ ride, entries, match: matchProp }) {
  const match = useMemo(
    () => matchProp || matchRideToTimetable({ ride, timetableEntries: entries }),
    [ride, entries, matchProp]
  );

  const wrap = (children) => (
    <div className="rounded-lg p-3 mt-1 text-xs" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
      <div className="flex items-center gap-1.5 mb-1.5 font-medium" style={{ color: "var(--mc-text-secondary)" }}>
        <Clock className="w-3.5 h-3.5" />Timetable-Zuordnung
      </div>
      {children}
    </div>
  );

  if (match.status === "missing_artist") {
    return wrap(<div style={{ color: "var(--mc-text-muted)" }}>Kein Artist für Timetable-Zuordnung hinterlegt</div>);
  }
  if (match.status === "invalid_artist") {
    return wrap(<div style={{ color: "var(--mc-text-muted)" }}>Artist-Angabe kann nicht verarbeitet werden</div>);
  }
  if (match.status === "no_match") {
    return wrap(<div style={{ color: "var(--mc-text-muted)" }}>Kein passendes Timetable-Set gefunden</div>);
  }

  if (match.status === "multiple_candidates") {
    return wrap(
      <div>
        <div className="mb-1.5" style={{ color: "var(--mc-st-assigned)" }}>Timetable-Zuordnung prüfen · mehrere plausible Sets</div>
        <div className="space-y-1">
          {match.candidates.map((c) => (
            <div key={c.id} style={{ color: "var(--mc-text)" }}>
              <span className="font-medium">{c.artist}</span>
              <span style={{ color: "var(--mc-text-muted)" }}> — {ttSetLine(null, c)}</span>
            </div>
          ))}
        </div>
        {renderDiagnostics(match)}
      </div>
    );
  }

  // exact / alias / b2b_member mit ausgewaehltem Set (selected)
  const sel = match.selected;
  return wrap(
    <div>
      <div className="font-semibold mb-0.5" style={{ color: "var(--mc-text)" }}>
        {sel.collaborationLabel || sel.artist}
      </div>
      <div style={{ color: "var(--mc-text-secondary)" }}>{ttSetLine(null, sel)}</div>
      <div className="mt-1" style={{ color: "var(--mc-text-muted)" }}>
        {match.matchStage === "exact" && <>Match: Exakter Artist-Name</>}
        {match.matchStage === "alias" && <>Match über Alias: {match.rideArtistOriginal}</>}
        {match.matchStage === "b2b_member" && <>Fahrt zugeordnet zu {sel.artist} innerhalb dieses B2B-Sets</>}
      </div>
      {renderDiagnostics(match)}
    </div>
  );
}

/* Aufklappbare, technisch nachvollziehbare Diagnose (keine Stacktraces). */
function renderDiagnostics(match) {
  return (
    <details className="mt-2">
      <summary className="cursor-pointer text-[11px]" style={{ color: "var(--mc-text-muted)" }}>Details</summary>
      <div className="mt-1 space-y-0.5 text-[11px]" style={{ color: "var(--mc-text-muted)" }}>
        <div>Ride-Artist: {match.rideArtistOriginal || "—"} (norm.: {match.rideArtistNormalized || "—"})</div>
        <div>Match-Stufe: {match.matchStage || match.status}</div>
        <div>Festival-Tag: {match.festivalDay || "—"}</div>
        <div>Fahrtrichtung: {match.direction}</div>
        <div>Kandidaten: {match.candidates.length}</div>
        {match.excluded && match.excluded.length > 0 && (
          <div>Ausgeschlossen: {match.excluded.map((x) => `${x.id} (${x.reason})`).join(", ")}</div>
        )}
        <div>Auswahl: {match.selected ? `${match.selected.artist} · ${match.selected.stage}` : match.reason}</div>
      </div>
    </details>
  );
}

/* =========================================================================
   TEILPAKET C3 - rein lesende Timetable-Zeitbewertung
   -------------------------------------------------------------------------
   Baut ausschliesslich auf dem C2-Match-Ergebnis (matchRideToTimetable) auf.
   Veraendert NICHTS: keine Ride-/Match-/Timetable-Mutation, kein State-Write,
   keine Persistenz (DB/Storage). Alle Werte werden bei Bedarf rein berechnet.
   Betriebstag ausschliesslich ueber festDayKey; Set-/Fahrtzeiten mitternachts-
   sicher ueber Absolutminuten (dieselbe Tagesmathematik wie ttAbsMin).
   ========================================================================= */

// Verbindliche, EINZIGE Quelle der Zeitpuffer (Spec Abschnitt 4). Keine zweiten
// Grenzwerte in anderen Funktionen/Komponenten.
const TIMETABLE_WARNING_CONFIG = {
  arrivalOnTimeBufferMin: 40,
  arrivalTightBufferMin: 20,
  returnGraceAfterSetMin: 0,
};

// Ride-Start als Absolutminute (Kalendertag * 1440 + Minuten). Gleiche Tages-
// mathematik wie ttAbsMin -> direkt mit Set-Start/-Ende vergleichbar, auch ueber
// Mitternacht. Streng: ungueltiges/fehlendes Datum oder Uhrzeit -> null (nie geraten).
function c3RideStartAbsMin(date, time) {
  const dm = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(date == null ? "" : date));
  if (!dm) return null;
  const Y = +dm[1], M = +dm[2], D = +dm[3];
  const tm = /^(\d{1,2}):(\d{2})$/.exec(String(time == null ? "" : time).trim());
  if (!tm) return null;
  const h = +tm[1], mi = +tm[2];
  if (h < 0 || h > 23 || mi < 0 || mi > 59) return null;
  const t = Date.UTC(Y, M - 1, D);
  const chk = new Date(t);
  // ungueltige Datumskombination (z. B. 2026-02-30) faengt der Rundlauf ab.
  if (chk.getUTCFullYear() !== Y || chk.getUTCMonth() !== M - 1 || chk.getUTCDate() !== D) return null;
  const days = Math.floor(t / 86400000);
  return days * 1440 + h * 60 + mi;
}

// Umkehrung: Absolutminute -> { iso:"YYYY-MM-DD HH:MM", hm:"HH:MM" } (nur Anzeige/Diagnose).
function c3AbsToParts(abs) {
  if (abs == null) return { iso: null, hm: null };
  const dayIndex = Math.floor(abs / 1440);
  const minOfDay = abs - dayIndex * 1440;
  const d = new Date(dayIndex * 86400000);
  const iso = `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())} ${pad(Math.floor(minOfDay / 60))}:${pad(minOfDay % 60)}`;
  return { iso, hm: `${pad(Math.floor(minOfDay / 60))}:${pad(minOfDay % 60)}` };
}
// "YYYY-MM-DD HH:MM" -> "HH:MM" (rein fuer die Anzeige).
function c3HM(iso) { return iso && iso.length >= 16 ? iso.slice(11, 16) : "—"; }

// Operative Orte/Knoten EXAKT wie der Teilpaket-B-Pfad in evaluateInsertion:
// resolveOperationalRideLocations (Sheraton-Override fuer Leonardo/HBF -> Festival)
// + rideEndpointMatrixNode. Rueckfahrten behalten ihr echtes Ziel. Reine Ableitung.
function c3OperationalNodes(ride, setup) {
  const opLoc = resolveOperationalRideLocations(ride, setup);
  const fromNode = rideEndpointMatrixNode(ride.fromId, ride.fromCustom, opLoc.operationalFrom.operationalRule && opLoc.operationalFrom.operationalLocation);
  const toNode = rideEndpointMatrixNode(ride.toId, ride.toCustom);
  return { opLoc, fromNode, toNode };
}

// Lueckenlose, ueberschneidungsfreie Stufenzuordnung der Ankunfts-Marge (Spec 4.5).
// >= onTime -> on_time | >= tight -> tight | >= 0 -> critical | sonst late.
function gradeArrivalMargin(margin, cfg) {
  if (margin >= cfg.arrivalOnTimeBufferMin) return { status: "on_time", severity: "ok" };
  if (margin >= cfg.arrivalTightBufferMin) return { status: "tight", severity: "warning" };
  if (margin >= 0) return { status: "critical", severity: "critical" };
  return { status: "late", severity: "critical" };
}

// Sichtbare Meldung fuer Hinfahrten (Planungsbewertung, klar als Plan formuliert).
function c3ArrivalMessage(status, margin) {
  if (status === "on_time") return `Geplante Ankunft ${margin} Minuten vor Set-Beginn.`;
  if (status === "tight") return `Geplante Ankunft nur ${margin} Minuten vor Set-Beginn.`;
  if (status === "critical") return margin === 0 ? "Geplante Ankunft exakt zum Set-Beginn." : `Geplante Ankunft nur ${margin} Minuten vor Set-Beginn.`;
  return `Geplante Ankunft ${Math.abs(margin)} Minuten nach Set-Beginn.`; // late
}

// Neutrale Zuordnung, wenn C2 KEIN eindeutiges Set liefert (Spec Abschnitt 11).
// Erzeugt bewusst KEINE harte Zeitbewertung.
function c3NeutralForMatch(status) {
  if (status === "multiple_candidates") return { status: "multiple_candidates", reason: "C2 lieferte mehrere plausible Sets", message: "Eine Zeitbewertung ist erst nach eindeutiger Zuordnung möglich." };
  if (status === "missing_artist") return { status: "missing_artist", reason: "Kein Artist hinterlegt", message: "Kein Artist hinterlegt." };
  if (status === "invalid_artist") return { status: "invalid_artist", reason: "Artist-Angabe nicht verarbeitbar", message: "Die Artist-Angabe kann nicht verarbeitet werden." };
  return { status: "no_match", reason: "Kein passendes Set gefunden", message: "Kein passendes Set gefunden." };
}

/* Zentrale reine Bewertungsfunktion (Spec Abschnitt 2/3/19). Veraendert nichts,
 * loest keine DB-/UI-Seiteneffekte aus, ist deterministisch (nutzt `now` NICHT
 * fuer die Bewertung - reine Planungsbewertung). Liefert eine vollstaendig aus
 * den enthaltenen Werten nachvollziehbare Struktur. */
function evaluateTimetableTiming({ ride, matchResult, setup, now }) {
  const cfg = TIMETABLE_WARNING_CONFIG;
  const reasons = [];
  const matchStatus = matchResult && matchResult.status ? matchResult.status : "no_match";

  // Operative Knoten + Fahrzeit (nur wenn Matrix vorhanden). Keine Schaetzung.
  let fromNode = null, toNode = null, travelMinutes = null;
  if (setup && setup.matrix) {
    const nodes = c3OperationalNodes(ride, setup);
    fromNode = nodes.fromNode;
    toNode = nodes.toNode;
    travelMinutes = travelMin(setup.matrix, fromNode, toNode); // null = unbekannt
  }
  const toFestival = toNode === "festival" && fromNode !== "festival";
  const fromFestival = fromNode === "festival" && toNode !== "festival";
  const direction = toFestival ? "to_festival" : fromFestival ? "from_festival" : "none";

  const sel = matchResult && matchResult.selected ? matchResult.selected : null;
  const base = {
    direction,
    matchStatus,
    rideStartAt: null,
    operationalFrom: fromNode,
    operationalTo: toNode,
    operationalTravelMinutes: travelMinutes == null ? null : travelMinutes,
    estimatedArrivalAt: null,
    plannedDepartureAt: null,
    setStartAt: sel ? sel.startAt : null,
    setEndAt: sel ? sel.endAt : null,
    marginMinutes: null,
    minutesRelativeToSetEnd: null,
    status: "timing_unknown",
    severity: "info",
    message: "",
    reasons,
  };

  // (1) Keine Festival-Beteiligung -> keine Hin-/Rueckfahrtbewertung (Spec 15).
  if (direction === "none") {
    reasons.push("Fahrt ohne Festivalbezug (weder Start noch Ziel ist das Festival)");
    return { ...base, status: "not_applicable", severity: "info", message: "Für diese Fahrt ist keine Festival-Zeitbewertung erforderlich." };
  }

  // (2) Kein eindeutiges C2-Set -> neutral spiegeln, KEINE harte Bewertung (Spec 11).
  const unique = (matchStatus === "exact" || matchStatus === "alias" || matchStatus === "b2b_member") && !!sel;
  if (!unique) {
    const n = c3NeutralForMatch(matchStatus);
    reasons.push(n.reason);
    return { ...base, status: n.status, severity: "info", message: n.message };
  }

  // (3) Fahrtzeit/-datum pruefen (Spec 13).
  const rideAbs = c3RideStartAbsMin(ride.date, ride.time);
  if (rideAbs == null) {
    reasons.push("Ride-Datum oder -Uhrzeit fehlt oder ist ungueltig");
    return { ...base, status: "timing_unknown", severity: "info", message: "Fahrtzeit kann nicht ausgewertet werden." };
  }
  base.rideStartAt = c3AbsToParts(rideAbs).iso;

  const setStartAbs = ttAbsMin(sel.startAt);
  const setEndAbs = ttAbsMin(sel.endAt);

  if (direction === "to_festival") {
    // (4) Timetable-Startzeit pruefen (Spec 14).
    if (setStartAbs == null) {
      reasons.push("Set-Startzeit fehlt oder ist ungueltig");
      return { ...base, status: "timing_unknown", severity: "info", message: "Timetable-Zeit kann nicht sicher ausgewertet werden." };
    }
    // (5) Operative Fahrzeit pruefen (Spec 12) - keine Schaetzung.
    if (travelMinutes == null) {
      reasons.push(`Keine sichere operative Fahrzeit fuer ${fromNode || "?"} -> ${toNode || "?"}`);
      return { ...base, status: "timing_unknown", severity: "info", message: "Ankunftszeit kann nicht berechnet werden. Für diese Ortsverbindung ist keine sichere Fahrzeit hinterlegt." };
    }
    const arrAbs = rideAbs + travelMinutes;
    const margin = setStartAbs - arrAbs;
    const g = gradeArrivalMargin(margin, cfg);
    base.estimatedArrivalAt = c3AbsToParts(arrAbs).iso;
    base.marginMinutes = margin;
    reasons.push(`Ankunft ${c3AbsToParts(arrAbs).hm} (Ride-Start ${c3AbsToParts(rideAbs).hm} + ${travelMinutes} min), Set-Beginn ${c3AbsToParts(setStartAbs).hm}, Puffer ${margin} min`);
    return { ...base, status: g.status, severity: g.severity, message: c3ArrivalMessage(g.status, margin) };
  }

  // direction === "from_festival": geplante Abfahrt gegen Set-Ende (Spec 8).
  if (setEndAbs == null) {
    reasons.push("Set-Endzeit fehlt oder ist ungueltig");
    return { ...base, status: "timing_unknown", severity: "info", message: "Timetable-Zeit kann nicht sicher ausgewertet werden." };
  }
  const depAbs = rideAbs;
  base.plannedDepartureAt = c3AbsToParts(depAbs).iso;
  const rel = depAbs - setEndAbs; // >= 0: zum/nach Set-Ende
  base.minutesRelativeToSetEnd = rel;
  reasons.push(`Abfahrt ${c3AbsToParts(depAbs).hm}, Set-Ende ${c3AbsToParts(setEndAbs).hm}, ${rel >= 0 ? "+" : ""}${rel} min relativ zum Set-Ende`);
  if (rel >= cfg.returnGraceAfterSetMin) {
    return { ...base, status: "return_ok", severity: "ok", message: rel === 0 ? "Rückfahrt zum Set-Ende geplant." : `Abfahrt ${rel} Minuten nach dem geplanten Set-Ende.` };
  }
  return { ...base, status: "return_before_set_end", severity: "critical", message: `Abfahrt ${Math.abs(rel)} Minuten vor dem geplanten Set-Ende.` };
}

/* ---- C3 UI: Planungsbewertung (nur Leitstelle, rein lesend) --------------- *
 * Erscheint direkt unter der C2-Match-Anzeige (RideForm / AssignModal). Nutzt
 * ausschliesslich bestehende, WCAG-gepruefte MC-Farbvariablen; keine neue Farbe.
 * matchResult wird von oben durchgereicht (Match nur einmal berechnet).
 * ------------------------------------------------------------------------- */
const C3_LABEL = {
  on_time: "Rechtzeitig geplant",
  tight: "Knapp geplant",
  critical: "Kritische Planung",
  late: "Zu spät geplant",
  return_ok: "Rückfahrt nach Set-Ende geplant",
  return_before_set_end: "Rückfahrt vor Set-Ende",
};
function c3SeverityColor(sev) {
  if (sev === "ok") return "var(--mc-st-done)";
  if (sev === "warning") return "var(--mc-st-assigned)";
  if (sev === "critical") return "var(--mc-st-problem)";
  return "var(--mc-text-muted)";
}
const C3_GRADED = ["on_time", "tight", "critical", "late", "return_ok", "return_before_set_end"];

function c3Diag(t) {
  return (
    <details className="mt-2">
      <summary className="cursor-pointer text-[11px]" style={{ color: "var(--mc-text-muted)" }}>Details</summary>
      <div className="mt-1 space-y-0.5 text-[11px]" style={{ color: "var(--mc-text-muted)" }}>
        <div>Richtung: {t.direction}</div>
        <div>Match-Status: {t.matchStatus}</div>
        <div>Ride-Start: {t.rideStartAt || "—"}</div>
        <div>Operativ: {t.operationalFrom || "—"} → {t.operationalTo || "—"}</div>
        <div>Operative Fahrzeit: {t.operationalTravelMinutes == null ? "—" : t.operationalTravelMinutes + " min"}</div>
        {t.estimatedArrivalAt && <div>Geplante Ankunft: {t.estimatedArrivalAt}</div>}
        {t.plannedDepartureAt && <div>Geplante Abfahrt: {t.plannedDepartureAt}</div>}
        <div>Set: {t.setStartAt || "—"} bis {t.setEndAt || "—"}</div>
        {t.marginMinutes != null && <div>Puffer: {t.marginMinutes} min</div>}
        {t.minutesRelativeToSetEnd != null && <div>Relativ zum Set-Ende: {t.minutesRelativeToSetEnd} min</div>}
        <div>Status / Severity: {t.status} / {t.severity}</div>
        {t.reasons && t.reasons.length > 0 && <div>Gründe: {t.reasons.join("; ")}</div>}
      </div>
    </details>
  );
}

function TimetableTimingInfo({ ride, matchResult, setup }) {
  const timing = useMemo(
    () => evaluateTimetableTiming({ ride, matchResult, setup, now: Date.now() }),
    [ride, matchResult, setup]
  );
  const st = timing.status;
  const wrap = (children) => (
    <div className="rounded-lg p-3 mt-1 text-xs" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
      <div className="flex items-center gap-1.5 mb-1.5 font-medium" style={{ color: "var(--mc-text-secondary)" }}>
        <Clock className="w-3.5 h-3.5" />Planungsbewertung
      </div>
      {children}
    </div>
  );

  if (st === "not_applicable") {
    return wrap(<div style={{ color: "var(--mc-text-muted)" }}>Für diese Fahrt ist keine Festival-Zeitbewertung erforderlich.</div>);
  }

  if (!C3_GRADED.includes(st)) {
    // Neutral: timing_unknown / multiple_candidates / no_match / missing_artist / invalid_artist.
    const heading = st === "multiple_candidates" ? "Timetable-Zuordnung prüfen"
      : st === "timing_unknown" ? "Zeitbewertung nicht möglich"
        : "Keine Timetable-Zeitbewertung möglich";
    return wrap(
      <div>
        <div className="font-medium mb-0.5" style={{ color: "var(--mc-text-secondary)" }}>{heading}</div>
        <div style={{ color: "var(--mc-text-muted)" }}>{timing.message}</div>
        {c3Diag(timing)}
      </div>
    );
  }

  const color = c3SeverityColor(timing.severity);
  const label = (st === "return_ok" && timing.minutesRelativeToSetEnd === 0) ? "Rückfahrt zum Set-Ende geplant" : C3_LABEL[st];
  return wrap(
    <div>
      <div className="font-semibold mb-0.5" style={{ color }}>{label}</div>
      <div style={{ color: "var(--mc-text-secondary)" }}>{timing.message}</div>
      <div className="mt-1 space-y-0.5" style={{ color: "var(--mc-text-muted)" }}>
        {timing.direction === "to_festival" && (
          <>
            <div>Geplante Ankunft: {c3HM(timing.estimatedArrivalAt)}</div>
            <div>Set-Beginn: {c3HM(timing.setStartAt)}</div>
            <div>Puffer: {timing.marginMinutes} Minuten</div>
          </>
        )}
        {timing.direction === "from_festival" && (
          <>
            <div>Geplante Rückfahrt: {c3HM(timing.rideStartAt)}</div>
            <div>Set-Ende: {c3HM(timing.setEndAt)}</div>
            <div>Differenz: {timing.minutesRelativeToSetEnd >= 0 ? "+" : ""}{timing.minutesRelativeToSetEnd} Minuten</div>
          </>
        )}
      </div>
      {c3Diag(timing)}
    </div>
  );
}


function MissionDriversTab({ setup, dyn, day }) {
  const [, setTick] = useState(0);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 30000); return () => clearInterval(t); }, []);

  // ---- Datenableitung: VERBATIM aus DriversTab (keine Logikaenderung) ----
  const rows = setup.drivers.map((d) => ({ d, s: computeDriverStats(setup, dyn, d.id, day) }));
  const maxMin = Math.max(1, ...rows.map((r) => r.s.drivingMin));
  const now = dayNowMin(day);
  const live = now >= 0 && now < 90000;
  const ln = (id) => setup.locations.find((l) => l.id === id)?.short || null;
  const freeCount = rows.filter((r) => r.s.availability === "free").length;
  const busyCount = rows.length - freeCount;
  const sorted = rows.slice().sort((a, b) => {
    // Beim Zuteilen sind freie Fahrer am interessantesten -> zuerst die freien
    // (nach geringster Auslastung), dann die belegten. (identisch zu DriversTab)
    if (live && a.s.availability !== b.s.availability) return a.s.availability === "free" ? -1 : 1;
    if (live && a.s.availability === "free" && b.s.availability === "free") return a.s.drivingMin - b.s.drivingMin;
    return b.s.drivingMin - a.s.drivingMin;
  });

  // ---- rein PRAESENTATIONAL (neu, keine Logikaenderung) ----
  // Online/letzter Kontakt: nur Lesen, gleiche Frische-Regel wie die Live-Karte.
  const gpsInfo = (id) => {
    const fix = dyn.driverState?.[id]?.gps;
    if (!fix || fix.at == null) return { has: false, online: false, ago: null };
    return { has: true, online: (Date.now() - fix.at) <= GPS_MAX_AGE_MS, ago: fmtAgo(fix.at) };
  };
  // Aktueller Auftrag = laufende Fahrt (s.active): Zeit + Route, reine Anzeige.
  const activeRoute = (r) => r ? { time: r.time, from: ln(r.fromId) || r.fromCustom || "?", to: ln(r.toId) || r.toCustom || "?" } : null;

  if (!setup.drivers.length) {
    return (
      <div className="mc-scope">
        <MissionPanel icon={Users} title="Fahrer" subtitle={`Auslastung ${fmtDate(day)}`}>
          <EmptyState icon={Users} title="Keine Fahrer geladen"
            hint="Sobald Fahrer in den Stammdaten stehen, erscheinen sie hier mit Status, Auslastung und Live-Kontakt." />
        </MissionPanel>
      </div>
    );
  }

  return (
    <div className="mc-scope space-y-3">
      <MissionPanel
        icon={Users}
        title="Fahrer"
        subtitle={`Auslastung ${fmtDate(day)} · gleichmäßiger Einsatz`}
        actions={live ? (
          <div className="flex items-center gap-2">
            <StatusBadge status="done" label={`${freeCount} frei`} />
            <StatusBadge status="enroute" label={`${busyCount} auf Fahrt`} />
          </div>
        ) : null}
      >
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-2">
          {sorted.map(({ d, s }) => {
            const loc = live ? ln(s.locNow) : null;
            const freeAtTxt = live && s.availability === "busy" && s.freeAt != null ? fromMin(s.freeAt) : null;
            const overload = s.drivingMin >= setup.config.softHoursMin;
            const gi = gpsInfo(d.id);
            const ar = live ? activeRoute(s.active) : null;
            const pct = Math.round((s.drivingMin / maxMin) * 100);
            const isVan = d.vehicleType === "Van";
            return (
              <div key={d.id} className="mc-ride-card" style={{ padding: "12px 14px" }}>
                {/* Kopf: Fahrzeug + Name + Online + Status */}
                <div className="flex items-center gap-3">
                  <span className="inline-flex items-center gap-1 text-[11px] font-mono px-1.5 py-0.5 rounded shrink-0"
                    style={{ background: isVan ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: isVan ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>
                    <Car className="w-3 h-3" />{isVan ? "Van" : "Car"}
                  </span>
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-sm font-semibold truncate" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName}</span>
                      {/* Teilpaket A: Springer-/Team-Kennzeichnung (rein informativ) */}
                      {driverCategoryOf(d) === "springer" && <span className="mc-badge mc-badge--problem text-[10px] shrink-0">Springer</span>}
                      {teamLabelOf(d, day) && <span className="mc-badge mc-badge--assigned text-[10px] shrink-0">{teamLabelOf(d, day)}</span>}
                      {gi.has && (
                        <span className="inline-flex items-center gap-1 text-[10px] shrink-0"
                          style={{ color: gi.online ? "var(--mc-st-done)" : "var(--mc-text-muted)" }}>
                          {gi.online ? <Wifi className="w-3 h-3" /> : <WifiOff className="w-3 h-3" />}
                          {gi.online ? "Online" : "Offline"}
                        </span>
                      )}
                    </div>
                    {gi.has && (
                      <div className="text-[10px] mt-0.5" style={{ color: "var(--mc-text-muted)" }}>letzter Kontakt {gi.ago}</div>
                    )}
                  </div>
                  {live && (
                    s.availability === "free"
                      ? <StatusBadge status="done" label={`Frei${loc ? ` · ${loc}` : ""}`} />
                      : <StatusBadge status="enroute" label={`Auf Fahrt${freeAtTxt ? ` · frei ${freeAtTxt}` : ""}`} />
                  )}
                </div>

                {/* Aktueller Auftrag (laufende Fahrt) */}
                {ar && (
                  <div className="mt-2 flex items-center gap-1.5 text-xs rounded-md px-2 py-1"
                    style={{ background: "var(--mc-inset)", color: "var(--mc-text-secondary)" }}>
                    <Navigation className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-st-enroute)" }} />
                    <span className="font-mono shrink-0" style={{ color: "var(--mc-text)" }}>{ar.time}</span>
                    <span className="truncate">{ar.from}</span>
                    <ArrowRight className="w-3 h-3 shrink-0" />
                    <span className="truncate">{ar.to}</span>
                  </div>
                )}

                {/* Auslastung: Balken + Fahrten-Count + Fahrzeit */}
                <div className="mt-2 flex items-center gap-3">
                  <div className="flex-1" style={{ height: 6, borderRadius: 999, background: "var(--mc-inset)", overflow: "hidden" }}>
                    <div style={{ height: "100%", width: `${pct}%`, borderRadius: 999, background: overload ? "var(--mc-st-problem)" : "var(--mc-st-assigned)" }} />
                  </div>
                  <span className="text-xs font-mono shrink-0" style={{ color: "var(--mc-text-secondary)" }}>{s.count}×</span>
                  <span className="text-xs font-mono shrink-0 inline-flex items-center gap-1"
                    style={{ color: overload ? "var(--mc-st-problem)" : "var(--mc-text-secondary)" }}>
                    <Gauge className="w-3.5 h-3.5" />{fmtDur(s.drivingMin)}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </MissionPanel>
    </div>
  );
}

/* -------- Punkt 5: WhatsApp-Texte (nur generieren + kopieren) ------------- */
function waLoc(setup, id, custom) { return setup.locations.find((l) => l.id === id)?.name || custom || "—"; }
function waDriverText(setup, ride) {
  const drv = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  return [
    "Neue Shuttle-Fahrt:",
    `Zeit: ${ride.time}`,
    `Route: ${waLoc(setup, ride.fromId, ride.fromCustom)} → ${waLoc(setup, ride.toId, ride.toCustom)}${ride.zone ? ` (${ride.zone})` : ""}`,
    ride.djName ? `Artist/Gast: ${ride.djName}` : null,
    `Personen: ${ride.passengerCount}`,
    ride.meetingPoint ? `Treffpunkt: ${ride.meetingPoint}` : null,
    ride.flightNo ? `Flug: ${ride.flightNo}${ride.flightStatus ? ` (${flightStyle(ride.flightStatus).l})` : ""}` : null,
    ride.notes ? `Notiz: ${ride.notes}` : null,
    drv ? `Fahrzeug: ${drv.vehicleType === "Van" ? "Van" : "Car"}` : null,
    "Bitte bestätigen.",
  ].filter(Boolean).join("\n");
}
function waArtistText(setup, ride) {
  const drv = setup.drivers.find((d) => d.id === ride.assignedDriverId);
  const veh = drv ? (drv.vehicleType === "Van" ? "Van" : "Car") : null;
  const contact = contactPhoneFor(setup, drv);
  return [
    "Your shuttle is confirmed.",
    `Date: ${fmtDateNum(ride.dayKey)}`,
    `Pickup time: ${ride.time}`,
    `Pickup location: ${waLoc(setup, ride.fromId, ride.fromCustom)}${ride.meetingPoint ? `, ${ride.meetingPoint}` : ""}`,
    drv ? `Driver: ${drv.firstName}` : null,
    veh ? `Vehicle: ${veh}` : null,
    contact ? `${contact.source === "driver" ? "Driver phone" : "Shuttle coordination"}: ${contact.label}` : null,
    `Destination: ${waLoc(setup, ride.toId, ride.toCustom)}${ride.zone ? ` – ${ride.zone}` : ""}`,
    "If anything changes, please contact us.",
  ].filter(Boolean).join("\n");
}
async function copyText(text) {
  try { await navigator.clipboard.writeText(text); return true; }
  catch {
    try {
      const ta = document.createElement("textarea"); ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0";
      document.body.appendChild(ta); ta.focus(); ta.select(); const ok = document.execCommand("copy"); document.body.removeChild(ta); return ok;
    } catch { return false; }
  }
}
function WhatsAppModal({ ride, setup, onClose, onCopied }) {
  const driverTxt = waDriverText(setup, ride);
  const artistTxt = waArtistText(setup, ride);
  const [copied, setCopied] = useState(null);
  const doCopy = async (which, txt) => { const ok = await copyText(txt); if (ok) { setCopied(which); onCopied?.(which === "driver" ? "Fahrer-Text" : "Artist-Text"); setTimeout(() => setCopied(null), 1800); } };
  const Block = ({ id, title, txt }) => (
    <div className="p-3" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
      <div className="flex items-center justify-between mb-2">
        <span className="mc-eyebrow">{title}</span>
        <button onClick={() => doCopy(id, txt)}
          className="mc-btn-primary text-xs px-2.5 py-1 flex items-center gap-1.5"
          style={copied === id ? { background: "var(--mc-st-done-soft)", color: "var(--mc-st-done)" } : undefined}>
          {copied === id ? <><Check className="w-3.5 h-3.5" />kopiert</> : <><Copy className="w-3.5 h-3.5" />Text kopieren</>}
        </button>
      </div>
      <pre className="text-xs whitespace-pre-wrap font-sans leading-relaxed" style={{ color: "var(--mc-text-secondary)" }}>{txt}</pre>
    </div>
  );
  return (
    <Modal onClose={onClose} title="WhatsApp-Texte" wide mc>
      <div className="text-xs mb-3" style={{ color: "var(--mc-text-muted)" }}>{ride.time} · {waLoc(setup, ride.fromId, ride.fromCustom)} → {waLoc(setup, ride.toId, ride.toCustom)}{ride.djName && <> · <span className="font-medium" style={{ color: "var(--mc-st-assigned)" }}>{ride.djName}</span></>}</div>
      <div className="space-y-3">
        <Block id="driver" title="Für den Fahrer (Deutsch)" txt={driverTxt} />
        <Block id="artist" title="Für Artist / Manager (English)" txt={artistTxt} />
      </div>
      <p className="text-[11px] mt-3" style={{ color: "var(--mc-text-muted)" }}>Texte werden nur kopiert – nichts wird automatisch gesendet.</p>
    </Modal>
  );
}

/* -------- Fahrer-Telefonnummern (für Anruf/Weitergabe an Manager) --------- */
// Weiche Telefon-Plausibilitaetspruefung fuer Eingabefelder: true, wenn etwas
// eingetragen ist, das NICHT wie eine Telefonnummer aussieht. Leer gilt als ok
// (Felder sind optional). Trennzeichen (Leerzeichen, - / . ( )) werden ignoriert,
// danach muessen es +? und 6-15 Ziffern sein (gleiche Regel wie extractContactPhones).
// Bewusst weich: nur ein Hinweis, blockiert nie das Speichern.
function phoneLooksInvalid(raw) {
  const s = String(raw || "").trim();
  if (!s) return false;
  const cleaned = s.replace(/[\s\-\/().]/g, "");
  return !/^\+?[0-9]{6,15}$/.test(cleaned);
}
// Normalisiert eine deutsche Handynummer auf internationales Format ("+49 ..."):
// - "0176 1234567" -> "+49 176 1234567"
// - "0049 176 1234567" -> "+49 176 1234567"
// - "+49 ..." bleibt (nur weiche Formatierung)
// - Ausland ("+43 ...") bleibt unveraendert
// - Leer/null -> null (Aufrufer entscheidet, was dann angezeigt wird)
// - Nicht erkennbar (Buchstaben etc.) -> Ausgangswert zurueck, blockiert nicht.
// Format-Ausgabe: Landesvorwahl, dann Netz-/Ortsvorwahl (3-4 Ziffern), Rest.
function driverPhoneIntl(raw) {
  const s = String(raw || "").trim();
  if (!s) return null;
  const digits = s.replace(/[\s\-\/().]/g, "");
  if (!/^\+?[0-9]{6,15}$/.test(digits)) return s;
  let intl;
  if (digits.startsWith("+")) intl = digits;
  else if (digits.startsWith("00")) intl = "+" + digits.slice(2);
  else if (digits.startsWith("0")) intl = "+49" + digits.slice(1);
  else intl = "+" + digits;
  // Laendervorwahl abtrennen: 1-stellig fuer +1 (Nordamerika) und +7 (Russland),
  // 3-stellig fuer bekannte europaeische +3xx/+4xx, sonst 2-stellig als Default
  // (deckt +49/+43/+41/+33/+44/+39/+34/... ab).
  const rest = intl.slice(1);
  let cc;
  if (/^(420|421|350|351|352|353|354|355|356|357|358|359|370|371|372|373|374|375|376|377|378|380|381|382|385|386|387|389)/.test(rest)) cc = rest.slice(0, 3);
  else if (/^[17]/.test(rest)) cc = rest.slice(0, 1);
  else cc = rest.slice(0, 2);
  const body = rest.slice(cc.length);
  if (body.length <= 3) return `+${cc} ${body}`;
  return `+${cc} ${body.slice(0, 3)} ${body.slice(3)}`;
}
// Liefert die Kontakt-Nummer, die dem Manager/Gast angezeigt/geschickt werden
// darf: bevorzugt die private Nummer des zugeteilten Fahrers (Jordans Freigabe
// vom 24.07.2026), Fallback ist die zentrale Shuttle-Coordination-Nummer aus
// setup.config.coordinationPhone. Gibt null, wenn beides fehlt.
function contactPhoneFor(setup, drv) {
  const drvIntl = drv && drv.phone ? driverPhoneIntl(drv.phone) : null;
  if (drvIntl) return { label: drvIntl, tel: drvIntl.replace(/\s/g, ""), source: "driver" };
  const coordIntl = driverPhoneIntl(setup?.config?.coordinationPhone);
  if (coordIntl) return { label: coordIntl, tel: coordIntl.replace(/\s/g, ""), source: "coord" };
  return null;
}
function DriverPhones({ setup, updateSetup }) {
  const [phones, setPhones] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.phone || ""])));
  const [plates, setPlates] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.plate || ""])));
  const [pins, setPins] = useState(() => Object.fromEntries(setup.drivers.map((d) => [d.id, d.pin || ""])));
  const [saved, setSaved] = useState(false);
  const [saveError, setSaveError] = useState("");
  const dirty = setup.drivers.some((d) => (phones[d.id] || "") !== (d.phone || "") || (plates[d.id] || "") !== (d.plate || "") || (pins[d.id] || "") !== (d.pin || ""));
  // Slice 3: weicher Hinweis auf ungewoehnliche Nummern (blockiert NICHT). Formate
  // variieren (Auslandsvorwahlen etc.), daher nur ein Hinweis, kein Speicherblocker.
  const oddPhones = setup.drivers.filter((d) => phoneLooksInvalid(phones[d.id])).map((d) => `${d.firstName} ${d.lastName[0]}.`);
  const save = async () => {
    setSaveError("");
    // "gespeichert" nur zeigen, wenn updateSetup wirklich ok meldet. Sonst
    // sähe der Nutzer eine Erfolgsmeldung, obwohl Telefonnummer/Kennzeichen/PIN
    // nie in der DB gelandet sind.
    const res = await updateSetup((s) => { s.drivers.forEach((d) => { d.phone = (phones[d.id] || "").trim(); d.plate = (plates[d.id] || "").trim(); d.pin = (pins[d.id] || "").trim(); }); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveError(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <SectionHeader icon={Radio} title="Fahrer-Telefonnummern, Kennzeichen & PIN" className="mb-3"
        subtitle={<>Telefonnummer für Anruf-Buttons in der Leitstelle. Kennzeichen optional — erscheint nur, wenn gepflegt, im Gast-/Artist-Link. Eigener PIN optional — leer lassen, um den Standard-PIN (unten bei „Zugangs-PINs") zu nutzen. Alles bleibt im System (im Deployment in der DB, nicht im Code).</>} />
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-4 gap-y-1.5 max-h-72 overflow-y-auto pr-1">
        {setup.drivers.map((d) => (
          <div key={d.id} className="flex items-center gap-1.5 text-sm flex-wrap">
            {/* Session 27b: Van = Amber, Car = Blau (Farbregel seit 27e, identisch
                zu AssignModal Z. 3827). Vorher war Van orange = Markenfarbe. */}
            <span className="text-[10px] px-1.5 py-0.5 rounded shrink-0 w-12 text-center" style={{ fontFamily: "var(--mc-font-mono)", color: d.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)", background: d.vehicleType === "Van" ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
            <span className="w-20 truncate shrink-0" style={{ color: "var(--mc-text-secondary)" }}>{d.firstName} {d.lastName[0]}.</span>
            <input type="tel" className="mc-input flex-1 min-w-0 px-2 py-1 text-sm"
              value={phones[d.id] || ""} onChange={(e) => setPhones((p) => ({ ...p, [d.id]: e.target.value }))} placeholder="+49 …" />
            <input className="mc-input w-16 shrink-0 px-2 py-1 text-sm"
              value={plates[d.id] || ""} onChange={(e) => setPlates((p) => ({ ...p, [d.id]: e.target.value }))} placeholder="Kennz." />
            <input className="mc-input w-16 shrink-0 px-2 py-1 text-sm"
              value={pins[d.id] || ""} onChange={(e) => setPins((p) => ({ ...p, [d.id]: e.target.value.replace(/\D/g, "") }))} placeholder="PIN" inputMode="numeric" />
          </div>
        ))}
      </div>
      <div className="flex items-center gap-2 mt-3">
        <button onClick={save} disabled={!dirty} className="mc-btn-primary disabled:opacity-40 text-sm px-3 py-2">Speichern</button>
        {saved && <span className="text-xs flex items-center gap-1" style={{ color: "var(--mc-st-done)" }}><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {saveError && <span className="text-xs" style={{ color: "var(--mc-st-problem)" }}>{saveError}</span>}
      </div>
      {oddPhones.length > 0 && (
        <div className="text-xs mt-2" style={{ color: "var(--mc-st-assigned)" }}>{oddPhones.length} Nummer(n) sehen ungewöhnlich aus ({oddPhones.slice(0, 4).join(", ")}{oddPhones.length > 4 ? " …" : ""}), bitte prüfen. Speichern geht trotzdem.</div>
      )}
    </div>
  );
}

/* -------- Leitstellen-Nutzer (für namentliche Zuordnung im Protokoll) ----- */
function DispatcherUsers({ setup, updateSetup }) {
  const [names, setNames] = useState(() => Object.fromEntries((setup.dispatchers || []).map((p) => [p.id, p.name])));
  const [pins, setPins] = useState(() => Object.fromEntries((setup.dispatchers || []).map((p) => [p.id, p.pin || ""])));
  const [saved, setSaved] = useState(false);
  const [saveError, setSaveError] = useState("");
  const dirty = (setup.dispatchers || []).some((p) => (names[p.id] || "") !== p.name || (pins[p.id] || "") !== (p.pin || ""));
  const save = async () => {
    setSaveError("");
    const res = await updateSetup((s) => { (s.dispatchers || []).forEach((p) => { p.name = (names[p.id] || p.name).trim(); p.pin = (pins[p.id] || "").trim(); }); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveError(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  const addOne = async () => {
    const name = window.prompt("Name des neuen Leitstellen-Nutzers?");
    if (!name || !name.trim()) return;
    setSaveError("");
    const res = await updateSetup((s) => { s.dispatchers = [...(s.dispatchers || []), { id: slug(name.trim()) + "-" + Date.now().toString(36).slice(-3), name: name.trim(), pin: "" }]; return s; });
    if (!(res && res.ok)) setSaveError(res?.error || "Hinzufügen fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <SectionHeader icon={Users} title="Leitstellen-Nutzer" className="mb-3"
        subtitle={<>Wer sich hier anmeldet, erscheint namentlich statt anonym „Leitstelle" im Änderungsprotokoll. Eigener PIN optional — leer lassen, um den Standard-PIN (unten bei „Zugangs-PINs") zu nutzen.</>} />
      <div className="space-y-1.5">
        {(setup.dispatchers || []).map((p) => (
          <div key={p.id} className="flex items-center gap-2 text-sm">
            <input className="mc-input flex-1 px-2 py-1.5 text-sm"
              value={names[p.id] ?? p.name} onChange={(e) => setNames((n) => ({ ...n, [p.id]: e.target.value }))} />
            <input className="mc-input w-20 shrink-0 px-2 py-1.5 text-sm"
              value={pins[p.id] || ""} onChange={(e) => setPins((n) => ({ ...n, [p.id]: e.target.value.replace(/\D/g, "") }))} placeholder="PIN" inputMode="numeric" />
          </div>
        ))}
      </div>
      <div className="flex items-center gap-2 mt-3">
        <button onClick={save} disabled={!dirty} className="mc-btn-primary disabled:opacity-40 text-sm px-3 py-2">Speichern</button>
        <button onClick={addOne} className="mc-btn-quiet text-sm px-3 py-2 flex items-center gap-1.5"><Plus className="w-3.5 h-3.5" />Person hinzufügen</button>
        {saved && <span className="text-xs flex items-center gap-1" style={{ color: "var(--mc-st-done)" }}><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {saveError && <span className="text-xs" style={{ color: "var(--mc-st-problem)" }}>{saveError}</span>}
      </div>
    </div>
  );
}

/* -------- Zugangs-PINs (Standard-Fallback + Stage-Manager) --------------- */
function AccessPinsSection({ setup, updateSetup }) {
  const [defaultPin, setDefaultPin] = useState(setup.config.defaultPin || "");
  const [stagePin, setStagePin] = useState(setup.config.stagePin || "");
  const [saved, setSaved] = useState(false);
  const [saveError, setSaveError] = useState("");
  const dirty = defaultPin !== (setup.config.defaultPin || "") || stagePin !== (setup.config.stagePin || "");
  const save = async () => {
    setSaveError("");
    const res = await updateSetup((s) => { s.config.defaultPin = defaultPin.trim() || PIN; s.config.stagePin = stagePin.trim(); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveError(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <SectionHeader icon={Radio} title="Zugangs-PINs" className="mb-3"
        subtitle="Standard-PIN gilt für jeden Fahrer/Leitstellen-Nutzer ohne eigenen PIN (oben pflegbar). Stage-Manager-PIN eigenständig, leer = nutzt ebenfalls den Standard-PIN." />
      <div className="space-y-2 max-w-xs">
        <Field mc label="Standard-PIN (Fallback)">
          <input className={mcInp} value={defaultPin} onChange={(e) => setDefaultPin(e.target.value.replace(/\D/g, ""))} placeholder="z. B. 1234" inputMode="numeric" />
        </Field>
        <Field mc label="Stage-Manager-PIN">
          <input className={mcInp} value={stagePin} onChange={(e) => setStagePin(e.target.value.replace(/\D/g, ""))} placeholder="leer = Standard-PIN" inputMode="numeric" />
        </Field>
      </div>
      <div className="flex items-center gap-2 mt-3">
        <button onClick={save} disabled={!dirty} className="mc-btn-primary disabled:opacity-40 text-sm px-3 py-2">Speichern</button>
        {saved && <span className="text-xs flex items-center gap-1" style={{ color: "var(--mc-st-done)" }}><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {saveError && <span className="text-xs" style={{ color: "var(--mc-st-problem)" }}>{saveError}</span>}
      </div>
    </div>
  );
}

/* -------- Gast-/Artist-Manager-Links verwalten --------------------------- */
function GuestLinksSection({ setup, dyn, updateSetup, onPreviewGuest }) {
  const [coordPhone, setCoordPhone] = useState(setup.config.coordinationPhone || "");
  const [savedPhone, setSavedPhone] = useState(false);
  const [phoneErr, setPhoneErr] = useState("");
  const [newArtist, setNewArtist] = useState("");
  const [copiedTok, setCopiedTok] = useState(null);
  const [saveError, setSaveError] = useState("");
  // Token-Liste ist seit Nachtrag 3 nicht mehr Teil des generellen setup-
  // Objekts (das ging vorher an jede Rolle raus, Fahrer/Stage inklusive).
  // Hier separat laden: im Supabase-Betrieb über die dispatcher-RPC, im
  // Chat-Artifact weiterhin aus setup.guestTokens (dort unverändert).
  const [tokens, setTokens] = useState(hasSupabase() ? null : (setup.guestTokens || []));

  useEffect(() => {
    if (!hasSupabase()) return;
    let stop = false;
    loadGuestTokens().then((t) => { if (!stop) setTokens(t); }).catch((e) => {
      console.error("loadGuestTokens fehlgeschlagen:", e);
      if (!stop) { setTokens([]); setSaveError("Gast-Links konnten nicht geladen werden. Bitte Seite neu laden."); }
    });
    return () => { stop = true; };
  }, []);

  const savePhone = async () => {
    setPhoneErr("");
    const res = await updateSetup((s) => { s.config.coordinationPhone = coordPhone.trim(); return s; });
    if (res && res.ok) { setSavedPhone(true); setTimeout(() => setSavedPhone(false), 1800); }
    else setPhoneErr(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  const artistOptions = useMemo(() => {
    const set = new Set();
    (dyn.rides || []).forEach((r) => { if (r.djName && r.status !== "cancelled") set.add(r.djName.trim()); });
    return [...set].sort();
  }, [dyn.rides]);
  const list = tokens || [];
  const existingNames = new Set(list.map((t) => t.djName.toLowerCase()));

  // WICHTIG: erst wirklich speichern, DANACH die Liste aktualisieren. Vorher
  // stand hier eine "optimistische" Aktualisierung vor dem Speichern — sah
  // in der Oberfläche sofort nach Erfolg aus, auch wenn das Speichern im
  // Hintergrund scheiterte (z. B. RPC-Fehler), der Link existierte dann gar
  // nicht wirklich in der Datenbank. Jetzt: bei Fehler bleibt die alte Liste
  // stehen und es gibt eine sichtbare Fehlermeldung statt eines stillen,
  // falschen Erfolgs.
  const persist = async (next) => {
    setSaveError("");
    const prev = list;
    try {
      if (hasSupabase()) await saveGuestTokens(next);
      else {
        // updateSetup wirft NICHT bei einem Schreibkonflikt, sondern liefert
        // { ok:false }. Ohne diese Pruefung liefe setTokens(next) trotzdem und
        // die UI zeigte einen Link, der nie gespeichert wurde.
        const res = await updateSetup((s) => { s.guestTokens = next; return s; });
        if (!res || !res.ok) throw new Error(res?.error || "Speichern fehlgeschlagen");
      }
      setTokens(next);
    } catch (e) {
      console.error("Gast-Link speichern fehlgeschlagen:", e);
      setTokens(prev); // zurückrollen, nicht mit falschem Stand weitermachen
      setSaveError("Speichern fehlgeschlagen, bitte nochmal versuchen. (Details in der Browser-Konsole)");
    }
  };
  const genFor = async (name) => {
    const n = (name || "").trim();
    if (!n) return;
    const token = genGuestToken();
    await persist([...list, { token, djName: n, createdAt: Date.now() }]);
    setNewArtist("");
  };
  const revoke = async (token) => {
    if (!window.confirm("Diesen Gast-Link wirklich löschen? Er funktioniert danach nicht mehr.")) return;
    await persist(list.filter((t) => t.token !== token));
  };
  const linkFor = (token) => `${window.location.origin}${window.location.pathname}?guest=${token}`;
  const copyLink = async (token) => { const ok = await copyText(linkFor(token)); if (ok) { setCopiedTok(token); setTimeout(() => setCopiedTok(null), 1800); } };

  return (
    <div>
      <SectionHeader icon={Link2} title="Gast-/Artist-Links" className="mb-3"
        subtitle={<>Persönliche Info-Seite für Artist/Manager — nur Ansicht, keine Dispo-Funktionen, standardmäßig Englisch.
          {/* Session 27b: Sicherheitshinweis ist eine WARNUNG, nicht die Marke.
              Vorher orange-300 = Markenfarbe, das war der Regelbruch. Amber ist
              die Warnfarbe, identisch zum oddPhones-Hinweis in DriverPhones. */}
          <b style={{ color: "var(--mc-st-assigned)" }}> Sicherheitshinweis:</b> Im Chat-Artifact blendet der Link nur die Oberfläche aus, ist keine echte Zugriffssperre. Nach dem Supabase-Deploy ist der Link echt auf die eigenen Fahrten beschränkt (RPC-basiert); die vollständige Liste hier ist trotzdem nur für die Leitstelle gedacht, nicht zum Weitergeben.</>} />
      {saveError && (
        <div className="mc-note mc-note--error mb-3 text-xs flex items-center gap-2">
          <AlertTriangle className="w-3.5 h-3.5 shrink-0" />{saveError}
        </div>
      )}

      <div className="mb-4 pb-4 border-b" style={{ borderColor: "var(--mc-border)" }}>
        <Field mc label="Zentrale Shuttle-Coordination-Nummer (nicht die private Fahrer-Nummer)">
          <div className="flex gap-2">
            <input type="tel" className={mcInp} value={coordPhone} onChange={(e) => setCoordPhone(e.target.value)} placeholder="+49 …" />
            <button onClick={savePhone} disabled={coordPhone === (setup.config.coordinationPhone || "")} className="mc-btn-primary shrink-0 disabled:opacity-40 text-sm px-3">Speichern</button>
          </div>
        </Field>
        {phoneLooksInvalid(coordPhone) && (
          <div className="text-xs mt-1.5" style={{ color: "var(--mc-st-assigned)" }}>Diese Nummer sieht ungewöhnlich aus. Für den WhatsApp-Link an Gäste sollten es nur + und Ziffern sein. Speichern geht trotzdem.</div>
        )}
        {savedPhone && <span className="text-xs flex items-center gap-1 mt-1.5" style={{ color: "var(--mc-st-done)" }}><Check className="w-3.5 h-3.5" />gespeichert</span>}
        {phoneErr && <span className="text-xs mt-1.5 block" style={{ color: "var(--mc-st-problem)" }}>{phoneErr}</span>}
      </div>

      <div className="mb-3">
        <span className="text-xs mb-1 block" style={{ color: "var(--mc-text-secondary)" }}>Neuen Link erzeugen</span>
        <div className="flex flex-wrap gap-1.5 mb-2">
          {artistOptions.filter((n) => !existingNames.has(n.toLowerCase())).slice(0, 12).map((n) => (
            <button key={n} onClick={() => genFor(n)} className="mc-btn-quiet text-xs px-2.5 py-1">{n}</button>
          ))}
        </div>
        <div className="flex gap-2">
          <input className={mcInp} value={newArtist} onChange={(e) => setNewArtist(e.target.value)} placeholder="oder Künstlername eingeben" onKeyDown={(e) => e.key === "Enter" && genFor(newArtist)} />
          <button onClick={() => genFor(newArtist)} className="mc-btn-quiet shrink-0 text-sm px-3 flex items-center gap-1.5"><Plus className="w-3.5 h-3.5" />Link</button>
        </div>
      </div>

      <div className="space-y-1.5 max-h-72 overflow-y-auto">
        {tokens === null && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>Lädt…</div>}
        {tokens !== null && list.length === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>Noch keine Gast-Links erzeugt.</div>}
        {list.slice().sort((a, b) => b.createdAt - a.createdAt).map((t) => (
          <div key={t.token} className="flex items-center gap-2 text-sm rounded-lg px-2.5 py-2" style={{ background: "var(--mc-inset)" }}>
            <span className="truncate" style={{ color: "var(--mc-text)" }}>{t.djName}</span>
            <span className="text-[10px] truncate" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-muted)" }}>{t.token.slice(0, 8)}…</span>
            <div className="ml-auto flex items-center gap-1 shrink-0">
              <button onClick={() => onPreviewGuest?.(t.token)} title="Vorschau" aria-label="Vorschau" className="mc-iconbtn w-7 h-7"><Eye className="w-3.5 h-3.5" /></button>
              {/* Kopiert-Bestaetigung behaelt bewusst die Erfolgsfarbe, wie "gespeichert". */}
              <button onClick={() => copyLink(t.token)} title="Link kopieren" aria-label="Link kopieren" className="mc-iconbtn w-7 h-7">{copiedTok === t.token ? <Check className="w-3.5 h-3.5" style={{ color: "var(--mc-st-done)" }} /> : <Copy className="w-3.5 h-3.5" />}</button>
              <button onClick={() => revoke(t.token)} title="Löschen" aria-label="Löschen" className="mc-iconbtn w-7 h-7"><Trash2 className="w-3.5 h-3.5" /></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

/* -------- Echte Push-Benachrichtigungen einrichten ------------------------ */
function PushSettingsSection({ setup, updateSetup }) {
  const [key, setKey] = useState(setup.config.vapidPublicKey || "");
  const [saved, setSaved] = useState(false);
  const [saveErr, setSaveErr] = useState("");
  const save = async () => {
    setSaveErr("");
    const res = await updateSetup((s) => { s.config.vapidPublicKey = key.trim(); return s; });
    if (res && res.ok) { setSaved(true); setTimeout(() => setSaved(false), 1800); }
    else setSaveErr(res?.error || "Speichern fehlgeschlagen, bitte erneut versuchen.");
  };
  return (
    <div>
      <SectionHeader icon={Radio} title="Echte Push-Benachrichtigungen" className="mb-3"
        subtitle="Damit Fahrer auch bei gesperrtem Handy eine Benachrichtigung bekommen (nicht nur solange die App offen ist), braucht es nach dem Deploy ein VAPID-Schlüsselpaar. Öffentlichen Schlüssel hier eintragen, den privaten als Umgebungsvariable auf dem Server (siehe BACKEND-README) — nie hier im Frontend." />
      <Field mc label="VAPID Public Key">
        <div className="flex gap-2">
          <input className={mcInp} value={key} onChange={(e) => setKey(e.target.value)} placeholder="z. B. BIed3…" />
          <button onClick={save} disabled={key === (setup.config.vapidPublicKey || "")} className="mc-btn-primary shrink-0 disabled:opacity-40 text-sm px-3">Speichern</button>
        </div>
      </Field>
      {saved && <span className="text-xs flex items-center gap-1 mt-1.5" style={{ color: "var(--mc-st-done)" }}><Check className="w-3.5 h-3.5" />gespeichert</span>}
      {saveErr && <span className="text-xs mt-1.5 block" style={{ color: "var(--mc-st-problem)" }}>{saveErr}</span>}
      {!setup.config.vapidPublicKey && <p className="text-[11px] mt-2" style={{ color: "var(--mc-text-muted)" }}>Solange kein Key hinterlegt ist, bleibt es beim Vordergrund-Hinweis (Toast/Vibration bei offener App) — funktioniert schon jetzt, ganz ohne Einrichtung.</p>}
    </div>
  );
}
// Übersetzt die "by"-Kennung aus logRide() in einen lesbaren Namen.
function byLabel(setup, by) {
  if (!by) return "—";
  if (by.startsWith("driver:")) {
    const d = setup.drivers.find((x) => x.id === by.slice(7));
    return d ? `Fahrer ${d.firstName} ${d.lastName}` : "Fahrer";
  }
  if (by.startsWith("stage:")) {
    const st = by.slice(6);
    return `Stage Manager${st && st !== "?" ? ` (${st})` : ""}`;
  }
  if (by.startsWith("dispo:")) {
    const p = (setup.dispatchers || []).find((x) => x.id === by.slice(6));
    return p ? p.name : "Leitstelle";
  }
  if (by.startsWith("guest:")) {
    const nm = by.slice(6);
    return `Artist/Manager${nm ? ` (${nm})` : ""}`;
  }
  const map = { dispo: "Leitstelle", auto: "Automatisch", system: "System", import: "Import", Beispiel: "Beispieldaten" };
  return map[by] || by;
}
function AuditLogSection({ setup, dyn }) {
  const [dayFilter, setDayFilter] = useState("all");
  const [q, setQ] = useState("");
  const days = dayTabs(setup, dyn);
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";

  const entries = useMemo(() => {
    const list = [];
    (dyn.rides || []).forEach((r) => {
      if (dayFilter !== "all" && r.dayKey !== dayFilter) return;
      (r.log || []).forEach((e) => list.push({ ...e, ride: r }));
    });
    list.sort((a, b) => b.at - a.at);
    if (!q.trim()) return list.slice(0, 300);
    const needle = q.toLowerCase();
    return list.filter((e) =>
      (LOG_LABEL[e.event] || e.event).toLowerCase().includes(needle) ||
      (e.detail || "").toLowerCase().includes(needle) ||
      byLabel(setup, e.by).toLowerCase().includes(needle) ||
      (e.ride.djName || "").toLowerCase().includes(needle)
    ).slice(0, 300);
  }, [dyn.rides, dayFilter, q, setup]);

  return (
    <div>
      <h3 className="font-medium text-stone-200 mb-1 flex items-center gap-2"><History className="w-4 h-4" />Änderungsprotokoll</h3>
      <p className="text-xs text-stone-500 mb-3">Automatische Nachvollziehbarkeit: jede Zuteilung, Statusänderung, Problemmeldung und Flug-Aktualisierung wird im Hintergrund mit Zeit und Urheber gespeichert.</p>
      <div className="flex flex-wrap items-center gap-2 mb-3">
        <select value={dayFilter} onChange={(e) => setDayFilter(e.target.value)} className="bg-stone-950 border border-stone-800 rounded-lg px-2.5 py-1.5 text-xs text-stone-200 focus:outline-none focus:border-orange-500">
          <option value="all">Alle Tage</option>
          {days.map((d) => <option key={d.key} value={d.key}>{d.label}</option>)}
        </select>
        <div className="relative flex-1 min-w-[160px] max-w-xs">
          <Search className="w-3.5 h-3.5 absolute left-2.5 top-2 text-stone-600" />
          <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Fahrer, Ereignis, DJ…"
            className="w-full bg-stone-950 border border-stone-800 rounded-lg pl-7 pr-2 py-1.5 text-xs placeholder-stone-600 focus:outline-none focus:border-orange-500" />
        </div>
        <span className="text-[11px] text-stone-600 ml-auto">{entries.length} Einträge{entries.length >= 300 ? " (letzte 300)" : ""}</span>
      </div>
      <div className="max-h-80 overflow-y-auto space-y-0.5 pr-1">
        {entries.map((e, i) => (
          <div key={i} className="flex items-center gap-2.5 text-xs px-2 py-1.5 rounded-lg hover:bg-stone-950/50">
            <span className="font-mono text-stone-500 shrink-0 w-11">{fmtClock(e.at)}</span>
            <span className="text-stone-200 shrink-0">{LOG_LABEL[e.event] || e.event}</span>
            <span className="text-stone-500 truncate">{e.ride.time} · {ln(e.ride.fromId, e.ride.fromCustom)} → {ln(e.ride.toId, e.ride.toCustom)}{e.ride.djName && <> · <span className="text-orange-300/90 font-medium">{e.ride.djName}</span></>}</span>
            {e.detail && <span className="text-stone-600 truncate hidden sm:inline">— {e.detail}</span>}
            <span className="text-stone-400 ml-auto shrink-0">{byLabel(setup, e.by)}</span>
          </div>
        ))}
        {entries.length === 0 && <div className="text-xs text-stone-600 py-4 text-center">Noch keine Einträge{dayFilter !== "all" ? " an diesem Tag" : ""}.</div>}
      </div>
    </div>
  );
}

/* ------------------------- Nachrichten (Nachtrag 6) ---------------------- *
 * Einfache, gerichtete Nachrichten zwischen Fahrern/Stage-Managern und der
 * Leitstelle — bewusst KEIN laufender Chat-Verlauf, sondern einzelne Meldungen
 * mit optionaler EINER Antwort. Deckt den realen Fall ab ("Artist muss um X
 * abgeholt werden" -> "bestätigt/nicht bestätigt"), ohne die grosse Komplexität
 * (Threads pro Person, Lese-Status, Scroll-Historie) eines echten Chats.
 *
 * Wichtig fürs Rollen-Prinzip: das gibt dem Stage Manager KEINE neue Handlungs-
 * macht (keine Fahrten/Fahrer/Status-Änderung) — es ist reine Kommunikation,
 * dieselbe Kategorie wie das bestehende "Problem melden", nur allgemeiner und
 * mit Antwortweg.
 *
 * Eine Nachricht in dyn.messages[]:
 *   { id, from: "driver:<id>"|"stage:<label>", fromLabel, text, artist?,
 *     at, reply?: { text, status: "confirmed"|"declined"|"info", by, at },
 *     readByDispatch?: bool }
 */
function makeMessage(from, fromLabel, text, artist) {
  return {
    id: "m" + Date.now() + Math.random().toString(36).slice(2, 6),
    from, fromLabel, text: (text || "").trim(), artist: (artist || "").trim() || null,
    at: Date.now(), reply: null, readByDispatch: false,
  };
}
// Nachrichten, die von einem bestimmten Absender (Fahrer/Stage) stammen —
// für die "Meine Nachrichten"-Ansicht in Fahrer-/Stage-App.
function messagesFrom(dyn, fromKey) {
  return (dyn.messages || []).filter((m) => m.from === fromKey).sort((a, b) => b.at - a.at);
}
// Offene (von der Leitstelle noch nicht gelesene ODER noch nicht beantwortete)
// Nachrichten — für das Postfach-Badge in der Leitstelle.
function openMessages(dyn) {
  return (dyn.messages || []).filter((m) => !m.reply).sort((a, b) => b.at - a.at);
}

// MC-Kopie von MessagesInbox (Tab "Chat" im Mission-Control-Modus). Etappe A:
// byte-genaue Kopie, nur Funktionsname geaendert. Classic MessagesInbox bleibt
// unangetastet. Render + Sende-/Fehler-Feedback folgen in Etappe B.
function MissionMessagesInbox({ dyn, updateDyn, by }) {
  const [sort, setSort] = useState("open"); // open | all
  const [drafts, setDrafts] = useState({}); // messageId -> Freitext-Entwurf
  // NEU (nur UI-Feedback, kein neues Datenmodell): welche Antwort gerade gesendet
  // wird ({id, status}) und pro Nachricht ein Fehlertext, falls das Speichern scheitert.
  const [sending, setSending] = useState(null);
  const [errors, setErrors] = useState({});
  const all = (dyn.messages || []).slice().sort((a, b) => b.at - a.at);
  const open = all.filter((m) => !m.reply);
  const shown = sort === "open" ? open : all;

  // Schreib-Vorgang identisch zur Classic-Version (m.reply-Objekt unveraendert);
  // NEU nur der await + sending/error-Status drumherum, damit es echten Sende-
  // status und eine Fehleranzeige gibt. Muster wie MessageComposer im selben Code.
  const reply = async (id, status) => {
    if (sending) return;
    const text = (drafts[id] || "").trim();
    setSending({ id, status });
    setErrors((e) => { const n = { ...e }; delete n[id]; return n; });
    const res = await updateDyn((d) => {
      const m = (d.messages || []).find((x) => x.id === id);
      // Nachricht inzwischen weg -> Konflikt statt stillem rev+1 ohne Wirkung.
      if (!m) return dynConflict("MSG_GONE", "Diese Nachricht gibt es nicht mehr.");
      m.reply = { status, text: text || null, by, at: Date.now() };
      return d;
    });
    setSending(null);
    if (res && res.ok === false) {
      setErrors((e) => ({ ...e, [id]: "Antwort konnte nicht gespeichert werden. Bitte erneut versuchen." }));
      return; // Entwurf bewusst behalten, damit nichts verloren geht
    }
    setDrafts((cur) => { const n = { ...cur }; delete n[id]; return n; });
  };
  // Antwort zurücknehmen (falls man sich vertan hat) -> wieder offen. Schreib-
  // Vorgang identisch (m.reply = null), NEU nur sending/error drumherum.
  const undoReply = async (id) => {
    if (sending) return;
    setSending({ id, status: "undo" });
    setErrors((e) => { const n = { ...e }; delete n[id]; return n; });
    const res = await updateDyn((d) => {
      const m = (d.messages || []).find((x) => x.id === id);
      if (!m) return dynConflict("MSG_GONE", "Diese Nachricht gibt es nicht mehr.");
      if (!m.reply) return NO_CHANGE; // schon zurueckgenommen -> No-op
      m.reply = null;
      return d;
    });
    setSending(null);
    if (res && res.ok === false) setErrors((e) => ({ ...e, [id]: "Antwort konnte nicht zurückgenommen werden. Bitte erneut versuchen." }));
  };

  const fromIsStage = (from) => !!from?.startsWith("stage:");
  const fromKind = (from) => fromIsStage(from) ? "Stage" : "Fahrer";
  const replyLabel = { confirmed: "Bestätigt", declined: "Nicht bestätigt", info: "Info" };
  const replyToken = { confirmed: "done", declined: "problem", info: "new" };

  return (
    <div className="mc-scope space-y-3">
      <MissionPanel
        icon={MessageSquare}
        title="Nachrichten"
        subtitle="Von Fahrern und Stage · eine Antwort pro Nachricht"
        actions={open.length > 0 ? <StatusBadge status="assigned" label={`${open.length} offen`} /> : null}
      >
        {/* Umschaltung Offen / Alle */}
        <div className="flex items-center gap-2 mb-3">
          <div className="inline-flex items-center gap-0.5 rounded-lg p-0.5"
            style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
            {[["open", "Offen"], ["all", "Alle"]].map(([k, l]) => (
              <button key={k} onClick={() => setSort(k)}
                className="text-xs px-3 py-1.5 rounded-md transition"
                style={sort === k
                  ? { background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)", fontWeight: 600 }
                  : { color: "var(--mc-text-secondary)" }}>{l}</button>
            ))}
          </div>
        </div>

        {shown.length === 0 ? (
          <EmptyState icon={MessageSquare}
            title={sort === "open" ? "Keine offenen Nachrichten." : "Noch keine Nachrichten eingegangen."}
            hint={sort === "open"
              ? "Sobald ein Fahrer oder die Stage etwas meldet, taucht es hier auf und wartet auf deine Antwort."
              : "Eingehende Nachrichten von Fahrern und Stage erscheinen hier."} />
        ) : (
          <div className="space-y-2.5">
            {shown.map((m) => {
              const isOpen = !m.reply;
              const stage = fromIsStage(m.from);
              const busy = sending && sending.id === m.id;
              const err = errors[m.id];
              const relTime = fmtAgo(m.at);
              const absTime = new Date(m.at).toLocaleString("de-DE", { weekday: "short", hour: "2-digit", minute: "2-digit" });
              return (
                <div key={m.id} className="mc-ride-card"
                  style={{ padding: "12px 14px", borderLeft: `3px solid ${isOpen ? "var(--mc-st-assigned)" : "var(--mc-border)"}` }}>
                  {/* Kopf: Absender-Art + Name + Artist + offen-Marker + Zeit */}
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="inline-flex items-center text-[10px] font-medium px-1.5 py-0.5 rounded"
                      style={{ background: stage ? "var(--mc-st-enroute-soft)" : "var(--mc-st-new-soft)", color: stage ? "var(--mc-st-enroute)" : "var(--mc-st-new)" }}>
                      {fromKind(m.from)}
                    </span>
                    <span className="text-sm font-semibold truncate" style={{ color: "var(--mc-text)" }}>{m.fromLabel}</span>
                    {m.artist && <span className="text-xs truncate" style={{ color: "var(--mc-st-assigned)" }}>· {m.artist}</span>}
                    {isOpen && <StatusBadge status="assigned" label="offen" />}
                    <span className="inline-flex items-center gap-1 text-[11px] font-mono ml-auto shrink-0"
                      style={{ color: "var(--mc-text-muted)" }} title={absTime}>
                      <Clock className="w-3 h-3" />{relTime}
                    </span>
                  </div>

                  {/* Nachrichtentext */}
                  <div className="text-sm mt-1.5 whitespace-pre-wrap break-words" style={{ color: "var(--mc-text)" }}>{m.text}</div>

                  {m.reply ? (
                    <div className="mt-2.5 flex items-center gap-2 flex-wrap">
                      <StatusBadge status={replyToken[m.reply.status] || "new"}
                        label={`${replyLabel[m.reply.status] || "Antwort"}${m.reply.text ? `: ${m.reply.text}` : ""}`} />
                      <button onClick={() => undoReply(m.id)} disabled={!!sending}
                        className="text-[11px] transition disabled:opacity-50 inline-flex items-center gap-1"
                        style={{ color: "var(--mc-text-muted)" }}>
                        {busy && sending.status === "undo" && <RefreshCw className="w-3 h-3 animate-spin" />}
                        Antwort zurücknehmen
                      </button>
                      {err && (
                        <span className="inline-flex items-center gap-1.5 text-xs w-full mt-1" style={{ color: "var(--mc-st-problem)" }}>
                          <AlertTriangle className="w-3.5 h-3.5 shrink-0" />{err}
                        </span>
                      )}
                    </div>
                  ) : (
                    <div className="mt-2.5">
                      <input value={drafts[m.id] || ""} onChange={(e) => setDrafts((c) => ({ ...c, [m.id]: e.target.value }))}
                        placeholder="Antworttext (optional)" disabled={!!busy}
                        className="mc-input w-full mb-2 disabled:opacity-60" />
                      <div className="flex items-center gap-2 flex-wrap">
                        {[["confirmed", "Bestätigt", Check], ["declined", "Nicht bestätigt", X], ["info", "Nur Info senden", null]].map(([st, label, Ic]) => {
                          const active = busy && sending.status === st;
                          const key = replyToken[st];
                          return (
                            <button key={st} onClick={() => reply(m.id, st)} disabled={!!sending}
                              className="text-sm px-3 py-1.5 rounded-lg inline-flex items-center gap-1.5 transition disabled:opacity-50"
                              style={{ background: `var(--mc-st-${key}-soft)`, color: `var(--mc-st-${key})`, border: `1px solid var(--mc-st-${key})` }}>
                              {active ? <RefreshCw className="w-4 h-4 animate-spin" /> : (Ic ? <Ic className="w-4 h-4" /> : null)}
                              {active ? "wird gesendet" : label}
                            </button>
                          );
                        })}
                      </div>
                      {err && (
                        <div className="mt-2 flex items-center gap-1.5 text-xs" style={{ color: "var(--mc-st-problem)" }}>
                          <AlertTriangle className="w-3.5 h-3.5 shrink-0" />{err}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </MissionPanel>
    </div>
  );
}

/* --------------------- Rückfahrt- / Nachtmodus (Punkt 7) ----------------- */
// Wer ist gerade auf dem Festival-Gelände und braucht noch eine Rückfahrt?
// Bewusst über ALLE Tage berechnet (nicht nur den gerade angezeigten), weil ein Artist
// an einem Tag ankommen und erst an einem späteren Tag zurückfahren kann — sonst würde
// ein Tageswechsel in der Ansicht fälschlich "niemand da" anzeigen.
//
// Manuelle Übersteuerung: dyn.artistPresence[name] kann pro Artist zwei
// bewusst gesetzte Flags tragen (beide optional, Standard = automatische
// Erkennung aus erledigten Fahrten):
//   - noReturn: true  -> "braucht keine Rückfahrt" (Schritt 1). Bleibt sichtbar,
//                        wird aber ausgegraut und zählt nicht als "fehlt noch".
//   - manual: "here"|"gone" -> manueller Präsenz-Status (Schritt 2), übersteuert
//                        die automatische arrived/returned-Rechnung.
function computeArtistPresence(dyn) {
  const presenceOverrides = dyn.artistPresence || {};
  const byArtist = {};
  (dyn.rides || []).forEach((r) => {
    const name = (r.djName || "").trim();
    if (!name || r.status === "cancelled") return;
    const isArrivalLeg = r.toId === "festival" && r.fromId !== "festival";
    const isReturnLeg = r.fromId === "festival";
    if (!isArrivalLeg && !isReturnLeg) return;
    const e = (byArtist[name] = byArtist[name] || { name, arrivals: [], returns: [] });
    if (isArrivalLeg) e.arrivals.push(r);
    if (isReturnLeg) e.returns.push(r);
  });
  return Object.values(byArtist)
    .map((a) => {
      const arrivedCount = a.arrivals.filter((r) => r.status === "done").length;
      const returnedCount = a.returns.filter((r) => r.status === "done").length;
      const autoOnSite = arrivedCount > returnedCount; // (wieder) angekommen, noch nicht (erneut) weg
      const ov = presenceOverrides[a.name] || {};
      // manueller Präsenz-Status übersteuert die Automatik (Schritt 2)
      const onSite = ov.manual === "gone" ? false : ov.manual === "here" ? true : autoOnSite;
      const pendingReturn = a.returns.filter((r) => r.status !== "done").sort((x, y) => sortMin(x.time) - sortMin(y.time))[0] || null;
      const noReturn = ov.noReturn === true; // "braucht keine Rückfahrt" (Schritt 1)
      return { name: a.name, onSite, pendingReturn, noReturn, manual: ov.manual || null, presenceBy: ov.by || null, presenceAt: ov.at || null };
    })
    .filter((a) => a.onSite)
    .sort((a, b) => (a.pendingReturn || a.noReturn ? 1 : 0) - (b.pendingReturn || b.noReturn ? 1 : 0) || a.name.localeCompare(b.name));
}

// Eigene Sektion zur manuellen Präsenz-Verwaltung: zeigt alle aktuell als
// "vor Ort" geltenden Artists (automatisch erkannt ODER manuell gesetzt),
// erlaubt pro Artist "ist weg"/"wieder da"/"zurück zur Automatik", und ein
// freies Eingabefeld, um jemanden manuell als anwesend zu ergänzen, den die
// Fahrten nicht hergeben. Aufklappbar (Standard zu), damit sie den Tab nicht
// dominiert.
function PresenceManager({ presence, manualOnly, onSetManual, onAdd, onSetNoReturn }) {
  const [open, setOpen] = useState(false);
  const [newName, setNewName] = useState("");
  const all = [...presence, ...manualOnly].sort((a, b) => a.name.localeCompare(b.name));
  const add = () => { if (newName.trim()) { onAdd(newName); setNewName(""); } };

  return (
    <div className="mb-4 bg-stone-900 border border-stone-800 rounded-xl overflow-hidden">
      <button onClick={() => setOpen((v) => !v)}
        className="w-full flex items-center gap-2 px-3 py-2.5 text-left hover:bg-stone-800/50">
        <Users className="w-4 h-4 text-orange-400 shrink-0" />
        <span className="text-sm text-stone-200 font-medium">Anwesenheit verwalten</span>
        <span className="text-xs text-stone-500">({all.length} vor Ort)</span>
        <span className="ml-auto text-stone-500 text-xs">{open ? "schließen" : "öffnen"}</span>
      </button>

      {open && (
        <div className="px-3 pb-3 pt-1 border-t border-stone-800">
          <p className="text-[11px] text-stone-500 mb-2.5">Normalerweise erkennt die App automatisch aus den Fahrten, wer vor Ort ist. Hier kannst du das übersteuern, falls es nicht passt (mehrere Personen/Fahrzeuge, Selbstorganisation, jemand bleibt).</p>

          <div className="space-y-1.5 mb-3">
            {all.length === 0 && <div className="text-xs text-stone-600 py-1">Aktuell ist niemand als vor Ort erfasst.</div>}
            {all.map((p) => (
              <div key={p.name} className="flex items-center gap-2 bg-stone-950/50 rounded-lg px-2.5 py-1.5">
                <span className="w-2 h-2 rounded-full bg-emerald-400 shrink-0" />
                <span className="text-sm text-stone-200 truncate flex-1">{p.name}</span>
                {p.manual === "here" && <span className="text-[10px] text-emerald-400/80 shrink-0">manuell da</span>}
                {p.manualOnly && <span className="text-[10px] text-stone-600 shrink-0">nur manuell</span>}
                {p.noReturn && <span className="text-[10px] text-stone-500 shrink-0">keine Rückfahrt</span>}
                <div className="flex items-center gap-1 shrink-0">
                  {/* "ist weg" markieren */}
                  <button onClick={() => onSetManual(p.name, "gone")}
                    title="Als weg markieren — verschwindet aus der Vor-Ort-Liste"
                    className="text-[11px] text-stone-400 hover:text-red-300 hover:bg-red-500/10 px-2 py-1 rounded">
                    ist weg
                  </button>
                  {/* zurück zur Automatik, nur wenn manuell übersteuert */}
                  {p.manual && (
                    <button onClick={() => onSetManual(p.name, null)}
                      title="Manuelle Übersteuerung aufheben — wieder automatisch erkennen"
                      className="text-stone-500 hover:text-stone-200 hover:bg-stone-800 p-1 rounded"><RefreshCw className="w-3 h-3" /></button>
                  )}
                </div>
              </div>
            ))}
          </div>

          {/* Manuell hinzufügen */}
          <div className="flex items-center gap-1.5">
            <input value={newName} onChange={(e) => setNewName(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && add()}
              placeholder="Name manuell als anwesend hinzufügen"
              className="flex-1 bg-stone-950 border border-stone-800 rounded-lg px-2.5 py-1.5 text-sm text-stone-200 placeholder-stone-600 focus:outline-none focus:border-orange-500" />
            <button onClick={add} disabled={!newName.trim()}
              className="bg-stone-800 hover:bg-stone-700 disabled:opacity-40 text-stone-100 text-sm px-3 py-1.5 rounded-lg flex items-center gap-1.5 shrink-0">
              <Plus className="w-3.5 h-3.5" />hinzufügen
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ======================================================================
   Teilpaket D: Operativer Rueckfahrten-Leitstand (rein lesend, abgeleitet)
   ----------------------------------------------------------------------
   Fuehrt vorhandene Informationen (Fahrt, Fahrerzuweisung, Fahrtstatus,
   C2-Match, C3-Zeitbewertung) zu genau EINEM operativen Zustand pro
   Rueckfahrt zusammen. Keine neue Datenstruktur, keine Speicherung, kein
   Schreibweg. Alle Zustaende werden zur Laufzeit aus `now` + Ride berechnet.
   ====================================================================== */

// Schwellwerte (einzige Quelle, Spec 7). Zeiten in Minuten.
const RETURN_CONTROL_CONFIG = {
  dueSoonWindowMin: 60,             // 0..60 min bis Abfahrt (mit Fahrer) -> bald faellig
  urgentDriverMissingWindowMin: 90, // bis 90 min bis Abfahrt & kein Fahrer -> Fahrer fehlt
  overdueGraceMin: 10,              // MEHR als 10 min nach Planabfahrt & nicht gestartet/erledigt -> ueberfaellig
};

// Anzeige-/Sortierreihenfolge (Spec 6). Kleinere Zahl = weiter oben/dringender.
const RETURN_OPERATIONAL_GROUP_ORDER = {
  needs_review: 10,
  overdue: 20,
  driver_missing: 30,
  due_soon: 40,
  driver_assigned: 50,
  in_progress: 60,
  not_due: 70,
  completed: 80,
};

// Sichtbare deutsche Labels + Farbschluessel. Nur bestehende, WCAG-gepruefte
// --mc-st-*-Variablen (keine neue Farbe): problem=rot, assigned=amber, new=blau,
// enroute=aktiv, idle=grau, done=gruen.
const RETURN_GROUP_META = {
  needs_review:    { label: "Prüfen",           stKey: "problem",  severity: "critical" },
  overdue:         { label: "Überfällig",        stKey: "problem",  severity: "critical" },
  driver_missing:  { label: "Fahrer fehlt",      stKey: "assigned", severity: "warning" },
  due_soon:        { label: "Bald fällig",       stKey: "assigned", severity: "warning" },
  driver_assigned: { label: "Fahrer zugeteilt",  stKey: "new",      severity: "ok" },
  in_progress:     { label: "Läuft",             stKey: "enroute",  severity: "info" },
  not_due:         { label: "Später",            stKey: "idle",     severity: "neutral" },
  completed:       { label: "Erledigt",          stKey: "done",     severity: "muted" },
};
const RETURN_GROUPS_IN_ORDER = ["needs_review", "overdue", "driver_missing", "due_soon", "driver_assigned", "in_progress", "not_due", "completed"];

// Status-Klassen aus den BESTEHENDEN Ride-Statuswerten (Spec 4). Keine neuen
// Statuswerte. planned|accepted = nicht gestartet (bestehende isOverdue-Konvention).
const RETURN_STATUS_COMPLETED = new Set(["done"]);
const RETURN_STATUS_ACTIVE = new Set(["enroute_pickup", "onboard"]);

// Abfahrts-Timestamp einer Fahrt (echter Kalendertag + Uhrzeit, Wanduhr). dayKey
// rollt nur die Betriebstag-Zuordnung zurueck; date/time bleiben echt -> Mitter-
// nacht korrekt. null = ungueltig/fehlend (nie geraten).
function returnDepartureTs(ride) {
  if (!ride || !ride.date || !ride.time) return null;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(ride.date)) return null;
  if (!/^\d{1,2}:\d{2}$/.test(ride.time)) return null;
  const t = new Date(`${ride.date}T${ride.time.length === 4 ? "0" + ride.time : ride.time}`).getTime();
  return Number.isFinite(t) ? t : null;
}

/* Zentrale reine Klassifizierung (Spec 3/8/9/30). Veraendert KEINE Eingabe,
 * loest keine Seiteneffekte aus, ist deterministisch fuer (ride, now). `now` in
 * ms. `driver` = bereits aufgeloestes Fahrerobjekt oder null. `timetableMatch` =
 * C2-Ergebnis (matchRideToTimetable). `timingEvaluation` = C3-Ergebnis
 * (evaluateTimetableTiming) - wird NUR wiederverwendet, nie neu berechnet. */
function deriveReturnRideOperationalState({ ride, driver, timetableMatch, timingEvaluation, now, setup }) {
  const reasons = [];
  const secondaryInfo = [];
  const status = ride && ride.status ? ride.status : "";
  const rideCompleted = RETURN_STATUS_COMPLETED.has(status);
  const rideStarted = RETURN_STATUS_ACTIVE.has(status);

  const driverIdRaw = ride && ride.assignedDriverId ? ride.assignedDriverId : null;
  const driverAssigned = !!driverIdRaw;      // echte Fahrerreferenz im Ride (Spec 22)
  const driverResolved = !!driver;           // Fahrerobjekt tatsaechlich auffindbar
  const driverUnresolved = driverAssigned && !driverResolved;

  // Zeitliche Einordnung (Spec 7/19). Absolute Wanduhr, Vorzeichen: >0 = Zukunft.
  const depTs = returnDepartureTs(ride);
  const minutesUntilRaw = depTs == null ? null : (depTs - now) / 60000;

  const tt = timingEvaluation || null;
  const matchStatus = timetableMatch && timetableMatch.status ? timetableMatch.status : "no_match";
  const ttStatus = tt && tt.status ? tt.status : matchStatus;
  const hasArtist = !!(ride && (ride.djName || "").trim());
  const uniqueMatch = matchStatus === "exact" || matchStatus === "alias" || matchStatus === "b2b_member";

  // ---- Harte Prueflagen sammeln (Spec 9/10/11/23) ----
  if (!ride || !ride.date || !ride.dayKey) reasons.push("festival_day_unknown");
  if (!ride || !ride.time) reasons.push("planned_departure_missing");
  else if (depTs == null) reasons.push("ride_time_invalid");
  if (ride && !ride.fromId && !((ride.fromCustom || "").trim())) reasons.push("start_location_unknown");
  if (driverUnresolved) reasons.push("driver_unresolved");
  if (ttStatus === "return_before_set_end") reasons.push("return_before_set_end");
  if (matchStatus === "invalid_artist") reasons.push("invalid_artist");
  if (hasArtist && matchStatus === "multiple_candidates") reasons.push("multiple_timetable_candidates");
  if (uniqueMatch && ttStatus === "timing_unknown") reasons.push("set_time_invalid");

  const hardReview = reasons.length > 0;

  // ---- Zusatzhinweise (nie Primaergruppe, Spec 8/11) ----
  if (driverUnresolved) secondaryInfo.push("Fahrerzuweisung prüfen");
  if (!driverAssigned) secondaryInfo.push("Kein Fahrer zugeteilt");
  if (ttStatus === "return_before_set_end" && tt && tt.minutesRelativeToSetEnd != null)
    secondaryInfo.push(`Rückfahrt ${Math.abs(tt.minutesRelativeToSetEnd)} min vor Set-Ende`);
  if (hasArtist && matchStatus === "multiple_candidates") secondaryInfo.push("Timetable-Zuordnung prüfen");
  if (hasArtist && matchStatus === "no_match") secondaryInfo.push("Kein passendes Timetable-Set gefunden");

  // ---- Entscheidungskette (Spec 8) - genau EINE Primaergruppe ----
  const cfg = RETURN_CONTROL_CONFIG;
  const m = minutesUntilRaw; // Kurzform
  let group;
  if (rideCompleted) group = "completed";
  else if (rideStarted) group = "in_progress";
  else if (hardReview) group = "needs_review";
  else if (m != null && m < -cfg.overdueGraceMin) group = "overdue";
  else if (!driverAssigned && m != null && m <= cfg.urgentDriverMissingWindowMin) group = "driver_missing";
  else if (m != null && m <= cfg.dueSoonWindowMin) group = "due_soon";
  else if (driverAssigned && m != null && m > cfg.dueSoonWindowMin) group = "driver_assigned";
  else group = "not_due";

  const meta = RETURN_GROUP_META[group];
  const minutesUntilDeparture = m == null ? null : Math.round(m);
  const minutesOverdue = (m == null || m >= 0) ? null : Math.round(-m);

  return {
    group,
    severity: meta.severity,
    label: meta.label,
    stKey: meta.stKey,
    sortPriority: RETURN_OPERATIONAL_GROUP_ORDER[group],
    scheduledDepartureAt: depTs == null ? null : `${ride.date}T${ride.time}`,
    minutesUntilDeparture,
    minutesOverdue,
    driverAssigned,
    driverResolved,
    rideStarted,
    rideCompleted,
    timetableStatus: ttStatus,
    requiresReview: group === "needs_review",
    reasons,
    secondaryInfo,
  };
}

// Innerhalb-Gruppen-Sortierung (Spec 18). Stabiler Tie-Breaker ueber Ride-ID.
function returnGroupSort(group, a, b) {
  const depA = returnDepartureTs(a.ride);
  const depB = returnDepartureTs(b.ride);
  const A = depA == null ? Infinity : depA;
  const B = depB == null ? Infinity : depB;
  const tie = () => String(a.ride.id || "").localeCompare(String(b.ride.id || ""));
  if (group === "completed") return (B - A) || tie(); // neueste (spaeteste Planzeit) zuerst
  if (group === "needs_review") {
    // 1. Rueckfahrt vor Set-Ende mit groesster Abweichung zuerst
    const devA = (a.timing && a.timing.status === "return_before_set_end" && a.timing.minutesRelativeToSetEnd != null) ? -a.timing.minutesRelativeToSetEnd : -Infinity;
    const devB = (b.timing && b.timing.status === "return_before_set_end" && b.timing.minutesRelativeToSetEnd != null) ? -b.timing.minutesRelativeToSetEnd : -Infinity;
    if (devA !== devB) return devB - devA;
    // 2. Abfahrt am naechsten, 3. fehlende Daten ans Ende (Infinity), 4. id
    return (A - B) || tie();
  }
  // overdue/driver_missing/due_soon/driver_assigned/in_progress/not_due:
  // frueheste/naechste Abfahrt zuerst; ueberfaelligste ist die frueheste.
  return (A - B) || tie();
}

/* =========================================================================
   Teilpaket E: Sichere Wartefahrt-Vorschlaege (REIN LESEND, additiv)
   -------------------------------------------------------------------------
   Idee (Spec 6): eine bestehende Hinfahrt zum Festival + derselbe zugeteilte
   Fahrer + eine zeitlich passende, noch unbesetzte Rueckfahrt vom Festival =
   Vorschlag "der Fahrer wartet und uebernimmt die Rueckfahrt". KEIN eigener
   Ride, KEIN gespeicherter Zustand, KEIN Schreibweg. Alle Funktionen hier sind
   reine Ableitungen aus vorhandenen Daten und mutieren nichts.

   Wiederverwendung (kein zweiter Detektor/Motor):
   - Richtung: rideFestivalDirection (zentrale C3-Logik).
   - Operative Orte/Ankunft: c3OperationalNodes + travelMin + c3RideStartAbsMin
     (Teilpaket B/C3; Sheraton-Pickup fuer Leonardo/HBF -> Festival, Rueckfahrt
     behaelt echtes Ziel; Matrixzeit verbindlich, nie 0/geschaetzt).
   - Konflikt/Verfuegbarkeit: evaluateInsertion (bestehender Motor, unveraendert).
   - Rueckfahrt-Status: RETURN_STATUS_COMPLETED/-ACTIVE (Teilpaket D).

   Vergleichsroute (Spec 25): ein Fahrer-Hub wird NIE pauschal erfunden. Nur wenn
   setup.config.driverHubLocationId explizit gesetzt ist, gilt eine Vergleichs-
   route als verlaesslich. Ohne verlaesslichen Hub: keine Einsparungsbehauptung,
   und ein starkes "Warten sinnvoll" entsteht dann bevorzugt NICHT (Spec 17/18).
   ========================================================================= */
const WAIT_RIDE_CONFIG = {
  minTurnaroundBufferMin: 10,   // Mindest-Wendezeit Ankunft Hinfahrt -> Abfahrt Rueckfahrt
  minUsefulWaitMin: 15,         // darunter: direkter Anschluss, keine echte Wartefahrt
  recommendedWaitMaxMin: 60,    // Obergrenze "Warten sinnvoll"
  possibleWaitMaxMin: 120,      // Obergrenze "Warten moeglicherweise sinnvoll"
  conflictBufferMin: 15,        // Info: Puffer um andere Fahrten (Konfliktmotor hat eigene Logik)
  minCalculatedDrivingSavedMin: 25, // Mindest-Einsparung fuer starkes "Warten sinnvoll"
};

const WAIT_RIDE_STATUS_LABEL = {
  wait_recommended: "Warten sinnvoll",
  wait_possible: "Warten möglicherweise sinnvoll",
  return_recommended: "Zurückfahren wahrscheinlich sinnvoller",
  not_evaluable: "Nicht sicher bewertbar",
  direct_connection: "Direkter Anschluss",
  already_planned: "Bereits geplant",
};

// Anzeige-/Sortier-Prioritaet (Spec 29). Kleinere Zahl = weiter oben/wichtiger.
const WAIT_RIDE_STATUS_ORDER = {
  wait_recommended: 10,
  direct_connection: 20,
  wait_possible: 30,
  already_planned: 40,
  return_recommended: 50,
  not_evaluable: 60,
};

// Nur diese Status sind operativ als Wartevorschlag "handlungsleitend" (Spec 31).
const WAIT_RIDE_ACTIONABLE = new Set(["wait_recommended", "wait_possible", "direct_connection"]);

// Severity -> bestehende, WCAG-gepruefte MC-Farbvariable (keine neue Farbe, Spec 33).
function waitSeverityColor(sev) {
  if (sev === "success") return "var(--mc-st-done)";      // gruen
  if (sev === "info") return "var(--mc-st-new)";          // blau (aktiv/informativ)
  if (sev === "warning") return "var(--mc-st-assigned)";  // amber (kein Alarmrot)
  return "var(--mc-text-muted)";                          // neutral/muted
}
function waitSeverityStKey(sev) {
  if (sev === "success") return "done";
  if (sev === "info") return "new";
  if (sev === "warning") return "assigned";
  return "idle";
}

// Operative Ankunft der Hinfahrt am Festival (Spec 13). Nur bestehende B/C3-Logik,
// nie Schaetzung. Reine Funktion. Gibt Absolutminuten + Diagnose; arrivalAbs=null,
// wenn nicht sicher berechenbar (fehlende Matrixkante, ungueltige Zeit, kein Ziel Festival).
function waitInboundArrival(inboundRide, setup) {
  const out = { arrivalAbs: null, startAbs: null, travelMinutes: null, fromNode: null, toNode: null, reason: null };
  if (!inboundRide || !setup || !setup.matrix) { out.reason = "no_setup"; return out; }
  if (rideFestivalDirection(inboundRide) !== "toFestival") { out.reason = "not_inbound"; return out; }
  const nodes = c3OperationalNodes(inboundRide, setup);
  out.fromNode = nodes.fromNode; out.toNode = nodes.toNode;
  if (nodes.toNode !== "festival") { out.reason = "to_not_festival"; return out; }
  const startAbs = c3RideStartAbsMin(inboundRide.date, inboundRide.time);
  if (startAbs == null) { out.reason = "invalid_datetime"; return out; }
  out.startAbs = startAbs;
  const tm = travelMin(setup.matrix, nodes.fromNode, nodes.toNode); // null = unbekannt (nie 0)
  if (tm == null) { out.reason = "no_matrix_edge"; return out; }
  out.travelMinutes = tm;
  out.arrivalAbs = startAbs + tm;
  return out;
}

// Vergleichsort/Hub (Spec 25). Sheraton wird NIE pauschal erfunden. Verlaesslich
// nur bei explizitem setup.config.driverHubLocationId, der auf einen bekannten
// Matrix-Knoten != festival zeigt. Reine Funktion.
function resolveWaitComparisonHub(setup) {
  const cfg = setup && setup.config ? setup.config : {};
  const explicit = cfg.driverHubLocationId;
  if (typeof explicit === "string" && explicit.trim()) {
    const node = LOC_MATRIX_NODE[explicit.trim()] || null;
    if (node && node !== "festival") return { node, reliable: true, source: "config_hub", requested: explicit.trim() };
  }
  return { node: null, reliable: false, source: null, requested: (typeof explicit === "string" ? explicit : null) };
}

// Vermeidbare Fahrminuten durch Warten (Spec 26): Festival -> Hub + Hub -> Festival.
// Beide Richtungen getrennt (asymmetrie-sicher ueber travelMin-Schluesselreihenfolge).
// Fehlt der Hub in der Matrix (eine Kante null) -> keine Einsparung, reliable=false.
function computeWaitDrivingSaved(hub, setup) {
  if (!hub || !hub.reliable || !hub.node || !setup || !setup.matrix) {
    return { savedMin: null, reliable: false, legOut: null, legBack: null };
  }
  const legOut = travelMin(setup.matrix, "festival", hub.node);  // Festival -> Hub
  const legBack = travelMin(setup.matrix, hub.node, "festival"); // Hub -> Festival
  if (legOut == null || legBack == null) {
    return { savedMin: null, reliable: false, legOut, legBack };
  }
  return { savedMin: legOut + legBack, reliable: true, legOut, legBack };
}

// finalize: deterministischer sortScore (grob nach Status, dann konfliktfrei,
// dann sichere Einsparung, dann kuerzere Wartezeit). Feinordnung uebernimmt der
// Comparator (waitCandidateCompare). Reine Funktion.
function finalizeWaitCandidate(c) {
  const order = WAIT_RIDE_STATUS_ORDER[c.status] != null ? WAIT_RIDE_STATUS_ORDER[c.status] : 99;
  let s = order * 1000;
  s += c.hasRideConflict ? 500 : 0;
  s += c.driverAvailable ? 0 : 250;
  const saved = (c.comparisonRouteReliable && c.estimatedDrivingSavedMin != null) ? c.estimatedDrivingSavedMin : 0;
  s -= Math.min(Math.max(saved, 0), 240) / 10; // hoehere Einsparung -> kleiner (max -24)
  c.sortScore = Math.round(s * 100) / 100;
  return c;
}

/* Zentrale reine Bewertungsfunktion (Spec 15). Veraendert KEINE Eingabe, loest
   KEINEN Schreibweg aus, ist deterministisch fuer die uebergebenen Daten (die
   Wartezeit-/Ankunftsmathematik ist rein planbasiert und nutzt `now` nicht;
   der Konfliktmotor evaluateInsertion wird unveraendert wiederverwendet). */
function evaluateWaitRideCandidate({ inboundRide, returnRide, driver, setup, dyn, now, comparisonHub }) {
  const cfg = WAIT_RIDE_CONFIG;
  const reasons = [];
  const warnings = [];
  const base = {
    status: "not_evaluable", severity: "neutral", label: WAIT_RIDE_STATUS_LABEL.not_evaluable,
    inboundRideId: inboundRide && inboundRide.id ? inboundRide.id : null,
    returnRideId: returnRide && returnRide.id ? returnRide.id : null,
    driverId: driver && driver.id ? driver.id : null,
    inboundDepartureAt: null, inboundArrivalAtFestival: null, returnDepartureAt: null,
    waitMinutes: null, turnaroundBufferMin: cfg.minTurnaroundBufferMin,
    estimatedDrivingSavedMin: null, comparisonRouteReliable: false,
    hasRideConflict: false, conflictRideIds: [],
    driverAvailable: false, returnRideUnassigned: false,
    reasons, warnings, sortScore: 0,
  };
  const done = (patch) => finalizeWaitCandidate(patch ? { ...base, ...patch } : base);

  // (1) Fahrer der Hinfahrt gueltig und aufloesbar? (Spec 10)
  const inboundDriverId = inboundRide && inboundRide.assignedDriverId ? inboundRide.assignedDriverId : null;
  if (!inboundDriverId) { reasons.push("inbound_no_driver"); return done(); }
  if (!driver || driver.id !== inboundDriverId) { reasons.push("inbound_driver_unresolved"); return done(); }

  // (2) Richtung (Spec 7/9) ueber die zentrale Richtungslogik.
  if (rideFestivalDirection(inboundRide) !== "toFestival") { reasons.push("inbound_not_to_festival"); return done(); }
  if (rideFestivalDirection(returnRide) !== "fromFestival") { reasons.push("return_not_from_festival"); return done(); }

  // (3) Ankunft der Hinfahrt (nur operative Matrixzeit, Spec 13).
  const arr = waitInboundArrival(inboundRide, setup);
  if (arr.arrivalAbs == null) { reasons.push("arrival_" + (arr.reason || "unknown")); return done(); }
  base.inboundDepartureAt = c3AbsToParts(arr.startAbs).iso;
  base.inboundArrivalAtFestival = c3AbsToParts(arr.arrivalAbs).iso;

  // (4) Abfahrt der Rueckfahrt (absolute Minute, Mitternacht-sicher, Spec 14).
  const retAbs = c3RideStartAbsMin(returnRide.date, returnRide.time);
  if (retAbs == null) { reasons.push("return_invalid_datetime"); return done(); }
  base.returnDepartureAt = c3AbsToParts(retAbs).iso;

  // (5) Rueckfahrtstatus (Spec 11/17): storniert/erledigt/laufend -> kein Kandidat.
  const rst = returnRide.status || "";
  if (rst === "cancelled") { reasons.push("return_cancelled"); return done(); }
  if (RETURN_STATUS_COMPLETED.has(rst)) { reasons.push("return_completed"); return done(); }
  if (RETURN_STATUS_ACTIVE.has(rst)) { reasons.push("return_in_progress"); return done(); }

  // (6) Rueckfahrt-Belegung (Spec 11).
  const retDriverId = returnRide.assignedDriverId ? returnRide.assignedDriverId : null;
  base.returnRideUnassigned = !retDriverId;
  if (retDriverId && retDriverId === driver.id) {
    reasons.push("same_driver_already_assigned");
    return done({ status: "already_planned", severity: "muted", label: WAIT_RIDE_STATUS_LABEL.already_planned });
  }
  if (retDriverId && retDriverId !== driver.id) {
    reasons.push("return_assigned_other_driver");
    return done(); // kein Vorschlag (Aufrufer filtert diesen Fall heraus)
  }

  // (7) Wartezeit (Spec 12/14).
  const waitMinutes = retAbs - arr.arrivalAbs;
  base.waitMinutes = waitMinutes;
  if (waitMinutes < 0) { reasons.push("return_before_arrival"); return done(); }
  if (waitMinutes < cfg.minTurnaroundBufferMin) { reasons.push("turnaround_too_short"); return done(); }

  // (8) Konflikt/Verfuegbarkeit ueber den bestehenden Motor (Spec 22/23).
  const ins = evaluateInsertion(setup, dyn, driver, returnRide);
  const conflictIds = [];
  if (ins.overlap && ins.stats && Array.isArray(ins.stats.rides)) {
    const T = sortMin(returnRide.time), end = T + effDur(setup.config, returnRide);
    ins.stats.rides.forEach((r) => {
      if (r.id === returnRide.id || r.status === "cancelled") return;
      const s = sortMin(r.time), e = s + effDur(setup.config, r);
      if (T < e && end > s) conflictIds.push(r.id);
    });
  }
  if (ins.lateToPickup > 0 && ins.prev) conflictIds.push(ins.prev.id);
  if (ins.lateToNext > 0 && ins.next) conflictIds.push(ins.next.id);
  const hasRideConflict = !!(ins.overlap || ins.lateToPickup > 0 || ins.lateToNext > 0);
  base.hasRideConflict = hasRideConflict;
  base.conflictRideIds = [...new Set(conflictIds)];
  base.driverAvailable = !!ins.available;
  if (hasRideConflict) reasons.push("ride_conflict");
  if (!ins.available) { reasons.push("driver_not_available"); if (ins.availabilityReason) warnings.push(ins.availabilityReason); }

  // (9) Vergleichsroute / vermeidbare Fahrzeit (Spec 25/26).
  const hub = comparisonHub || resolveWaitComparisonHub(setup);
  const saved = computeWaitDrivingSaved(hub, setup);
  base.comparisonRouteReliable = !!saved.reliable;
  base.estimatedDrivingSavedMin = saved.reliable ? saved.savedMin : null;

  const conflictBlocks = hasRideConflict || !ins.available;

  // (10) Statuszuordnung (Spec 16-21).
  // direkter Anschluss: [minTurnaround, minUseful)
  if (waitMinutes < cfg.minUsefulWaitMin) {
    if (conflictBlocks) { reasons.push("direct_but_conflict"); return done({ status: "return_recommended", severity: "neutral", label: WAIT_RIDE_STATUS_LABEL.return_recommended }); }
    reasons.push("direct_connection");
    return done({ status: "direct_connection", severity: "info", label: WAIT_RIDE_STATUS_LABEL.direct_connection });
  }
  // zu lange Wartezeit: > possibleWaitMax -> zurueckfahren (Spec 12/19)
  if (waitMinutes > cfg.possibleWaitMaxMin) {
    reasons.push("wait_too_long");
    return done({ status: "return_recommended", severity: "neutral", label: WAIT_RIDE_STATUS_LABEL.return_recommended });
  }
  // Konflikt/nicht verfuegbar im Wartefenster -> Warteoption ausgeschlossen (Spec 19)
  if (conflictBlocks) {
    return done({ status: "return_recommended", severity: "neutral", label: WAIT_RIDE_STATUS_LABEL.return_recommended });
  }
  // Verlaessliche Route zeigt zu geringe Einsparung -> zurueckfahren (Spec 19)
  if (saved.reliable && saved.savedMin < cfg.minCalculatedDrivingSavedMin) {
    reasons.push("reliable_savings_below_threshold");
    return done({ status: "return_recommended", severity: "neutral", label: WAIT_RIDE_STATUS_LABEL.return_recommended });
  }
  // Empfohlenes Fenster [minUseful, recommendedMax]
  if (waitMinutes <= cfg.recommendedWaitMaxMin) {
    if (saved.reliable && saved.savedMin >= cfg.minCalculatedDrivingSavedMin) {
      reasons.push("wait_recommended_with_savings");
      return done({ status: "wait_recommended", severity: "success", label: WAIT_RIDE_STATUS_LABEL.wait_recommended });
    }
    // keine verlaessliche Vergleichsroute -> bevorzugt wait_possible (Spec 17/18)
    reasons.push("wait_no_reliable_comparison");
    warnings.push("Keine sichere Vergleichsroute zum Fahrerstützpunkt verfügbar.");
    return done({ status: "wait_possible", severity: "warning", label: WAIT_RIDE_STATUS_LABEL.wait_possible });
  }
  // Moegliches Fenster (recommendedMax, possibleMax] -> wait_possible (Spec 18)
  reasons.push("wait_in_possible_window");
  return done({ status: "wait_possible", severity: "warning", label: WAIT_RIDE_STATUS_LABEL.wait_possible });
}

// Deterministischer Comparator (Spec 29). Reine Funktion, mutiert nichts.
function waitCandidateCompare(a, b) {
  const oa = WAIT_RIDE_STATUS_ORDER[a.status] != null ? WAIT_RIDE_STATUS_ORDER[a.status] : 99;
  const ob = WAIT_RIDE_STATUS_ORDER[b.status] != null ? WAIT_RIDE_STATUS_ORDER[b.status] : 99;
  if (oa !== ob) return oa - ob;                                   // 1. Status-Prioritaet
  const ca = a.hasRideConflict ? 1 : 0, cb = b.hasRideConflict ? 1 : 0;
  if (ca !== cb) return ca - cb;                                   // 2. konfliktfrei zuerst
  const va = a.driverAvailable ? 0 : 1, vb = b.driverAvailable ? 0 : 1;
  if (va !== vb) return va - vb;                                   // 3. verfuegbar zuerst
  const sa = (a.comparisonRouteReliable && a.estimatedDrivingSavedMin != null) ? a.estimatedDrivingSavedMin : -1;
  const sb = (b.comparisonRouteReliable && b.estimatedDrivingSavedMin != null) ? b.estimatedDrivingSavedMin : -1;
  if (sa !== sb) return sb - sa;                                   // 4. hoehere sichere Einsparung zuerst
  const wa = a.waitMinutes == null ? Infinity : a.waitMinutes;
  const wb = b.waitMinutes == null ? Infinity : b.waitMinutes;
  if (wa !== wb) return wa - wb;                                   // 5. kuerzere Wartezeit zuerst
  const da = a.returnDepartureAt || "", db2 = b.returnDepartureAt || "";
  if (da !== db2) return da < db2 ? -1 : 1;                        // 6. fruehere Rueckfahrt zuerst
  const ka = `${a.returnRideId || ""}|${a.inboundRideId || ""}|${a.driverId || ""}`; // 7./8. stabile IDs
  const kb = `${b.returnRideId || ""}|${b.inboundRideId || ""}|${b.driverId || ""}`;
  return ka < kb ? -1 : ka > kb ? 1 : 0;
}

// Rein: sortierte KOPIE, mutiert die Eingabe nicht (Spec 37).
function rankWaitCandidates(list) {
  return (Array.isArray(list) ? list.slice() : []).sort(waitCandidateCompare);
}

/* Kandidaten pro unbesetzter Rueckfahrt (Spec 27/28/36). Vorfilter nach
   Betriebstag, Richtung, gueltigem Fahrer und Zeitfenster; danach reine
   Bewertung + deterministisches Ranking. Reine Funktion, mutiert nichts,
   schreibt nichts. Rueckgabe: Map returnId -> { returnRide, candidates, best }
   plus Hub und die Menge der Fahrer, die fuer >1 Rueckfahrt beste Option sind. */
function buildWaitRideCandidates({ dyn, setup, now, day }) {
  const rides = (dyn && Array.isArray(dyn.rides)) ? dyn.rides : [];
  const drivers = (setup && Array.isArray(setup.drivers)) ? setup.drivers : [];
  const driverById = new Map(drivers.map((d) => [d.id, d]));
  const hub = resolveWaitComparisonHub(setup);
  const cfg = WAIT_RIDE_CONFIG;

  const dayRides = rides.filter((r) => r && r.dayKey === day && r.status !== "cancelled");
  const inbounds = dayRides.filter((r) => rideFestivalDirection(r) === "toFestival"
    && r.assignedDriverId && driverById.has(r.assignedDriverId));
  const returns = dayRides.filter((r) => rideFestivalDirection(r) === "fromFestival"
    && !RETURN_STATUS_COMPLETED.has(r.status || "") && !RETURN_STATUS_ACTIVE.has(r.status || ""));
  const inboundArr = inbounds
    .map((r) => ({ ride: r, arr: waitInboundArrival(r, setup) }))
    .filter((x) => x.arr.arrivalAbs != null);

  const byReturn = new Map();
  for (const ret of returns) {
    const retDriverId = ret.assignedDriverId || null;
    const retAbs = c3RideStartAbsMin(ret.date, ret.time);
    const cands = [];
    for (const { ride: inb, arr } of inboundArr) {
      const drvId = inb.assignedDriverId;
      if (retDriverId && retDriverId !== drvId) continue; // anderem Fahrer zugeteilt: nur derselbe -> already_planned
      if (retAbs != null && arr.arrivalAbs != null) {
        const w = retAbs - arr.arrivalAbs;
        if (w < cfg.minTurnaroundBufferMin || w > cfg.possibleWaitMaxMin) continue; // Zeitfenster (Spec 36)
      }
      const driver = driverById.get(drvId) || null;
      const c = evaluateWaitRideCandidate({ inboundRide: inb, returnRide: ret, driver, setup, dyn, now, comparisonHub: hub });
      if (c.status === "not_evaluable" && c.reasons.includes("return_assigned_other_driver")) continue;
      cands.push(c);
    }
    if (cands.length === 0) continue;
    const ranked = rankWaitCandidates(cands);
    byReturn.set(ret.id, { returnRide: ret, candidates: ranked, best: ranked[0] });
  }

  // Fahrer, die fuer mehr als eine Rueckfahrt beste (handlungsleitende) Option
  // sind -> Kennzeichnung "kann nur eine uebernehmen" (Spec 27/28).
  const bestDriverCount = new Map();
  for (const { best } of byReturn.values()) {
    if (best && best.driverId && WAIT_RIDE_ACTIONABLE.has(best.status)) {
      bestDriverCount.set(best.driverId, (bestDriverCount.get(best.driverId) || 0) + 1);
    }
  }
  const multiBestDrivers = new Set([...bestDriverCount].filter(([, n]) => n > 1).map(([id]) => id));
  return { byReturn, hub, multiBestDrivers };
}

/* =========================================================================
   Teilpaket F (Scheibe F1): Sichere Sammelfahrt-Vorschlaege - reine Logik.
   REIN LESEND und additiv. Keine Fahrt/kein Fahrer/keine Zuteilung wird
   veraendert, kein Schreibweg, kein gespeicherter Zustand (Spec 3/4/38).
   Nutzt ausschliesslich bestehende reine Helfer: rideFestivalDirection
   (Richtung, Spec 8), c3OperationalNodes + travelMin (operative Orte/Fahrzeit
   inkl. Leonardo/HBF -> Sheraton-Pickup, Spec 25), c3RideStartAbsMin (mitter-
   nachtssichere Absolutminute, Spec 19), validPassengerCount (Sitzplatzlogik,
   Spec 17), evaluateTimetableTiming/matchRideToTimetable (C2/C3-Veto, Spec 20/21/28).
   F1 unterstuetzt bewusst NUR Paare (maxGroupSize 2); Dreiergruppen sind auf
   Scheibe F3 verschoben (Spec 7/31: Stabilitaet vor Dreiern). Keine UI hier.
   ========================================================================= */

// Verbindliche, EINZIGE Schwellenquelle fuer F (Spec 10). Keine zweiten Grenz-
// werte in anderen Funktionen/Komponenten. minTurnaroundBufferMin aus dem Spec-
// Entwurf ist bewusst NICHT enthalten: eine Sammelfahrt hat keine Wende.
const GROUP_RIDE_CONFIG = {
  maxDepartureDifferenceMin: 20,      // groesserer Abstand -> kein positiver Vorschlag
  preferredDepartureDifferenceMin: 10, // Info: bevorzugter Bereich
  maxTotalDetourMin: 25,              // Obergrenze operativer Gesamtumweg
  minSavedDrivingMin: 15,             // Mindest-Einsparung fuer starke Empfehlung
  maxGroupSize: 2,                    // F1: nur Paare (F3 -> 3)
};

// Sichtbare Labels (Spec 12). same_route_direct/already_planned sind bewusst
// KEINE eigenen Status; "identische Route" laeuft ueber das Flag identicalRoute,
// das haelt die Statusmaschine und das Ranking eindeutig.
const GROUP_RIDE_STATUS_LABEL = {
  group_recommended: "Sammelfahrt sinnvoll",
  group_possible: "Sammelfahrt möglicherweise sinnvoll",
  group_not_recommended: "Getrennte Fahrten sinnvoller",
  group_not_evaluable: "Nicht sicher bewertbar",
};

// Anzeige-/Sortier-Prioritaet (Spec 30). Kleinere Zahl = weiter oben.
const GROUP_RIDE_STATUS_ORDER = {
  group_recommended: 10,
  group_possible: 20,
  group_not_recommended: 40,
  group_not_evaluable: 60,
};

// Nur diese Status sind operativ als Sammelvorschlag handlungsleitend (Spec 31).
const GROUP_RIDE_ACTIONABLE = new Set(["group_recommended", "group_possible"]);

// Zone eines Matrix-Knotens (bestehende Zonenzuordnung, Spec 23: keine neue Zone).
function groupZoneOfNode(node) {
  if (!node) return "UNKNOWN";
  return (typeof LOC_ZONE === "object" && LOC_ZONE && LOC_ZONE[node]) ? LOC_ZONE[node] : "UNKNOWN";
}

// Flotten-Sitzplaetze: hoechste Kapazitaet + kapazitiv passende Fahrzeuge (Spec 17).
// BEWUSST keine Verfuegbarkeit behauptet - nur "welches Fahrzeug haette ueberhaupt
// genug Sitze". Reine Funktion.
function groupFleetSeats(setup, need) {
  const drivers = (setup && Array.isArray(setup.drivers)) ? setup.drivers : [];
  let maxSeats = 0;
  const suitable = [];
  for (const d of drivers) {
    const s = (typeof d.seats === "number" && Number.isFinite(d.seats)) ? d.seats : 0;
    if (s > maxSeats) maxSeats = s;
    if (need != null && s >= need && d.vehicleId) suitable.push(d.vehicleId);
  }
  // Fahrzeuge deduplizieren, stabile Reihenfolge.
  const seen = new Set();
  const suitableVehicleIds = suitable.filter((v) => (seen.has(v) ? false : (seen.add(v), true))).sort();
  return { maxSeats, suitableVehicleIds };
}

// Operative Endpunkte einer Fahrt: variabler Knoten (nicht-Festival-Seite) und
// Festival-Seite, plus Absolut-Startminute. Reine Ableitung ueber die bestehende
// B/C3-Kette. null-Felder = nicht sicher aufloesbar (nie geraten).
function groupRideEndpoints(ride, setup) {
  const dir = rideFestivalDirection(ride); // toFestival | fromFestival | other
  const out = { dir, festivalNode: null, variableNode: null, fromNode: null, toNode: null, startAbs: null, zone: "UNKNOWN" };
  if (!ride || !setup || !setup.matrix) return out;
  const nodes = c3OperationalNodes(ride, setup);
  out.fromNode = nodes.fromNode; out.toNode = nodes.toNode;
  out.startAbs = c3RideStartAbsMin(ride.date, ride.time);
  if (dir === "toFestival") { out.festivalNode = nodes.toNode; out.variableNode = nodes.fromNode; }
  else if (dir === "fromFestival") { out.festivalNode = nodes.fromNode; out.variableNode = nodes.toNode; }
  out.zone = groupZoneOfNode(out.variableNode);
  return out;
}

// Route + Einsparung eines Paars (Spec 24/25/26). Beide Richtungen getrennt ueber
// travelMin (asymmetrie-sicher). Fehlt EINE benoetigte Kante -> routeReliable=false,
// KEINE Einsparung (nie 0/geschaetzt). identicalRoute wird gesondert behandelt.
function groupPairRoute(epA, epB, setup) {
  const out = {
    routeReliable: false, separateDrivingMin: null, groupedDrivingMin: null,
    estimatedDrivingSavedMin: null, detourMin: null, identicalRoute: false,
    sameOrigin: false, sameDestination: false, sameZone: false,
  };
  const m = setup.matrix;
  const leg = (a, b) => travelMin(m, a, b);
  out.sameOrigin = !!(epA.fromNode && epB.fromNode && epA.fromNode === epB.fromNode);
  out.sameDestination = !!(epA.toNode && epB.toNode && epA.toNode === epB.toNode);
  out.sameZone = epA.zone !== "UNKNOWN" && epA.zone === epB.zone;

  // Gemeinsamer Festival-Knoten und die zwei variablen Knoten.
  const fest = epA.festivalNode; // == epB.festivalNode (gleiche Richtung, gepr. vom Aufrufer)
  const vA = epA.variableNode, vB = epB.variableNode;
  if (!fest || !vA || !vB) return out; // unbekannter Ort -> nicht berechenbar

  if (out.sameOrigin && out.sameDestination) {
    // Identische Route: eine gemeinsame Fahrt statt zwei identischen.
    const singleLeg = epA.dir === "toFestival" ? leg(vA, fest) : leg(fest, vA);
    if (singleLeg == null) return out;
    out.identicalRoute = true;
    out.groupedDrivingMin = singleLeg;
    out.separateDrivingMin = singleLeg * 2;
    out.estimatedDrivingSavedMin = singleLeg;
    out.detourMin = 0;
    out.routeReliable = true;
    return out;
  }

  if (epA.dir === "toFestival") {
    // Zwei Abholorte -> Festival. Reihenfolgen vA->vB->F und vB->vA->F.
    const dA = leg(vA, fest), dB = leg(vB, fest), ab = leg(vA, vB), ba = leg(vB, vA);
    if (dA == null || dB == null) return out; // Einzelbein unbekannt -> nicht berechenbar
    out.separateDrivingMin = dA + dB;
    const opt1 = (ab != null) ? ab + dB : null; // vA->vB->F
    const opt2 = (ba != null) ? ba + dA : null; // vB->vA->F
    const opts = [opt1, opt2].filter((x) => x != null);
    if (opts.length === 0) return out; // Zwischenbein unbekannt
    out.groupedDrivingMin = Math.min(...opts);
    out.estimatedDrivingSavedMin = out.separateDrivingMin - out.groupedDrivingMin;
    out.detourMin = out.groupedDrivingMin - Math.max(dA, dB);
    out.routeReliable = true;
    return out;
  }

  // fromFestival: Festival -> zwei Ziele. Reihenfolgen F->dA->dB und F->dB->dA.
  const fA = leg(fest, vA), fB = leg(fest, vB), ab = leg(vA, vB), ba = leg(vB, vA);
  if (fA == null || fB == null) return out;
  out.separateDrivingMin = fA + fB;
  const opt1 = (ab != null) ? fA + ab : null; // F->dA->dB
  const opt2 = (ba != null) ? fB + ba : null; // F->dB->dA
  const opts = [opt1, opt2].filter((x) => x != null);
  if (opts.length === 0) return out;
  out.groupedDrivingMin = Math.min(...opts);
  out.estimatedDrivingSavedMin = out.separateDrivingMin - out.groupedDrivingMin;
  out.detourMin = out.groupedDrivingMin - Math.max(fA, fB);
  out.routeReliable = true;
  return out;
}

// C3-Status einer Fahrt (nur wenn Timetable-Eintraege uebergeben werden). Reine
// Ableitung; ohne Eintraege oder ohne eindeutiges Set = null (kein Veto, Spec 20).
function groupRideC3(ride, setup, timetableEntries, now) {
  if (!Array.isArray(timetableEntries) || timetableEntries.length === 0) return null;
  const match = matchRideToTimetable({ ride, timetableEntries });
  const timing = evaluateTimetableTiming({ ride, matchResult: match, setup, now: now || 0 });
  return timing || null;
}

// deterministischer sortScore (grob nach Status, dann Route/Einsparung/Umweg).
// Feinordnung uebernimmt der Comparator. Reine Funktion.
function finalizeGroupCandidate(c) {
  const order = GROUP_RIDE_STATUS_ORDER[c.status] != null ? GROUP_RIDE_STATUS_ORDER[c.status] : 99;
  let s = order * 1000;
  s += c.routeReliable ? 0 : 200;                 // vollstaendige Route bevorzugt
  s += (c.driverAssignment === "two_drivers" || c.driverAssignment === "mixed") ? 120 : 0; // keine Fahreraenderung bevorzugt
  s += c.capacityKnown && c.fitsFleet ? 0 : 150;  // ausreichende Kapazitaet bevorzugt
  const saved = (c.routeReliable && c.estimatedDrivingSavedMin != null) ? c.estimatedDrivingSavedMin : 0;
  s -= Math.min(Math.max(saved, 0), 240) / 10;    // hoehere Einsparung -> kleiner (max -24)
  s += (c.detourMin != null ? Math.min(Math.max(c.detourMin, 0), 60) : 0) / 20; // geringerer Umweg bevorzugt (max +3)
  c.sortScore = Math.round(s * 100) / 100;
  return c;
}

/* Zentrale reine Paar-Bewertung (Spec 11). Veraendert KEINE Eingabe, loest KEINEN
   Schreibweg aus, ist deterministisch fuer die uebergebenen Daten. Kanonisiert
   die Paarreihenfolge (frueherer Start zuerst, dann Ride-Id) fuer stabile Ausgabe. */
function evaluateRidePairForGrouping({ rideA, rideB, drivers, setup, now, timetableEntries }) {
  const cfg = GROUP_RIDE_CONFIG;
  const reasons = [];
  const warnings = [];

  // Kanonische Reihenfolge (stabil, unabhaengig von der Aufrufreihenfolge).
  const startAbsRaw = (r) => c3RideStartAbsMin(r && r.date, r && r.time);
  let a = rideA, b = rideB;
  const sa = startAbsRaw(a), sb = startAbsRaw(b);
  if (sa != null && sb != null) { if (sb < sa || (sb === sa && String(b.id) < String(a.id))) { const t = a; a = b; b = t; } }
  else if (String((b && b.id) || "") < String((a && a.id) || "")) { const t = a; a = b; b = t; }

  const rideIds = [a && a.id, b && b.id];
  const base = {
    status: "group_not_evaluable", severity: "neutral", label: GROUP_RIDE_STATUS_LABEL.group_not_evaluable,
    rideIds, direction: null, festDayKey: null,
    combinedPassengerCount: null, requiredSeatCount: null, capacityKnown: false, fitsFleet: false, suitableVehicleIds: [],
    departureDifferenceMin: null, proposedDepartureAt: null, departureShift: {},
    sameOrigin: false, sameDestination: false, sameZone: false, identicalRoute: false,
    separateDrivingMin: null, groupedDrivingMin: null, estimatedDrivingSavedMin: null, detourMin: null, routeReliable: false,
    driverAssignment: null, hasDriverConflict: false, conflictRideIds: [],
    c3: { a: null, b: null },
    reasons, warnings, sortScore: 0,
  };
  const done = (patch) => finalizeGroupCandidate(patch ? { ...base, ...patch } : base);

  if (!a || !b || !a.id || !b.id || a.id === b.id) { reasons.push("invalid_pair"); return done(); }

  // (1) Richtung: gleiche operative Richtung, sonst kein Kandidat (Spec 8).
  const dirA = rideFestivalDirection(a), dirB = rideFestivalDirection(b);
  if (dirA === "other" || dirB === "other" || dirA !== dirB) {
    reasons.push("direction_incompatible");
    return done({ status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended });
  }
  base.direction = dirA === "toFestival" ? "to_festival" : "from_festival";

  // (2) Status der beteiligten Fahrten (Spec 9): laufend/erledigt/storniert -> raus.
  const blocked = new Set(["cancelled", "done", "enroute_pickup", "onboard"]);
  if (blocked.has(a.status) || blocked.has(b.status)) {
    reasons.push("ride_state_excluded");
    return done({ status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended });
  }

  // (3) Zeit + Betriebstag (Spec 13/19). Ungueltige Zeit -> nicht bewertbar.
  const absA = c3RideStartAbsMin(a.date, a.time), absB = c3RideStartAbsMin(b.date, b.time);
  if (absA == null || absB == null) { reasons.push("invalid_datetime"); return done(); }
  const dayA = a.dayKey || (typeof festDayKey === "function" ? festDayKey(a.date, a.time) : null);
  const dayB = b.dayKey || (typeof festDayKey === "function" ? festDayKey(b.date, b.time) : null);
  if (!dayA || !dayB) { reasons.push("unknown_operating_day"); return done(); }
  base.festDayKey = dayA;
  if (dayA !== dayB) {
    reasons.push("different_operating_day");
    return done({ status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended });
  }
  base.departureDifferenceMin = Math.abs(absA - absB);

  // (4) Fahrerzuweisung aufloesen (Spec 18).
  const driverList = Array.isArray(drivers) ? drivers : ((setup && setup.drivers) || []);
  const byId = new Map(driverList.map((d) => [d.id, d]));
  const resolve = (r) => {
    const id = r.assignedDriverId || null;
    if (!id) return { id: null, resolved: null, unresolved: false };
    const d = byId.get(id) || null;
    return { id, resolved: d, unresolved: !d };
  };
  const drA = resolve(a), drB = resolve(b);
  if (drA.unresolved || drB.unresolved) { reasons.push("driver_unresolved"); return done(); }
  let driverAssignment;
  if (!drA.id && !drB.id) driverAssignment = "both_unassigned";
  else if (drA.id && drB.id && drA.id === drB.id) driverAssignment = "same_driver";
  else if ((drA.id && !drB.id) || (!drA.id && drB.id)) driverAssignment = "mixed";
  else driverAssignment = "two_drivers";
  base.driverAssignment = driverAssignment;

  // (5) Kapazitaet (Spec 17): nur Sitzplatzlogik, fehlende Personenzahl -> nicht bewertbar.
  const needA = validPassengerCount(a.passengerCount), needB = validPassengerCount(b.passengerCount);
  if (needA == null || needB == null) { reasons.push("passenger_count_missing"); return done(); }
  const combined = needA + needB;
  base.combinedPassengerCount = combined; base.requiredSeatCount = combined; base.capacityKnown = true;
  const fleet = groupFleetSeats(setup, combined);
  base.fitsFleet = fleet.maxSeats >= combined; base.suitableVehicleIds = fleet.suitableVehicleIds;

  // (6) Endpunkte + Route (Spec 24/25/26).
  const epA = groupRideEndpoints(a, setup), epB = groupRideEndpoints(b, setup);
  if (!epA.variableNode || !epB.variableNode || !epA.festivalNode || !epB.festivalNode) {
    reasons.push("unknown_location"); return done();
  }
  const route = groupPairRoute(epA, epB, setup);
  Object.assign(base, {
    sameOrigin: route.sameOrigin, sameDestination: route.sameDestination, sameZone: route.sameZone,
    identicalRoute: route.identicalRoute, separateDrivingMin: route.separateDrivingMin,
    groupedDrivingMin: route.groupedDrivingMin, estimatedDrivingSavedMin: route.routeReliable ? route.estimatedDrivingSavedMin : null,
    detourMin: route.routeReliable ? route.detourMin : null, routeReliable: route.routeReliable,
  });

  // (7) C3-Bewertung je Fahrt (nur wenn Timetable uebergeben; sonst kein Veto, Spec 20).
  const c3A = groupRideC3(a, setup, timetableEntries, now);
  const c3B = groupRideC3(b, setup, timetableEntries, now);
  // Echte C3-Felder: to_festival -> status/severity/marginMinutes; from_festival ->
  // status/severity/minutesRelativeToSetEnd (evaluateTimetableTiming liefert KEIN
  // setEndAt). Set-Ende laesst sich exakt als depAbs - minutesRelativeToSetEnd ableiten.
  base.c3 = {
    a: c3A ? { status: c3A.status, severity: c3A.severity, marginMinutes: c3A.marginMinutes != null ? c3A.marginMinutes : null, minutesRelativeToSetEnd: c3A.minutesRelativeToSetEnd != null ? c3A.minutesRelativeToSetEnd : null } : null,
    b: c3B ? { status: c3B.status, severity: c3B.severity, marginMinutes: c3B.marginMinutes != null ? c3B.marginMinutes : null, minutesRelativeToSetEnd: c3B.minutesRelativeToSetEnd != null ? c3B.minutesRelativeToSetEnd : null } : null,
  };

  // ---- Statusleiter ------------------------------------------------------
  // Harte Ausschluesse zuerst (Spec 15).
  if (base.departureDifferenceMin > cfg.maxDepartureDifferenceMin) {
    reasons.push("departure_gap_too_large");
    return done({ ...base, status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended, severity: "neutral" });
  }
  if (!base.fitsFleet) {
    reasons.push("capacity_insufficient");
    return done({ ...base, status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended, severity: "neutral" });
  }
  if (route.routeReliable && route.detourMin > cfg.maxTotalDetourMin) {
    reasons.push("detour_too_large");
    return done({ ...base, status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended, severity: "neutral" });
  }
  if (route.routeReliable && route.estimatedDrivingSavedMin != null && route.estimatedDrivingSavedMin <= 0) {
    reasons.push("no_saving");
    return done({ ...base, status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended, severity: "neutral" });
  }

  // Gemeinsame Abfahrt (unverbindlicher Planungswert) + Verschiebung je Fahrt (Spec 19/27).
  let proposedAbs;
  if (base.direction === "from_festival") {
    // Rueckfahrt: nicht vor spaetestem relevantem Set-Ende (Spec 21). Set-Ende
    // exakt aus C3: setEndAbs = Ride-Abfahrtsminute - minutesRelativeToSetEnd.
    // absA/base.c3.a bzw. absB/base.c3.b gehoeren zur jeweils selben (kanonischen) Fahrt.
    const endAbs = (rideAbs, c3) => (c3 && c3.minutesRelativeToSetEnd != null) ? rideAbs - c3.minutesRelativeToSetEnd : null;
    const ends = [endAbs(absA, base.c3.a), endAbs(absB, base.c3.b)].filter((x) => x != null);
    proposedAbs = Math.max(absA, absB, ...(ends.length ? ends : [-Infinity]));
    if (!isFinite(proposedAbs)) proposedAbs = Math.max(absA, absB);
  } else {
    // Hinfahrt: gemeinsame Abfahrt = spaetere der beiden (frueher Geplante wartet).
    proposedAbs = Math.max(absA, absB);
  }
  base.proposedDepartureAt = c3AbsToParts(proposedAbs).iso;
  base.departureShift = { [a.id]: proposedAbs - absA, [b.id]: proposedAbs - absB };
  const maxShift = Math.max(base.departureShift[a.id], base.departureShift[b.id]);
  if (maxShift > cfg.maxDepartureDifferenceMin) {
    reasons.push("shift_too_large");
    return done({ ...base, status: "group_not_recommended", label: GROUP_RIDE_STATUS_LABEL.group_not_recommended, severity: "neutral" });
  }

  // C3-Veto (Spec 28): schlechteste der beiden Fahrten deckelt die Empfehlung.
  // Deckelung nur nach unten, nie Aufwertung. Richtungsspezifische echte Status:
  // to_festival: on_time/tight/critical/late; from_festival: return_ok/return_before_set_end.
  let cap = "group_recommended";
  const worstBy = (rank) => [c3A, c3B].reduce((w, c) => {
    if (!c || rank[c.status] == null) return w;
    return rank[c.status] > (rank[w] || 0) ? c.status : w;
  }, null);
  if (base.direction === "to_festival") {
    const worst = worstBy({ late: 4, critical: 3, tight: 2, on_time: 1, timing_unknown: 0 });
    if (worst === "late") { reasons.push("c3_late"); cap = "group_not_recommended"; }
    else if (worst === "critical" || worst === "tight") { warnings.push("c3_buffer_tight"); cap = "group_possible"; }
  } else {
    const worst = worstBy({ return_before_set_end: 3, return_ok: 1, timing_unknown: 0 });
    if (worst === "return_before_set_end") { warnings.push("c3_return_before_set_end"); cap = "group_possible"; }
    // Erfordert die gemeinsame Abfahrt eine echte Verschiebung -> transparent (Spec 27).
    if (maxShift > 0) warnings.push("common_departure_shift");
  }

  // Route-/Einsparungslage deckelt ebenfalls (Spec 14): ohne verlaessliche Route
  // oder unter Mindest-Einsparung nie starke Empfehlung.
  if (!route.routeReliable) { reasons.push("route_incomplete"); if (cap === "group_recommended") cap = "group_possible"; }
  else if (route.estimatedDrivingSavedMin != null && route.estimatedDrivingSavedMin < cfg.minSavedDrivingMin) {
    reasons.push("saving_below_threshold"); if (cap === "group_recommended") cap = "group_possible";
  }

  // Fahrerzuweisung deckelt (Spec 18): gemischte/zwei Fahrer nie starke Empfehlung.
  if (driverAssignment === "mixed") { warnings.push("driver_assignment_review"); if (cap === "group_recommended") cap = "group_possible"; }
  else if (driverAssignment === "two_drivers") { warnings.push("two_driver_assignments"); if (cap === "group_recommended") cap = "group_possible"; }

  // Endstatus + Severity.
  const status = cap;
  let severity;
  if (status === "group_recommended") severity = "success";
  else if (status === "group_possible") severity = "info";
  else severity = "neutral";
  if (status === "group_recommended") reasons.push(base.identicalRoute ? "identical_route" : "grouping_beneficial");

  return done({ ...base, status, severity, label: GROUP_RIDE_STATUS_LABEL[status] });
}

// Deterministischer Comparator (Spec 30). Reine Funktion, mutiert nichts.
function groupCandidateCompare(x, y) {
  if (x.sortScore !== y.sortScore) return x.sortScore - y.sortScore;
  const ox = GROUP_RIDE_STATUS_ORDER[x.status] != null ? GROUP_RIDE_STATUS_ORDER[x.status] : 99;
  const oy = GROUP_RIDE_STATUS_ORDER[y.status] != null ? GROUP_RIDE_STATUS_ORDER[y.status] : 99;
  if (ox !== oy) return ox - oy;
  const sx = (x.routeReliable && x.estimatedDrivingSavedMin != null) ? x.estimatedDrivingSavedMin : -1;
  const sy = (y.routeReliable && y.estimatedDrivingSavedMin != null) ? y.estimatedDrivingSavedMin : -1;
  if (sx !== sy) return sy - sx; // hoehere Einsparung zuerst
  const dx = x.detourMin != null ? x.detourMin : 9999, dy = y.detourMin != null ? y.detourMin : 9999;
  if (dx !== dy) return dx - dy; // geringerer Umweg zuerst
  if ((x.departureDifferenceMin || 0) !== (y.departureDifferenceMin || 0)) return (x.departureDifferenceMin || 0) - (y.departureDifferenceMin || 0);
  const kx = (x.rideIds || []).join("|"), ky = (y.rideIds || []).join("|");
  return kx < ky ? -1 : kx > ky ? 1 : 0; // stabiler Ride-Identifier
}

// Ranking (Spec 30): sortierte KOPIE (mutiert die Eingabe nicht) + Markierung des
// Hauptvorschlags je Fahrt, damit eine Fahrt nicht in mehreren gleichwertigen
// Hauptempfehlungen erscheint. Reine Funktion.
function rankGroupRideCandidates(cands) {
  const list = Array.isArray(cands) ? cands.slice() : [];
  list.sort(groupCandidateCompare);
  const claimed = new Set();
  return list.map((c) => {
    const ids = c.rideIds || [];
    const actionable = GROUP_RIDE_ACTIONABLE.has(c.status);
    const overlaps = actionable && ids.some((id) => claimed.has(id));
    const isPrimary = actionable && !overlaps;
    if (isPrimary) ids.forEach((id) => claimed.add(id));
    return { ...c, isPrimary, overlapsPrimary: overlaps };
  });
}

/* Kandidatenerzeugung fuer Paare (Spec 36). Vorfilterung nach Betriebstag +
   Richtung + Status + gueltiger Zeit; danach nur zeitlich benachbarte Paare
   (Fenster maxDepartureDifferenceMin) vergleichen -> keine Vollkombination.
   Reine Funktion, mutiert nichts. Liefert gerankte, aktionable Kandidaten +
   Diagnosezaehler. */
function buildGroupRidePairCandidates({ rides, drivers, setup, now, timetableEntries }) {
  const all = Array.isArray(rides) ? rides : [];
  const blocked = new Set(["cancelled", "done", "enroute_pickup", "onboard"]);
  // Vorfilter: gueltige, gruppierbare Fahrten mit Richtung + Betriebstag + Startzeit.
  const usable = [];
  for (const r of all) {
    if (!r || !r.id) continue;
    const dir = rideFestivalDirection(r);
    if (dir === "other") continue;
    if (blocked.has(r.status)) continue;
    const abs = c3RideStartAbsMin(r.date, r.time);
    if (abs == null) continue;
    const day = r.dayKey || (typeof festDayKey === "function" ? festDayKey(r.date, r.time) : null);
    if (!day) continue;
    usable.push({ ride: r, dir, abs, day });
  }
  // Nach (Betriebstag, Richtung) buendeln, je Bucket nach Startzeit sortieren.
  const buckets = new Map();
  for (const u of usable) {
    const key = u.day + "|" + u.dir;
    if (!buckets.has(key)) buckets.set(key, []);
    buckets.get(key).push(u);
  }
  const cfg = GROUP_RIDE_CONFIG;
  const cands = [];
  for (const arr of buckets.values()) {
    arr.sort((p, q) => p.abs - q.abs || (String(p.ride.id) < String(q.ride.id) ? -1 : 1));
    for (let i = 0; i < arr.length; i++) {
      for (let j = i + 1; j < arr.length; j++) {
        if (arr[j].abs - arr[i].abs > cfg.maxDepartureDifferenceMin) break; // Fenster -> abbrechen
        const c = evaluateRidePairForGrouping({ rideA: arr[i].ride, rideB: arr[j].ride, drivers, setup, now, timetableEntries });
        cands.push(c);
      }
    }
  }
  const ranked = rankGroupRideCandidates(cands);
  const actionable = ranked.filter((c) => GROUP_RIDE_ACTIONABLE.has(c.status));
  const counts = { group_recommended: 0, group_possible: 0, group_not_recommended: 0, group_not_evaluable: 0 };
  ranked.forEach((c) => { counts[c.status] = (counts[c.status] || 0) + 1; });
  return { ranked, actionable, primaries: ranked.filter((c) => c.isPrimary), counts };
}

/* =========================================================================
   Teilpaket G1: Sichere Rueckstellungs- und Leerfahrt-Vorschlaege (Kern)
   (REIN LESEND, additiv, keine Schreibwege, kein neues dyn-Feld, keine DB).
   -------------------------------------------------------------------------
   Idee (Spec 1/2): der Leitstelle rein lesend zeigen, wenn ein Fahrer nach
   Plan an einem operativ unguenstigen Ort frei wird und eine Leerfahrt zur
   naechsten zugeteilten Fahrt bzw. eine Rueckstellung zu offenem Festival-
   Bedarf sinnvoll waere. KEIN neuer Ride, kein Typ, kein gespeicherter
   Status, keine automatische Umsetzung. Alles zur Laufzeit aus Bestandsdaten.

   Wiederverwendung (kein zweiter Motor, Spec 7/21/31):
   - Position: computeDriverStats (UNVERAENDERT) fuer aktive/vergangene Fahrten.
   - Operative Orte/Fahrzeit: c3OperationalNodes + travelMin + c3RideStartAbsMin
     (Teilpaket B/C3; Sheraton-Pickup fuer Leonardo/HBF -> Festival, Rueckfahrt
     behaelt echtes Ziel; Matrixzeit verbindlich, nie 0/geschaetzt).
   - Erreichbarkeit/Konflikt/Kapazitaet: evaluateInsertion (Bestandsmotor, UNVERAENDERT).
   - Bedarf: D-Zustaende (op.group overdue/driver_missing/due_soon) als EINGABE
     (returnRideViewModels), nicht neu gebaut.
   - E-Vorrang: wait_recommended pro Fahrer als EINGABE (Spec 22).
   - F: nur optionaler neutraler Hinweis, nie positionsbestimmend (Spec 23).

   Scope-Entscheidung (mit Jordan geklaert, 20.07.2026):
   - Voll umgesetzt: direct_to_next_pickup, reposition_to_festival,
     stay_at_current_location, not_evaluable.
   - reposition_to_demand_zone (Nicht-Festival-Zonen) BEWUSST VERTAGT: braucht
     eine zweite Bedarfsquelle (offene Hinfahrten aus dyn.rides) + eine
     now-Abs-Umrechnung, die vor dem Festival-Freeze nicht ueberhastet gebaut
     wird. Das Status-Feld existiert, feuert in G1 aber nicht.

   Basis-Entscheidung (mit Jordan geklaert): es gibt KEINE verbindliche
   Fahrerbasis. baseLocationId ("sheraton") ist nur Positions-Fallback in
   computeDriverStats und wird fuer G NICHT als Position/Ziel angenommen ->
   Fahrer ohne relevante Fahrt = Position unbekannt = not_evaluable. Kein
   return_to_base, Sheraton nie als pauschale Basis (Spec 8/11/16).
========================================================================= */
const REPOSITION_CONFIG = {
  minMovementBenefitMin: 10,       // Mindestnutzen einer Bewegung (Spec 9)
  minArrivalBufferMin: 15,         // Mindestpuffer am naechsten Abholort (Spec 9/27)
  preferredArrivalBufferMin: 25,   // bevorzugter Puffer (nur Info)
  demandLookaheadMin: 90,          // Bedarfsfenster fuer Rueckstellungen (Spec 9/14)
  maxRepositionTravelMin: 35,      // max. Fahrzeit einer allgemeinen Rueckstellung (Spec 9/14)
  minDemandScoreForReposition: 2,  // Mindestbedarf fuer positive Rueckstellung (Spec 9/10)
  sameLocationToleranceMin: 0,     // gleicher Ort = keine Bewegung
  stalePastRideGraceMin: 15,       // Toleranz fuer knapp vergangene Fahrten
};

const REPOSITION_STATUS_LABEL = {
  direct_to_next_pickup: "Leerfahrt zum nächsten Abholort sinnvoll",
  reposition_to_festival: "Rückstellung zum Festival prüfen",
  reposition_to_demand_zone: "Rückstellung in Bedarfszone prüfen",
  stay_at_current_location: "Keine Bewegung nötig",
  not_evaluable: "Nicht sicher bewertbar",
};
// Prioritaet (Spec 26): kleiner = wichtiger.
const REPOSITION_STATUS_ORDER = {
  direct_to_next_pickup: 0, reposition_to_festival: 1, reposition_to_demand_zone: 2,
  stay_at_current_location: 3, not_evaluable: 4,
};
// handlungsleitende Status (fuer Zaehler/Filter in G2).
const REPOSITION_ACTIONABLE = new Set(["direct_to_next_pickup", "reposition_to_festival", "reposition_to_demand_zone"]);
// D-Gruppen, die als offener Bedarf zaehlen (Spec 10/24). completed/cancelled/
// in_progress/driver_assigned/not_due/needs_review zaehlen NICHT.
const REPOSITION_DEMAND_GROUPS = new Set(["overdue", "driver_missing", "due_soon"]);
// Gewicht je Bedarfsgruppe (Spec 10).
const REPOSITION_DEMAND_WEIGHT = { overdue: 3, driver_missing: 2, due_soon: 1 };

// Ortslabel fuer die Anzeige (aus setup.locations, sonst Custom-Text/id).
function repositionLocLabel(setup, id, custom) {
  if (custom && String(custom).trim()) return String(custom).trim();
  const l = setup && Array.isArray(setup.locations) ? setup.locations.find((x) => x.id === id) : null;
  return (l && (l.short || l.name)) || id || "unbekannt";
}

/* Geplantes Fahrtende EINER Fahrt als Absolutminute ueber die verbindliche
   Matrixzeit (wie C3/E/F), NICHT ueber estDurationMin (Spec 18). Fehlt die
   Kante -> reliable:false, abs:null (nie 0, nie 20-min-Fallback). Rein. */
function repositionRideEndAbs(ride, setup) {
  const startAbs = c3RideStartAbsMin(ride.date, ride.time);
  if (startAbs == null) return { abs: null, reliable: false, node: null };
  const nodes = c3OperationalNodes(ride, setup);
  const t = travelMin(setup.matrix, nodes.fromNode, nodes.toNode);
  if (t == null) return { abs: null, reliable: false, node: nodes.toNode || null };
  return { abs: startAbs + t, reliable: true, node: nodes.toNode || null };
}

/* Reine Planungsposition eines Fahrers (Spec 6/7). Position AUSSCHLIESSLICH aus
   dem Fahrplan des Fahrers (aktive oder zuletzt planmaessig beendete Fahrt),
   NIE aus baseLocationId, State oder GPS -> keine Live-Position behauptet, kein
   Basis-Assumption. Ohne relevante Fahrt = confidence "unknown". Nutzt
   computeDriverStats unveraendert und veraendert selbst nichts. */
function deriveDriverPlannedPosition({ driver, dyn, setup, now, dayKey }) {
  const reasons = [];
  const out = {
    driverId: driver && driver.id ? driver.id : null,
    locationId: null, locationLabel: null, locationNode: null,
    availableAt: null, sourceRideId: null, sourceType: "unknown",
    confidence: "unknown", reasons,
  };
  if (!driver || !driver.id) { reasons.push("driver_invalid"); return out; }
  const stats = computeDriverStats(setup, dyn, driver.id, dayKey);
  // (a) Aktive Fahrt: Position = deren ECHTES Ziel, frei ab deren Matrix-Ende.
  if (stats.active) {
    const r = stats.active;
    const end = repositionRideEndAbs(r, setup);
    out.sourceRideId = r.id; out.sourceType = "active_ride_end"; out.confidence = "active";
    out.locationId = r.toId || null; out.locationLabel = repositionLocLabel(setup, r.toId, r.toCustom);
    out.locationNode = end.node; out.availableAt = end.abs;
    if (!end.reliable) reasons.push("ride_end_not_reliable");
    if (!out.locationNode) reasons.push("location_unknown");
    return out;
  }
  // (b) Sonst: zuletzt planmaessig beendete, nicht stornierte Fahrt.
  const nowMinOfDay = stats.now;
  const past = (stats.rides || []).filter((r) =>
    r.status !== "cancelled" && (sortMin(r.time) + effDur(setup.config, r)) <= nowMinOfDay);
  // stabile Auswahl: spaeteste Planzeit zuerst, Tie-Break id (Spec 6).
  past.sort((a, b) => (sortMin(a.time) - sortMin(b.time)) || String(a.id || "").localeCompare(String(b.id || "")));
  const last = past[past.length - 1];
  if (last) {
    const end = repositionRideEndAbs(last, setup);
    out.sourceRideId = last.id; out.sourceType = "planned_ride_end"; out.confidence = "planned";
    out.locationId = last.toId || null; out.locationLabel = repositionLocLabel(setup, last.toId, last.toCustom);
    out.locationNode = end.node; out.availableAt = end.abs;
    if (!end.reliable) reasons.push("ride_end_not_reliable");
    if (!out.locationNode) reasons.push("location_unknown");
    return out;
  }
  // (c) Keine relevante Fahrt -> Position unbekannt (KEIN Basis-Fallback, Spec 8/16).
  reasons.push("no_plan_position");
  return out;
}

/* Naechste diesem Fahrer zugeteilte Fahrt nach seiner geplanten Verfuegbarkeit
   (Spec 17). Nur zugeteilt, nicht storniert/erledigt/laufend, Start-Abs >=
   availableAt. Stabil: frueheste Start-Abs, Tie-Break id. Rein. */
function repositionNextAssignedRide({ driver, dyn, setup, dayKey, availableAt }) {
  if (availableAt == null) return null;
  const mine = driverDay(dyn.rides, driver.id, dayKey).filter((r) =>
    r.assignedDriverId === driver.id &&
    r.status !== "cancelled" &&
    !RETURN_STATUS_COMPLETED.has(r.status || "") &&
    !RETURN_STATUS_ACTIVE.has(r.status || ""));
  const withAbs = mine.map((r) => ({ r, abs: c3RideStartAbsMin(r.date, r.time) }))
    .filter((x) => x.abs != null && x.abs >= availableAt);
  withAbs.sort((a, b) => (a.abs - b.abs) || String(a.r.id || "").localeCompare(String(b.r.id || "")));
  return withAbs.length ? withAbs[0].r : null;
}

/* Deterministischer Bedarfsscore fuer einen Ziel-Matrix-Knoten (Spec 10). Zaehlt
   NUR unbesetzte offene Fahrten am Knoten innerhalb des Lookahead-Fensters,
   gewichtet nach D-Gruppe. needs_review/assigned/completed/cancelled/in_progress
   zaehlen NICHT (Spec 24). Nutzt Ds bereits now-relative minutesUntilDeparture
   (keine eigene Zeitrechnung). Rein. */
function repositionDemandScore({ node, returnRideViewModels, setup, config }) {
  const cfg = config || REPOSITION_CONFIG;
  const ids = [];
  let score = 0;
  const vms = Array.isArray(returnRideViewModels) ? returnRideViewModels : [];
  for (const vm of vms) {
    if (!vm || !vm.ride || !vm.op) continue;
    if (vm.op.driverAssigned) continue;                          // nur unbesetzt (Spec 10)
    if (!REPOSITION_DEMAND_GROUPS.has(vm.op.group)) continue;    // nur overdue/driver_missing/due_soon
    const m = vm.op.minutesUntilDeparture;
    if (m != null && m > cfg.demandLookaheadMin) continue;       // ueberfaellig (m<0) immer, sonst <= lookahead
    const nodes = c3OperationalNodes(vm.ride, setup);
    if (nodes.fromNode !== node) continue;                       // Bedarf am Ziel-Knoten
    score += REPOSITION_DEMAND_WEIGHT[vm.op.group] || 0;
    ids.push(vm.ride.id);
  }
  if (ids.length >= 2) score += 1;                               // mehrere passende (Spec 10)
  return { score, demandRideIds: ids, count: ids.length };
}

/* Anzahl ANDERER Fahrer, die nach Plan bereits am Ziel-Knoten frei sind
   (Spec 30). Nutzt die einmal vorberechneten Planungspositionen. Rein. */
function repositionFreeDriverCoverage({ node, driverPlannedPositions, excludeDriverId }) {
  const list = Array.isArray(driverPlannedPositions) ? driverPlannedPositions : [];
  let n = 0;
  for (const p of list) {
    if (!p || p.driverId === excludeDriverId) continue;
    if (p.confidence === "unknown" || p.availableAt == null) continue;
    if (p.locationNode === node) n++;
  }
  return n;
}

/* Mindestens eine der offenen Bedarfsfahrten am Ziel muss fuer DIESEN Fahrer
   ueber den Bestandsmotor erreichbar sein (Spec 31/32: Kapazitaet, Konflikt,
   availableFrom, Rechtzeitigkeit, Leonardo/HBF-Pickup). Rein, evaluateInsertion
   ist unveraendert. Gibt die Ride-IDs der erreichbaren Fahrten zurueck. */
function repositionReachableOpenRides({ driver, demandRideIds, dyn, setup }) {
  const byId = new Map((dyn.rides || []).map((r) => [r.id, r]));
  const reachable = [];
  for (const id of (demandRideIds || [])) {
    const ride = byId.get(id);
    if (!ride) continue;
    const ev = evaluateInsertion(setup, dyn, driver, ride);
    if (ev && ev.feasible) reachable.push(id);
  }
  return reachable;
}

/* Zentrale reine Bewertung eines Fahrers (Spec 25/26). Genau EIN primaerer
   Status je Fahrer. Veraendert nichts, keine DB-/UI-Seiteneffekte. now wird nur
   durchgereicht (G rechnet in Absolutminuten bzw. nutzt Ds now-relative Werte);
   kein eigener Timer. */
function evaluateDriverRepositionSuggestion({ driver, dyn, setup, now, dayKey,
  returnRideViewModels, waitRideSuggestions, groupRideSuggestions, driverPlannedPositions }) {
  const cfg = REPOSITION_CONFIG;
  const reasons = [];
  const warnings = [];
  const out = {
    status: "not_evaluable", severity: "warning", label: REPOSITION_STATUS_LABEL.not_evaluable,
    driverId: driver && driver.id ? driver.id : null,
    fromLocationId: null, fromLocationLabel: null, availableAt: null,
    toLocationId: null, toLocationLabel: null,
    nextRideId: null, demandRideIds: [],
    travelMinutes: null, departureAt: null, arrivalAt: null, bufferBeforeNextRideMin: null,
    demandScore: 0, routeReliable: false, hasConflict: false,
    alternatives: [], reasons, warnings, sortScore: REPOSITION_STATUS_ORDER.not_evaluable * 1000,
  };
  const finalize = (patch) => {
    const o = patch ? Object.assign(out, patch) : out;
    const base = (REPOSITION_STATUS_ORDER[o.status] != null ? REPOSITION_STATUS_ORDER[o.status] : 4) * 1000;
    // innerhalb gleicher Prioritaet: hoeherer Bedarf zuerst, kuerzere Route zuerst.
    o.sortScore = base - (o.demandScore || 0) * 10 + (o.travelMinutes != null ? Math.min(o.travelMinutes, 99) / 100 : 0);
    o.label = REPOSITION_STATUS_LABEL[o.status] || o.label;
    return o;
  };

  if (!driver || !driver.id) { reasons.push("driver_invalid"); return finalize(); }

  // (1) Planungsposition.
  const pos = deriveDriverPlannedPosition({ driver, dyn, setup, now, dayKey });
  out.fromLocationId = pos.locationId;
  out.fromLocationLabel = pos.locationLabel;
  out.availableAt = pos.availableAt;
  if (pos.confidence === "unknown" || pos.locationNode == null || pos.availableAt == null) {
    pos.reasons.forEach((r) => reasons.push(r));
    if (!reasons.length) reasons.push("position_not_reliable");
    return finalize({ status: "not_evaluable" });
  }
  out.departureAt = c3AbsToParts(pos.availableAt).iso;

  // (2) E-Vorrang (Spec 22): ein konfliktfreier wait_recommended fuer diesen
  //     Fahrer schlaegt jede G-Bewegung als Hauptvorschlag -> keine
  //     widerspruechliche Empfehlung. G tritt zurueck (stay), E bleibt fuehrend.
  const eWait = (Array.isArray(waitRideSuggestions) ? waitRideSuggestions : []).find(
    (w) => w && w.driverId === driver.id && w.status === "wait_recommended" && !w.hasRideConflict);
  if (eWait) {
    reasons.push("e_wait_recommended_priority");
    return finalize({ status: "stay_at_current_location", severity: "neutral" });
  }

  // (3) Konkrete Leerfahrt zur naechsten zugeteilten Fahrt (Spec 12/27) - hat
  //     Vorrang vor der Rueckstellung.
  const next = repositionNextAssignedRide({ driver, dyn, setup, dayKey, availableAt: pos.availableAt });
  if (next) {
    out.nextRideId = next.id;
    const nn = c3OperationalNodes(next, setup);
    const nextPickupNode = nn.fromNode;
    const nextStartAbs = c3RideStartAbsMin(next.date, next.time);
    out.toLocationId = next.fromId || null;
    out.toLocationLabel = repositionLocLabel(setup, next.fromId, next.fromCustom);
    // gleicher Ort -> keine Bewegung noetig (Spec 13/27).
    if (nextPickupNode && nextPickupNode === pos.locationNode) {
      reasons.push("next_ride_same_location");
      return finalize({ status: "stay_at_current_location", severity: "neutral" });
    }
    const travel = travelMin(setup.matrix, pos.locationNode, nextPickupNode);
    if (travel == null || nextStartAbs == null) {
      reasons.push(travel == null ? "empty_route_unknown" : "next_ride_time_invalid");
      return finalize({ status: "not_evaluable", routeReliable: false });
    }
    out.travelMinutes = travel;
    out.routeReliable = true;
    const arrivalAbs = pos.availableAt + travel;
    out.arrivalAt = c3AbsToParts(arrivalAbs).iso;
    const buffer = nextStartAbs - arrivalAbs;
    out.bufferBeforeNextRideMin = buffer;
    // Konflikt ueber den Bestandsmotor (Spec 21).
    const ev = evaluateInsertion(setup, dyn, driver, next);
    const conflict = !!(ev && (ev.overlap || !ev.available || ev.lateToPickup > 0));
    out.hasConflict = conflict;
    if (ev && !ev.available && ev.availabilityReason) warnings.push(ev.availabilityReason);
    if (buffer < cfg.minArrivalBufferMin || conflict) {
      reasons.push(buffer < cfg.minArrivalBufferMin ? "buffer_below_min" : "conflict");
      // nicht sicher erreichbar -> keine positive Empfehlung (Spec 27).
      return finalize({ status: "not_evaluable", severity: "warning" });
    }
    reasons.push("direct_reachable_with_buffer");
    return finalize({ status: "direct_to_next_pickup", severity: "info" });
  }

  // (4) Keine konkrete naechste Fahrt -> Rueckstellung zum Festival (Spec 14).
  const FEST = "festival";
  // bereits am Festival -> keine Bewegung (Spec 13).
  if (pos.locationNode === FEST) {
    reasons.push("already_at_festival");
    return finalize({ status: "stay_at_current_location", severity: "neutral" });
  }
  const demand = repositionDemandScore({ node: FEST, returnRideViewModels, setup, config: cfg });
  out.demandScore = demand.score;
  out.demandRideIds = demand.demandRideIds;
  const travelFest = travelMin(setup.matrix, pos.locationNode, FEST);
  if (travelFest == null) {
    reasons.push("reposition_route_unknown");
    return finalize({ status: "not_evaluable", routeReliable: false });
  }
  out.routeReliable = true;
  out.travelMinutes = travelFest;
  out.toLocationId = FEST;
  out.toLocationLabel = repositionLocLabel(setup, FEST, null);
  out.arrivalAt = c3AbsToParts(pos.availableAt + travelFest).iso;
  // optionaler neutraler F-Hinweis (Spec 23): existiert fuer eine Bedarfsfahrt
  // zusaetzlich ein Sammelfahrt-Vorschlag? Rein informativ, nicht positionsbestimmend.
  const groupIds = new Set((Array.isArray(groupRideSuggestions) ? groupRideSuggestions : [])
    .filter((g) => g && REPOSITION_ACTIONABLE_GROUP(g)).flatMap((g) => Array.isArray(g.rideIds) ? g.rideIds : []).filter(Boolean));
  if (demand.demandRideIds.some((id) => groupIds.has(id))) warnings.push("group_suggestion_exists");

  if (demand.score < cfg.minDemandScoreForReposition) {
    reasons.push("no_sufficient_demand");
    return finalize({ status: "stay_at_current_location", severity: "neutral" });
  }
  // mindestens eine offene Bedarfsfahrt muss erreichbar sein (Spec 31).
  const reachable = repositionReachableOpenRides({ driver, demandRideIds: demand.demandRideIds, dyn, setup });
  if (reachable.length === 0) {
    reasons.push("no_reachable_open_ride");
    return finalize({ status: "stay_at_current_location", severity: "neutral" });
  }
  // Bedarfsdeckung durch bereits freie Fahrer am Festival (Spec 30).
  const coverage = repositionFreeDriverCoverage({ node: FEST, driverPlannedPositions, excludeDriverId: driver.id });
  const coverageSufficient = demand.count > 0 && coverage >= demand.count;
  // zu weite Bewegung -> nur neutral als pruefbar (Spec 14/28), keine starke Empfehlung.
  const tooFar = travelFest > cfg.maxRepositionTravelMin;
  if (coverageSufficient) warnings.push("sufficient_coverage");
  if (tooFar) warnings.push("travel_over_max");
  const weak = coverageSufficient || tooFar;
  reasons.push(weak ? "festival_demand_weak" : "festival_demand");
  return finalize({ status: "reposition_to_festival", severity: weak ? "neutral" : "attention" });
}

// Hilfsflag: gilt ein F-Kandidat als handlungsleitend? (nur fuer den neutralen
// Hinweis; F-Status-Set liegt in GROUP_RIDE_ACTIONABLE.)
function REPOSITION_ACTIONABLE_GROUP(g) {
  return !!(g && typeof GROUP_RIDE_ACTIONABLE !== "undefined" && GROUP_RIDE_ACTIONABLE.has && GROUP_RIDE_ACTIONABLE.has(g.status));
}

/* Deterministischer Vergleich fuer die Anzeige-Reihenfolge (Spec 26/29). Rein. */
function repositionCompare(a, b) {
  if (a.sortScore !== b.sortScore) return a.sortScore - b.sortScore;
  const da = a.demandScore || 0, db = b.demandScore || 0;
  if (da !== db) return db - da;                                  // hoeherer Bedarf zuerst
  const ta = a.travelMinutes == null ? Infinity : a.travelMinutes;
  const tb = b.travelMinutes == null ? Infinity : b.travelMinutes;
  if (ta !== tb) return ta - tb;                                  // kuerzere Route zuerst
  return String(a.driverId || "").localeCompare(String(b.driverId || "")); // stabiler Tie-Break
}

/* Sortiert eine KOPIE (mutiert die Eingabe nicht, Spec 41). */
function rankRepositionSuggestions(list) {
  return (Array.isArray(list) ? list.slice() : []).sort(repositionCompare);
}

/* Orchestrierung (Spec 40): je Fahrer genau EIN Vorschlag. Planungspositionen
   werden EINMAL vorberechnet und in die Bewertung gereicht (O(n) statt O(n^2)).
   Rein lesend, mutiert nichts. */
function buildRepositionSuggestions({ drivers, dyn, setup, now, dayKey,
  returnRideViewModels, waitRideSuggestions, groupRideSuggestions }) {
  const ds = Array.isArray(drivers) ? drivers : [];
  // 1x alle Planungspositionen (fuer die Bedarfsdeckung, Spec 30/40).
  const driverPlannedPositions = ds.map((driver) =>
    deriveDriverPlannedPosition({ driver, dyn, setup, now, dayKey }));
  const suggestions = ds.map((driver) => evaluateDriverRepositionSuggestion({
    driver, dyn, setup, now, dayKey,
    returnRideViewModels, waitRideSuggestions, groupRideSuggestions, driverPlannedPositions,
  }));
  const ranked = rankRepositionSuggestions(suggestions);
  const counts = { direct_to_next_pickup: 0, reposition_to_festival: 0,
    reposition_to_demand_zone: 0, stay_at_current_location: 0, not_evaluable: 0 };
  ranked.forEach((s) => { counts[s.status] = (counts[s.status] || 0) + 1; });
  const byDriver = {};
  ranked.forEach((s) => { if (s.driverId) byDriver[s.driverId] = s; });
  const actionable = ranked.filter((s) => REPOSITION_ACTIONABLE.has(s.status));
  return { ranked, byDriver, actionable, counts, driverPlannedPositions };
}


/* ---- Teilpaket F2: rein praesentationale Anzeige der Sammelfahrt-Vorschlaege --
 * Reine Anzeige-Komponente. Kein Schreibweg, kein Handler ausser den beiden
 * bestehenden Oeffnen-Aktionen (onOpenPartner -> Ride-Editor, onOpenAssign ->
 * Zuteilung). Zeigt NUR handlungsleitende Status (recommended/possible). Ruhige
 * Variante: schmaler Akzentstrich, Farbe nur auf Label/Icon, Details gedaempft.
 * group_recommended -> Gruen (--mc-st-done), group_possible -> Blau (--mc-st-new,
 * kein Alarmrot). */
const GROUP_C3_WARNING_LABEL = {
  c3_buffer_tight: "Zeitpuffer knapp, Ankunft beachten",
  c3_return_before_set_end: "Abfahrt läge vor Set-Ende, bitte prüfen",
};
function groupDriverHint(assignment) {
  if (assignment === "two_drivers") return "zwei Fahrer zugeteilt, bitte prüfen";
  if (assignment === "mixed") return "einer zugeteilt, einer offen, bitte prüfen";
  if (assignment === "same_driver") return "gleicher Fahrer";
  if (assignment === "both_unassigned") return "beide noch ohne Fahrer";
  return null;
}
function GroupSuggestionNote({ candidate, thisRideId, rides, onOpenPartner, onOpenAssign }) {
  if (!candidate || !GROUP_RIDE_ACTIONABLE.has(candidate.status)) return null;
  const c = candidate;
  const partnerId = (c.rideIds || []).find((id) => id !== thisRideId) || null;
  const partner = partnerId ? (rides || []).find((r) => r.id === partnerId) : null;
  const accent = c.status === "group_recommended" ? "var(--mc-st-done)" : "var(--mc-st-new)";
  const partnerLabel = partner ? `${partner.djName || "Fahrt"} (${partner.time})` : "Partnerfahrt";
  const savedText = (c.routeReliable && c.estimatedDrivingSavedMin != null)
    ? `${c.estimatedDrivingSavedMin} Fahrminuten sparbar`
    : "Fahrzeit unvollständig, keine Einsparung geschätzt";
  const detourText = (c.routeReliable && c.detourMin != null) ? ` · Umweg ${c.detourMin} min` : "";
  const capText = c.combinedPassengerCount != null
    ? `${c.combinedPassengerCount} Pers.${c.fitsFleet ? "" : " (kein Fahrzeug groß genug)"}`
    : null;
  const driverHint = groupDriverHint(c.driverAssignment);
  const c3Warn = (c.warnings || []).map((w) => GROUP_C3_WARNING_LABEL[w]).find(Boolean) || null;
  return (
    <div className="mt-2 pl-2.5 text-xs" style={{ borderLeft: `3px solid ${accent}` }}>
      <div className="inline-flex items-center gap-1.5 font-semibold" style={{ color: accent }}>
        <Users className="w-3.5 h-3.5 shrink-0" />{c.label} · mit {partnerLabel}
      </div>
      <div className="mt-0.5" style={{ color: "var(--mc-text-muted)" }}>{savedText}{detourText}</div>
      {(capText || driverHint) && (
        <div style={{ color: "var(--mc-text-muted)" }}>{[capText, driverHint].filter(Boolean).join(" · ")}</div>
      )}
      {c3Warn && <div style={{ color: "var(--mc-text-muted)" }}>{c3Warn}</div>}
      <div className="mt-1 flex items-center gap-3">
        {onOpenPartner && partner && (
          <button onClick={() => onOpenPartner(partner)} className="hover:opacity-80" style={{ color: "var(--mc-text-secondary)" }}>Fahrt öffnen</button>
        )}
        {onOpenAssign && (
          <button onClick={onOpenAssign} className="hover:opacity-80" style={{ color: "var(--mc-text-secondary)" }}>Zuweisung öffnen</button>
        )}
      </div>
    </div>
  );
}

/* ---- Mission-Control-Variante der Rueckfahrten (Session 7; Teilpaket D) --- *
 * Datenableitung und ALLE Schreib-Handler (Anwesenheit) sind VERBATIM aus der
 * bestehenden Ansicht uebernommen (keine Aenderung an Rueckfahrten-/Zeit-/
 * Zuteilungs-/Supabase-Logik). Teilpaket D ergaenzt REIN LESEND: eine zentrale
 * operative Klassifizierung pro Rueckfahrt (deriveReturnRideOperationalState),
 * gruppierte Darstellung, operative Zaehler und einen Gruppenfilter. Kein neuer
 * Schreibweg, keine gespeicherten Zustaende. -------------------------------- */
function MissionReturnsTab({ setup, dyn, day, updateDyn, by, onErr, onAssign, onWhatsApp, onEdit, onNewReturn }) {
  const [sort, setSort] = useState("time"); // time | dest (bestehend)
  const [q, setQ] = useState("");
  const [groupFilter, setGroupFilter] = useState("all"); // all | <gruppe> (Teilpaket D)
  const [onlyNoDriver, setOnlyNoDriver] = useState(false); // Teilpaket D
  const [onlyWaitSuggestion, setOnlyWaitSuggestion] = useState(false); // Teilpaket E
  const [onlyGroupSuggestion, setOnlyGroupSuggestion] = useState(false); // Teilpaket F2
  const [now, setNow] = useState(Date.now());
  // Teilpaket D: Aktualisierung der operativen Einordnung einmal pro Minute
  // (Spec 19). Rein Re-Render: kein Schreibweg, kein DB-Abruf. Beim Unmount weg.
  useEffect(() => { const t = setInterval(() => setNow(Date.now()), 60000); return () => clearInterval(t); }, []);
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const destName = (r) => ln(r.toId, r.toCustom);
  const origName = (r) => ln(r.fromId, r.fromCustom); // Abholort (i.d.R. Festival)

  // ---- Rueckfahrt-Erkennung: VERBATIM bestehende zentrale Logik (Spec 1/21) --
  const returns = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled" && (r.type === "return" || r.fromId === "festival"));
  const presence = useMemo(() => computeArtistPresence(dyn), [dyn.rides, dyn.artistPresence]);
  const missing = presence.filter((p) => !p.pendingReturn && !p.noReturn);
  const noReturnList = presence.filter((p) => !p.pendingReturn && p.noReturn);
  const covered = presence.filter((p) => p.pendingReturn);

  // Schreib-Handler VERBATIM aus der bestehenden Ansicht (gleiche updateDyn-Kette).
  const setNoReturn = async (name, value) => {
    const res = await updateDyn((d) => {
      d.artistPresence = d.artistPresence || {};
      const cur = d.artistPresence[name] || {};
      if (cur.noReturn === value) return NO_CHANGE; // schon im Zielzustand -> kein rev-Bump/Poll
      d.artistPresence[name] = { ...cur, noReturn: value, by, at: Date.now() };
      return d;
    });
    if ((!res || !res.ok) && onErr) onErr(res?.error || "Rueckfahrt-Status konnte nicht gespeichert werden, bitte erneut versuchen.");
  };
  const setManualPresence = async (name, value) => {
    const res = await updateDyn((d) => {
      d.artistPresence = d.artistPresence || {};
      const cur = d.artistPresence[name] || {};
      if (value === null ? cur.manual === undefined : cur.manual === value) return NO_CHANGE; // schon im Zielzustand -> kein rev-Bump/Poll
      if (value === null) { const { manual, ...rest } = cur; d.artistPresence[name] = { ...rest, by, at: Date.now() }; }
      else d.artistPresence[name] = { ...cur, manual: value, by, at: Date.now() };
      return d;
    });
    if ((!res || !res.ok) && onErr) onErr(res?.error || "Anwesenheit konnte nicht gespeichert werden, bitte erneut versuchen.");
  };
  const addManualArtist = async (rawName) => {
    const name = (rawName || "").trim();
    if (!name) return;
    const at = Date.now();
    const res = await updateDyn((d) => {
      d.artistPresence = d.artistPresence || {};
      const cur = d.artistPresence[name] || {};
      if (cur.manual === "here") return NO_CHANGE; // schon manuell anwesend -> kein rev-Bump/Poll
      d.artistPresence[name] = { ...cur, manual: "here", by, at };
      return d;
    });
    if ((!res || !res.ok) && onErr) onErr(res?.error || "Anwesenheit konnte nicht gespeichert werden, bitte erneut versuchen.");
  };

  const presenceNames = new Set(presence.map((p) => p.name));
  const manualOnly = Object.entries(dyn.artistPresence || {})
    .filter(([name, ov]) => ov?.manual === "here" && !presenceNames.has(name))
    .map(([name]) => ({ name, onSite: true, pendingReturn: null, noReturn: false, manual: "here", manualOnly: true }));

  const atFestival = setup.drivers
    .map((d) => ({ d, s: computeDriverStats(setup, dyn, d.id, day) }))
    // Nur Fahrer, deren letzte Fahrt tatsaechlich am Festival endete. Frueher
    // "|| !x.s.locNow" hat Fahrer ohne bekannten Standort als am Festival gezaehlt,
    // was falsche Vor-Ort-Vorschlaege verursacht hat (computeDriverStats.locNow
    // faellt bei fehlender Info bewusst auf baseLocationId zurueck).
    .filter((x) => !x.s.active && x.s.locNow === "festival")
    .sort((a, b) => a.s.drivingMin - b.s.drivingMin);

  // ---- Teilpaket D: operatives View-Model pro Rueckfahrt (rein lesend) ------
  // Basis (C2-Match + C3-Zeitbewertung) haengt NICHT von `now` ab -> nur bei
  // Datenaenderung neu. C3 nutzt `now` nicht (reine Planungsbewertung).
  const ttMatchEntries = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  const baseModels = useMemo(() => returns.map((r) => {
    const driver = setup.drivers.find((d) => d.id === r.assignedDriverId) || null;
    const match = matchRideToTimetable({ ride: r, timetableEntries: ttMatchEntries });
    const timing = evaluateTimetableTiming({ ride: r, matchResult: match, setup, now: 0 });
    return { ride: r, driver, match, timing };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }), [dyn.rides, day, setup, ttMatchEntries]);
  // Operative Einordnung: EINMAL pro Render aus baseModels + now abgeleitet und
  // von Zaehlern, Gruppen, Filter, Sortierung und Karten gemeinsam genutzt (Spec 26).
  const viewModels = useMemo(() => baseModels.map((b) => ({
    ...b,
    op: deriveReturnRideOperationalState({ ride: b.ride, driver: b.driver, timetableMatch: b.match, timingEvaluation: b.timing, now, setup }),
  })), [baseModels, now, setup]);

  // Operative Tages-Zaehler: echte Totale, unabhaengig von Suche/Filter (Spec 16).
  const counts = {};
  RETURN_GROUPS_IN_ORDER.forEach((g) => { counts[g] = 0; });
  viewModels.forEach((vm) => { counts[vm.op.group] = (counts[vm.op.group] || 0) + 1; });

  // ---- Teilpaket E: Wartefahrt-Vorschlaege (rein lesend, gemeinsames Modell) --
  // EIN useMemo fuer Zaehler, Filter und Karten (Spec 36). Planbasiert (die
  // Bewertung nutzt `now` nicht), Abhaengigkeit dennoch auf `now` fuer den
  // Konfliktmotor (evaluateInsertion), damit die Anzeige mit dem Minuten-Tick
  // aktuell bleibt. Kein Schreibweg, keine gespeicherten Zustaende.
  const waitModel = useMemo(() => buildWaitRideCandidates({ dyn, setup, now, day }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [dyn.rides, day, setup, now]);
  const waitByReturn = waitModel.byReturn;
  const waitCounts = { wait_recommended: 0, wait_possible: 0, direct_connection: 0 };
  waitByReturn.forEach((v) => { if (v.best && waitCounts[v.best.status] != null) waitCounts[v.best.status] += 1; });
  const waitActionableTotal = waitCounts.wait_recommended + waitCounts.wait_possible + waitCounts.direct_connection;
  const hasActionableWait = (rideId) => {
    const w = waitByReturn.get(rideId);
    return !!(w && w.best && WAIT_RIDE_ACTIONABLE.has(w.best.status));
  };

  // ---- Teilpaket F2: Sammelfahrt-Vorschlaege (rein lesend) -----------------
  // Nur Rueckfahrten (fromFestival) werden hier gezeigt. Plan-basiert -> now
  // spielt keine Rolle (C3 ist reine Planbewertung). Kein Schreibweg.
  const groupModel = useMemo(() => buildGroupRidePairCandidates({
    rides: dyn.rides, drivers: setup.drivers, setup, now: 0, timetableEntries: ttMatchEntries,
  }), [dyn.rides, day, setup, ttMatchEntries]);
  const groupPrimaryByRide = useMemo(() => {
    const m = new Map();
    (groupModel.primaries || []).forEach((c) => (c.rideIds || []).forEach((id) => { if (!m.has(id)) m.set(id, c); }));
    return m;
  }, [groupModel]);
  const groupPrimaryFor = (rideId) => {
    const c = groupPrimaryByRide.get(rideId);
    return c && GROUP_RIDE_ACTIONABLE.has(c.status) ? c : null;
  };
  const groupSuggestionCount = returns.filter((r) => groupPrimaryFor(r.id)).length;

  // ---- Teilpaket G2: Rueckstellungs-Vorschlaege (rein lesend, nur Anzeige) --
  // buildRepositionSuggestions ist der einzige Einstieg (Logik unangetastet). Die
  // drei Eingaben liegen oben bereits als reine Modelle vor (D/E/F). Kein
  // Schreibweg, kein zweiter Timer (nutzt den vorhandenen now-Tick).
  const repo = useMemo(() => buildRepositionSuggestions({
    drivers: setup.drivers, dyn, setup, now, dayKey: day,
    returnRideViewModels: viewModels,
    waitRideSuggestions: [...waitByReturn.values()].map((v) => v.best).filter(Boolean),
    groupRideSuggestions: groupModel.primaries,
  }), [setup, dyn, day, now, viewModels, waitByReturn, groupModel]);

  // ---- Ansicht-Filter (rein praesentational) ----
  const matchesQ = (r) => {
    if (!q.trim()) return true;
    const hay = `${r.djName || ""} ${destName(r)} ${origName(r)} ${r.meetingPoint || ""}`.toLowerCase();
    return hay.includes(q.trim().toLowerCase());
  };
  const passesFilters = (vm) => matchesQ(vm.ride)
    && (groupFilter === "all" || vm.op.group === groupFilter)
    && (!onlyNoDriver || !vm.op.driverAssigned)
    && (!onlyWaitSuggestion || hasActionableWait(vm.ride.id))
    && (!onlyGroupSuggestion || !!groupPrimaryFor(vm.ride.id));
  const anyFilter = q.trim().length > 0 || groupFilter !== "all" || onlyNoDriver || onlyWaitSuggestion || onlyGroupSuggestion;

  // Gruppierte, sortierte Darstellung. Leere Gruppen fallen raus (Spec 15/29).
  const grouped = RETURN_GROUPS_IN_ORDER.map((g) => ({
    group: g, meta: RETURN_GROUP_META[g],
    items: viewModels.filter((vm) => vm.op.group === g && passesFilters(vm))
      .sort((a, b) => sort === "dest" ? (destName(a.ride).localeCompare(destName(b.ride)) || returnGroupSort(g, a, b)) : returnGroupSort(g, a, b)),
  })).filter((x) => x.items.length > 0);
  const shownTotal = grouped.reduce((n, x) => n + x.items.length, 0);

  // Minuten-Text fuer die Karte (Spec 14).
  const depText = (op) => {
    if (op.minutesUntilDeparture == null) return null;
    if (op.group === "overdue") return `seit ${op.minutesOverdue} min`;
    const m = op.minutesUntilDeparture;
    if (m < 0) return `Abfahrt fällig (${Math.abs(m)} min)`;
    if (m < 60) return `Abfahrt in ${m} min`;
    const h = Math.floor(m / 60), mm = m % 60;
    return mm ? `Abfahrt in ${h} Std. ${mm} min` : `Abfahrt in ${h} Std.`;
  };

  const OpTile = ({ vm }) => {
    const r = vm.ride, op = vm.op, timing = vm.timing;
    const drv = vm.driver;
    const flow = STATUS_FLOW[r.status];
    const issue = rideHasOpenIssue(r);
    const stripeKey = mcRideStatusKey(r.status, !!r.assignedDriverId);
    // Akzentstreifen richtet sich nach der operativen Gruppe (Spec 14).
    const accent = `var(--mc-st-${op.stKey})`;
    const critical = op.severity === "critical";
    return (
      <div className="mc-ride-card relative flex items-stretch overflow-hidden">
        <span className="w-1 shrink-0 self-stretch" style={{ background: accent }} aria-hidden="true" />
        <div className="flex-1 min-w-0 p-3.5">
          <div className="flex items-start justify-between gap-2">
            <div className="flex items-start gap-3 min-w-0">
              <div className="text-center shrink-0">
                <div className="font-mono text-2xl font-bold leading-none tabular-nums" style={{ color: critical ? "var(--mc-st-problem)" : "var(--mc-text)" }}>{r.time}</div>
                {depText(op) && (
                  <div className="text-[9px] uppercase tracking-wide mt-1 font-semibold leading-tight" style={{ color: `var(--mc-st-${op.stKey})` }}>{depText(op)}</div>
                )}
              </div>
              <div className="min-w-0">
                <div className="flex items-center gap-1.5 text-sm flex-wrap">
                  <span style={{ color: "var(--mc-text-muted)" }}>{origName(r)}</span>
                  <ArrowRight className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-text-muted)" }} />
                  <Moon className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-text-secondary)" }} />
                  <span className="font-semibold truncate" style={{ color: "var(--mc-text)" }}>{destName(r)}</span>
                </div>
                <div className="text-sm font-semibold truncate mt-0.5" style={{ color: "var(--mc-text)" }}>{r.djName || "—"}</div>
                <div className="text-xs inline-flex items-center gap-1 mt-0.5" style={{ color: "var(--mc-text-muted)" }}><Users className="w-3 h-3" />{r.passengerCount} Pers.</div>
              </div>
            </div>
            <span className="mc-badge shrink-0 inline-flex items-center gap-1 text-[11px] px-2 py-1 rounded-[var(--mc-r-sm)]"
              style={{ background: `var(--mc-st-${op.stKey}-soft)`, color: `var(--mc-st-${op.stKey})`, border: `1px solid color-mix(in srgb, var(--mc-st-${op.stKey}) 40%, transparent)` }}>
              {op.severity === "critical" ? <AlertTriangle className="w-3 h-3" /> : op.group === "completed" ? <CheckCircle2 className="w-3 h-3" /> : <Clock className="w-3 h-3" />}{op.label}
            </span>
          </div>
          {timing && timing.setEndAt && (
            <div className="text-xs mt-2 inline-flex items-center gap-1.5" style={{ color: "var(--mc-text-muted)" }}><Clock className="w-3.5 h-3.5" />Set-Ende {c3HM(timing.setEndAt)}</div>
          )}
          {op.secondaryInfo.map((s, i) => (
            <div key={i} className="text-xs mt-1.5 inline-flex items-center gap-1.5" style={{ color: op.requiresReview ? "var(--mc-st-problem)" : "var(--mc-st-assigned)" }}><AlertTriangle className="w-3.5 h-3.5 shrink-0" />{s}</div>
          ))}
          {r.meetingPoint && <div className="text-xs mt-2 inline-flex items-center gap-1.5" style={{ color: "var(--mc-st-assigned)" }}><MapPin className="w-3.5 h-3.5" />{r.meetingPoint}</div>}
          {issue && <div className="text-xs mt-2 inline-flex items-center gap-1" style={{ color: "var(--mc-st-problem)" }}><AlertTriangle className="w-3.5 h-3.5" />{(r.issues || []).filter(issueOpen).map((i) => i.type).join(", ")}</div>}

          {/* Teilpaket E: Wartefahrt-Vorschlag (nur unbesetzte Rueckfahrt mit
              handlungsleitender Bewertung). Rein lesend; Aktion nutzt den
              bestehenden "Fahrer zuweisen"/"Fahrt oeffnen"-Knopf unten. */}
          {(() => {
            const w = waitByReturn.get(r.id);
            if (!w || !w.best || vm.op.driverAssigned || !WAIT_RIDE_ACTIONABLE.has(w.best.status)) return null;
            const best = w.best;
            const wdrv = setup.drivers.find((d) => d.id === best.driverId) || null;
            const inb = (dyn.rides || []).find((x) => x.id === best.inboundRideId) || null;
            const col = waitSeverityColor(best.severity);
            const stk = waitSeverityStKey(best.severity);
            const arrHM = best.inboundArrivalAtFestival ? c3HM(best.inboundArrivalAtFestival) : "—";
            const multi = waitModel.multiBestDrivers.has(best.driverId);
            const alt = w.candidates.filter((c) => WAIT_RIDE_ACTIONABLE.has(c.status)).length - 1;
            return (
              <div className="mt-2.5 rounded-[var(--mc-r)] p-2.5" style={{ background: `var(--mc-st-${stk}-soft)`, border: `1px solid color-mix(in srgb, ${col} 40%, transparent)` }}>
                <div className="inline-flex items-center gap-1.5 text-xs font-semibold" style={{ color: col }}>
                  <Coffee className="w-3.5 h-3.5 shrink-0" />Wartefahrt-Vorschlag · {best.label}
                </div>
                <div className="text-xs mt-1" style={{ color: "var(--mc-text-secondary)" }}>
                  {wdrv ? `${wdrv.firstName}${wdrv.lastName ? " " + wdrv.lastName : ""}` : "Fahrer"} wäre nach Plan um {arrHM} Uhr am Festival · Wartezeit {best.waitMinutes} min
                </div>
                {inb && (
                  <div className="text-xs mt-0.5" style={{ color: "var(--mc-text-muted)" }}>Hinfahrt: {ln(inb.fromId, inb.fromCustom)} → Festival</div>
                )}
                {!best.hasRideConflict
                  ? <div className="text-xs mt-0.5 inline-flex items-center gap-1" style={{ color: "var(--mc-text-muted)" }}><Check className="w-3 h-3" style={{ color: "var(--mc-st-done)" }} />Keine Fahrtkonflikte</div>
                  : <div className="text-xs mt-0.5 inline-flex items-center gap-1" style={{ color: "var(--mc-st-assigned)" }}><AlertTriangle className="w-3 h-3" />Fahrtkonflikt prüfen</div>}
                {best.comparisonRouteReliable && best.estimatedDrivingSavedMin != null
                  ? <div className="text-xs mt-0.5" style={{ color: "var(--mc-text-muted)" }}>Geschätzt {best.estimatedDrivingSavedMin} zusätzliche Fahrminuten vermeidbar.</div>
                  : (best.warnings && best.warnings.length ? <div className="text-xs mt-0.5" style={{ color: "var(--mc-text-muted)" }}>{best.warnings[0]}</div> : null)}
                {multi && <div className="text-xs mt-0.5" style={{ color: "var(--mc-text-muted)" }}>Fahrer ist beste Option für mehrere Rückfahrten (nur eine möglich).</div>}
                {alt > 0 && <div className="text-[11px] mt-0.5" style={{ color: "var(--mc-text-muted)" }}>{alt} weitere{alt === 1 ? "r" : ""} Fahrer möglich.</div>}
              </div>
            );
          })()}

          {(() => { const gc = groupPrimaryFor(r.id); return gc ? (
            <GroupSuggestionNote candidate={gc} thisRideId={r.id} rides={dyn.rides}
              onOpenPartner={(pr) => onEdit(pr)} onOpenAssign={() => onAssign(r)} />
          ) : null; })()}

          <div className="flex items-center flex-wrap gap-2 mt-3">
            {drv ? (
              <span className="text-sm inline-flex items-center gap-1.5" style={{ color: "var(--mc-text-secondary)" }}>
                <span className="w-2.5 h-2.5 rounded-full shrink-0" style={{ background: drv.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }} />{drv.vehicleType === "Van" ? "Van" : "Car"} · {drv.firstName}
                {drv.phone && <a href={`tel:${drv.phone}`} title="Anrufen" className="hover:opacity-80" style={{ color: "var(--mc-text-muted)" }}><Navigation className="w-3.5 h-3.5 rotate-90" /></a>}
              </span>
            ) : (
              <button onClick={() => onAssign(r)} className="mc-btn-assign text-sm px-3.5 py-2 inline-flex items-center gap-1.5"><Navigation className="w-4 h-4" />Fahrer zuweisen</button>
            )}
            {drv && flow?.next && <button onClick={() => onAssign(r)} className="text-sm px-2 py-2 rounded-[var(--mc-r)] hover:bg-white/5 transition-colors" style={{ color: "var(--mc-text-secondary)" }}>umteilen</button>}
            <button onClick={() => onWhatsApp(r)} className="text-sm px-3 py-2 rounded-[var(--mc-r)] inline-flex items-center gap-1.5 transition-colors hover:opacity-90" style={{ background: "var(--mc-hover)", color: "var(--mc-text)" }}><MessageSquare className="w-4 h-4" />Text</button>
            <button onClick={() => onEdit(r)} title="Fahrt öffnen" className="mc-iconbtn ml-auto"><ChevronRight className="w-5 h-5" /></button>
          </div>
        </div>
      </div>
    );
  };

  // Kompakte Erledigt-Zeile (dezent).
  const DoneRow = ({ vm }) => {
    const r = vm.ride, drv = vm.driver;
    return (
      <div className="flex items-center gap-2 text-xs rounded-[var(--mc-r)] px-3 py-2 opacity-70" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
        <span className="font-mono tabular-nums" style={{ color: "var(--mc-text-secondary)" }}>{r.time}</span><span style={{ color: "var(--mc-text-secondary)" }}>{destName(r)}</span>
        <span className="truncate" style={{ color: "var(--mc-text-muted)" }}>{r.djName || ""}</span>
        <span className="ml-auto" style={{ color: "var(--mc-text-muted)" }}>{drv ? drv.vehicleId : ""}</span>
      </div>
    );
  };

  const summaryTiles = [
    ["needs_review", "Prüfen"], ["overdue", "Überfällig"], ["driver_missing", "Fahrer fehlt"],
    ["due_soon", "Bald fällig"], ["in_progress", "Läuft"],
  ];

  return (
    <div>
      {/* Kopf: Titel + Datum + Suche + Sort */}
      <div className="flex flex-wrap items-center gap-3 mb-4">
        <h3 className="text-base font-medium inline-flex items-center gap-2" style={{ color: "var(--mc-text)" }}><Moon className="w-5 h-5" style={{ color: "var(--mc-st-enroute)" }} />Rückfahrten · Leitstand</h3>
        <span className="text-xs" style={{ color: "var(--mc-text-muted)" }}>{fmtDate(day)}</span>
        <div className="relative flex-1 min-w-[160px] max-w-xs ml-auto">
          <Search className="w-4 h-4 absolute left-2.5 top-2.5 pointer-events-none" style={{ color: "var(--mc-text-muted)" }} />
          <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Artist, Ziel, Treffpunkt…" className="mc-input w-full pl-8 pr-8 py-2 text-sm" />
          {q && <button onClick={() => setQ("")} aria-label="Suche leeren" className="absolute right-2 top-2.5" style={{ color: "var(--mc-text-muted)" }}><X className="w-4 h-4" /></button>}
        </div>
        <div className="flex items-center gap-0.5 p-1 rounded-[var(--mc-r)]" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
          <button onClick={() => setSort("time")} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] transition-colors" style={sort === "time" ? { background: "var(--mc-hover)", color: "var(--mc-text)", fontWeight: 500 } : { color: "var(--mc-text-secondary)" }}>nach Zeit</button>
          <button onClick={() => setSort("dest")} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] transition-colors" style={sort === "dest" ? { background: "var(--mc-hover)", color: "var(--mc-text)", fontWeight: 500 } : { color: "var(--mc-text-secondary)" }}>nach Ziel</button>
        </div>
      </div>

      {/* Wer ist vor Ort: pro Artist ein Button (fehlende / geplante / keine Rueckfahrt) */}
      {presence.length > 0 && (
        <div className="mb-4">
          <div className="mc-eyebrow mb-2 inline-flex items-center gap-1.5"><MapPin className="w-3.5 h-3.5" style={{ color: "var(--mc-st-assigned)" }} />Vor Ort ({presence.length}){missing.length > 0 ? ` · ${missing.length} ohne Rückfahrt` : ""}</div>
          <div className="flex flex-wrap gap-2">
            {missing.map((p) => (
              <div key={p.name} className="flex items-center gap-0.5 rounded-[var(--mc-r)] overflow-hidden" style={{ background: "var(--mc-st-assigned-soft)", border: "1px solid color-mix(in srgb, var(--mc-st-assigned) 45%, transparent)" }}>
                <button onClick={() => onNewReturn && onNewReturn(p.name)} title="Noch keine Rückfahrt angelegt — antippen zum Anlegen"
                  className="flex items-center gap-1.5 text-xs pl-2.5 pr-2 py-1.5 hover:opacity-90" style={{ color: "var(--mc-st-assigned)" }}>
                  <AlertTriangle className="w-3.5 h-3.5 shrink-0" />{p.name}<span style={{ opacity: 0.7 }}>braucht Rückfahrt</span>
                </button>
                <button onClick={() => setNoReturn(p.name, true)} title="Braucht keine Rückfahrt — aus der offenen Liste nehmen"
                  className="px-1.5 py-1.5 text-[10px] whitespace-nowrap hover:opacity-90" style={{ color: "var(--mc-st-assigned)", borderLeft: "1px solid color-mix(in srgb, var(--mc-st-assigned) 30%, transparent)" }}>
                  keine nötig
                </button>
              </div>
            ))}
            {covered.map((p) => (
              <button key={p.name} onClick={() => onEdit && onEdit(p.pendingReturn)} title="Rückfahrt bereits geplant — antippen zum Öffnen"
                className="flex items-center gap-1.5 text-xs px-2.5 py-1.5 rounded-[var(--mc-r)] hover:opacity-90" style={{ background: "var(--mc-panel)", border: "1px solid var(--mc-border)", color: "var(--mc-text-secondary)" }}>
                <CheckCircle2 className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-st-done)" }} />{p.name}<span style={{ color: "var(--mc-text-muted)" }}>{p.pendingReturn.time}</span>
              </button>
            ))}
            {noReturnList.map((p) => (
              <div key={p.name} className="flex items-center gap-0.5 rounded-[var(--mc-r)] overflow-hidden opacity-60" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
                <span className="flex items-center gap-1.5 text-xs pl-2.5 pr-2 py-1.5 line-through" style={{ color: "var(--mc-text-muted)" }}>{p.name}</span>
                <span className="text-[10px] pr-1.5" style={{ color: "var(--mc-text-muted)" }}>keine Rückfahrt</span>
                <button onClick={() => setNoReturn(p.name, false)} title="Doch wieder als braucht Rückfahrt aufnehmen"
                  className="px-1.5 py-1.5 hover:opacity-90" style={{ color: "var(--mc-text-secondary)", borderLeft: "1px solid var(--mc-border)" }}><RefreshCw className="w-3 h-3" /></button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Praesenz-Verwaltung (gemeinsame Komponente, unveraendert wiederverwendet) */}
      <PresenceManager
        presence={presence} manualOnly={manualOnly}
        onSetManual={setManualPresence} onAdd={addManualArtist} onSetNoReturn={setNoReturn} />

      {/* Teilpaket D: operative Zaehler (echte Tages-Totale). Klick filtert die Gruppe. */}
      <div className="grid grid-cols-3 sm:grid-cols-5 gap-2 mb-3">
        {summaryTiles.map(([g, l]) => {
          const meta = RETURN_GROUP_META[g];
          const v = counts[g] || 0;
          const activeSel = groupFilter === g;
          return (
            <button key={g} onClick={() => setGroupFilter(activeSel ? "all" : g)}
              className="rounded-[var(--mc-r)] px-3 py-2.5 text-center transition-colors"
              style={{ background: activeSel ? `var(--mc-st-${meta.stKey}-soft)` : "var(--mc-panel)", border: `1px solid ${activeSel ? `var(--mc-st-${meta.stKey})` : "var(--mc-border)"}` }}
              title={activeSel ? "Filter aufheben" : `Nur ${l} zeigen`}>
              <div className="text-2xl font-bold font-mono tabular-nums" style={{ color: v > 0 ? `var(--mc-st-${meta.stKey})` : "var(--mc-text)" }}><MissionCount value={v} /></div>
              <div className="text-[10px] uppercase tracking-wide" style={{ color: "var(--mc-text-muted)" }}>{l}</div>
            </button>
          );
        })}
      </div>

      {/* Teilpaket D: Gruppenfilter (operative Prioritaet) + nur ohne Fahrer */}
      <div className="flex flex-wrap items-center gap-1.5 mb-4">
        <button onClick={() => setGroupFilter("all")} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] transition-colors"
          style={groupFilter === "all" ? { background: "var(--mc-hover)", color: "var(--mc-text)", fontWeight: 500, border: "1px solid var(--mc-border)" } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>Alle</button>
        {RETURN_GROUPS_IN_ORDER.map((g) => {
          const meta = RETURN_GROUP_META[g];
          const sel = groupFilter === g;
          return (
            <button key={g} onClick={() => setGroupFilter(sel ? "all" : g)} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1 transition-colors"
              style={sel ? { background: `var(--mc-st-${meta.stKey}-soft)`, color: `var(--mc-st-${meta.stKey})`, fontWeight: 500, border: `1px solid var(--mc-st-${meta.stKey})` } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
              <span className="w-1.5 h-1.5 rounded-full" style={{ background: `var(--mc-st-${meta.stKey})` }} />{meta.label}{counts[g] ? ` ${counts[g]}` : ""}
            </button>
          );
        })}
        <button onClick={() => setOnlyNoDriver((v) => !v)} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1 transition-colors ml-1"
          style={onlyNoDriver ? { background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)", fontWeight: 500, border: "1px solid var(--mc-st-assigned)" } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
          <Navigation className="w-3 h-3" />nur ohne Fahrer
        </button>
        {/* Teilpaket E: Filter auf Rueckfahrten mit handlungsleitendem Wartevorschlag */}
        {waitActionableTotal > 0 && (
          <button onClick={() => setOnlyWaitSuggestion((v) => !v)} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1 transition-colors"
            style={onlyWaitSuggestion ? { background: "var(--mc-st-done-soft)", color: "var(--mc-st-done)", fontWeight: 500, border: "1px solid var(--mc-st-done)" } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
            <Coffee className="w-3 h-3" />nur mit Wartevorschlag {waitActionableTotal}
          </button>
        )}
        {groupSuggestionCount > 0 && (
          <button onClick={() => setOnlyGroupSuggestion((v) => !v)} className="text-xs px-2.5 py-1 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1 transition-colors"
            style={onlyGroupSuggestion ? { background: "var(--mc-st-new-soft)", color: "var(--mc-st-new)", fontWeight: 500, border: "1px solid var(--mc-st-new)" } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
            <Users className="w-3 h-3" />nur mit Sammelfahrt {groupSuggestionCount}
          </button>
        )}
      </div>

      {returns.length === 0 && (
        <EmptyState icon={Moon} title="Keine Rückfahrten für diesen Betriebstag vorhanden."
          hint="Rückfahrten entstehen aus Fahrten vom Festival weg oder über „braucht Rückfahrt“ oben." />
      )}

      {returns.length > 0 && anyFilter && shownTotal === 0 && (
        <EmptyState icon={Search} title="Keine Rückfahrten entsprechen den aktuellen Filtern."
          action={<button onClick={() => { setQ(""); setGroupFilter("all"); setOnlyNoDriver(false); setOnlyWaitSuggestion(false); setOnlyGroupSuggestion(false); }} className="text-xs px-3 py-1.5 rounded-[var(--mc-r)]" style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>Filter zurücksetzen</button>} />
      )}

      {returns.length > 0 && !(anyFilter && shownTotal === 0) && (
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
        <div className="xl:col-span-2 space-y-4">
          {grouped.map(({ group, meta, items }) => (
            group === "completed" ? (
              <details key={group} className="group">
                <summary className="mc-eyebrow cursor-pointer mb-2 inline-flex items-center gap-1.5"><CheckCircle2 className="w-3.5 h-3.5" style={{ color: "var(--mc-st-done)" }} />{meta.label} ({items.length})</summary>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-2 mt-2">{items.map((vm) => <DoneRow key={vm.ride.id} vm={vm} />)}</div>
              </details>
            ) : (
              <div key={group}>
                <div className="mc-eyebrow mb-2 inline-flex items-center gap-1.5" style={{ color: `var(--mc-st-${meta.stKey})` }}>
                  <span className="w-2 h-2 rounded-full" style={{ background: `var(--mc-st-${meta.stKey})` }} />{meta.label} ({items.length})
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">{items.map((vm) => <OpTile key={vm.ride.id} vm={vm} />)}</div>
              </div>
            )
          ))}
        </div>

        {/* Fahrer am Festival / frei + Live-Karte */}
        <div className="space-y-3">
          <div className="rounded-[var(--mc-r-lg)] p-3" style={{ background: "var(--mc-panel)", border: "1px solid var(--mc-border)" }}>
            <div className="mc-eyebrow mb-2 inline-flex items-center gap-1.5"><MapPin className="w-3.5 h-3.5" style={{ color: "var(--mc-st-assigned)" }} />Am Festival / frei ({atFestival.length})</div>
            <div className="space-y-1 max-h-[16rem] overflow-y-auto">
              {atFestival.map(({ d, s }) => (
                <div key={d.id} className="flex items-center gap-2 text-sm rounded-[var(--mc-r)] px-2.5 py-2" style={{ background: "var(--mc-inset)" }}>
                  <span className="w-2 h-2 rounded-full shrink-0" style={{ background: "var(--mc-st-done)" }} />
                  <span className="font-mono text-xs" style={{ color: "var(--mc-text-secondary)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
                  <span className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{d.firstName} {d.lastName[0]}.</span>
                  {(() => { const g = repo.byDriver[d.id];
                    return g && REPOSITION_ACTIONABLE.has(g.status)
                      ? <span className={`mc-badge text-[10px] shrink-0 ${g.status === "direct_to_next_pickup" ? "mc-badge--new" : "mc-badge--assigned"}`} title={g.label}>{g.label}</span>
                      : null; })()}
                  <span className="ml-auto text-xs" style={{ color: "var(--mc-text-muted)" }}>{s.count}×</span>
                  {d.phone && <a href={`tel:${d.phone}`} title="Anrufen" className="shrink-0 hover:opacity-80" style={{ color: "var(--mc-text-muted)" }}><Navigation className="w-3.5 h-3.5 rotate-90" /></a>}
                </div>
              ))}
              {atFestival.length === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>niemand frei am Festival</div>}
            </div>
          </div>

          <BoardMiniMap setup={setup} dyn={dyn} day={day} onEdit={onEdit} />
        </div>
      </div>
      )}

      {/* Timeline — wer wann besetzt ist, volle Breite (gemeinsame Komponente) */}
      <TimelineView setup={setup} dyn={dyn} day={day} onEdit={onEdit} />
    </div>
  );
}

/* -------------------------- Flughafen-Modul (Punkt 4/7) ------------------- */
function FlightTab({ setup, dyn, day, updateDyn, by, onErr, onEdit }) {
  const [busy, setBusy] = useState(null); // rideId | "all"
  const [note, setNote] = useState(null);
  const rides = (dyn.rides || [])
    .filter((r) => r.dayKey === day && r.status !== "cancelled" && (r.fromId === "airport" || r.flightNo))
    .sort((a, b) => sortMin(a.scheduledArrival || a.time) - sortMin(b.scheduledArrival || b.time));

  // Gibt das Schreibergebnis ({ok,...}) zurueck, damit updateOne/updateAll die
  // "aktualisiert"-Notiz nur bei echtem Erfolg zeigen bzw. Fehlschlaege zaehlen
  // koennen (statt still "aktualisiert" zu melden, obwohl das Speichern scheiterte).
  const applyResult = async (rideId, res) => {
    // before aus dem gerenderten Stand festhalten: nach dem Save laesst sich der
    // Vorher-Status nicht mehr aus dem Ergebnis lesen. Dient nur dem Push-Vergleich.
    const before = (dyn.rides || []).find((x) => x.id === rideId)?.flightStatus;
    const wr = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === rideId);
      if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt gibt es nicht mehr.");
      // manuelle Werte nicht ueberschreiben -> echter No-op (idempotent, KEIN
      // Fehler): frueher schrieb dieser Pfad still rev+1, obwohl nichts geaendert
      // wurde. Ein Auto-Update auf eine manuell gepflegte Fahrt ist bewusst wirkungslos.
      if (r.manualOverride) return NO_CHANGE;
      const beforeIn = r.flightStatus;
      r.airline = res.airline || r.airline;
      r.terminal = res.terminal || r.terminal;
      r.scheduledArrival = res.scheduledArrival || r.scheduledArrival;
      r.estimatedArrival = res.estimatedArrival || r.estimatedArrival;
      r.actualArrival = res.actualArrival || r.actualArrival;
      r.flightStatus = res.flightStatus || r.flightStatus;
      r.delayMinutes = res.delayMinutes ?? r.delayMinutes ?? 0;
      r.lastFlightUpdate = Date.now();
      r.lastFlightCheck = Date.now(); // für die Abfrage-Abklingzeit, unabhängig davon ob sich der Status geändert hat
      r.flightUpdateSource = res.source || FLIGHT_PROVIDER;
      if (beforeIn !== r.flightStatus) logRide(r, "flight", "auto", `Flug: ${flightStyle(r.flightStatus).l}`);
      return d;
    });
    // Push erst NACH bestaetigtem Save, nie im Mutator (CAS-Retry wuerde ihn
    // mehrfach ausloesen). Statuswechsel aus dem bestaetigten Stand ableiten.
    if (wr && wr.ok) {
      const saved = (wr.value.rides || []).find((x) => x.id === rideId);
      if (saved && before !== saved.flightStatus) {
        if (saved.assignedDriverId && ["verspätet", "gelandet", "annulliert"].includes(saved.flightStatus)) {
          triggerPush(saved.assignedDriverId, `Flug jetzt ${flightStyle(saved.flightStatus).l}`, `${saved.flightNo || ""} · ${saved.djName || "Fahrt"}`, `ride-${saved.id}`);
        }
        if (needsDispatcherFlightAlert(saved)) {
          triggerDispatcherPush(`Flug kritisch: ${flightAlert(saved).label}`, `${saved.flightNo || ""} · ${saved.djName || "Fahrt"}`, `ride-${saved.id}`);
        }
      }
    }
    return wr;
  };

  const updateOne = async (r, force) => {
    if (r.manualOverride) { setNote({ id: r.id, ok: false, text: "manuell überschrieben – Auto übersprungen" }); return; }
    if (!force && flightRefreshOnCooldown(r)) {
      setNote({ id: r.id, ok: true, cooldown: true, text: `vor ${FLIGHT_REFRESH_COOLDOWN_MIN - flightCooldownRemainingMin(r)} Min. abgefragt · noch ${flightCooldownRemainingMin(r)} Min.` });
      return;
    }
    setBusy(r.id); setNote(null);
    const res = await getFlightStatus(r.flightNo, r.dayKey);
    setBusy(null);
    if (!res.ok) { setNote({ id: r.id, ok: false, text: res.error }); return; }
    const wr = await applyResult(r.id, res);
    if (wr && wr.ok) setNote({ id: r.id, ok: true, text: "aktualisiert" });
    else setNote({ id: r.id, ok: false, text: (wr && wr.error) || "Speichern fehlgeschlagen, bitte erneut versuchen" });
  };
  const updateAll = async () => {
    setBusy("all"); setNote(null);
    const due = rides.filter((x) => x.flightNo && !x.manualOverride && !flightRefreshOnCooldown(x));
    const onCooldown = rides.filter((x) => x.flightNo && !x.manualOverride && flightRefreshOnCooldown(x)).length;
    let ok = 0, fail = 0;
    for (const r of due) {
      const res = await getFlightStatus(r.flightNo, r.dayKey);
      if (!res.ok) { fail++; continue; }
      const wr = await applyResult(r.id, res);
      if (wr && wr.ok) ok++; else fail++;
    }
    setBusy(null);
    const skipNote = onCooldown > 0 ? ` · ${onCooldown} noch frisch übersprungen` : "";
    setNote({ id: "all", ok: ok > 0 || (due.length === 0 && onCooldown > 0), text: due.length === 0 ? `Alle Flüge noch frisch (Abklingzeit ${FLIGHT_REFRESH_COOLDOWN_MIN} Min.), nichts abgefragt` : (ok > 0 ? `${ok} aktualisiert${skipNote}` : `Automatik nicht verfügbar – bitte manuell pflegen${skipNote}`) });
  };

  // schnelle manuelle Korrektur
  const quickSet = async (rideId, patch) => {
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === rideId);
      if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
      Object.assign(r, patch);
      r.manualOverride = true; r.flightUpdateSource = "manuell"; r.lastFlightUpdate = Date.now();
      if (patch.flightStatus !== undefined) logRide(r, "flight", by, `Flug: ${flightStyle(patch.flightStatus).l}`);
      if (r.scheduledArrival && (r.actualArrival || r.estimatedArrival)) r.delayMinutes = Math.max(0, sortMin(r.actualArrival || r.estimatedArrival) - sortMin(r.scheduledArrival));
      return d;
    });
    if (!res || !res.ok) { if (onErr) onErr(res?.error || "Flug-Korrektur konnte nicht gespeichert werden, bitte erneut versuchen."); return; }
    // Push erst NACH bestaetigtem Save (nie im Mutator). Nur wenn ein flightStatus
    // gesetzt wurde und der bestaetigte Stand kritisch ist.
    if (patch.flightStatus !== undefined) {
      const saved = (res.value.rides || []).find((x) => x.id === rideId);
      if (saved) {
        if (saved.assignedDriverId && ["verspätet", "gelandet", "annulliert"].includes(saved.flightStatus)) {
          triggerPush(saved.assignedDriverId, `Flug jetzt ${flightStyle(saved.flightStatus).l}`, `${saved.flightNo || ""} · ${saved.djName || "Fahrt"}`, `ride-${saved.id}`);
        }
        if (needsDispatcherFlightAlert(saved)) {
          triggerDispatcherPush(`Flug kritisch: ${flightAlert(saved).label}`, `${saved.flightNo || ""} · ${saved.djName || "Fahrt"}`, `ride-${saved.id}`);
        }
      }
    }
  };

  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";

  return (
    <div className="mc-scope space-y-3">
      <div className="flex flex-wrap items-center gap-3">
        <h3 className="text-sm flex items-center gap-2" style={{ color: "var(--mc-text-secondary)" }}><Plane className="w-4 h-4" />Flughafen-Pickups · {fmtDate(day)}</h3>
        <button onClick={updateAll} disabled={busy === "all"} className="mc-btn-primary text-xs px-2.5 py-1.5 flex items-center gap-1.5 disabled:opacity-40">
          <RefreshCw className={`w-3.5 h-3.5 ${busy === "all" ? "animate-spin" : ""}`} />Alle Flüge aktualisieren
        </button>
        {note && note.id === "all" && <span className="text-xs" style={{ color: note.ok ? "var(--mc-st-done)" : "var(--mc-st-assigned)" }}>{note.text}</span>}
        <span className="text-[11px] ml-auto" style={{ color: "var(--mc-text-muted)" }}>Provider: {FLIGHT_PROVIDER} · Live-Abruf nur im Deployment; manuelle Pflege immer möglich.</span>
      </div>

      {rides.length === 0 && (
        <MissionPanel padded>
          <EmptyState icon={Plane} title="Keine Flughafen-Abholungen an diesem Tag."
            hint="Hier stehen nur Fahrten ab Flughafen oder mit hinterlegter Flugnummer." />
        </MissionPanel>
      )}

      <div className="space-y-1.5">
        {rides.map((r) => {
          const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
          const al = flightAlert(r);
          const alTone = al.level === "critical" ? "problem" : al.level === "warn" ? "assigned" : null;
          return (
            <div key={r.id} className="mc-ride-card px-3 py-2.5" style={ALERT_ROW[al.level]}>
              <div className="flex items-center flex-wrap gap-x-3 gap-y-1.5">
                <div className="flex items-center gap-2 w-40 shrink-0">
                  <Plane className="w-4 h-4 shrink-0" style={{ color: "var(--mc-st-new)" }} />
                  <div>
                    <div className="text-sm" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text)" }}>{r.flightNo || "—"}</div>
                    <div className="text-[10px]" style={{ color: "var(--mc-text-muted)" }}>{r.airline || "Airline ?"}</div>
                  </div>
                </div>

                <div className="text-xs w-24 shrink-0" style={{ color: "var(--mc-text-muted)" }}>
                  <div>Plan: <span style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-secondary)" }}>{r.scheduledArrival || "—"}</span></div>
                  <div>Live: <span style={{ fontFamily: "var(--mc-font-mono)", color: alTone ? `var(--mc-st-${alTone})` : "var(--mc-text)", fontWeight: alTone ? 600 : 400 }}>{r.actualArrival || r.estimatedArrival || "—"}</span></div>
                </div>

                {/* schnelle Korrektur */}
                <input type="time" value={r.actualArrival || ""} onChange={(e) => quickSet(r.id, { actualArrival: e.target.value })}
                  title="Echte Ankunft" className="mc-input w-24 px-2 py-1 text-xs" style={{ fontFamily: "var(--mc-font-mono)" }} />
                <input value={r.terminal || ""} onChange={(e) => quickSet(r.id, { terminal: e.target.value })} placeholder="Terminal"
                  className="mc-input w-24 px-2 py-1 text-xs" />
                <select value={r.flightStatus || ""} onChange={(e) => quickSet(r.id, { flightStatus: e.target.value })}
                  className="w-28 px-2 py-1 text-xs" style={{ border: "none", borderRadius: "var(--mc-r-sm)", fontWeight: 500, ...mcFlightStyle(r.flightStatus) }}>
                  {FLIGHT_STATUS.map((s) => <option key={s.k} value={s.k} style={{ background: "var(--mc-panel-raised)", color: "var(--mc-text)", fontWeight: 400 }}>{s.k === "" ? "unbekannt" : s.l}</option>)}
                </select>

                <div className="text-xs w-28 shrink-0">
                  <div className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{drv ? `${drv.vehicleType === "Van" ? "Van" : "Car"} · ${drv.firstName}` : <span style={{ color: "var(--mc-st-problem)", fontWeight: 500 }}>kein Fahrer</span>}</div>
                  <div className="text-[10px]" style={{ color: "var(--mc-text-muted)" }}>Pickup {r.time}</div>
                </div>

                <div className="ml-auto flex items-center gap-2 shrink-0">
                  {r.manualOverride && <span className="mc-badge mc-badge--assigned" title="manuell gepflegt, Auto-Update übersprungen">manuell</span>}
                  {note && note.id === r.id && <span className="text-[11px]" style={{ color: note.ok ? "var(--mc-st-done)" : "var(--mc-st-assigned)" }}>{note.text}</span>}
                  {/* bewusst kein IconButton: der reicht keine Klasse ans Icon durch,
                      das Rad soll beim Abfragen aber weiter drehen. Gleiche Klasse. */}
                  <button onClick={() => updateOne(r, note && note.id === r.id && note.cooldown)} disabled={busy === r.id}
                    title="Flugstatus aktualisieren" aria-label="Flugstatus aktualisieren" className="mc-iconbtn">
                    <RefreshCw className={`w-[18px] h-[18px] ${busy === r.id ? "animate-spin" : ""}`} />
                  </button>
                  {r.manualOverride && <button onClick={() => quickSet(r.id, { manualOverride: false })} title="Auto-Update wieder erlauben" className="mc-btn-quiet text-[10px] px-2 py-1">auto</button>}
                  <IconButton icon={ChevronRight} label="Fahrt öffnen" onClick={() => onEdit(r)} />
                </div>
              </div>
              {al.level !== "none" && al.label && (
                <div className="text-[11px] mt-1 flex items-center gap-1.5" style={{ color: alTone ? `var(--mc-st-${alTone})` : "var(--mc-text-muted)" }}>
                  {alTone && <AlertTriangle className="w-3 h-3" />}{al.label}
                  {r.lastFlightUpdate && <span className="ml-2" style={{ color: "var(--mc-text-muted)" }}>· Stand {fmtClock(r.lastFlightUpdate)} ({r.flightUpdateSource})</span>}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* -------------------------- Notfallmodus (Punkt 6) ----------------------- */
// Ermittelt akute Fälle: kritische/offene Probleme, Flug gelandet ohne Fahrer,
// annulliert, kurzfristig ohne Fahrer, Fahrer nicht gestartet (Artist wartet).
function emergencyCases(setup, dyn, day) {
  const now = dayNowMin(day);
  const live = now >= 0 && now < 90000;
  const cases = [];
  const rides = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled" && r.status !== "done");
  rides.forEach((r) => {
    const issues = (r.issues || []).filter(issueOpen);
    const critIssue = issues.find((i) => CRITICAL_ISSUES.includes(i.type));
    if (critIssue) cases.push({ r, sev: "critical", type: "issue", label: critIssue.type + (critIssue.note ? `: ${critIssue.note}` : "") });
    else if (issues.length) cases.push({ r, sev: "warn", type: "issue", label: issues.map((i) => i.type).join(", ") });

    const al = flightAlert(r);
    if (al.level === "critical") cases.push({ r, sev: "critical", type: "flight", label: al.label });

    if (live && !r.assignedDriverId) {
      const dt = sortMin(r.time) - now;
      if (dt <= 45 && dt > -120) cases.push({ r, sev: dt <= 15 ? "critical" : "warn", type: "nodriver", label: dt <= 0 ? "ohne Fahrer · Start überfällig" : `ohne Fahrer · Start in ${dt} min` });
    }
    if (live && r.assignedDriverId && ["planned", "accepted"].includes(r.status)) {
      const over = now - sortMin(r.time);
      if (over >= 5) cases.push({ r, sev: over >= 20 ? "critical" : "warn", type: "waiting", label: `Fahrer nicht gestartet · ${over} min über Zeit` });
    }
  });
  return cases.sort((a, b) => (a.sev !== b.sev ? (a.sev === "critical" ? -1 : 1) : sortMin(a.r.time) - sortMin(b.r.time)));
}
const CASE_ICON = { issue: AlertTriangle, flight: Plane, nodriver: Navigation, waiting: Clock };

// MC-Kopie von EmergencyTab (Tab "Probleme" im Mission-Control-Modus). Etappe A:
// byte-genaue Kopie, nur Funktionsname geaendert. Classic EmergencyTab bleibt
// unangetastet. Render + Filter + Ladezustand folgen in Etappe B.
function MissionEmergencyTab({ setup, dyn, day, updateDyn, by, onErr, onAssign, onWhatsApp, onEdit }) {
  const cases = emergencyCases(setup, dyn, day);
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const freeDrivers = setup.drivers
    .map((d) => ({ d, s: computeDriverStats(setup, dyn, d.id, day) }))
    .filter((x) => !x.s.active)
    .sort((a, b) => a.s.drivingMin - b.s.drivingMin);
  const shiftable = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled" && r.status !== "done" && r.onDemand);

  // NEU (nur UI-Feedback): welche Fahrt gerade als erledigt gespeichert wird.
  const [resolving, setResolving] = useState(null);
  // NEU (nur Anzeige): Prioritaets-Filter. Aendert die cases/Logik NICHT, filtert
  // nur, was angezeigt wird.
  const [filter, setFilter] = useState("all"); // all | critical | warn

  // Effekt 4 (rein lesend, KEIN Schreibweg): neu gemeldete Probleme pulsieren
  // genau einmal kurz rot. seenIssueIdsRef haelt die bereits gesehenen offenen
  // issue-IDs. Beim ersten Lauf wird nur geseedet (kein Puls beim Laden). Danach
  // loest jede neue offene issue-ID einen einmaligen roten Puls auf der
  // zugehoerigen Fahrt-Karte aus. Muster gespiegelt vom Board-Flash (Shell).
  // Dependency ist eine stabile issue-ID-Signatur, damit das 3s-Polling ohne
  // echte Aenderung nichts ausloest. Kein Dauerblinken (iteration 1 im CSS).
  const seenIssueIdsRef = useRef(null);
  const [pulseIds, setPulseIds] = useState({});
  const issueSig = cases
    .filter((c) => c.type === "issue")
    .flatMap((c) => (c.r.issues || []).filter(issueOpen).map((iss) => iss.id))
    .sort()
    .join(",");
  useEffect(() => {
    const prev = seenIssueIdsRef.current;
    const seen = {};
    const freshRideIds = [];
    cases.forEach((c) => {
      if (c.type !== "issue") return;
      (c.r.issues || []).filter(issueOpen).forEach((iss) => {
        seen[iss.id] = true;
        if (prev && !prev[iss.id]) freshRideIds.push(c.r.id);
      });
    });
    seenIssueIdsRef.current = seen;
    if (prev == null || !freshRideIds.length) return;
    const uniq = [...new Set(freshRideIds)];
    setPulseIds((f) => { const n = { ...f }; uniq.forEach((id) => { n[id] = (n[id] || 0) + 1; }); return n; });
    const timers = uniq.map((id) => setTimeout(() => setPulseIds((f) => {
      const n = { ...f }; if (n[id] > 1) n[id] -= 1; else delete n[id]; return n;
    }), 1400));
    return () => timers.forEach(clearTimeout);
  }, [issueSig]);

  const resolveIssues = async (rideId) => {
    if (resolving) return;
    setResolving(rideId);
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === rideId);
      if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
      const offen = (r.issues || []).filter(issueOpen);
      // Bereits von jemand anderem erledigt -> echter No-op (idempotent, kein
      // Fehler, kein rev+1, kein Log-Eintrag doppelt).
      if (offen.length === 0) return NO_CHANGE;
      offen.forEach((i) => { i.state = "done"; });
      logRide(r, "problem_done", by);
      return d;
    });
    setResolving(null);
    if ((!res || !res.ok) && onErr) onErr(res?.error || "Problem konnte nicht als erledigt gespeichert werden, bitte erneut versuchen.");
  };

  const critCount = cases.filter((c) => c.sev === "critical").length;
  const warnCount = cases.length - critCount;
  const shown = filter === "all" ? cases : cases.filter((c) => c.sev === filter);
  const typeMeta = { issue: "Problem", flight: "Flug", nodriver: "Ohne Fahrer", waiting: "Wartet" };

  const secBtn = "text-sm px-3 py-2 rounded-lg inline-flex items-center gap-1.5 transition";
  const secStyle = { background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" };

  return (
    <div className="mc-scope space-y-3">
      {/* Kopf: Lage + Filter nach Prioritaet */}
      <div className="flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg"
          style={critCount
            ? { background: "var(--mc-st-problem-soft)", color: "var(--mc-st-problem)" }
            : { background: "var(--mc-inset)", color: "var(--mc-text-secondary)" }}>
          <Siren className="w-5 h-5" style={{ color: critCount ? "var(--mc-st-problem)" : "var(--mc-text-muted)" }} />
          <span className="font-medium text-sm">{cases.length === 0 ? "Keine akuten Notfälle" : `${cases.length} Fall${cases.length > 1 ? "e" : ""}`}{critCount ? ` · ${critCount} kritisch` : ""}</span>
        </div>
        <span className="text-xs" style={{ color: "var(--mc-text-muted)" }}>{fmtDate(day)}</span>
        {cases.length > 0 && (
          <div className="inline-flex items-center gap-0.5 rounded-lg p-0.5 ml-auto"
            style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
            {[["all", `Alle (${cases.length})`, "assigned"], ["critical", `Kritisch (${critCount})`, "problem"], ["warn", `Warnung (${warnCount})`, "assigned"]].map(([k, l, tok]) => (
              <button key={k} onClick={() => setFilter(k)}
                className="text-xs px-3 py-1.5 rounded-md transition"
                style={filter === k
                  ? { background: `var(--mc-st-${tok}-soft)`, color: `var(--mc-st-${tok})`, fontWeight: 600 }
                  : { color: "var(--mc-text-secondary)" }}>{l}</button>
            ))}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
        {/* Fälle */}
        <div className="xl:col-span-2 space-y-2.5">
          {cases.length === 0 ? (
            <MissionPanel padded>
              <EmptyState icon={CheckCircle2} title="Aktuell alles im grünen Bereich."
                hint="Probleme, gelandete Flüge ohne Fahrer oder überfällige Fahrten erscheinen hier automatisch." />
            </MissionPanel>
          ) : shown.length === 0 ? (
            <MissionPanel padded>
              <EmptyState icon={CheckCircle2} title="Keine Fälle in dieser Ansicht."
                hint="Der Prioritäts-Filter blendet die anderen Fälle gerade aus."
                action={<button onClick={() => setFilter("all")} className={secBtn} style={secStyle}>Alle anzeigen</button>} />
            </MissionPanel>
          ) : (
            shown.map((c, i) => {
              const r = c.r;
              const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
              const Icon = CASE_ICON[c.type] || AlertTriangle;
              const sugg = suggestDrivers(setup, dyn, r).slice(0, 3);
              const crit = c.sev === "critical";
              const key = crit ? "problem" : "assigned";
              const busy = resolving === r.id;
              return (
                <div key={i} className={"mc-ride-card" + (c.type === "issue" && pulseIds[r.id] ? " mc-flash-problem" : "")}
                  style={{ padding: "14px", borderLeft: `3px solid var(--mc-st-${key})` }}>
                  <div className="flex items-start gap-3">
                    <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0"
                      style={{ background: `var(--mc-st-${key}-soft)`, color: `var(--mc-st-${key})` }}><Icon className="w-5 h-5" /></div>
                    <div className="min-w-0 flex-1">
                      {/* Prioritaet + Art + Fahrt-Zuordnung */}
                      <div className="flex items-center gap-2 flex-wrap">
                        <StatusBadge status={key} label={crit ? "Kritisch" : "Warnung"} />
                        <span className="text-[10px] font-medium px-1.5 py-0.5 rounded"
                          style={{ background: "var(--mc-inset)", color: "var(--mc-text-secondary)" }}>{typeMeta[c.type] || "Fall"}</span>
                      </div>
                      <div className="flex items-center gap-2 flex-wrap mt-1.5">
                        <span className="font-mono text-lg font-semibold" style={{ color: "var(--mc-text)" }}>{r.time}</span>
                        <span className="text-sm" style={{ color: "var(--mc-text-secondary)" }}>{ln(r.fromId, r.fromCustom)} → {ln(r.toId, r.toCustom)}</span>
                        {r.zone && <ZoneChip zone={r.zone} />}
                        <span className="text-xs inline-flex items-center gap-1" style={{ color: "var(--mc-text-muted)" }}><Users className="w-3 h-3" />{r.passengerCount}</span>
                      </div>
                      {r.djName && <div className="text-sm font-semibold truncate mt-0.5" style={{ color: "var(--mc-st-assigned)" }}>{r.djName}</div>}
                      <div className="text-sm mt-0.5 font-medium" style={{ color: `var(--mc-st-${key})` }}>{c.label}</div>
                      <div className="text-xs mt-0.5" style={{ color: "var(--mc-text-muted)" }}>
                        {drv ? `Fahrer: ${drv.firstName} ${drv.lastName} (${drv.vehicleType === "Van" ? "Van" : "Car"})${drv.phone ? " · " + drv.phone : ""}` : "kein Fahrer zugeteilt"}
                      </div>

                      {/* nächste passende Fahrer */}
                      {sugg.length > 0 && (
                        <div className="mt-2 text-xs">
                          <span style={{ color: "var(--mc-text-muted)" }}>
                            {sugg.some((x) => x.emergencySpringer) ? "Kein regulärer Fahrer – Springer: " : "Passende Fahrer: "}
                          </span>
                          {sugg.map((x, k) => (
                            <span key={x.driver.id} className="inline-flex items-center gap-1 mr-2"
                              style={{ color: x.feasible ? "var(--mc-st-done)" : "var(--mc-st-assigned)" }}>
                              {x.driver.vehicleType === "Van" ? "Van" : "Car"} {x.driver.firstName}{x.emergencySpringer ? " (Springer)" : ""}{x.teamLabel ? ` [${x.teamLabel}]` : ""}{x.deadKnown ? ` (${x.deadMin}′)` : ""}{k < sugg.length - 1 ? "," : ""}
                            </span>
                          ))}
                        </div>
                      )}

                      {/* große Aktions-Buttons */}
                      <div className="flex flex-wrap gap-2 mt-3">
                        <button onClick={() => onAssign(r)} className="mc-btn-assign text-sm px-3 py-2 inline-flex items-center gap-1.5">
                          <Navigation className="w-4 h-4" />{drv ? "Ersatzfahrer suchen" : "Fahrer zuweisen"}
                        </button>
                        {drv && drv.phone && <a href={`tel:${drv.phone}`} className={secBtn} style={secStyle}><Navigation className="w-4 h-4 rotate-90" />Fahrer anrufen</a>}
                        <button onClick={() => onWhatsApp(r)} className={secBtn} style={secStyle}><MessageSquare className="w-4 h-4" />WhatsApp-Text</button>
                        {c.type === "issue" && (
                          <button onClick={() => resolveIssues(r.id)} disabled={busy} className={secBtn + " disabled:opacity-60"}
                            style={{ background: "var(--mc-st-done-soft)", color: "var(--mc-st-done)", border: "1px solid var(--mc-st-done)" }}>
                            {busy ? <RefreshCw className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}{busy ? "wird gespeichert" : "Problem erledigt"}
                          </button>
                        )}
                        <button onClick={() => onEdit(r)} className="text-sm px-2 py-2 transition" style={{ color: "var(--mc-text-secondary)" }}>Fahrt öffnen</button>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* rechte Spalte: freie Fahrer + verschiebbare Fahrten */}
        <div className="space-y-3">
          <MissionPanel icon={CheckCircle2} title={`Freie Fahrer jetzt (${freeDrivers.length})`}>
            <div className="space-y-1 max-h-72 overflow-y-auto">
              {freeDrivers.map(({ d, s }) => {
                const loc = setup.locations.find((l) => l.id === s.locNow);
                return (
                  <div key={d.id} className="flex items-center gap-2 text-xs rounded px-2 py-1.5" style={{ background: "var(--mc-inset)" }}>
                    <span className="w-2 h-2 rounded-full shrink-0" style={{ background: "var(--mc-st-done)" }} />
                    <span style={{ color: "var(--mc-text-secondary)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
                    <span className="truncate" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName[0]}.</span>
                    <span className="ml-auto truncate" style={{ color: "var(--mc-text-muted)" }}>{loc ? loc.short : "—"} · {s.count}×</span>
                    {d.phone && <a href={`tel:${d.phone}`} className="shrink-0" style={{ color: "var(--mc-text-muted)" }}><Navigation className="w-3.5 h-3.5 rotate-90" /></a>}
                  </div>
                );
              })}
              {freeDrivers.length === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>alle Fahrer im Einsatz</div>}
            </div>
          </MissionPanel>

          <MissionPanel icon={Clock} title="Verschiebbar (on demand)">
            <div className="space-y-1">
              {shiftable.sort((a, b) => sortMin(a.time) - sortMin(b.time)).map((r) => (
                <button key={r.id} onClick={() => onEdit(r)} className="w-full flex items-center gap-2 text-left text-xs rounded px-1.5 py-1 transition"
                  style={{ color: "var(--mc-text-secondary)" }}>
                  <span className="font-mono" style={{ color: "var(--mc-text)" }}>{r.time}</span>
                  <span className="truncate">{ln(r.fromId, r.fromCustom)} → {ln(r.toId, r.toCustom)}</span>
                </button>
              ))}
              {shiftable.length === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>keine flexiblen Fahrten</div>}
            </div>
          </MissionPanel>
        </div>
      </div>
    </div>
  );
}

/* ------------- Mission Control: Ueberblick (Session 17, Scheibe 1) ---------
 * MC-eigene Variante von OverviewTab. Ansatz A wie bei MissionReturnsTab:
 * OverviewTab ist eine GETEILTE Komponente (Classic-Dashboard + MC), ein Umbau
 * dort traefe Classic. Deshalb eigene Kopie, Classic bleibt byte-genau.
 *
 * BEWUSST WENIGER ALS CLASSIC (Jordans Entscheidung 15.07., "doppelt gemoppelt").
 * Der Ueberblick soll in zehn Sekunden zeigen ob was brennt, nicht die halbe
 * Karte doppeln:
 *  - Flughafen-Pickups RAUS, dafuer gibt es den flights-Tab (die Liste hier
 *    verlinkte ohnehin nur dorthin).
 *  - TimelineView RAUS, dafuer gibt es MissionTimelinePage im timeline-Tab.
 *  - Die drei Chips unten RAUS, das macht die linke MC-Nav schon.
 *  - NEU: "Was brennt" aus emergencyCases(), vorhandener reiner Helfer. Deckt
 *    offene Probleme, kritische Fluege, Fahrten ohne Fahrer und nicht gestartete
 *    Fahrer ab. KEINE neue Logik, kein zweiter Problembegriff.
 *  - Toter Code aus Classic (freeCount: dort berechnet, nirgends benutzt)
 *    bewusst NICHT mituebernommen.
 *
 * BYTE-GLEICH AUS OverviewTab UEBERNOMMEN: die 30s-Uhr, ln(), rides, activeNow,
 * ref, soon, rep, anstehend. (openUnassigned haengt in Classic nur am Chip und
 * faellt mit ihm weg.) "Offen" (rep.open) behaelt bewusst
 * die Classic-Bedeutung, siehe UEBERGABE-Session-16 ("Offen" bedeutet an zwei
 * Stellen Verschiedenes, nicht ungefragt vereinheitlichen).
 *
 * Rein praesentational: kein updateDyn/updateSetup, keine Status-, Zeit-,
 * Zuteilungs- oder GPS-Logik. Liest nur und ruft dieselben Callbacks
 * (onEdit/onAssign/setTab) wie Classic.
 */
function MissionOverviewTab({ setup, dyn, day, setTab, onEdit, onAssign }) {
  const [, setTick] = useState(0);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 30000); return () => clearInterval(t); }, []);
  const [ovRef, ovWidth] = useElementWidth();
  const sideBySide = ovWidth >= 820; // gemessen statt Viewport-Breakpoint, wie Classic
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const now = dayNowMin(day);
  const live = now >= 0 && now < 90000;

  const rides = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled");
  const activeNow = rides.filter((r) => ["enroute_pickup", "onboard"].includes(r.status));
  const ref = live ? now : Math.min(...rides.map((r) => sortMin(r.time)).concat([720]));
  const soon = rides.filter((r) => r.status === "planned" && sortMin(r.time) >= ref && sortMin(r.time) <= ref + 60).sort((a, b) => sortMin(a.time) - sortMin(b.time));
  const rep = dayReport(setup, dyn, day);
  const anstehend = rides.filter((r) => r.status === "planned").length;
  const emCases = emergencyCases(setup, dyn, day);

  // Kachel = MetricCard im Button, damit der Sprung ins Fachtab erhalten bleibt
  // (Classic hatte den auch, nur als eigene Stone-Kachel).
  const Kpi = ({ label, value, icon, status, go }) => (
    <button onClick={() => setTab(go)} className="text-left w-full">
      <MetricCard label={label} value={value} icon={icon} status={status} />
    </button>
  );

  const McList = ({ title, icon: I, items, empty, moreGo, renderItem }) => (
    <MissionPanel padded={false}
      header={(
        <div className="flex items-center justify-between gap-2">
          <span className="mc-eyebrow flex items-center gap-1.5">{I && <I className="w-3.5 h-3.5" />}{title}</span>
          {moreGo && <button onClick={() => setTab(moreGo)} className="text-[11px]" style={{ color: "var(--mc-text-muted)" }}>alle</button>}
        </div>
      )}
      bodyClassName="p-2 space-y-1 max-h-52 overflow-y-auto">
      {items.length === 0
        ? <div className="px-2 py-3 text-xs" style={{ color: "var(--mc-text-muted)" }}>{empty}</div>
        : items.map(renderItem)}
    </MissionPanel>
  );

  const Row = ({ onClick, children }) => (
    <button onClick={onClick} className="w-full text-left flex items-center gap-1.5 text-xs rounded-lg px-2 py-1.5"
      style={{ background: "var(--mc-inset)" }}>
      {children}
    </button>
  );

  return (
    <div>
      <div className="flex flex-wrap items-center gap-3 mb-4">
        <h3 className="text-lg font-semibold flex items-center gap-2" style={{ color: "var(--mc-text)" }}>
          <LayoutGrid className="w-5 h-5" style={{ color: "var(--mc-text-secondary)" }} />Mission Control
        </h3>
        <span className="text-xs" style={{ color: "var(--mc-text-muted)" }}>{fmtDate(day)}</span>
        {live && (
          <span className="flex items-center gap-1.5 text-xs" style={{ color: "var(--mc-text-secondary)" }}>
            <span className="mc-live-dot" />live {fromMin(now)}
          </span>
        )}
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
        <Kpi label="Erledigt" value={rep.done} icon={CheckCircle2} status="done" go="board" />
        <Kpi label="Offen" value={rep.open} icon={Navigation} status="assigned" go="board" />
        <Kpi label="Anstehend" value={anstehend} icon={Clock} status="new" go="board" />
        <Kpi label="Gesamt" value={rep.total} icon={Route} go="settings" />
      </div>

      <div ref={ovRef} className="grid gap-4" style={{ gridTemplateColumns: sideBySide ? "minmax(420px,1.7fr) minmax(260px,1fr)" : "1fr" }}>
        {/* Live-Karte: bewusst die kompakte, kostenlose Schema-Ansicht.
            Die grosse Karte mit Filtern/Simulation/Google liegt im map-Tab. */}
        <div>
          <BoardMiniMap setup={setup} dyn={dyn} day={day} SchematicComponent={MissionSchematicMap} onEdit={onEdit} />
        </div>

        <div className="space-y-3">
          <McList title="Was brennt" icon={Siren} items={emCases} empty="alles ruhig"
            moreGo="emergency"
            renderItem={(c, i) => {
              const CIcon = CASE_ICON[c.type] || AlertTriangle;
              const drv = setup.drivers.find((d) => d.id === c.r.assignedDriverId);
              return (
                <Row key={`${c.r.id}-${c.type}-${i}`} onClick={() => (drv ? onEdit(c.r) : onAssign(c.r))}>
                  <CIcon className="w-3.5 h-3.5 shrink-0" style={{ color: c.sev === "critical" ? "var(--mc-st-problem)" : "var(--mc-st-assigned)" }} />
                  <span className="font-mono shrink-0" style={{ color: "var(--mc-text)" }}>{c.r.time}</span>
                  <span className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{c.r.djName || ln(c.r.toId, c.r.toCustom)}</span>
                  <span className="ml-auto truncate max-w-[45%] text-[10px]" style={{ color: "var(--mc-text-muted)" }}>{c.label}</span>
                </Row>
              );
            }} />

          <McList title="Jetzt unterwegs" icon={Navigation} items={activeNow} empty="gerade niemand unterwegs"
            renderItem={(r) => {
              const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
              return (
                <Row key={r.id} onClick={() => onEdit(r)}>
                  <span className="font-mono shrink-0" style={{ color: "var(--mc-text)" }}>{r.time}</span>
                  <span className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{ln(r.toId, r.toCustom)}</span>
                  {drv && <span className="text-[9px] font-mono ml-auto shrink-0" style={{ color: "var(--mc-text-muted)" }}>{drv.vehicleType === "Van" ? "Van" : "Car"}</span>}
                </Row>
              );
            }} />

          <McList title="Naechste 60 Minuten" icon={Clock} items={soon} empty="nichts in der naechsten Stunde"
            renderItem={(r) => {
              const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
              return (
                <Row key={r.id} onClick={() => (drv ? onEdit(r) : onAssign(r))}>
                  <span className="font-mono shrink-0" style={{ color: "var(--mc-text)" }}>{r.time}</span>
                  <span className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{ln(r.toId, r.toCustom)}</span>
                  {flightDelayed(r) && <Plane className="w-3 h-3 shrink-0" style={{ color: "var(--mc-st-problem)" }} />}
                  {!drv && <span className="text-[10px] ml-auto shrink-0" style={{ color: "var(--mc-st-assigned)" }}>zuteilen</span>}
                </Row>
              );
            }} />
        </div>
      </div>
    </div>
  );
}

/* --------------------------- Tagesabschluss (Punkt 10) -------------------- */
function ReportSection({ setup, dyn, day }) {
  const rep = dayReport(setup, dyn, day);
  return (
    <div>
      <div className="flex items-center gap-2 mb-1">
        <h3 className="font-medium text-stone-200 flex items-center gap-2"><BarChart3 className="w-4 h-4" />Tagesabschluss</h3>
        <span className="text-xs text-stone-500">{fmtDate(day)}</span>
        <div className="ml-auto flex gap-2">
          <button onClick={() => exportReport(setup, dyn, day, "xlsx")} className="text-xs bg-stone-800 hover:bg-stone-700 px-2.5 py-1.5 rounded-lg flex items-center gap-1.5"><Upload className="w-3.5 h-3.5 rotate-180" />Excel</button>
          <button onClick={() => exportReport(setup, dyn, day, "csv")} className="text-xs bg-stone-800 hover:bg-stone-700 px-2.5 py-1.5 rounded-lg">CSV</button>
        </div>
      </div>
      <p className="text-xs text-stone-500 mb-3">Kennzahlen für den oben gewählten Tag. Zum Wechseln des Tages die Tagesauswahl oben in der Kopfzeile nutzen.</p>

      <div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-8 gap-2 mb-4">
        {[["Gesamt", rep.total, "text-stone-100"], ["Erledigt", rep.done, "text-emerald-400"], ["Offen", rep.open, "text-orange-400"], ["Ohne Fahrer", rep.unassigned, "text-orange-400"], ["Abgesagt", rep.cancelled, "text-stone-400"], ["Probleme", rep.issues, rep.issues ? "text-red-400" : "text-stone-400"], ["Verspätet", rep.delayed, rep.delayed ? "text-amber-400" : "text-stone-400"], ["Offene Rückf.", rep.openReturns, rep.openReturns ? "text-orange-400" : "text-stone-400"]].map(([l, v, c]) => (
          <div key={l} className="bg-stone-950/50 rounded-lg px-2 py-2 text-center">
            <div className={`text-xl font-bold font-mono ${c}`}>{v}</div>
            <div className="text-[9px] uppercase tracking-wide text-stone-500 leading-tight">{l}</div>
          </div>
        ))}
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <div className="text-xs text-stone-400 mb-1.5">Fahrten pro Fahrer — wer wie oft gefahren ist</div>
          <div className="space-y-1 max-h-64 overflow-y-auto">
            {rep.perDriver.slice(0, 20).map((x, i) => (
              <div key={x.d.id} className="flex items-center gap-2 text-xs">
                <span className="text-stone-600 w-4">{i + 1}.</span>
                <span className="font-mono text-stone-400">{x.d.vehicleType === "Van" ? "Van" : "Car"}</span>
                <span className="text-stone-300 truncate">{x.d.firstName} {x.d.lastName[0]}.</span>
                <div className="flex-1 h-1.5 bg-stone-800 rounded-full overflow-hidden mx-1"><div className="h-full bg-orange-500" style={{ width: `${(x.n / (rep.perDriver[0]?.n || 1)) * 100}%` }} /></div>
                <span className="font-mono text-stone-300 shrink-0">{x.n}</span>
              </div>
            ))}
            {rep.perDriver.length === 0 && <div className="text-xs text-stone-600">keine zugeteilten Fahrten</div>}
          </div>
        </div>
        <div>
          <div className="text-xs text-stone-400 mb-1.5">Fahrten pro Route</div>
          <div className="space-y-1 max-h-64 overflow-y-auto">
            {rep.perRoute.slice(0, 20).map(([route, n]) => (
              <div key={route} className="flex items-center gap-2 text-xs">
                <span className="text-stone-300 truncate">{route}</span>
                <span className="font-mono text-stone-400 ml-auto shrink-0">{n}×</span>
              </div>
            ))}
            {rep.perRoute.length === 0 && <div className="text-xs text-stone-600">keine Fahrten</div>}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ------------------- Große Timeline-Seite (eigener Tab) ------------------ */
// Anders als die kompakte TimelineView (nur Überblick, unten eingebettet):
// hier sind die Fahrten groß genug für Künstlername + Strecke UND anklickbar —
// Klick auf die Fahrt öffnet die Schnellzuteilung (Fahrer wechseln), das
// Stift-Symbol öffnet die volle Bearbeitung (Zeit/Route/Details).
// Kalenderdatum passend zu einer neuen Uhrzeit halten, während der festival dayKey
// FEST bleibt (wichtig beim Ziehen über Mitternacht: die Fahrt darf beim Verschieben
// nie aus der gerade offenen Tages-Ansicht verschwinden).
function dateForNightTime(dayKey, time) {
  if (toMin(time) < 360) {
    const d = new Date(dayKey + "T12:00:00"); d.setDate(d.getDate() + 1);
    return localDateISO(d);
  }
  return dayKey;
}
const TL_LABEL_W = 160; // px, entspricht w-40
const TL_DRAG_THRESHOLD = 6; // px Mindestbewegung, bevor aus Klick ein Ziehen wird

function MissionTimelinePage({ setup, dyn, day, onEdit, onAssign, updateDyn, by, onUndo, onErr }) {
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const [, setTick] = useState(0);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 30000); return () => clearInterval(t); }, []);
  const [filter, setFilter] = useState("all");
  const [selectedId, setSelectedId] = useState(null);
  const gridRef = useRef(null);
  const scrollRef = useRef(null); // die horizontal scrollbare Zeitraster-Fläche (für Zoom + Ziehen-Berechnung)
  const [drag, setDrag] = useState(null);
  const dragRef = useRef(null);
  const assignBusyRef = useRef(false); // Doppelklick-Schutz fuer die Timeline-Schnellzuteilung
  // Bestätigung vor dem eigentlichen Verschieben: erst nach Loslassen wird nichts
  // sofort übernommen, sondern ein Hinweis an der Zielposition eingeblendet.
  // Reines Antippen (kein echtes Ziehen) braucht weiterhin keine Bestätigung.
  const [pendingDrop, setPendingDrop] = useState(null);
  // Kurzer "Rückgängig"-Hinweis direkt an der Fahrt, nachdem eine Verschiebung
  // bestätigt wurde — verschwindet nach ein paar Sekunden von selbst.
  const [recentlyMoved, setRecentlyMoved] = useState(null);
  useEffect(() => {
    if (!recentlyMoved) return;
    const t = setTimeout(() => setRecentlyMoved((r) => (r && r.at === recentlyMoved.at ? null : r)), 8000);
    return () => clearTimeout(t);
  }, [recentlyMoved]);
  useEffect(() => {
    if (!pendingDrop) return;
    const onKey = (e) => { if (e.key === "Escape") setPendingDrop(null); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [pendingDrop]);

  const nowMin = dayNowMin(day);
  const live = nowMin >= 0 && nowMin < 90000;
  const allRides = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled");

  const start = (r) => sortMin(r.time);
  const end = (r) => sortMin(r.time) + effDur(setup.config, r);
  const barColor = (r) => r.status === "done" ? "bg-emerald-600/80 border-emerald-400"
    : r.status === "onboard" ? "bg-orange-500/90 border-orange-300"
      : r.status === "enroute_pickup" ? "bg-blue-500/90 border-blue-300"
        : r.status === "accepted" ? "bg-blue-500/50 border-blue-400"
          : "bg-stone-600/70 border-stone-400";
  const hasConflict = (rs, i) => rs.some((o, j) => j !== i && start(o) < end(rs[i]) && end(o) > start(rs[i]));

  let winStart = 720, winEnd = 1620, hours = [];
  if (allRides.length > 0) {
    winStart = Math.floor((Math.min(...allRides.map(start)) - 20) / 30) * 30;
    winEnd = Math.ceil((Math.max(...allRides.map(end)) + 20) / 30) * 30;
  }
  const span = Math.max(60, winEnd - winStart);
  const pct = (m) => ((m - winStart) / span) * 100;
  for (let m = Math.ceil(winStart / 60) * 60; m <= winEnd; m += 60) hours.push(m);
  const showNowLine = live && nowMin >= winStart && nowMin <= winEnd;

  // Zoom: Zeitraster bekommt eine feste Pixelbreite statt sich immer auf die
  // verfügbare Breite zu strecken -> "Passend" misst die tatsächlich
  // verfügbare Breite und setzt den Zoom so, dass alles ohne Scrollen reinpasst
  // (das ist der bisherige, einzige Zustand gewesen). +/- weicht davon ab,
  // wird bei Bedarf horizontal scrollbar. Läuft automatisch neu beim
  // Tageswechsel, NICHT bei jeder kleinen Datenänderung — sonst würde ein
  // manuell gewählter Zoom ständig überschrieben.
  const [zoom, setZoom] = useState(1);
  const ZOOM_MIN = 0.4, ZOOM_MAX = 5;
  const BASE_PX_PER_MIN = 1.3;
  const fitToScreen = useCallback(() => {
    const el = scrollRef.current;
    const available = el ? el.clientWidth - TL_LABEL_W : 0;
    if (available <= 0) { setZoom(1); return; }
    const needed = available / (span * BASE_PX_PER_MIN);
    setZoom(Math.min(ZOOM_MAX, Math.max(ZOOM_MIN, needed)));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [span]);
  useEffect(() => { fitToScreen(); }, [day]); // eslint-disable-line react-hooks/exhaustive-deps
  const pxPerMin = BASE_PX_PER_MIN * zoom;
  const contentW = Math.max(280, span * pxPerMin);
  // Konflikt-Zähler: über den kompletten (ungefilterten) Tag, nicht nur die sichtbare Auswahl.
  const withDriverAll = setup.drivers.map((d) => ({ d, rs: allRides.filter((r) => r.assignedDriverId === d.id).sort((a, b) => start(a) - start(b)) }));
  let conflictCount = 0;
  withDriverAll.forEach(({ rs }) => rs.forEach((r, i) => { if (hasConflict(rs, i)) conflictCount++; }));

  // Status-Filter — filtert welche FAHRTEN gezeigt werden (Alle/Unterwegs/...).
  // Fahrer-ZEILEN bleiben unabhängig davon immer alle sichtbar (siehe withDriver
  // unten), auch wenn der Filter gerade keine ihrer Fahrten zeigt.
  const FILTERS = [["all", "Alle"], ["active", "Unterwegs"], ["problem", "Problem"], ["done", "Erledigt"], ["unassigned", "Ohne Fahrer"]];
  const passesFilter = (r) => {
    if (filter === "active") return ["enroute_pickup", "onboard"].includes(r.status);
    if (filter === "problem") return rideHasOpenIssue(r);
    if (filter === "done") return r.status === "done";
    if (filter === "unassigned") return !r.assignedDriverId;
    return true;
  };
  const rides = allRides.filter(passesFilter);
  // Auf Jordans Wunsch: ALLE Fahrer sichtbar, auch ohne Fahrten heute (vorher
  // .filter((x) => x.rs.length > 0) rausgenommen), UND feste Reihenfolge, die
  // sich nicht mit Zuteilungen verschiebt (vorher nach Beginn der ersten
  // Fahrt sortiert -> Zeilen sprangen um). Reihenfolge jetzt einfach wie in
  // den Fahrer-Stammdaten (Einstellungen → Fahrer), bleibt stabil.
  const withDriver = setup.drivers
    .map((d) => ({ d, rs: rides.filter((r) => r.assignedDriverId === d.id).sort((a, b) => start(a) - start(b)) }));
  const unassigned = rides.filter((r) => !r.assignedDriverId).sort((a, b) => start(a) - start(b));

  // Lücken-Hervorhebung: offene Fahrt anklicken -> passende Fahrer leuchten in der
  // Timeline auf, Klick auf deren Zeile weist sofort zu (ohne Dialog).
  const selectedRide = selectedId ? allRides.find((r) => r.id === selectedId) : null;
  const evalFor = (driverId) => selectedRide ? evaluateInsertion(setup, dyn, setup.drivers.find((d) => d.id === driverId), selectedRide) : null;

  const quickAssign = async (driverId) => {
    if (!selectedRide || assignBusyRef.current) return;
    assignBusyRef.current = true;
    const rideId = selectedRide.id;
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === rideId);
      // Fahrt weg -> Konflikt statt stillem rev+1: sonst meldet der Aufrufer
      // ok:true und der Push unten ginge faelschlich an einen Fahrer fuer eine
      // nicht mehr existierende Fahrt.
      if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
      logRide(r, "assigned", by, "Schnellzuteilung über Timeline");
      r.assignedDriverId = driverId;
      if (r.status !== "planned") setRideStatus(r, "planned", by); else r.updatedAt = Date.now();
      return d;
    });
    assignBusyRef.current = false;
    // Push und Auswahl-Reset erst NACH bestaetigtem Save; bei Fehler bleibt die
    // Auswahl erhalten und es gibt eine Meldung. Empfaenger aus dem bestaetigten Stand.
    if (!res || !res.ok) { onErr?.(res?.error || "Zuteilung konnte nicht gespeichert werden, bitte erneut versuchen."); return; }
    setSelectedId(null);
    const saved = (res.value.rides || []).find((x) => x.id === rideId);
    const drv = saved?.assignedDriverId;
    if (drv) triggerPush(drv, "Neue Fahrt zugeteilt", `${saved.time} · ${saved.djName || "Fahrt"}`, `ride-${rideId}`);
  };

  // ---- Ziehen: Zeit ändern (horizontal) und/oder Fahrer wechseln (Zeile) --------
  // Nutzt jetzt scrollRef (die tatsächliche Zeitraster-Fläche, feste Pixel-
  // breite bei Zoom) statt gridRef (das war vorher der ganze Seiten-Wrapper,
  // hat nur zufällig gepasst weil er dieselbe Breite wie das Raster hatte —
  // stimmt seit dem horizontalen Scrollen bei Zoom nicht mehr). scrollLeft
  // wird mit eingerechnet, sonst stimmt die Zielzeit beim Ziehen nicht mehr,
  // sobald nach rechts gescrollt wurde.
  const timeFromClientX = (clientX) => {
    const el = scrollRef.current; if (!el || contentW <= 0) return null;
    const rect = el.getBoundingClientRect();
    const contentX = (clientX - rect.left - TL_LABEL_W) + el.scrollLeft;
    const relX = Math.min(1, Math.max(0, contentX / contentW));
    return Math.round((winStart + relX * span) / 5) * 5;
  };
  const driverIdFromClientY = (clientX, clientY) => {
    const el = document.elementFromPoint(clientX, clientY);
    const rowEl = el && el.closest ? el.closest("[data-row-driver]") : null;
    if (!rowEl) return undefined; // kein gültiges Ziel -> Fahrer nicht ändern
    const v = rowEl.getAttribute("data-row-driver");
    return v === "unassigned" ? null : v;
  };
  const applyDrop = async (rideId, newStartMin, newDriverIdOrUndefined) => {
    const cur = allRides.find((x) => x.id === rideId);
    if (!cur || newStartMin == null) return;
    const newTime = fromMin(newStartMin);
    const timeChanged = newTime !== cur.time;
    const driverChanged = newDriverIdOrUndefined !== undefined && newDriverIdOrUndefined !== (cur.assignedDriverId || null);
    if (!timeChanged && !driverChanged) return;
    const res = await updateDyn((d) => {
      const r = d.rides.find((x) => x.id === rideId);
      if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
      if (timeChanged) { logRide(r, "time", by, `${r.time} → ${newTime} (Timeline gezogen)`); r.date = dateForNightTime(day, newTime); r.time = newTime; }
      if (driverChanged) {
        logRide(r, newDriverIdOrUndefined ? (cur.assignedDriverId ? "reassigned" : "assigned") : "reassigned", by, "Timeline: Fahrer per Ziehen geändert");
        r.assignedDriverId = newDriverIdOrUndefined;
      }
      if (driverChanged && r.status !== "planned") setRideStatus(r, "planned", by); else r.updatedAt = Date.now();
      return d;
    });
    // Push erst NACH bestaetigtem Save; bei Fehler Meldung, die Timeline rendert
    // ohnehin aus dem (unveraenderten) Serverstand weiter. Empfaenger/Text aus
    // dem bestaetigten Stand.
    if (!res || !res.ok) { onErr?.(res?.error || "Verschiebung konnte nicht gespeichert werden, bitte erneut versuchen."); return res; }
    const saved = (res.value.rides || []).find((x) => x.id === rideId);
    if (driverChanged && newDriverIdOrUndefined) triggerPush(newDriverIdOrUndefined, "Neue Fahrt zugeteilt", `${saved?.time || newTime} · ${saved?.djName || cur.djName || "Fahrt"}`, `ride-${rideId}`);
    else if (timeChanged && (saved?.assignedDriverId || cur.assignedDriverId)) triggerPush(saved?.assignedDriverId || cur.assignedDriverId, "Fahrt geändert", `${saved?.djName || cur.djName || "Fahrt"} · neue Zeit ${saved?.time || newTime}`, `ride-${rideId}`);
    return res;
  };

  const beginDrag = (e, r) => {
    if (e.pointerType === "mouse" && e.button !== 0) return;
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    const st = { rideId: r.id, ride: r, x0: e.clientX, y0: e.clientY, x: e.clientX, y: e.clientY, grabDx: e.clientX - rect.left, w: rect.width, moved: false };
    dragRef.current = st; setDrag(st);
  };
  useEffect(() => {
    if (!drag) return;
    const onMove = (e) => {
      const st = dragRef.current; if (!st) return;
      const moved = st.moved || Math.hypot(e.clientX - st.x0, e.clientY - st.y0) > TL_DRAG_THRESHOLD;
      const next = { ...st, x: e.clientX, y: e.clientY, moved };
      dragRef.current = next; setDrag(next);
    };
    const onUp = (e) => {
      const st = dragRef.current; dragRef.current = null; setDrag(null);
      if (!st) return;
      if (!st.moved) {
        // wie ein normaler Tap behandeln
        if (!st.ride.assignedDriverId) setSelectedId((s) => (s === st.rideId ? null : st.rideId));
        else onAssign && onAssign(st.ride);
        return;
      }
      const newStart = timeFromClientX(e.clientX - st.grabDx + st.w / 2);
      const newDriver = driverIdFromClientY(e.clientX, e.clientY);
      if (newStart == null) return;
      const newTime = fromMin(newStart);
      const timeChanged = newTime !== st.ride.time;
      const driverChanged = newDriver !== undefined && newDriver !== (st.ride.assignedDriverId || null);
      if (!timeChanged && !driverChanged) return; // an derselben Stelle losgelassen -> nichts zu bestätigen
      setPendingDrop({ rideId: st.rideId, ride: st.ride, newStartMin: newStart, newDriverIdOrUndefined: newDriver, x: e.clientX, y: e.clientY });
    };
    window.addEventListener("pointermove", onMove);
    window.addEventListener("pointerup", onUp);
    return () => { window.removeEventListener("pointermove", onMove); window.removeEventListener("pointerup", onUp); };
  }, [drag]);

  const confirmPendingDrop = async () => {
    if (!pendingDrop) return;
    const pd = pendingDrop;
    setPendingDrop(null);
    // Der "Verschoben/Rueckgaengig"-Hinweis suggeriert Erfolg -> erst zeigen, wenn
    // das Speichern bestaetigt ist. Bei Fehler meldet applyDrop selbst (onErr).
    const res = await applyDrop(pd.rideId, pd.newStartMin, pd.newDriverIdOrUndefined);
    if (res && res.ok) setRecentlyMoved({ rideId: pd.rideId, at: Date.now(), x: pd.x, y: pd.y });
  };
  const cancelPendingDrop = () => setPendingDrop(null);

  const NowLine = () => showNowLine ? (
    <div className="absolute top-0 bottom-0 z-10 pointer-events-none" style={{ left: `${pct(nowMin)}%`, width: 2, background: "var(--mc-st-assigned)" }}>
      <div className="absolute -top-4 -translate-x-1/2 text-[9px] font-mono whitespace-nowrap" style={{ color: "var(--mc-st-assigned)" }}>{fromMin(nowMin % 1440)}</div>
    </div>
  ) : null;

  // Ziel während des Ziehens EINMAL pro Render berechnen (nicht pro Zeile) — spart
  // wiederholte elementFromPoint-Aufrufe bei vielen Fahrern.
  const dragActive = drag && drag.moved;
  const dropNewStart = dragActive ? timeFromClientX(drag.x - drag.grabDx + drag.w / 2) : null;
  const dropDriverId = dragActive ? driverIdFromClientY(drag.x, drag.y) : undefined;

  const Block = ({ r, warn, conflict }) => {
    const to = ln(r.toId, r.toCustom), from = ln(r.fromId, r.fromCustom);
    const isOpen = !r.assignedDriverId;
    const selected = selectedId === r.id;
    const problem = rideHasOpenIssue(r);
    const dragging = drag && drag.rideId === r.id && drag.moved;
    // Rein LESEND: geplante Endzeit aus effDur (start + Dauer). Bei unbekannter
    // Dauer faellt effDur auf config.minDurationMin zurueck -> sichtbar als "ca."
    // markiert, es wird keine echte Endzeit erfunden.
    const stKey = mcRideStatusKey(r.status, !!r.assignedDriverId);
    const durKnown = r.estDurationMin != null;
    const endTime = fromMin(end(r) % 1440);
    return (
      <div onPointerDown={(e) => beginDrag(e, r)} onClick={(e) => e.stopPropagation()}
        title={`${r.time} · ${from} → ${to}${r.djName ? " · " + r.djName : ""} — ziehen zum Verschieben, ${isOpen ? "tippen: passende Fahrer anzeigen" : "tippen: Fahrer ändern"}`}
        style={{
          left: `${pct(start(r))}%`, width: `${Math.max(9, pct(end(r)) - pct(start(r)))}%`,
          minWidth: 92, touchAction: "none", opacity: dragging ? 0.25 : 1,
          background: `var(--mc-st-${stKey}-fill)`,
          borderColor: conflict ? "var(--mc-st-problem)" : selected ? "var(--mc-text)" : `var(--mc-st-${stKey})`,
          boxShadow: conflict ? "0 0 0 1.5px var(--mc-st-problem)" : selected ? "0 0 0 1.5px var(--mc-text)" : "var(--mc-shadow-sm)",
        }}
        className="mc-tl-block absolute top-1.5 bottom-1.5 rounded-lg border pl-2 pr-1 py-1 overflow-hidden cursor-grab active:cursor-grabbing">
        <div className="text-[11px] font-semibold leading-tight truncate" style={{ color: "#ffffff" }}>{r.djName || "—"}</div>
        <div className="text-[9px] leading-tight truncate" style={{ color: "rgba(255,255,255,0.85)" }}>{from} → {to}</div>
        <div className="text-[9px] font-mono leading-tight" style={{ color: "rgba(255,255,255,0.78)" }}>
          {r.time} → {durKnown ? endTime : <span style={{ color: "rgba(255,255,255,0.92)", fontWeight: 600 }}>ca. {endTime}</span>}
        </div>
        {problem && (
          <span title="Offene Problemmeldung" className="absolute top-0.5 left-0.5 w-4 h-4 rounded-full flex items-center justify-center" style={{ background: "var(--mc-st-problem)" }}>
            <AlertTriangle className="w-2.5 h-2.5 text-white" />
          </span>
        )}
        <button onPointerDown={(e) => e.stopPropagation()} onClick={(e) => { e.stopPropagation(); onEdit && onEdit(r); }} title="Fahrt bearbeiten"
          className="absolute top-0.5 right-0.5 w-5 h-5 rounded-md flex items-center justify-center" style={{ background: "rgba(0,0,0,0.32)" }}>
          <ChevronRight className="w-3 h-3" style={{ color: "var(--mc-text)" }} />
        </button>
      </div>
    );
  };

  const Row = ({ driverId, label, sub, rs, conflictCheck, warn }) => {
    const ev = selectedRide && driverId ? evalFor(driverId) : null;
    const clickable = ev && ev.eligible && !ev.overlap;
    const isDropTarget = dragActive && dropDriverId !== undefined && dropDriverId === (driverId || null);
    const rowBg = isDropTarget ? "var(--mc-st-assigned-soft)"
      : !selectedRide ? "var(--mc-panel)"
        : clickable ? (ev.feasible ? "var(--mc-st-done-soft)" : "var(--mc-st-assigned-soft)")
          : "var(--mc-panel)";
    const dimmed = selectedRide && !clickable && !isDropTarget;
    return (
      <div data-row-driver={driverId || "unassigned"} onClick={() => clickable && quickAssign(driverId)}
        className={`mc-tl-row flex items-stretch ${clickable ? "mc-tl-row-click cursor-pointer" : ""}`}
        style={{ borderBottom: "1px solid var(--mc-border)", background: rowBg, opacity: dimmed ? 0.4 : 1 }}>
        <div className="w-40 shrink-0 px-3 py-2.5 sticky left-0 z-10" style={{ background: "var(--mc-panel)" }}>
          <div className="text-sm font-medium truncate" style={{ color: warn ? "var(--mc-st-assigned)" : "var(--mc-text)" }}>{label}</div>
          {sub && <div className="text-[10px] font-mono truncate mt-0.5" style={{ color: "var(--mc-text-muted)" }}>{sub}</div>}
          {clickable && <div className="text-[9px] mt-0.5" style={{ color: ev.feasible ? "var(--mc-st-done)" : "var(--mc-st-assigned)" }}>{ev.feasible ? "passt · antippen" : "knapp · antippen"}</div>}
        </div>
        <div className="relative shrink-0 h-16" style={{ width: contentW }}>
          {hours.map((m) => <div key={m} className="absolute top-0 bottom-0 w-px" style={{ left: `${pct(m)}%`, background: "var(--mc-border)" }} />)}
          <NowLine />
          {rs.map((r, i) => <Block key={r.id} r={r} warn={warn} conflict={conflictCheck && hasConflict(rs, i)} />)}
        </div>
      </div>
    );
  };

  // Schwebende Vorschau während des Ziehens: zeigt Zielzeit + Zielfahrer live an.
  const DragGhost = () => {
    if (!dragActive) return null;
    const targetLabel = dropDriverId === undefined ? "kein gültiges Ziel"
      : dropDriverId === null ? "Ohne Fahrer"
        : (() => { const dd = setup.drivers.find((x) => x.id === dropDriverId); return dd ? `${dd.firstName} ${dd.lastName}` : "—"; })();
    return (
      <div className="mc-panel fixed z-50 pointer-events-none px-3 py-2"
        style={{ left: drag.x + 14, top: drag.y + 14, borderColor: "var(--mc-st-new)" }}>
        <div className="text-sm font-semibold" style={{ color: "var(--mc-text)" }}>{dropNewStart != null ? fromMin(dropNewStart) : "—"}</div>
        <div className="text-[10px]" style={{ color: "var(--mc-text-secondary)" }}>{targetLabel}</div>
      </div>
    );
  };

  // Bestätigung nach dem Loslassen: nichts wird direkt übernommen, sondern erst
  // hier freigegeben oder verworfen — schützt vor versehentlichem Verschieben.
  const PendingDropConfirm = () => {
    if (!pendingDrop) return null;
    const { ride, newStartMin, newDriverIdOrUndefined } = pendingDrop;
    const newTime = fromMin(newStartMin);
    const timeChanged = newTime !== ride.time;
    const driverChanged = newDriverIdOrUndefined !== undefined && newDriverIdOrUndefined !== (ride.assignedDriverId || null);
    const driverLabel = (id) => { if (!id) return "Ohne Fahrer"; const d = setup.drivers.find((x) => x.id === id); return d ? `${d.firstName} ${d.lastName[0]}.` : "?"; };
    const left = Math.min(Math.max(pendingDrop.x - 110, 8), window.innerWidth - 228);
    const top = Math.min(pendingDrop.y + 16, window.innerHeight - 140);
    return (
      <>
        <div className="fixed inset-0 z-40" onPointerDown={cancelPendingDrop} />
        <div className="mc-panel fixed z-50 w-56 p-3" style={{ left, top, borderColor: "var(--mc-st-new)" }}
          onPointerDown={(e) => e.stopPropagation()}>
          <div className="text-sm font-semibold truncate mb-1.5" style={{ color: "var(--mc-text)" }}>{ride.djName || "Fahrt"} wirklich verschieben?</div>
          {timeChanged && <div className="text-xs mb-1" style={{ color: "var(--mc-text-secondary)" }}>Zeit: <span style={{ color: "var(--mc-text-muted)" }}>{ride.time}</span> → <span className="font-medium" style={{ color: "var(--mc-text)" }}>{newTime}</span></div>}
          {driverChanged && <div className="text-xs mb-1" style={{ color: "var(--mc-text-secondary)" }}>Fahrer: <span style={{ color: "var(--mc-text-muted)" }}>{driverLabel(ride.assignedDriverId)}</span> → <span className="font-medium" style={{ color: "var(--mc-text)" }}>{driverLabel(newDriverIdOrUndefined)}</span></div>}
          <div className="flex gap-2 mt-2">
            <button onClick={cancelPendingDrop} className="flex-1 text-xs py-1.5 rounded-lg" style={{ background: "var(--mc-hover)", color: "var(--mc-text-secondary)" }}>Abbrechen</button>
            <button onClick={confirmPendingDrop} className="mc-btn-primary flex-1 text-xs py-1.5">Verschieben</button>
          </div>
        </div>
      </>
    );
  };

  // Kurzer Hinweis direkt an der Fahrt, nachdem eine Verschiebung bestätigt wurde.
  const RecentlyMovedHint = () => {
    if (!recentlyMoved) return null;
    const left = Math.min(Math.max(recentlyMoved.x - 60, 8), window.innerWidth - 180);
    const top = Math.min(recentlyMoved.y + 16, window.innerHeight - 60);
    return (
      <div className="mc-panel fixed z-40 flex items-center gap-2 px-2.5 py-1.5 text-[11px]"
        style={{ left, top, color: "var(--mc-text-secondary)" }}>
        <CheckCircle2 className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-st-done)" }} />
        Verschoben
        <button onClick={() => { onUndo && onUndo(); setRecentlyMoved(null); }} className="font-medium" style={{ color: "var(--mc-st-new)" }}>Rückgängig</button>
      </div>
    );
  };

  return (
    <div ref={gridRef} onPointerMove={() => {}}>
      <style>{`
        .mc-tl-row-click:hover { background: var(--mc-hover) !important; }
        .mc-tl-block:hover { filter: brightness(1.10); }
        .mc-tl-scroll::-webkit-scrollbar { height: 10px; width: 10px; }
        .mc-tl-scroll::-webkit-scrollbar-thumb { background: var(--mc-border-strong); border-radius: 999px; }
        .mc-tl-scroll::-webkit-scrollbar-track { background: transparent; }
      `}</style>

      <div className="flex flex-wrap items-center justify-between gap-2 mb-3">
        <div className="flex items-center gap-2.5">
          <div className="flex items-center gap-2">
            <Gauge className="w-4 h-4" style={{ color: "var(--mc-text-secondary)" }} />
            <h2 className="text-[15px] font-semibold" style={{ color: "var(--mc-text)" }}>Timeline · wer ist wann belegt</h2>
          </div>
          {conflictCount > 0 && (
            <span className="mc-badge mc-badge--problem"><AlertTriangle className="w-3 h-3" />{conflictCount} Konflikt{conflictCount > 1 ? "e" : ""}</span>
          )}
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-0.5 p-0.5 rounded-lg" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
            <button onClick={() => setZoom((z) => Math.max(ZOOM_MIN, z / 1.3))} title="Kleiner"
              className="w-7 h-7 flex items-center justify-center rounded text-base font-medium leading-none" style={{ color: "var(--mc-text-secondary)" }}>−</button>
            <button onClick={fitToScreen} title="An Bildschirmbreite anpassen"
              className="px-2 h-7 flex items-center text-[11px] rounded whitespace-nowrap" style={{ color: "var(--mc-text-secondary)" }}>Passend</button>
            <button onClick={() => setZoom((z) => Math.min(ZOOM_MAX, z * 1.3))} title="Größer"
              className="w-7 h-7 flex items-center justify-center rounded text-base font-medium leading-none" style={{ color: "var(--mc-text-secondary)" }}>+</button>
          </div>
          <div className="hidden sm:flex items-center gap-3 text-xs" style={{ color: "var(--mc-text-muted)" }}>
            <span className="flex items-center gap-1.5"><span className="w-3 h-3 rounded" style={{ background: "var(--mc-st-enroute)" }} />unterwegs</span>
            <span className="flex items-center gap-1.5"><span className="w-3 h-3 rounded" style={{ background: "var(--mc-st-done)" }} />erledigt</span>
            <span className="flex items-center gap-1.5"><span className="w-3 h-3 rounded" style={{ boxShadow: "0 0 0 1.5px var(--mc-st-problem)" }} />Konflikt</span>
          </div>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-1.5 mb-3">
        {FILTERS.map(([k, l]) => (
          <button key={k} onClick={() => setFilter(k)}
            className="text-xs px-2.5 py-1 rounded-lg border transition"
            style={filter === k
              ? { background: "var(--mc-text)", color: "var(--mc-bg)", borderColor: "var(--mc-text)", fontWeight: 500 }
              : { background: "var(--mc-panel)", color: "var(--mc-text-secondary)", borderColor: "var(--mc-border)" }}>{l}</button>
        ))}
      </div>

      <p className="text-xs mb-3" style={{ color: "var(--mc-text-muted)" }}>
        {selectedRide
          ? <>Offene Fahrt <b style={{ color: "var(--mc-text-secondary)" }}>{selectedRide.djName || selectedRide.time}</b> ausgewählt — grüne/gelbe Zeilen antippen zum Zuteilen, oder nochmal auf die Fahrt tippen zum Abbrechen.</>
          : "Fahrt ziehen = Zeit ändern / in eine andere Zeile ziehen = Fahrer wechseln, wird erst nach Bestätigung übernommen · Tippen ohne Ziehen = offene Fahrt: passende Fahrer anzeigen, zugeteilte Fahrt: Fahrer ändern · Stift = Details bearbeiten. · Endzeit im Balken ist geschätzt (ca. = Dauer unbekannt)."}
      </p>

      {rides.length === 0 ? (
        <EmptyState icon={Gauge} title="Keine Fahrten in dieser Ansicht" hint="Filter wechseln oder neue Fahrten anlegen." />
      ) : (
        <div className="mc-panel overflow-hidden" style={{ padding: 0 }}>
          {/* Eigener scrollbarer Bereich (statt der ganzen Seite): so bleiben
              Kopfzeile (oben) UND Fahrer-Namen (links) beim Scrollen stehen,
              ohne mit dem Dashboard-Header oben in der Seite zu kollidieren. */}
          <div ref={scrollRef} className="mc-tl-scroll overflow-auto max-h-[65vh]">
            <div className="flex sticky top-0 z-20" style={{ borderBottom: "1px solid var(--mc-border)", background: "var(--mc-inset)" }}>
              <div className="w-40 shrink-0 sticky left-0 z-30" style={{ background: "var(--mc-inset)" }} />
              <div className="relative shrink-0 h-6" style={{ width: contentW }}>
                {hours.map((m) => <div key={m} className="absolute text-[10px] top-1.5" style={{ left: `${pct(m)}%`, transform: "translateX(-50%)", color: "var(--mc-text-muted)" }}>{fromMin(m % 1440)}</div>)}
              </div>
            </div>
            <div>
              {unassigned.length > 0 && <Row label="Ohne Fahrer" sub={`${unassigned.length} Fahrt(en)`} rs={unassigned} warn />}
              {withDriver.map(({ d, rs }) => <Row key={d.id} driverId={d.id} label={`${d.firstName} ${d.lastName}`} sub={d.vehicleType === "Van" ? "Van" : "Car"} rs={rs} conflictCheck />)}
            </div>
          </div>
        </div>
      )}
      <DragGhost />
      <PendingDropConfirm />
      <RecentlyMovedHint />
    </div>
  );
}

/* ---------------------------- Timeline (Punkt 13) ------------------------ */
function TimelineView({ setup, dyn, day, onEdit }) {
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const rides = (dyn.rides || []).filter((r) => r.dayKey === day && r.status !== "cancelled");
  if (rides.length === 0) return <div className="text-sm py-8 text-center" style={{ color: "var(--mc-text-muted)" }}>Keine Fahrten für die Timeline.</div>;

  const start = (r) => sortMin(r.time);
  const end = (r) => sortMin(r.time) + effDur(setup.config, r);
  let winStart = Math.min(...rides.map(start)) - 20;
  let winEnd = Math.max(...rides.map(end)) + 20;
  winStart = Math.floor(winStart / 30) * 30; winEnd = Math.ceil(winEnd / 30) * 30;
  const span = Math.max(60, winEnd - winStart);
  const pct = (m) => ((m - winStart) / span) * 100;

  // Gleiche Farbzuordnung wie die grosse MC-Timeline (mcRideStatusKey + die
  // -fill/-Rahmen-Tokens). Reine Darstellung, keine Statuslogik.
  const barStyle = (r) => {
    const k = mcRideStatusKey(r.status, !!r.assignedDriverId);
    return { background: `var(--mc-st-${k}-fill)`, borderColor: `var(--mc-st-${k})` };
  };

  // Stundenraster
  const hours = [];
  for (let m = Math.ceil(winStart / 60) * 60; m <= winEnd; m += 60) hours.push(m);

  const withDriver = setup.drivers
    .map((d) => ({ d, rs: rides.filter((r) => r.assignedDriverId === d.id).sort((a, b) => start(a) - start(b)) }))
    .filter((x) => x.rs.length > 0);
  const unassigned = rides.filter((r) => !r.assignedDriverId).sort((a, b) => start(a) - start(b));

  // Konflikt = Überschneidung zweier Fahrten desselben Fahrers
  const hasConflict = (rs, i) => rs.some((o, j) => j !== i && start(o) < end(rs[i]) && end(o) > start(rs[i]));

  const Row = ({ label, sub, rs, conflictCheck, warn }) => (
    <div className="flex items-stretch" style={{ borderBottom: "1px solid var(--mc-border)" }}>
      <div className="w-28 shrink-0 px-2 py-1.5 text-xs">
        <div className="text-sm truncate" style={{ color: warn ? "var(--mc-st-assigned)" : "var(--mc-text)" }}>{label}</div>
        {sub && <div className="text-[9px] truncate" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-muted)" }}>{sub}</div>}
      </div>
      <div className="relative flex-1 h-9 my-0.5">
        {hours.map((m) => <div key={m} className="absolute top-0 bottom-0 w-px" style={{ left: `${pct(m)}%`, background: "var(--mc-border)" }} />)}
        {rs.map((r, i) => {
          const conflict = conflictCheck && hasConflict(rs, i);
          const bar = barStyle(r);
          return (
            <button key={r.id} onClick={() => onEdit && onEdit(r)}
              title={`${r.time} ${ln(r.fromId, r.fromCustom)} → ${ln(r.toId, r.toCustom)} · ${r.djName || ""}`}
              className="mc-tl-block absolute top-1 bottom-1 border text-[9px] px-1 overflow-hidden whitespace-nowrap"
              style={{
                left: `${pct(start(r))}%`, width: `${Math.max(2.5, pct(end(r)) - pct(start(r)))}%`,
                borderRadius: "var(--mc-r-sm)", color: "#ffffff",
                ...bar,
                ...(conflict ? { borderColor: "var(--mc-st-problem)", boxShadow: "0 0 0 1.5px var(--mc-st-problem)" } : null),
              }}>
              {r.djName || ln(r.toId, r.toCustom)}
            </button>
          );
        })}
      </div>
    </div>
  );

  return (
    <div className="mc-panel p-3 mt-4">
      <div className="flex items-center justify-between mb-2">
        <h3 className="text-sm flex items-center gap-2" style={{ color: "var(--mc-text-secondary)" }}><Gauge className="w-4 h-4" />Timeline · wer ist wann belegt</h3>
        <div className="flex items-center gap-3 text-[10px]" style={{ color: "var(--mc-text-muted)" }}>
          <span className="flex items-center gap-1"><span className="w-2.5 h-2.5" style={{ borderRadius: "var(--mc-r-sm)", background: "var(--mc-st-enroute)" }} />unterwegs</span>
          <span className="flex items-center gap-1"><span className="w-2.5 h-2.5" style={{ borderRadius: "var(--mc-r-sm)", background: "var(--mc-st-done)" }} />erledigt</span>
          <span className="flex items-center gap-1"><span className="w-2.5 h-2.5" style={{ borderRadius: "var(--mc-r-sm)", boxShadow: "0 0 0 1.5px var(--mc-st-problem)" }} />Konflikt</span>
        </div>
      </div>
      {/* Stundenachse */}
      <div className="flex">
        <div className="w-28 shrink-0" />
        <div className="relative flex-1 h-4">
          {hours.map((m) => <div key={m} className="absolute text-[9px]" style={{ left: `${pct(m)}%`, transform: "translateX(-50%)", color: "var(--mc-text-muted)" }}>{fromMin(m % 1440)}</div>)}
        </div>
      </div>
      <div className="max-h-[22rem] overflow-y-auto">
        {unassigned.length > 0 && <Row label="ohne Fahrer" sub={`${unassigned.length} Fahrt(en)`} rs={unassigned} warn />}
        {withDriver.map(({ d, rs }) => <Row key={d.id} label={`${d.firstName} ${d.lastName}`} sub={d.vehicleType === "Van" ? "Van" : "Car"} rs={rs} conflictCheck />)}
      </div>
    </div>
  );
}

/* ------------------------------ Live-Karte ------------------------------- */
// Kleiner Baustein: ein Ortsknoten + Label (mit Hintergrundfläche, Punkt 11).
function MapNode({ node }) {
  const s = NODE_STYLE[node.type] || NODE_STYLE.custom;
  const lx = node.x + (node.labelDx || 0), ly = node.y + (node.labelDy || 0);
  const w = node.short.length * 7.6 + 14;
  return (
    <g>
      {node.custom && <circle cx={node.x} cy={node.y} r={s.r + 3} fill="none" stroke="#57534e" strokeWidth="1" strokeDasharray="2 3" />}
      <circle cx={node.x} cy={node.y} r={s.r} fill={s.fill} stroke={s.stroke} strokeWidth="2.5" />
      {node.type === "festival" && <circle cx={node.x} cy={node.y} r={s.r + 5} fill="none" stroke={s.stroke} strokeWidth="1" opacity="0.4" />}
      <rect x={lx - w / 2} y={ly - 21} width={w} height={18} rx="4" fill="#0c0a09" stroke="#292524" strokeWidth="1" />
      <text x={lx} y={ly - 8} textAnchor="middle" fontSize="13" fill="#fafaf9" fontWeight="700">{node.short}</text>
    </g>
  );
}

// Kleiner Baustein: eine (gebogene) Routen-Linie.
function RoutePath({ a, b, color, dashed, width = 2, opacity = 1 }) {
  if (!a || !b) return null;
  const g = edgeGeom(a, b, curvFor(a.id, b.id));
  return <path d={g.path} fill="none" stroke={color} strokeWidth={width} opacity={opacity} strokeLinecap="round" strokeDasharray={dashed ? "7 6" : undefined} />;
}

// Kleiner Baustein: ein Fahrer-Marker (Fahrzeug-ID, Statusfarbe, Warnsymbol).
// Initialen aus Vor- und Nachname, für den kompakten Marker auf der Live-Karte.
const driverInitials = (d) => `${(d.firstName || "")[0] || ""}${(d.lastName || "")[0] || ""}`.toUpperCase();

function DriverMarker({ pos, selected, onSelect, onHover }) {
  if (!pos.xy) return null;
  const stl = STATUS_STYLE[pos.mode] || STATUS_STYLE.free;
  const r = selected ? 16 : 13;
  const warn = pos.problem || pos.lateMin > 0 || pos.uncertain;
  const warnColor = pos.problem ? "#ef4444" : pos.lateMin > 0 ? "#ef4444" : "#f59e0b";
  return (
    <g style={{ cursor: "pointer" }} onClick={() => onSelect(selected ? null : pos.driver.id)}
      onMouseEnter={() => onHover(pos.driver.id)} onMouseLeave={() => onHover(null)}>
      {selected && <circle cx={pos.xy.x} cy={pos.xy.y} r={r + 5} fill="none" stroke="#fdba74" strokeWidth="2.5" />}
      {/* GPS exakt = voll, geschätzt = gestrichelter Ring (Punkt 16) */}
      {pos.positionSource !== "gps" && <circle cx={pos.xy.x} cy={pos.xy.y} r={r + 2.5} fill="none" stroke={stl.fill} strokeWidth="1.5" strokeDasharray="2 2.5" opacity="0.6" />}
      <circle cx={pos.xy.x} cy={pos.xy.y} r={r} fill={stl.fill} stroke="#0c0a09" strokeWidth="2" />
      <text x={pos.xy.x} y={pos.xy.y + 3.8} textAnchor="middle" fontSize={selected ? "11.5" : "10.5"} fill="#0c0a09" fontWeight="800">{driverInitials(pos.driver)}</text>
      {warn && (
        <g>
          <circle cx={pos.xy.x + r - 1} cy={pos.xy.y - r + 1} r="6.5" fill={warnColor} stroke="#0c0a09" strokeWidth="1.2" />
          <text x={pos.xy.x + r - 1} y={pos.xy.y - r + 4.5} textAnchor="middle" fontSize="9.5" fill="#fff" fontWeight="800">!</text>
        </g>
      )}
    </g>
  );
}

// Kleiner Baustein: offene (unbesetzte) Fahrt als Hohl-Marker am Pickup.
function OpenRideMarker({ x, y, color, onClick, active }) {
  return (
    <g style={{ cursor: "pointer" }} onClick={onClick}>
      <rect x={x - 6} y={y - 6} width="12" height="12" rx="2" transform={`rotate(45 ${x} ${y})`}
        fill="#0c0a09" stroke={color} strokeWidth={active ? "2.5" : "1.8"} />
      {active && <rect x={x - 9} y={y - 9} width="18" height="18" rx="3" transform={`rotate(45 ${x} ${y})`} fill="none" stroke={color} strokeWidth="1" opacity="0.5" />}
    </g>
  );
}

// SVG-Tooltip beim Hovern (Punkt 10).
function MapTooltip({ pos, setup, nodes }) {
  if (!pos || !pos.xy) return null;
  const stl = STATUS_STYLE[pos.mode] || STATUS_STYLE.free;
  const nn = (id) => nodes[id]?.short || "?";
  const lines = [`${pos.driver.firstName} ${pos.driver.lastName} · ${pos.driver.vehicleType === "Van" ? "Van" : "Car"}`, stl.label];
  if (pos.ride) lines.push(`${nn(pos.fromId)} → ${nn(pos.toId)} · ${pos.ride.time}`);
  if (pos.etaMin != null) lines.push(`ETA ${pos.etaMin} min${pos.uncertain ? " (unsicher)" : ""}`);
  if (pos.lateMin > 0) lines.push(`⚠ ${pos.lateMin} min Verspätung`);
  if (pos.positionSource === "gps" && pos.gps?.at) lines.push(`📍 GPS · ${fmtAgo(pos.gps.at)}`);
  const w = 176, h = 14 + lines.length * 15;
  const flipX = pos.xy.x > MAP_VW - w - 20, flipY = pos.xy.y > MAP_VH - h - 20;
  const tx = flipX ? pos.xy.x - w - 14 : pos.xy.x + 14;
  const ty = flipY ? pos.xy.y - h - 8 : pos.xy.y + 8;
  return (
    <g pointerEvents="none">
      <rect x={tx} y={ty} width={w} height={h} rx="6" fill="#0c0a09" stroke="#44403c" strokeWidth="1" opacity="0.96" />
      {lines.map((l, i) => (
        <text key={i} x={tx + 9} y={ty + 17 + i * 15} fontSize="11" fill={i === 0 ? "#fafaf9" : "#a8a29e"} fontWeight={i === 0 ? "700" : "400"}>{l}</text>
      ))}
    </g>
  );
}

// Legende (Punkt: Farben/Zähler + geschätzt/GPS-Hinweis).
function MapLegend({ counts }) {
  return (
    <div className="flex flex-wrap gap-x-4 gap-y-1.5 px-2 pt-2 text-xs" style={{ color: "var(--mc-text-secondary)" }}>
      {Object.entries(STATUS_STYLE).map(([k, v]) => (
        <span key={k} className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full" style={{ background: v.fill }} />{v.label} ({counts[k] || 0})</span>
      ))}
      <span className="flex items-center gap-1.5" style={{ color: "var(--mc-text-muted)" }}><span className="w-2.5 h-2.5 rounded-full border" style={{ borderStyle: "dashed", borderColor: "var(--mc-text-muted)" }} />geschätzt</span>
      <span className="flex items-center gap-1.5" style={{ color: "var(--mc-text-muted)" }}><span className="w-2.5 h-2.5 rotate-45 border" style={{ borderColor: "var(--mc-text-muted)" }} />offene Fahrt</span>
    </div>
  );
}

// Filter (Punkt 13).
const MAP_FILTERS = [["all", "Alle"], ["unterwegs", "Unterwegs"], ["frei", "Frei"], ["verspaetet", "Verspätet"], ["problem", "Problem"], ["unbekannt", "Unbekannt"]];
function MapFilters({ value, onChange, counts }) {
  return (
    <div className="flex flex-wrap gap-1">
      {MAP_FILTERS.map(([k, l]) => (
        <button key={k} onClick={() => onChange(k)}
          className="text-xs px-2.5 py-1 border"
          style={{ borderRadius: "var(--mc-r)", ...(value === k
            ? { background: "var(--mc-st-assigned)", borderColor: "var(--mc-st-assigned)", color: "#ffffff" }
            : { background: "var(--mc-panel)", borderColor: "var(--mc-border)", color: "var(--mc-text-secondary)" }) }}>
          {l}{k !== "all" && counts[k] ? ` ${counts[k]}` : ""}
        </button>
      ))}
    </div>
  );
}

// Detail-Panel rechts (Punkt 12).
function DriverDetailsPanel({ pos, setup, nodes, onClose }) {
  const stl = STATUS_STYLE[pos.mode] || STATUS_STYLE.free;
  const nn = (id) => nodes[id]?.name || nodes[id]?.short || "unbekannt";
  const posText = (pos.mode === "onboard" || pos.mode === "toPickup")
    ? `unterwegs: ${nodes[pos.fromId]?.short || "?"} → ${nodes[pos.toId]?.short || "?"} (${Math.round(pos.f * 100)} %)`
    : nn(pos.nodeId);
  const srcLabel = { gps: "GPS", manual: "manuell gesetzt", estimated: "geschätzt" }[pos.positionSource];
  return (
    <div className="mc-panel p-3" style={{ borderColor: "var(--mc-st-assigned)" }}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-xs px-1.5 py-0.5" style={{ borderRadius: "var(--mc-r-sm)", fontFamily: "var(--mc-font-mono)", background: pos.driver.vehicleType === "Van" ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: pos.driver.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>{pos.driver.vehicleType === "Van" ? "Van" : "Car"}</span>
          <span className="text-sm font-medium" style={{ color: "var(--mc-text)" }}>{pos.driver.firstName} {pos.driver.lastName}</span>
        </div>
        <button onClick={onClose} className="mc-iconbtn w-7 h-7"><X className="w-4 h-4" /></button>
      </div>

      <div className="flex items-center gap-1.5 mt-2">
        <span className="w-2 h-2 rounded-full" style={{ background: stl.fill }} />
        <span className="text-xs" style={{ color: "var(--mc-text-secondary)" }}>{stl.label}</span>
        {pos.problem && <span className="mc-badge mc-badge--problem text-[10px]">Problem</span>}
        {pos.lateMin > 0 && <span className="mc-badge mc-badge--problem text-[10px]">+{pos.lateMin} min</span>}
      </div>

      <dl className="mt-3 space-y-1.5 text-xs">
        <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>Position</dt><dd className="text-right" style={{ color: "var(--mc-text)" }}>{posText}</dd></div>
        <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>Quelle</dt><dd style={{ color: "var(--mc-text-secondary)" }}>{srcLabel}{pos.uncertain ? " · unsicher" : ""}{pos.positionSource === "gps" && pos.gps?.at ? ` · ${fmtAgo(pos.gps.at)}` : ""}</dd></div>
        {pos.ride && (
          <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>Aktuelle Fahrt</dt><dd className="text-right" style={{ color: "var(--mc-text)" }}>{pos.ride.djName || "—"} · {pos.ride.time}{pos.ride.zone ? ` · ${pos.ride.zone}` : ""}</dd></div>
        )}
        {pos.etaMin != null && (
          <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>ETA Ziel</dt><dd style={{ color: "var(--mc-text)" }}>{pos.etaMin} min{pos.uncertain ? " (unsicher)" : ""}</dd></div>
        )}
        {pos.nextRide && (
          <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>Nächster Auftrag</dt><dd className="text-right" style={{ color: "var(--mc-text)" }}>{pos.nextRide.time} · {nodes[resolveNode(nodes, pos.nextRide.fromId, pos.nextRide.fromId === "festival" ? pos.nextRide.zone : null, pos.nextRide.fromCustom)]?.short || "?"} → {nodes[resolveNode(nodes, pos.nextRide.toId, pos.nextRide.zone, pos.nextRide.toCustom)]?.short || "?"}</dd></div>
        )}
        {pos.lastChange && (
          <div className="flex justify-between gap-2"><dt style={{ color: "var(--mc-text-muted)" }}>Letzte Änderung</dt><dd style={{ color: "var(--mc-text-secondary)" }}>{STATUS_LABEL[pos.lastChange.status] || pos.lastChange.status} · {fmtClock(pos.lastChange.at)}</dd></div>
        )}
      </dl>

      {pos.driver.phone
        ? <a href={`tel:${pos.driver.phone}`} className="mc-btn-primary mt-3 w-full inline-flex items-center justify-center gap-2 text-sm py-2" style={{ background: "var(--mc-st-done)", color: "#ffffff" }}><Navigation className="w-4 h-4" />Anrufen</a>
        : <div className="mt-3 text-[11px]" style={{ color: "var(--mc-text-muted)" }}>Keine Telefonnummer hinterlegt.</div>}
    </div>
  );
}
function fmtClock(ts) { const d = new Date(ts); return `${pad(d.getHours())}:${pad(d.getMinutes())}`; }
// Relative Frische einer GPS-Meldung ("vor 12s" / "vor 3 min").
function fmtAgo(ts) {
  const s = Math.max(0, Math.round((Date.now() - ts) / 1000));
  if (s < 60) return `vor ${s}s`;
  return `vor ${Math.round(s / 60)} min`;
}

// Die SVG-Karte selbst (Netz + Routen + offene Fahrten + Marker + Tooltip).
function SchematicMap({ nodes, positions, openRides, selected, hovered, onSelect, onHover, activeOpen, onOpenClick }) {
  const nodeList = Object.values(nodes);
  const festival = nodes.festival;
  const zoneNodes = nodeList.filter((n) => n.type === "zone");
  const hoveredPos = positions.find((p) => p.driver.id === hovered);
  const selectedPos = positions.find((p) => p.driver.id === selected);
  const movers = positions.filter((p) => (p.mode === "onboard" || p.mode === "toPickup") && p.fromXY && p.toXY);

  return (
    <svg viewBox={`0 0 ${MAP_VW} ${MAP_VH}`} className="w-full h-auto" style={{ maxHeight: 640 }}>
      {/* Basis-Netz */}
      {MAP_EDGES.map(([a, b], i) => nodes[a] && nodes[b] && <RoutePath key={i} a={nodes[a]} b={nodes[b]} color="#292524" width="3" />)}
      {festival && zoneNodes.map((z) => <RoutePath key={z.id} a={festival} b={z} color="#292524" width="2.5" />)}

      {/* aktive Fahrer-Routen (Punkt 6) */}
      {movers.map((p) => {
        const isSel = p.driver.id === selected;
        const col = p.mode === "onboard" ? "#f97316" : "#3b82f6";
        return <RoutePath key={"r" + p.driver.id} a={nodes[p.fromId]} b={nodes[p.toId]} color={col} dashed={p.mode === "toPickup"} width={isSel ? 4 : 2.5} opacity={isSel ? 1 : 0.75} />;
      })}

      {/* offene Fahrten (Punkt 14): Route der aktiven offenen Fahrt + Marker am Pickup */}
      {activeOpen && nodes[activeOpen.fromNode] && nodes[activeOpen.toNode] && (
        <RoutePath a={nodes[activeOpen.fromNode]} b={nodes[activeOpen.toNode]} color="#a8a29e" dashed width="2" opacity="0.8" />
      )}
      {openRides.map((o, i) => nodes[o.fromNode] && (
        <OpenRideMarker key={i} x={nodes[o.fromNode].x + o.ox} y={nodes[o.fromNode].y + o.oy} color={o.color}
          active={activeOpen === o} onClick={() => onOpenClick(activeOpen === o ? null : o)} />
      ))}

      {/* Knoten */}
      {nodeList.map((n) => <MapNode key={n.id} node={n} />)}

      {/* Fahrer-Marker (ausgewählter zuletzt = oben) */}
      {positions.filter((p) => p.xy && p.driver.id !== selected).map((p) => (
        <DriverMarker key={p.driver.id} pos={p} selected={false} onSelect={onSelect} onHover={onHover} />
      ))}
      {selectedPos && selectedPos.xy && <DriverMarker pos={selectedPos} selected onSelect={onSelect} onHover={onHover} />}

      {/* Tooltip */}
      {hoveredPos && hovered !== selected && <MapTooltip pos={hoveredPos} setup={null} nodes={nodes} />}
    </svg>
  );
}

// --- Mission-Control-Variante der Schema-Karte (Effekt 10) -----------------
// Nur fuer uiMode "mission-control". Classic nutzt weiter SchematicMap/DriverMarker
// byte-genau unveraendert. Einziger Unterschied: Fahrer-Marker gleiten bei kleiner
// Positionsaenderung weich (CSS-transform-Transition) statt hart zu springen; bei
// grossen Spruengen / erster Erscheinung teleportieren sie weiterhin. Reduced-motion
// greift automatisch ueber den ".mc-scope * { transition: none }"-Block (10035).
// KEINE Daten-/GPS-/Statuslogik: wir LESEN nur pos.xy (identisch zu DriverMarker).
const MC_GLIDE_MAX_JUMP = 90; // SVG-Nutzereinheiten; groesserer Sprung -> teleportieren statt gleiten
function mcMarkerAnimate(prev, cur) {
  if (!prev || !cur) return false;               // erste Erscheinung -> teleportieren (kein Gleiten)
  const dx = cur.x - prev.x, dy = cur.y - prev.y;
  return (dx * dx + dy * dy) <= MC_GLIDE_MAX_JUMP * MC_GLIDE_MAX_JUMP;
}

// Wie DriverMarker, aber die Position sitzt als CSS-transform am aeusseren <g>
// (Kinder relativ zu 0,0), damit sie per CSS-Transition weich wandern kann.
// cx/cy lassen sich nicht zuverlaessig transitionen, transform schon.
function MissionDriverMarker({ pos, selected, animate, onSelect, onHover }) {
  if (!pos.xy) return null;
  const stl = STATUS_STYLE[pos.mode] || STATUS_STYLE.free;
  const r = selected ? 16 : 13;
  const warn = pos.problem || pos.lateMin > 0 || pos.uncertain;
  const warnColor = pos.problem ? "#ef4444" : pos.lateMin > 0 ? "#ef4444" : "#f59e0b";
  return (
    <g
      style={{
        cursor: "pointer",
        transform: `translate(${pos.xy.x}px, ${pos.xy.y}px)`,
        transition: animate ? "transform var(--mc-anim-slow) var(--mc-ease)" : "none",
      }}
      onClick={() => onSelect(selected ? null : pos.driver.id)}
      onMouseEnter={() => onHover(pos.driver.id)} onMouseLeave={() => onHover(null)}>
      {selected && <circle cx={0} cy={0} r={r + 5} fill="none" stroke="#fdba74" strokeWidth="2.5" />}
      {/* GPS exakt = voll, geschätzt = gestrichelter Ring (Punkt 16) */}
      {pos.positionSource !== "gps" && <circle cx={0} cy={0} r={r + 2.5} fill="none" stroke={stl.fill} strokeWidth="1.5" strokeDasharray="2 2.5" opacity="0.6" />}
      <circle cx={0} cy={0} r={r} fill={stl.fill} stroke="#0c0a09" strokeWidth="2" />
      <text x={0} y={3.8} textAnchor="middle" fontSize={selected ? "11.5" : "10.5"} fill="#0c0a09" fontWeight="800">{driverInitials(pos.driver)}</text>
      {warn && (
        <g>
          <circle cx={r - 1} cy={-r + 1} r="6.5" fill={warnColor} stroke="#0c0a09" strokeWidth="1.2" />
          <text x={r - 1} y={-r + 4.5} textAnchor="middle" fontSize="9.5" fill="#fff" fontWeight="800">!</text>
        </g>
      )}
    </g>
  );
}

// Wie SchematicMap, aber mit gleitenden Fahrer-Markern. Zwei bewusste Unterschiede
// gegenueber der Classic-Variante, damit CSS-Transitionen ueberhaupt feuern:
//  1) EIN Knoten je Fahrer mit stabilem, positions-unabhaengigem Key (Identitaet
//     bleibt ueber Renders erhalten). Der ausgewaehlte wird NICHT als zweites
//     Element gedoppelt, sondern nur zuletzt gezeichnet (oben).
//  2) Sprung-vs-Gleiten-Heuristik: kleine Schritte gleiten, grosse teleportieren.
function MissionSchematicMap({ nodes, positions, openRides, selected, hovered, onSelect, onHover, activeOpen, onOpenClick }) {
  const nodeList = Object.values(nodes);
  const festival = nodes.festival;
  const zoneNodes = nodeList.filter((n) => n.type === "zone");
  const hoveredPos = positions.find((p) => p.driver.id === hovered);
  const movers = positions.filter((p) => (p.mode === "onboard" || p.mode === "toPickup") && p.fromXY && p.toXY);

  // letzte gerenderte x/y je Fahrer merken (rein fuer die Anzeige, keine
  // Fach-/Schreiblogik). Update nach dem Commit, damit der Vergleich beim
  // naechsten Render gegen den zuletzt gezeichneten Stand laeuft.
  const lastXY = useRef({});
  const animateMap = {};
  positions.forEach((p) => { if (p.xy) animateMap[p.driver.id] = mcMarkerAnimate(lastXY.current[p.driver.id], p.xy); });
  useLayoutEffect(() => {
    const next = {};
    positions.forEach((p) => { if (p.xy) next[p.driver.id] = { x: p.xy.x, y: p.xy.y }; });
    lastXY.current = next;
  });

  // Ein Knoten je Fahrer; ausgewaehlter zuletzt (= oben). Sortierung aendert nur
  // die Zeichenreihenfolge, dank stabilem Key bleibt die Identitaet erhalten.
  const orderedMarkers = positions.filter((p) => p.xy)
    .sort((a, b) => (a.driver.id === selected ? 1 : 0) - (b.driver.id === selected ? 1 : 0));

  return (
    <svg viewBox={`0 0 ${MAP_VW} ${MAP_VH}`} className="w-full h-auto" style={{ maxHeight: 640 }}>
      {/* Basis-Netz */}
      {MAP_EDGES.map(([a, b], i) => nodes[a] && nodes[b] && <RoutePath key={i} a={nodes[a]} b={nodes[b]} color="#292524" width="3" />)}
      {festival && zoneNodes.map((z) => <RoutePath key={z.id} a={festival} b={z} color="#292524" width="2.5" />)}

      {/* aktive Fahrer-Routen (Punkt 6) */}
      {movers.map((p) => {
        const isSel = p.driver.id === selected;
        const col = p.mode === "onboard" ? "#f97316" : "#3b82f6";
        return <RoutePath key={"r" + p.driver.id} a={nodes[p.fromId]} b={nodes[p.toId]} color={col} dashed={p.mode === "toPickup"} width={isSel ? 4 : 2.5} opacity={isSel ? 1 : 0.75} />;
      })}

      {/* offene Fahrten (Punkt 14) */}
      {activeOpen && nodes[activeOpen.fromNode] && nodes[activeOpen.toNode] && (
        <RoutePath a={nodes[activeOpen.fromNode]} b={nodes[activeOpen.toNode]} color="#a8a29e" dashed width="2" opacity="0.8" />
      )}
      {openRides.map((o, i) => nodes[o.fromNode] && (
        <OpenRideMarker key={i} x={nodes[o.fromNode].x + o.ox} y={nodes[o.fromNode].y + o.oy} color={o.color}
          active={activeOpen === o} onClick={() => onOpenClick(activeOpen === o ? null : o)} />
      ))}

      {/* Knoten */}
      {nodeList.map((n) => <MapNode key={n.id} node={n} />)}

      {/* Fahrer-Marker: EIN Knoten je Fahrer, stabiler Key (Transition-Identitaet),
          ausgewaehlter zuletzt gezeichnet = oben (SVG kennt kein z-index). */}
      {orderedMarkers.map((p) => (
        <MissionDriverMarker key={p.driver.id} pos={p} selected={p.driver.id === selected}
          animate={animateMap[p.driver.id]} onSelect={onSelect} onHover={onHover} />
      ))}

      {/* Tooltip */}
      {hoveredPos && hovered !== selected && <MapTooltip pos={hoveredPos} setup={null} nodes={nodes} />}
    </svg>
  );
}

// Gemeinsame Berechnung (von großer Karte und Board-Minikarte genutzt).
function computeMapPositions(setup, dyn, day, nowMin, mode, nodes) {
  const ctx = { setup, dyn, dayKey: day, nowMin, mode, nodes };
  const list = setup.drivers.map((d) => {
    const pos = estimateDriverPosition(ctx, d);
    let xy = null, fromXY = null, toXY = null;
    if ((pos.mode === "onboard" || pos.mode === "toPickup") && nodes[pos.fromId] && nodes[pos.toId]) {
      fromXY = nodes[pos.fromId]; toXY = nodes[pos.toId];
      const g = edgeGeom(fromXY, toXY, curvFor(pos.fromId, pos.toId));
      xy = edgePointAt(g, pos.f);
    } else if (nodes[pos.nodeId]) {
      xy = { x: nodes[pos.nodeId].x, y: nodes[pos.nodeId].y };
    }
    return { ...pos, xy, fromXY, toXY };
  });
  const buckets = {};
  list.forEach((p) => { if (!p.xy || p.fromXY) return; const k = p.nodeId; (buckets[k] = buckets[k] || []).push(p); });
  Object.values(buckets).forEach((grp) => {
    if (grp.length === 1) return;
    const rad = 17 + grp.length * 1.8;
    grp.forEach((p, i) => { const ang = (i / grp.length) * Math.PI * 2 - Math.PI / 2; p.xy = { x: p.xy.x + Math.cos(ang) * rad, y: p.xy.y + Math.sin(ang) * rad }; });
  });
  return list;
}
function computeOpenRides(setup, dyn, day, nodes) {
  const list = (dyn.rides || []).filter((r) => r.dayKey === day && !r.assignedDriverId && r.status !== "cancelled");
  const perNode = {};
  return list.map((r) => {
    const fromNode = resolveNode(nodes, r.fromId, r.fromId === "festival" ? r.zone : null, r.fromCustom);
    const toNode = resolveNode(nodes, r.toId, r.zone, r.toCustom);
    const n = (perNode[fromNode] = (perNode[fromNode] || 0) + 1);
    const color = r.type === "arrival" ? "#38bdf8" : r.type === "return" ? "#fb923c" : "#e879f9";
    return { ride: r, fromNode, toNode, color, ox: 16 + (n - 1) * 6, oy: -16 - (n - 1) * 6 };
  });
}

// Kompakte Live-Karte für die Board-Ansicht (breite Bildschirme, mitscrollend).
function BoardMiniMap({ setup, dyn, day, onEdit, SchematicComponent = SchematicMap }) {
  const isToday = dayNowMin(day) >= 0 && dayNowMin(day) < 90000;
  const [simMin, setSimMin] = useState(isToday ? dayNowMin(day) : 1080);
  const [selected, setSelected] = useState(null);
  const [hovered, setHovered] = useState(null);
  const mode = isToday ? "live" : "sim";
  const nowMin = isToday ? dayNowMin(day) : simMin;
  const nodes = useMemo(() => buildMapNodes(setup, dyn, day), [setup, dyn.rides, day]);
  const positions = useMemo(() => computeMapPositions(setup, dyn, day, nowMin, mode, nodes), [setup, dyn, day, nowMin, mode, nodes]);
  const openRides = useMemo(() => computeOpenRides(setup, dyn, day, nodes), [dyn.rides, day, nodes]);
  const counts = { onboard: 0, toPickup: 0, free: 0 };
  positions.forEach((p) => { counts[p.mode] = (counts[p.mode] || 0) + 1; });
  const sel = positions.find((p) => p.driver.id === selected);

  return (
    <div className="mc-panel p-2">
      <div className="flex items-center gap-2 px-1 pb-1.5">
        <MapIcon className="w-4 h-4" style={{ color: "var(--mc-text-secondary)" }} />
        <span className="mc-eyebrow">Live-Karte</span>
        {!isToday && (
          <div className="flex items-center gap-1.5 flex-1 min-w-0">
            <span className="text-[11px] w-9 shrink-0" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-secondary)" }}>{fromMin(nowMin < 0 ? 720 : nowMin)}</span>
            <input type="range" min="720" max="1620" step="5" value={Math.min(1620, Math.max(720, nowMin < 0 ? 720 : nowMin))}
              onChange={(e) => setSimMin(Number(e.target.value))} className="flex-1 h-1" style={{ accentColor: "var(--mc-st-assigned)" }} />
          </div>
        )}
        {isToday && <span className="text-[10px] ml-auto flex items-center gap-1.5" style={{ color: "var(--mc-st-done)" }}><span className="mc-live-dot" />live</span>}
      </div>
      <SchematicComponent nodes={nodes} positions={positions} openRides={openRides}
        selected={selected} hovered={hovered} onSelect={setSelected} onHover={setHovered}
        activeOpen={null} onOpenClick={() => {}} />
      <div className="flex flex-wrap gap-x-3 gap-y-1 px-1 pt-1.5 text-[10px]" style={{ color: "var(--mc-text-muted)" }}>
        {Object.entries(STATUS_STYLE).map(([k, v]) => (
          <span key={k} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{ background: v.fill }} />{v.label} ({counts[k] || 0})</span>
        ))}
      </div>
      {sel && (
        <button onClick={() => onEdit && sel.ride && onEdit(sel.ride)} className="mc-ride-card w-full text-left mt-1.5 px-2 py-1.5 text-xs">
          <span style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text)" }}>{sel.driver.vehicleType === "Van" ? "Van" : "Car"}</span>
          <span style={{ color: "var(--mc-text-secondary)" }}> · {sel.driver.firstName} {sel.driver.lastName} · {STATUS_STYLE[sel.mode]?.label}</span>
          {sel.ride && <span style={{ color: "var(--mc-text-muted)" }}> · {nodes[sel.fromId]?.short} → {nodes[sel.toId]?.short}</span>}
        </button>
      )}
    </div>
  );
}

// Echte Google-Maps-Ansicht mit den Live-GPS-Positionen der Fahrer
// (driverState[driverId].gps, siehe useDriverLocationSharing weiter oben).
// WICHTIG fürs Kontingent: google.maps.Map wird nur EINMAL erzeugt (mapRef),
// danach nur noch Marker-Positionen aktualisiert (setPosition) statt die
// Karte neu zu laden — ein "Map Load" zählt beim Erzeugen, nicht bei
// Marker-Updates. Zeigt nur Fahrer mit einer GPS-Position, die jünger als
// GPS_MAX_AGE_MS ist; ältere/keine Position -> kein Marker (statt eine
// falsche/veraltete Position zu zeigen, siehe gpsOverrideF oben).
// InfoWindow-Inhalt ist rohes HTML (Google-Maps-API) - Namen/Telefon o.ä.
// deshalb immer escapen, bevor sie da reinkommen (sonst potenzielles HTML/
// Skript-Einschleusen über Fahrer-Stammdaten möglich).
function escapeHtml(s) {
  return String(s ?? "").replace(/[&<>"']/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));
}
function driverInfoWindowHtml(driver, fix) {
  const ageS = fix?.at ? Math.round((Date.now() - fix.at) / 1000) : null;
  const ageTxt = ageS == null ? "unbekannt" : ageS < 60 ? `vor ${ageS}s` : `vor ${Math.round(ageS / 60)} Min`;
  return `<div style="font:12px sans-serif;color:#1c1917;min-width:150px;line-height:1.5">
    <div style="font-weight:700;margin-bottom:2px;">${escapeHtml(driver.firstName)} ${escapeHtml(driver.lastName)}</div>
    <div>${driver.vehicleType === "Van" ? "Van" : "Car"}${driver.vehicleId ? " · " + escapeHtml(driver.vehicleId) : ""}</div>
    ${driver.phone ? `<div>${escapeHtml(driver.phone)}</div>` : ""}
    <div style="color:#78716c;margin-top:4px;font-size:11px;">Position ${ageTxt} aktualisiert</div>
  </div>`;
}
// Weiches Gleiten der Google-Marker (Effekt 10, Teil 2). Reine Helfer, damit sie
// testbar sind. GOOGLE_GLIDE_MS orientiert sich an --mc-anim-slow. Grosse Spruenge
// (keine Ausgangsposition, GPS-Fix weit weg) werden hart gesetzt statt ueber die
// halbe Karte zu fliegen.
const GOOGLE_GLIDE_MS = 380;
// Session 27e: Google zeichnet seine Marker auf ein Canvas und versteht KEINE
// CSS-Variablen, deshalb hier echte Hex-Werte. Sie sind 1:1 die MC-Tokens, damit
// die Google-Karte dieselbe Sprache spricht wie die Schema-Karte:
//   Van = --mc-st-assigned, Car = --mc-st-new (dieselbe Zuordnung wie in
//   AssignModal und DriverDetailsPanel), Ort = --mc-st-idle, Kontur = --mc-bg.
// Wenn ein Token in MissionStyles geaendert wird, muss es hier mitgezogen werden,
// automatisch geht das nicht.
const GMAP_COLORS = { van: "#f5a524", car: "#4b90f6", place: "#7c8797", stroke: "#0a0c10" };
const GOOGLE_GLIDE_MAX_JUMP_DEG = 0.02; // ~2 km; groesserer Sprung -> hart setzen
function googleMarkerBigJump(from, to) {
  if (!from || !to) return true;
  const dLat = to.lat - from.lat, dLng = to.lng - from.lng;
  return (dLat * dLat + dLng * dLng) > GOOGLE_GLIDE_MAX_JUMP_DEG * GOOGLE_GLIDE_MAX_JUMP_DEG;
}

function LiveGoogleMap({ setup, dyn, glide = false }) {
  const containerRef = useRef(null);
  const mapRef = useRef(null);
  const markersRef = useRef({}); // driverId -> google.maps.Marker
  const animRef = useRef({}); // driverId -> laufende rAF-Id (weiches Gleiten, nur MC)
  const infoWindowRef = useRef(null); // ein einziges, wiederverwendetes Info-Fenster
  const driverDataRef = useRef({}); // driverId -> { driver, fix } - immer der aktuelle Stand,
  // damit ein Klick auf einen älteren Marker keine veralteten Daten zeigt
  // (der Klick-Handler wird nur EINMAL beim Anlegen des Markers gesetzt).
  const [status, setStatus] = useState(hasGoogleMaps() ? "loading" : "no-key"); // loading|ready|error|no-key
  const [errorMsg, setErrorMsg] = useState("");

  // Weiches Gleiten (nur MC): alte -> neue Position per rAF ueber GOOGLE_GLIDE_MS
  // interpolieren. Pro Marker nur EIN Loop; ein neuer Aufruf bricht den laufenden
  // ab (kein Ueberlagern). Kein Dauerloop: bei t=1 wird die rAF-Id geloescht.
  const animateMarkerTo = (id, marker, to) => {
    if (animRef.current[id]) { cancelAnimationFrame(animRef.current[id]); delete animRef.current[id]; }
    const p0 = marker.getPosition();
    const from = p0 ? { lat: p0.lat(), lng: p0.lng() } : to;
    const t0 = (typeof performance !== "undefined" ? performance.now() : Date.now());
    const step = (now) => {
      const t = Math.min(1, (now - t0) / GOOGLE_GLIDE_MS);
      marker.setPosition({ lat: from.lat + (to.lat - from.lat) * t, lng: from.lng + (to.lng - from.lng) * t });
      if (t < 1) { animRef.current[id] = requestAnimationFrame(step); }
      else { delete animRef.current[id]; }
    };
    animRef.current[id] = requestAnimationFrame(step);
  };

  // beim Unmount alle laufenden Interpolationen abraeumen (kein Loop nach Ende)
  useEffect(() => () => {
    Object.values(animRef.current).forEach((raf) => cancelAnimationFrame(raf));
    animRef.current = {};
  }, []);

  useEffect(() => {
    if (!hasGoogleMaps()) { setStatus("no-key"); return; }
    let cancelled = false;
    loadGoogleMapsApi().then((maps) => {
      if (cancelled || !containerRef.current) return;
      const locs = (setup.locations || []).filter((l) => l.lat != null && l.lng != null);
      const center = locs.length
        ? { lat: locs.reduce((s, l) => s + l.lat, 0) / locs.length, lng: locs.reduce((s, l) => s + l.lng, 0) / locs.length }
        : { lat: 49.55, lng: 10.95 }; // Großraum Nürnberg/Herzogenaurach als Fallback
      mapRef.current = new maps.Map(containerRef.current, {
        center, zoom: 11, streetViewControl: false, mapTypeControl: false, fullscreenControl: false,
      });
      infoWindowRef.current = new maps.InfoWindow();
      locs.forEach((l) => {
        new maps.Marker({
          position: { lat: l.lat, lng: l.lng }, map: mapRef.current, title: l.name,
          icon: { path: maps.SymbolPath.CIRCLE, scale: 6, fillColor: GMAP_COLORS.place, fillOpacity: 1, strokeColor: GMAP_COLORS.stroke, strokeWeight: 1.5 },
        });
      });
      setStatus("ready");
    }).catch((e) => { if (!cancelled) { setStatus("error"); setErrorMsg(e?.message || "Fehler beim Laden von Google Maps."); } });
    return () => { cancelled = true; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // bewusst nur beim ersten Mount: die Karte selbst soll nicht neu erzeugt werden

  useEffect(() => {
    if (status !== "ready" || !window.google?.maps || !mapRef.current) return;
    const maps = window.google.maps;
    const seen = new Set();
    (setup.drivers || []).forEach((d) => {
      const fix = dyn.driverState?.[d.id]?.gps;
      const fresh = fix && fix.lat != null && fix.lng != null && fix.at && (Date.now() - fix.at) <= GPS_MAX_AGE_MS;
      if (!fresh) return;
      seen.add(d.id);
      driverDataRef.current[d.id] = { driver: d, fix }; // immer aktuell halten, siehe Klick-Handler unten
      const pos = { lat: fix.lat, lng: fix.lng };
      const title = `${d.vehicleType === "Van" ? "Van" : "Car"} · ${d.firstName} ${d.lastName}`;
      // Initialen direkt auf dem Marker sichtbar (Google-Maps-Marker-Label,
      // kein eigenes Icon/SVG nötig) - sonst sind bei mehreren Fahrern auf
      // der Karte nur gleichfarbige Punkte zu unterscheiden.
      const initials = `${(d.firstName || "?")[0] || "?"}${(d.lastName || "")[0] || ""}`.toUpperCase();
      const markerLabel = { text: initials, color: GMAP_COLORS.stroke, fontSize: "10px", fontWeight: "700" };
      if (markersRef.current[d.id]) {
        const marker = markersRef.current[d.id];
        const p0 = marker.getPosition();
        const from = p0 ? { lat: p0.lat(), lng: p0.lng() } : null;
        if (glide && !prefersReducedMotion() && !googleMarkerBigJump(from, pos)) {
          animateMarkerTo(d.id, marker, pos);   // weich per rAF (nur MC)
        } else {
          if (animRef.current[d.id]) { cancelAnimationFrame(animRef.current[d.id]); delete animRef.current[d.id]; }
          marker.setPosition(pos);              // hart: Classic, reduced-motion oder grosser Sprung
        }
        marker.setLabel(markerLabel);
      } else {
        const marker = new maps.Marker({
          position: pos, map: mapRef.current, title, label: markerLabel,
          icon: { path: maps.SymbolPath.CIRCLE, scale: 11, fillColor: d.vehicleType === "Van" ? GMAP_COLORS.van : GMAP_COLORS.car, fillOpacity: 1, strokeColor: GMAP_COLORS.stroke, strokeWeight: 2 },
        });
        // Klick-Handler wird nur EINMAL beim Anlegen gesetzt, liest aber bei
        // jedem Klick aus driverDataRef.current -> zeigt immer die zuletzt
        // bekannte Position/Zeit, auch wenn der Marker schon länger existiert.
        marker.addListener("click", () => {
          const cur = driverDataRef.current[d.id] || { driver: d, fix };
          infoWindowRef.current.setContent(driverInfoWindowHtml(cur.driver, cur.fix));
          infoWindowRef.current.open(mapRef.current, marker);
        });
        markersRef.current[d.id] = marker;
      }
    });
    // Marker für Fahrer ohne (mehr) frische GPS-Position entfernen
    Object.keys(markersRef.current).forEach((id) => {
      if (!seen.has(id)) {
        if (animRef.current[id]) { cancelAnimationFrame(animRef.current[id]); delete animRef.current[id]; }
        markersRef.current[id].setMap(null); delete markersRef.current[id];
      }
    });
  }, [status, setup.drivers, dyn.driverState]);

  if (status === "no-key") {
    return (
      <div className="mc-scope">
        <EmptyState icon={MapIcon} title="Kein Google-Maps-Key hinterlegt"
          hint={<>Env-Variable <code style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text-secondary)" }}>VITE_GOOGLE_MAPS_API_KEY</code> fehlt. Die Schema-Karte bleibt kostenlos nutzbar.</>} />
      </div>
    );
  }
  if (status === "error") {
    return <div className="mc-scope"><ErrorState title="Google Maps nicht geladen" message={errorMsg} /></div>;
  }
  return (
    <div className="mc-scope">
      {/* eigene Flaeche unter der Karte: bis Google gezeichnet hat, stand hier
          sonst ein leeres Rechteck im Browser-Weiss statt im MC-Dunkel. */}
      <div ref={containerRef} style={{ width: "100%", height: 420, borderRadius: "var(--mc-r-lg)", overflow: "hidden", background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }} />
      {status === "loading" && <div className="text-xs px-1 pt-1.5 flex items-center gap-1.5" style={{ color: "var(--mc-text-secondary)" }}><RefreshCw className="w-3 h-3 animate-spin" />Google Maps wird geladen…</div>}
      <div className="text-[11px] px-1 pt-1.5" style={{ color: "var(--mc-text-muted)" }}>Zeigt nur Fahrer mit aktueller GPS-Freigabe (jünger als {Math.round(GPS_MAX_AGE_MS / 60000)} Min).</div>
    </div>
  );
}

// Zeigt Fahrer, die HEUTE mindestens eine Fahrt haben, aber aktuell keine
// frische GPS-Position teilen (siehe useDriverLocationSharing weiter oben,
// landet in driverState[id].gps) — damit die Leitstelle proaktiv nachhaken
// kann ("Fahrer XY, kannst du den Standort aktivieren?"), statt es erst an
// einer leeren Stelle auf der Karte zu bemerken. Fahrer ohne Fahrt heute
// werden bewusst nicht gelistet, sonst wäre die Liste bei einem mehrtägigen
// Festival ständig voll mit Leuten, die einfach nicht im Dienst sind.
function NoGpsSharingPanel({ setup, dyn, day }) {
  const withoutGps = useMemo(() => {
    return (setup.drivers || []).filter((d) => {
      if (driverDay(dyn.rides || [], d.id, day).length === 0) return false;
      const fix = dyn.driverState?.[d.id]?.gps;
      const fresh = fix && fix.lat != null && fix.at && (Date.now() - fix.at) <= GPS_MAX_AGE_MS;
      return !fresh;
    });
  }, [setup.drivers, dyn.rides, dyn.driverState, day]);

  if (withoutGps.length === 0) return null; // nichts Auffälliges -> kein leeres/beruhigendes Panel nötig

  return (
    <div className="mc-panel p-3" style={{ borderColor: "var(--mc-st-assigned)" }}>
      <div className="text-xs mb-2 flex items-center gap-1.5" style={{ color: "var(--mc-st-assigned)" }}><AlertTriangle className="w-3.5 h-3.5" />Kein Live-Standort ({withoutGps.length})</div>
      <div className="space-y-1">
        {withoutGps.map((d) => (
          <div key={d.id} className="flex items-center gap-2 text-xs">
            <span className="text-[10px] px-1.5 py-0.5 shrink-0" style={{ borderRadius: "var(--mc-r-sm)", fontFamily: "var(--mc-font-mono)", background: d.vehicleType === "Van" ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)", color: d.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
            <span className="truncate flex-1" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName}</span>
            {d.phone && <a href={`tel:${d.phone}`} className="mc-iconbtn shrink-0 w-6 h-6" title={`Anrufen: ${d.phone}`}><Navigation className="w-3.5 h-3.5 rotate-90" /></a>}
          </div>
        ))}
      </div>
    </div>
  );
}

function MapTab({ setup, dyn, day, onEdit, SchematicComponent = SchematicMap, glideMarkers = false }) {
  const isToday = dayNowMin(day) >= 0 && dayNowMin(day) < 90000;
  const [mode, setMode] = useState(isToday ? "live" : "sim");   // 'live' | 'sim' (Punkt 8)
  const [simMin, setSimMin] = useState(isToday ? dayNowMin(day) : 1080);
  const [, setTick] = useState(0);
  const [selected, setSelected] = useState(null);
  const [hovered, setHovered] = useState(null);
  const [filter, setFilter] = useState("all");
  const [activeOpen, setActiveOpen] = useState(null);
  // 'schema' = kostenlose eigene Karte (Standard), 'google' = echte Google-Maps-Ansicht
  // mit Live-GPS — bewusst nicht automatisch aktiv, siehe LiveGoogleMap oben.
  const [mapView, setMapView] = useState("schema");

  useEffect(() => { setMode(isToday ? "live" : "sim"); if (isToday) setSimMin(dayNowMin(day)); }, [day, isToday]);
  useEffect(() => { if (mode !== "live") return; const t = setInterval(() => setTick((x) => x + 1), 15000); return () => clearInterval(t); }, [mode]);
  const nowMin = mode === "live" ? (isToday ? dayNowMin(day) : -1) : simMin;

  const nodes = useMemo(() => buildMapNodes(setup, dyn, day), [setup, dyn.rides, day]);

  // Positionen berechnen + auf Karte verorten
  const positions = useMemo(() => computeMapPositions(setup, dyn, day, nowMin, mode, nodes), [setup, dyn, day, nowMin, mode, nodes]);

  // Offene (unbesetzte) Fahrten (Punkt 14)
  const openRides = useMemo(() => computeOpenRides(setup, dyn, day, nodes), [dyn.rides, day, nodes]);

  // Zähler
  const counts = { onboard: 0, toPickup: 0, free: 0, unterwegs: 0, frei: 0, verspaetet: 0, problem: 0, unbekannt: 0 };
  positions.forEach((p) => { counts[p.mode] = (counts[p.mode] || 0) + 1; driverTags(p).forEach((t) => counts[t] = (counts[t] || 0) + 1); });

  const shown = positions.filter((p) => filter === "all" || driverTags(p).includes(filter));
  const selPos = positions.find((p) => p.driver.id === selected);

  return (
    <div>
      <div className="flex flex-wrap items-center gap-3 mb-3">
        <h3 className="text-sm flex items-center gap-2" style={{ color: "var(--mc-text-secondary)" }}><MapIcon className="w-4 h-4" />Shuttle-Netz · {fmtDate(day)}</h3>
        <div className="flex items-center gap-1 p-0.5" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
          <button onClick={() => { setMode("live"); if (isToday) setSimMin(dayNowMin(day)); }}
            className="text-xs px-2.5 py-1" style={{ borderRadius: "var(--mc-r-sm)", ...(mode === "live" ? { background: "var(--mc-st-done)", color: "#ffffff" } : { color: "var(--mc-text-muted)" }) }}>{isToday ? "Live" : "Live"}</button>
          <button onClick={() => setMode("sim")}
            className="text-xs px-2.5 py-1" style={{ borderRadius: "var(--mc-r-sm)", ...(mode === "sim" ? { background: "var(--mc-st-assigned)", color: "#ffffff" } : { color: "var(--mc-text-muted)" }) }}>Simulation</button>
        </div>
        <div className="flex items-center gap-2 flex-1 min-w-[220px]">
          <span className="text-sm w-12" style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text)" }}>{fromMin(nowMin < 0 ? 720 : nowMin > 1620 ? 1620 : nowMin)}</span>
          <input type="range" min="720" max="1620" step="5" disabled={mode === "live"}
            value={Math.min(1620, Math.max(720, nowMin < 0 ? 720 : nowMin))}
            onChange={(e) => { setMode("sim"); setSimMin(Number(e.target.value)); }}
            className="flex-1 disabled:opacity-40" style={{ accentColor: "var(--mc-st-assigned)" }} />
        </div>
      </div>

      <div className="mb-3 flex flex-wrap items-center gap-3">
        <MapFilters value={filter} onChange={setFilter} counts={counts} />
        <div className="flex items-center gap-1 p-0.5" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
          <button onClick={() => setMapView("schema")}
            className="text-xs px-2.5 py-1" style={{ borderRadius: "var(--mc-r-sm)", ...(mapView === "schema" ? { background: "var(--mc-text)", color: "var(--mc-bg)", fontWeight: 500 } : { color: "var(--mc-text-muted)" }) }}>Schema-Karte</button>
          <button onClick={() => setMapView("google")} title="Lädt Google Maps (externe Verbindung, siehe BACKEND-README)"
            className="text-xs px-2.5 py-1" style={{ borderRadius: "var(--mc-r-sm)", ...(mapView === "google" ? { background: "var(--mc-text)", color: "var(--mc-bg)", fontWeight: 500 } : { color: "var(--mc-text-muted)" }) }}>Google Maps</button>
        </div>
      </div>

      {mode === "live" && !isToday && (
        <div className="text-xs mb-2" style={{ color: "var(--mc-st-assigned)" }}>Live-Modus zeigt den echten Status – am gewählten (zukünftigen) Tag noch nichts unterwegs. Für „wer ist wann wo" auf Simulation wechseln.</div>
      )}
      {mode === "sim" && (
        <div className="text-xs mb-2" style={{ color: "var(--mc-text-muted)" }}>Simulation: reiner Fahrplan zur gewählten Uhrzeit (Status/Zeitstempel werden ignoriert).</div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        <div className="mc-panel lg:col-span-3 p-2">
          {mapView === "google" ? (
            <LiveGoogleMap setup={setup} dyn={dyn} glide={glideMarkers} />
          ) : (
            <>
              <SchematicComponent nodes={nodes} positions={shown} openRides={openRides}
                selected={selected} hovered={hovered} onSelect={setSelected} onHover={setHovered}
                activeOpen={activeOpen} onOpenClick={setActiveOpen} />
              <MapLegend counts={counts} />
            </>
          )}
        </div>

        <div className="space-y-3">
          {selPos && <DriverDetailsPanel pos={selPos} setup={setup} nodes={nodes} onClose={() => setSelected(null)} />}

          <NoGpsSharingPanel setup={setup} dyn={dyn} day={day} />

          {/* Offene Fahrten */}
          <div className="mc-panel p-3">
            <div className="text-xs mb-2 flex items-center gap-1.5" style={{ color: "var(--mc-text-secondary)" }}><Navigation className="w-3.5 h-3.5" />Offene Fahrten ({openRides.length})</div>
            <div className="space-y-1 max-h-48 overflow-y-auto">
              {openRides.length === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>alle Fahrten zugeteilt</div>}
              {openRides.sort((a, b) => sortMin(a.ride.time) - sortMin(b.ride.time)).map((o, i) => (
                <button key={i} onClick={() => setActiveOpen(activeOpen === o ? null : o)}
                  className="mc-ride-card w-full flex items-center gap-2 text-left text-xs px-1.5 py-1"
                  style={activeOpen === o ? { borderColor: "var(--mc-text)" } : undefined}>
                  <span className="w-2 h-2 rotate-45 shrink-0" style={{ background: o.color }} />
                  <span style={{ fontFamily: "var(--mc-font-mono)", color: "var(--mc-text)" }}>{o.ride.time}</span>
                  <span className="truncate" style={{ color: "var(--mc-text-secondary)" }}>{nodes[o.fromNode]?.short || "?"} → {nodes[o.toNode]?.short || "?"}</span>
                  <span className="ml-auto shrink-0" style={{ color: "var(--mc-text-muted)" }}>{o.ride.passengerCount}P</span>
                </button>
              ))}
            </div>
          </div>

          {/* Unterwegs */}
          <div className="mc-panel p-3">
            <div className="text-xs mb-2" style={{ color: "var(--mc-text-secondary)" }}>Unterwegs ({counts.unterwegs || 0})</div>
            <div className="space-y-1">
              {positions.filter((p) => p.mode === "onboard" || p.mode === "toPickup").sort((a, b) => a.driver.vehicleId.localeCompare(b.driver.vehicleId)).map((p) => (
                <button key={p.driver.id} onClick={() => setSelected(p.driver.id)} className="mc-ride-card w-full flex items-center gap-2 text-left text-xs px-1.5 py-1">
                  <span className="w-2 h-2 rounded-full shrink-0" style={{ background: (STATUS_STYLE[p.mode] || {}).fill }} />
                  <span className="truncate" style={{ color: "var(--mc-text)" }}>{p.driver.vehicleType === "Van" ? "Van" : "Car"} · {p.driver.firstName}</span>
                  <span className="ml-auto shrink-0" style={{ color: "var(--mc-text-muted)" }}>→ {nodes[p.toId]?.short || "?"}</span>
                </button>
              ))}
              {(counts.unterwegs || 0) === 0 && <div className="text-xs" style={{ color: "var(--mc-text-muted)" }}>niemand unterwegs</div>}
            </div>
          </div>

          <div className="text-[11px] px-1" style={{ color: "var(--mc-text-muted)" }}>Positionen nutzen echtes Fahrer-GPS wo verfügbar (sonst Fahrplan-Schätzung). Für die Ansicht mit echter Straßenkarte oben auf „Google Maps" wechseln.</div>
        </div>
      </div>

      <TimelineView setup={setup} dyn={dyn} day={day} onEdit={onEdit} />
    </div>
  );
}

/* ------------------------------ Einstellungen ---------------------------- */
// Session 27b: Upload-Icon um 180 Grad gedreht = Export/Download. SectionHeader
// rendert das Icon selbst und reicht KEINE Klasse durch (gleiche Grenze wie
// IconButton, siehe FlightTab 27e), <Upload className="rotate-180" /> kaeme dort
// also nie an. Deshalb dieser duenne Wrapper. Rein Darstellung, kein Handler.
function ExportIcon({ className = "", ...rest }) {
  return <Upload className={`${className} rotate-180`} {...rest} />;
}
function SettingsTab({ setup, dyn, day, updateSetup, updateDyn, onPreviewGuest }) {
  const fileRef = useRef();
  const [wb, setWb] = useState(null);         // geladene Arbeitsmappe (Punkt 15)
  const [sheet, setSheet] = useState("");
  const [imp, setImp] = useState(null);
  const [matchDrivers, setMatchDrivers] = useState(true);
  const [importing, setImporting] = useState(false); // Doppelklick-/Mehrfachimport-Schutz
  const [importErr, setImportErr] = useState("");     // sichtbare Meldung, falls der Import nicht gespeichert wird
  const [newFestDate, setNewFestDate] = useState(""); // Hinzufuegen-Feld "Festival-Tage" (kontrolliert, damit es sich nach dem Speichern leert)

  // Punkt 14: robustere Signatur – zusätzlich Flug, Passagiere, Treffpunkt (oder Zeilen-ID)
  const rideSig = (r) => r.srcId ? `src:${r.srcId}` :
    `${r.dayKey}|${r.time}|${r.fromId}|${r.toId}|${(r.djName || "").toLowerCase()}|${r.passengerCount}|${(r.flightNo || "").toLowerCase()}|${(r.passengers || "").toLowerCase().slice(0, 40)}|${(r.meetingPoint || "").toLowerCase().slice(0, 30)}`;

  const parseSheet = (workbook, sheetName) => {
    const ws = workbook.Sheets[sheetName];
    const rows = XLSX.utils.sheet_to_json(ws, { defval: "" });
    const valid = [], errors = [];
    rows.forEach((row, idx) => {
      const res = parseRow(setup, row, matchDrivers);
      if (res.error) { errors.push({ row: idx + 2, reason: res.error, artist: res.artist }); }
      else valid.push(res.ride);
    });
    // Duplikate: gegen bestehende Fahrten UND innerhalb der Datei
    const existing = new Set((dyn.rides || []).filter((r) => r.status !== "cancelled").map(rideSig));
    const seen = new Set();
    let dupExisting = 0, dupInFile = 0;
    const rides = valid.filter((r) => {
      const sig = rideSig(r);
      if (existing.has(sig)) { dupExisting++; return false; }
      if (seen.has(sig)) { dupInFile++; return false; }
      seen.add(sig); return true;
    });
    const matched = rides.filter((r) => r.assignedDriverId).length;
    // Slice 3: weiche Import-Warnungen (warnen, NICHT blockieren). Diese Fahrten
    // werden trotzdem importiert, aber der Nutzer sieht sie in der Zusammenfassung,
    // statt dass sie still durchrutschen. Datum/Uhrzeit sind bereits harte Pflicht
    // (parseRow -> errors[]); hier nur die weichen Faelle:
    //  - namenlose Fahrten (djName leer)
    //  - Datum liegt ausserhalb der eingetragenen Festivaltage (Tippfehler-Verdacht,
    //    gleiche Regel wie die RideForm-Warnung; nur wenn ueberhaupt Tage hinterlegt sind,
    //    Vor-/Nachtag bleibt bewusst nur ein Hinweis).
    const festDates = setup.config.festivalDates || [];
    const noName = rides.filter((r) => !(r.djName || "").trim()).length;
    const offDates = festDates.length
      ? [...new Set(rides.map((r) => r.dayKey).filter((dk) => dk && !festDates.includes(dk)))].sort()
      : [];
    setImp({ rides, errors, dupExisting, dupInFile, matched, total: rows.length, noName, offDates });
  };

  const onFile = async (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    const buf = await file.arrayBuffer();
    const workbook = XLSX.read(buf, { type: "array", cellDates: true }); // Punkt 3
    setWb(workbook);
    const first = workbook.SheetNames[0];
    setSheet(first);
    parseSheet(workbook, first);
    e.target.value = "";
  };

  const onSheet = (name) => { setSheet(name); if (wb) parseSheet(wb, name); };

  const doImport = async () => {
    // Doppelklick-/Mehrfachimport-Schutz: bricht ab, wenn schon ein Import läuft,
    // sonst wird bei schnellem Doppelklick die komplette Liste zweimal angelegt
    // (IDs unterscheiden sich, die Dedup-Prüfung greift dann nicht).
    if (importing || !imp || imp.rides.length === 0) return;
    setImporting(true); setImportErr("");
    try {
      const list = imp.rides;
      const dates = [...new Set(list.map((r) => r.dayKey))].filter(Boolean).sort();
      // Stabile IDs VOR dem Mutator (CAS-Retry-sicher): sonst bekaeme die Liste bei
      // einem Schreibkonflikt-Retry neue IDs. Einmal fest vergeben, dann verwenden.
      const withIds = list.map((r, i) => ({ ...r, __id: "r" + Date.now() + i + Math.random().toString(36).slice(2, 6) }));
      // Ergebnis beider Schreibvorgaenge auswerten. Erst wenn beide bestaetigt sind,
      // die Vorschau verwerfen; bei Fehler bleibt sie erhalten und der Nutzer kann
      // erneut importieren. festivalDates zuerst (harmlos ohne Fahrten), dann die
      // Fahrten selbst (updateDyn ist atomar: alle oder keine).
      const setupRes = await updateSetup((s) => {
        s.config.festivalDates = [...new Set([...(s.config.festivalDates || []), ...dates])].sort();
        return s;
      });
      if (!setupRes || !setupRes.ok) { setImportErr(setupRes?.error || "Import konnte nicht gespeichert werden, bitte erneut versuchen."); return; }
      const dynRes = await updateDyn((d) => {
        withIds.forEach(({ __id, ...r }) => {
          const nr = { id: __id, ...r };
          if (!nr.statusHistory) setRideStatus(nr, "planned", "import");
          d.rides.push(nr);
        });
        return d;
      });
      if (!dynRes || !dynRes.ok) { setImportErr(dynRes?.error || "Fahrten konnten nicht gespeichert werden, bitte erneut versuchen."); return; }
      setImp(null); setWb(null);
    } finally {
      setImporting(false);
    }
  };

  const matrixCell = (a, b) => {
    const t = travel(setup.matrix, a, b);
    return t ? `${t.min}/${t.km}` : "";
  };
  const setMatrix = (a, b, raw) => {
    const [min, km] = raw.split("/").map((x) => Number(x.trim()));
    updateSetup((s) => { s.matrix[`${a}|${b}`] = { min: min || 0, km: km || 0 }; return s; });
  };

  const locs = setup.locations;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 max-w-5xl 2xl:max-w-6xl">
      {/* Import */}
      <section className="mc-panel p-4">
        <SectionHeader icon={Upload} title="Pickup-Liste importieren" className="mb-3"
          subtitle="Excel im Format der Vorjahresliste. Deutsche und englische Spaltennamen (Datum/Date, Uhrzeit/Zeit/Time, Von/From, Nach/Ziel/To, Treffpunkt/Meeting Point …) und Datumsformate werden automatisch erkannt. Verarbeitung passiert lokal im Browser." />
        <label className="flex items-center gap-2 text-sm mb-3" style={{ color: "var(--mc-text-secondary)" }}>
          <input type="checkbox" checked={matchDrivers} onChange={(e) => { setMatchDrivers(e.target.checked); if (wb) parseSheet(wb, sheet); }} className="w-4 h-4" style={{ accentColor: "var(--mc-brand)" }} />
          Fahrer aus der Liste automatisch übernehmen (per Name)
        </label>
        <button onClick={() => fileRef.current?.click()} className="mc-btn-quiet text-sm px-3 py-2 flex items-center gap-2"><Upload className="w-4 h-4" />Datei wählen</button>
        <input ref={fileRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={onFile} />

        {wb && wb.SheetNames.length > 1 && (
          <div className="mt-3">
            <span className="text-xs mr-2" style={{ color: "var(--mc-text-secondary)" }}>Tabellenblatt:</span>
            <select className={mcInp + " inline-block w-auto"} value={sheet} onChange={(e) => onSheet(e.target.value)}>
              {wb.SheetNames.map((n) => <option key={n} value={n}>{n}</option>)}
            </select>
          </div>
        )}

        {imp && (
          <div className="mt-3">
            <div className="text-sm mb-1" style={{ color: "var(--mc-text)" }}>{imp.rides.length} neue Fahrten · {[...new Set(imp.rides.map((r) => r.dayKey))].filter(Boolean).length} Tage{imp.matched > 0 ? ` · ${imp.matched} Fahrer zugeordnet` : ""}</div>
            {(imp.dupExisting > 0 || imp.dupInFile > 0) && (
              <div className="text-xs mb-1" style={{ color: "var(--mc-text-muted)" }}>{imp.dupExisting} bereits vorhanden übersprungen{imp.dupInFile > 0 ? `, ${imp.dupInFile} Doppelte in der Datei` : ""}</div>
            )}
            {(imp.noName > 0 || (imp.offDates && imp.offDates.length > 0)) && (
              <div className="mc-note mc-note--warn text-xs mb-2">
                <div className="font-medium mb-0.5">Werden importiert, bitte prüfen:</div>
                {imp.noName > 0 && <div>{imp.noName} Fahrt(en) ohne Namen (Name später ergänzen)</div>}
                {imp.offDates && imp.offDates.length > 0 && (
                  <div>{imp.offDates.reduce((n, dk) => n + imp.rides.filter((r) => r.dayKey === dk).length, 0)} Fahrt(en) mit Datum außerhalb der Festivaltage: {imp.offDates.map((dk) => fmtDate(dk)).join(", ")} (Datum prüfen, Vor-/Nachtag ist ok)</div>
                )}
              </div>
            )}
            {imp.errors.filter((e) => e.reason).length > 0 && (
              <div className="mc-note mc-note--error text-xs mb-2 max-h-28 overflow-y-auto">
                <div className="font-medium mb-0.5">{imp.errors.filter((e) => e.reason).length} Zeile(n) nicht importierbar:</div>
                {imp.errors.filter((e) => e.reason).slice(0, 12).map((e, i) => <div key={i}>Zeile {e.row}: {e.reason}{e.artist ? ` (${e.artist})` : ""}</div>)}
              </div>
            )}
            <div className="max-h-40 overflow-y-auto text-xs space-y-0.5 mb-3" style={{ color: "var(--mc-text-muted)" }}>
              {imp.rides.slice(0, 8).map((r, i) => <div key={i}>{fmtDate(r.dayKey)} {r.time} · {r.djName || "?"} · {r.passengerCount}P{r.assignedDriverId ? " · ✓ Fahrer" : ""}</div>)}
              {imp.rides.length > 8 && <div>… +{imp.rides.length - 8} weitere</div>}
            </div>
            <div className="flex gap-2">
              <button onClick={doImport} disabled={imp.rides.length === 0 || importing}
                className="mc-btn-primary text-sm px-3 py-2 disabled:opacity-40">{importing ? "Importiere…" : `${imp.rides.length} importieren`}</button>
              <button onClick={() => { setImp(null); setWb(null); setImportErr(""); }} disabled={importing} className="mc-btn-quiet disabled:opacity-40 text-sm px-3 py-2">Verwerfen</button>
            </div>
            {importErr && <div className="text-xs mt-2" style={{ color: "var(--mc-st-problem)" }}>{importErr}</div>}
          </div>
        )}
      </section>

      {/* Festival-Tage */}
      <section className="mc-panel p-4">
        <SectionHeader icon={Clock} title="Festival-Tage" className="mb-3"
          subtitle="Fahrten von 00–06 Uhr zählen zur Nacht des Vortags. Tag hinzufügen über das leere Feld unten." />
        <div className="space-y-2">
          {/* Leere/ungueltige Eintraege werden nicht angezeigt: sie erzeugen ohnehin
              keinen Tag (dayTabs filtert per Boolean), wuerden hier aber als
              "Geisterzeile" erscheinen, die sich scheinbar nicht loeschen laesst.
              Alle Handler arbeiten ueber den WERT statt ueber den Index, damit das
              Sortieren beim Schreiben nicht auf den falschen Eintrag zeigt. */}
          {(setup.config.festivalDates || []).filter(Boolean).map((d) => (
            <div key={d} className="flex items-center gap-2">
              <span className="text-xs w-10 shrink-0" style={{ color: "var(--mc-text-muted)" }}>{fmtDate(d)}</span>
              <input type="date" className={mcInp} value={d} autoComplete="off"
                onChange={(e) => updateSetup((s) => {
                  const arr = (s.config.festivalDates || []).map((x) => (x === d ? e.target.value : x));
                  s.config.festivalDates = [...new Set(arr.filter(Boolean))].sort(); return s;
                })} />
              <button onClick={() => updateSetup((s) => {
                s.config.festivalDates = (s.config.festivalDates || []).filter(Boolean).filter((x) => x !== d); return s;
              })} title="Tag entfernen" aria-label="Tag entfernen" className="mc-iconbtn shrink-0"><X className="w-4 h-4" /></button>
            </div>
          ))}
          {/* Eigener State statt konstantem value="": nur so setzt React das Feld
              nach dem Hinzufuegen wirklich zurueck. autoComplete="off" verhindert,
              dass der Browser beim Neuladen einen alten Wert wieder einsetzt. */}
          <input type="date" className={mcInp} value={newFestDate} autoComplete="off"
            onChange={async (e) => {
              const v = e.target.value;
              setNewFestDate(v);
              if (!v) return;
              await updateSetup((s) => {
                s.config.festivalDates = [...new Set([...(s.config.festivalDates || []), v].filter(Boolean))].sort(); return s;
              });
              setNewFestDate("");
            }} />
        </div>
      </section>

      {/* Fahrzeit-Matrix */}
      <section className="mc-panel p-4 lg:col-span-2">
        <SectionHeader icon={Route} title="Fahrzeit-Matrix (Minuten / km)" className="mb-3"
          subtitle={<>Schätzwerte – bitte prüfen und an eure Erfahrung anpassen. Format je Feld: <span style={{ fontFamily: "var(--mc-font-mono)" }}>Minuten/km</span>.</>} />
        <div className="overflow-x-auto">
          <table className="text-sm">
            <thead>
              <tr><th className="p-2"></th>{locs.map((l) => <th key={l.id} className="p-2 font-medium text-xs" style={{ color: "var(--mc-text-secondary)" }}>{l.short}</th>)}</tr>
            </thead>
            <tbody>
              {locs.map((a, ai) => (
                <tr key={a.id}>
                  <td className="p-2 text-xs font-medium" style={{ color: "var(--mc-text-secondary)" }}>{a.short}</td>
                  {locs.map((b, bi) => (
                    <td key={b.id} className="p-1">
                      {ai === bi ? <span style={{ color: "var(--mc-border-strong)" }}>—</span> : ai < bi ? (
                        <input defaultValue={matrixCell(a.id, b.id)} onBlur={(e) => setMatrix(a.id, b.id, e.target.value)}
                          className="mc-input w-20 px-2 py-1 text-center text-xs" style={{ fontFamily: "var(--mc-font-mono)" }} placeholder="min/km" />
                      ) : <span className="text-xs" style={{ color: "var(--mc-border-strong)" }}>↑</span>}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      {/* Fahrer/Fahrzeuge Übersicht */}
      <section className="mc-panel p-4 lg:col-span-2">
        <SectionHeader icon={Users} title={`Fahrer & Fahrzeuge (${setup.drivers.length})`} className="mb-3" />
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-1.5">
          {setup.drivers.map((d) => (
            <div key={d.id} className="px-3 py-2" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", borderRadius: "var(--mc-r)" }}>
              <div className="text-sm truncate" style={{ color: "var(--mc-text)" }}>{d.firstName} {d.lastName}</div>
              <div className="flex items-center gap-1.5 mt-0.5">
                {/* Session 27b: Van = Amber, Car = Blau (Farbregel seit 27e, gilt auch
                    in AssignModal, DriverDetailsPanel und auf der Google-Karte).
                    Vorher war Van orange, das ist die Markenfarbe und darf keinen
                    Fahrzeugtyp bedeuten. */}
                <span className="text-[10px] px-1 rounded" style={{ fontFamily: "var(--mc-font-mono)", color: d.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)", background: d.vehicleType === "Van" ? "var(--mc-st-assigned-soft)" : "var(--mc-st-new-soft)" }}>{d.vehicleType === "Van" ? "Van" : "Car"}</span>
                <span className="text-[10px]" style={{ color: "var(--mc-text-muted)" }}>{d.vehicleType === "Van" ? "Van · 7" : "Car · 4"}</span>
              </div>
            </div>
          ))}
        </div>
        <p className="text-xs mt-3" style={{ color: "var(--mc-text-muted)" }}>Van: Finn, Björn, Amar, Patrick, Mustafa, Lukas · übrige fahren Car. Feste Zuordnung.</p>
      </section>

      {/* Fahrer-Telefonnummern */}
      <section className="mc-panel p-4 lg:col-span-2">
        <DriverPhones setup={setup} updateSetup={updateSetup} />
      </section>

      {/* Leitstellen-Nutzer */}
      <section className="mc-panel p-4 lg:col-span-2">
        <DispatcherUsers setup={setup} updateSetup={updateSetup} />
      </section>

      {/* Zugangs-PINs */}
      <section className="mc-panel p-4 lg:col-span-2">
        <AccessPinsSection setup={setup} updateSetup={updateSetup} />
      </section>

      {/* Gast-/Artist-Links */}
      <section className="mc-panel p-4 lg:col-span-2">
        <GuestLinksSection setup={setup} dyn={dyn} updateSetup={updateSetup} onPreviewGuest={onPreviewGuest} />
      </section>

      {/* Push-Benachrichtigungen */}
      <section className="mc-panel p-4 lg:col-span-2">
        <PushSettingsSection setup={setup} updateSetup={updateSetup} />
      </section>

      {/* Tagesabschluss (Punkt 10) */}
      <section className="mc-panel p-4 lg:col-span-2">
        <ReportSection setup={setup} dyn={dyn} day={day} />
      </section>

      {/* Änderungsprotokoll (Punkt 9, global) */}
      <section className="mc-panel p-4 lg:col-span-2">
        <AuditLogSection setup={setup} dyn={dyn} />
      </section>

      {/* Export & Backup (Punkt 16) */}
      <section className="mc-panel p-4 lg:col-span-2">
        <SectionHeader icon={ExportIcon} title="Export & Backup" className="mb-3"
          subtitle="Aktuelle Fahrten als Excel/CSV sichern, Fahrerplan exportieren oder Tagesplan drucken." />
        <div className="flex flex-wrap gap-2">
          <button onClick={() => exportRows(setup, dyn, "byTime", "xlsx")} className="mc-btn-quiet text-sm px-3 py-2 flex items-center gap-2"><Upload className="w-4 h-4 rotate-180" />Excel (alle Fahrten)</button>
          <button onClick={() => exportRows(setup, dyn, "byTime", "csv")} className="mc-btn-quiet text-sm px-3 py-2">CSV</button>
          <button onClick={() => exportRows(setup, dyn, "byDriver", "xlsx")} className="mc-btn-quiet text-sm px-3 py-2">Fahrerplan (Excel)</button>
          <button onClick={() => printPlan(setup, dyn)} className="mc-btn-quiet text-sm px-3 py-2">Tagesplan drucken</button>
        </div>
      </section>

      {/* Beispiel & Live-Start */}
      <section className="mc-panel p-4 lg:col-span-2">
        <SectionHeader icon={Play} title="Beispiel & Live-Start" className="mb-3"
          subtitle="Zum Ausprobieren die Beispieldaten laden. Vor dem echten Einsatz alle Fahrten löschen und eure eigene Pickup-Liste importieren oder Fahrten manuell anlegen." />
        <div className="flex flex-wrap gap-2">
          <button onClick={() => updateDyn((d) => { d.rides = seedExampleRides(setup); d.driverState = {}; return d; })}
            className="mc-btn-quiet text-sm px-3 py-2 flex items-center gap-2"><RefreshCw className="w-4 h-4" />Beispieldaten neu laden</button>
          <button onClick={() => { if (window.confirm("Wirklich alle Fahrten löschen? Für den echten Einsatz gedacht.")) updateDyn((d) => { d.rides = []; d.driverState = {}; return d; }); }}
            className="mc-btn-danger text-sm px-3 py-2 flex items-center gap-2"><Ban className="w-4 h-4" />Alle Fahrten löschen</button>
        </div>
      </section>
    </div>
  );
}

/* -------------------------- Excel-Zeile parsen --------------------------- */
function matchLoc(txt) {
  const t = (txt || "").toLowerCase();
  // matchLoc-/Orts-Fix (21.07.): Reihenfolge = SPEZIFISCH VOR ALLGEMEIN.
  // Bestands-Reihenfolge bleibt vorne (sheraton, dann moevenpick VOR airport, weil
  // "Moevenpick Hotel Nuernberg Airport" das Wort Airport enthaelt).
  if (/sheraton/.test(t)) return { id: "sheraton" };
  if (/m(ö|oe|o)venpick/.test(t)) return { id: "moevenpick" };
  // Neue echte Orte der 2026-Liste. Karl August, Leonardo, HBF -> eigene IDs
  // (Name bleibt sichtbar, Fahrzeit ueber Nachbar-Knoten). Muenchen und GAT VOR
  // dem allgemeinen Nuernberg-Airport-Muster, sonst wuerden sie dort gefangen.
  // Orts-Nachtrag (23.07., Jordan): MELTER ist ein eigenes Hotel, Entfernung wie
  // Karl August. MUSS VOR karl_august stehen, sonst wird die Doppelnennung
  // "MELTER - a Neighborhood Hotel + Karl August Hotel" still als Karl August verbucht.
  if (/melter/.test(t)) return { id: "melter" };
  if (/karl.?august/.test(t)) return { id: "karl_august" };
  if (/leonardo/.test(t)) return { id: "leonardo" };
  if (/\bhbf\b|hauptbahnhof|central station/.test(t)) return { id: "hbf_nue" };
  if (/munich|m(ü|ue)nchen|\bmuc\b/.test(t)) return { id: "airport_muc" };
  if (/private jet|\bgat\b/.test(t)) return { id: "gat_nue" };
  if (/(airport|flughafen).*(n(ü|u)rnberg|nuremberg)|n(ü|u)rnberg.*(airport|flughafen)|^airport nuremberg|nuremberg - private|private jet gat/.test(t)) return { id: "airport" };
  // Orts-Nachtrag (23.07., Jordan): Flugplatz Herzogenaurach (EDQH, Am Birkenbuehl 1)
  // und Bahnhof Puschendorf. Beide VOR dem Festival-Muster, damit sie nicht ueber
  // "stage"/"zone" o. ae. dort landen. Schreibvarianten der Liste abgedeckt.
  if (/flugplatz.*herzogenaurach|herzogenaurach.*flugplatz|\bedqh\b/.test(t)) return { id: "flugplatz_herzo" };
  if (/puschendor/.test(t)) return { id: "bahnhof_puschendorf" };
  if (/venue|caldera|zone|stonelands|forest|stage|woods|festival/.test(t)) {
    // Festival-Zonen-Regel (21.07., Jordan): fuer dieses Festival laufen ALLE
    // Zonen ausser Caldera/Zone 3/Stonelands unter Caldera (dort Pickup + Absetzung).
    let zone = "Caldera";
    if (/caldera/.test(t)) zone = "Caldera";
    else if (/zone\s*(iii|3)/.test(t)) zone = "Zone 3";
    else if (/stonelands/.test(t)) zone = "Stonelands";
    return { id: "festival", zone };
  }
  return { id: "__custom", custom: (txt || "").trim() };
}
function parseDate(v) {
  if (v === "" || v == null) return "";
  if (v instanceof Date) return localDateISO(v);           // dank cellDates meist hier
  if (typeof v === "number") return localDateISO(excelSerialToDate(v)); // Punkt 3: Serial-Fallback
  const s = String(v).trim();
  let m = s.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})/); // DD/MM/YYYY oder DD.MM.YYYY
  if (m) { let [_, d, mo, y] = m; if (y.length === 2) y = "20" + y; return `${y}-${pad(+mo)}-${pad(+d)}`; }
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})/); if (m) return m[0];
  return "";
}
function parseTime(v) {
  if (v == null || v === "") return "";  // Punkt 4: nicht still auf 12:00 setzen
  if (v instanceof Date) return `${pad(v.getHours())}:${pad(v.getMinutes())}`;
  if (typeof v === "number") { const mins = Math.round((v % 1) * 24 * 60); return `${pad(Math.floor(mins / 60) % 24)}:${pad(mins % 60)}`; }
  const s = String(v).trim(); const m = s.match(/(\d{1,2}):(\d{2})/); return m ? `${pad(+m[1])}:${pad(+m[2])}` : "";
}
function extractFlight(txt) {
  const m = (txt || "").match(/\b([A-Z]{2,3}\s?\d{2,4}|ICE\s?\d{2,4})\b/);
  return m ? m[1].replace(/\s+/, "") : "";
}
// Telefonnummern, die im Passagiere-Text hinter dem jeweiligen Namen in Klammern
// stehen, z. B. "Florian Goldschmidt (+4915175000987)". Nicht jede Klammer ist eine
// Nummer (z. B. Künstlernamen/Hinweise) -> nur akzeptieren, was wirklich wie eine
// Telefonnummer aussieht (überwiegend Ziffern, mind. 6 Stellen).
function extractContactPhones(text) {
  if (!text) return [];
  const parts = String(text).split(",").map((s) => s.trim()).filter(Boolean);
  const out = [];
  parts.forEach((p) => {
    const m = p.match(/^(.*?)\s*\(([^)]+)\)\s*$/);
    if (!m) return;
    const name = m[1].trim();
    const digitsOnly = m[2].trim().replace(/[\s\-\/]/g, "");
    if (/^\+?[0-9]{6,15}$/.test(digitsOnly)) out.push({ name: name || null, phone: digitsOnly });
  });
  return out;
}
// Punkt 5: Fahrer aus Excel-„Driver"-Spalte per Name der Roster zuordnen
function matchDriver(setup, name) {
  const n = (name || "").trim().toLowerCase();
  if (!n) return null;
  let d = setup.drivers.find((x) => `${x.firstName} ${x.lastName}`.toLowerCase() === n);
  if (d) return d.id;
  d = setup.drivers.find((x) => `${x.lastName} ${x.firstName}`.toLowerCase() === n); // „Nachname Vorname"
  return d ? d.id : null;
}
function parseRow(setup, row, matchDrivers) {
  // Punkt 4: Header robust – trimmen, lowercase, Sonderzeichen entfernen, dann per Alias suchen
  const norm = (k) => { const n = String(k).trim().toLowerCase().replace(/[^a-z0-9]/g, ""); return n || String(k).trim().toLowerCase(); };
  const map = {};
  Object.keys(row).forEach((k) => { map[norm(k)] = row[k]; });
  const get = (...aliases) => { for (const a of aliases) { const v = map[norm(a)]; if (v !== undefined && v !== "") return v; } return ""; };

  const date = parseDate(get("date", "datum"));
  const time = parseTime(get("time", "uhrzeit", "zeit"));
  const artist = String(get("artist", "dj", "djname", "künstler", "kuenstler") || "").trim();
  const fromRaw = get("from", "pickup", "von", "abholung");
  const toRaw = get("to", "dropoff", "destination", "nach", "ziel");

  // komplett leere Zeile -> überspringen (kein Fehler)
  if (!date && !time && !artist && !fromRaw && !toRaw) return { error: null };
  // Punkt 3/4: Pflichtfelder Datum + Uhrzeit
  if (!date) return { error: "kein/ungültiges Datum", artist };
  if (!time) return { error: "keine/ungültige Uhrzeit", artist };

  const from = matchLoc(fromRaw);
  const to = matchLoc(toRaw);
  const notes = String(get("notes", "note", "bemerkung", "notiz") || "").trim();
  const meeting = String(get("meetingpoint", "meeting", "treffpunkt") || "").trim();
  const flight = extractFlight(notes) || extractFlight(meeting) || String(get("flight", "flightno", "flug", "flugnummer") || "").trim();
  // Fahrzeit ueber die B-Ortsaufloesung (rideEndpointMatrixNode), NICHT ueber die
  // rohe matchLoc-ID: bekannte Bestands-IDs -> identischer Matrix-Knoten (byte-
  // identisch), Custom-Orte wie Muenchen/Leonardo/Karl August loesen jetzt auf
  // ihren Knoten (muc/sheraton) auf statt als "__custom" auf null zu fallen.
  // matchLoc bleibt unberuehrt; echt unbekannter Ort -> weiterhin null (Punkt 10).
  const durFromNode = rideEndpointMatrixNode(from.id, from.custom);
  const durToNode = rideEndpointMatrixNode(to.id, to.custom);
  const durMin = travelMin(setup.matrix, durFromNode, durToNode); // null wenn unbekannt (Punkt 10)
  const driverId = matchDrivers ? matchDriver(setup, get("driver", "fahrer")) : null;
  const srcId = String(get("id", "rowid", "ridenumber") || "").trim(); // Punkt 14: optionale Zeilen-ID
  const passengersTxt = String(get("passengers", "passagiere", "namen", "gäste", "gaeste") || "").trim();

  return {
    ride: {
      date, time, dayKey: festDayKey(date, time),
      fromId: from.id, fromCustom: from.custom || "",
      toId: to.id, toCustom: to.custom || "",
      zone: to.zone || "",
      djName: artist,
      // Vor-Festival-Sicherheitsphase: wie beim Formular keine stille 1 mehr.
      passengerCount: validPassengerCount(get("#", "pax", "personen", "anzahl")),
      passengers: passengersTxt,
      contactPhones: extractContactPhones(passengersTxt), // aus "Name (+49…)" im Passagiere-Text
      flightNo: flight,
      meetingPoint: meeting,
      notes,
      onDemand: from.id === "festival",
      estDurationMin: durMin,
      type: classify(from.id, to.id, from.custom, to.custom),
      assignedDriverId: driverId,
      srcId: srcId || undefined,
    },
  };
}

/* --------------------------- Export & Drucken --------------------------- */
// Punkt 10: Tagesabschluss/Report-Kennzahlen
function dayReport(setup, dyn, day) {
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "—";
  const all = (dyn.rides || []).filter((r) => r.dayKey === day);
  const active = all.filter((r) => r.status !== "cancelled");
  const done = active.filter((r) => r.status === "done");
  const openR = active.filter((r) => r.status !== "done");
  const unassigned = active.filter((r) => !r.assignedDriverId);
  const cancelled = all.filter((r) => r.status === "cancelled");
  const withIssue = active.filter((r) => (r.issues || []).length > 0);
  const delayed = active.filter(flightDelayed);
  const openReturns = active.filter((r) => (r.type === "return" || r.fromId === "festival") && !r.assignedDriverId && r.status !== "done");
  const perDriver = setup.drivers
    .map((d) => ({ d, n: active.filter((r) => r.assignedDriverId === d.id).length, min: computeDriverStats(setup, dyn, d.id, day).drivingMin }))
    .filter((x) => x.n > 0).sort((a, b) => b.n - a.n);
  const routeMap = {};
  active.forEach((r) => { const k = `${ln(r.fromId, r.fromCustom)} → ${ln(r.toId, r.toCustom)}`; routeMap[k] = (routeMap[k] || 0) + 1; });
  const perRoute = Object.entries(routeMap).sort((a, b) => b[1] - a[1]);
  return {
    total: active.length, done: done.length, open: openR.length, unassigned: unassigned.length,
    cancelled: cancelled.length, issues: withIssue.length, delayed: delayed.length,
    openReturns: openReturns.length, perDriver, perRoute, topDriver: perDriver[0] || null,
  };
}
function exportReport(setup, dyn, day, fmt) {
  try {
    const rep = dayReport(setup, dyn, day);
    const summary = [
      ["Tag", fmtDate(day)],
      ["Fahrten gesamt", rep.total], ["Erledigt", rep.done], ["Offen", rep.open],
      ["Ohne Fahrer", rep.unassigned], ["Abgesagt", rep.cancelled], ["Mit Problem", rep.issues],
      ["Verspätete Flüge", rep.delayed], ["Offene Rückfahrten", rep.openReturns],
      ["Fahrer mit den meisten Fahrten", rep.topDriver ? `${rep.topDriver.d.vehicleType === "Van" ? "Van" : "Car"} ${rep.topDriver.d.firstName} (${rep.topDriver.n})` : "—"],
    ];
    const drv = rep.perDriver.map((x) => ({ Fahrzeug: x.d.vehicleId, Fahrer: `${x.d.firstName} ${x.d.lastName}`, Fahrten: x.n, "Fahrzeit(min)": x.min }));
    const rt = rep.perRoute.map(([route, n]) => ({ Route: route, Fahrten: n }));
    const name = `open-beatz-tagesreport-${day}`;
    if (fmt === "csv") {
      const lines = ["Tagesabschluss;" + fmtDate(day), "", ...summary.map((r) => r.join(";")), "", "Fahrten pro Fahrer", "Fahrzeug;Fahrer;Fahrten;Fahrzeit(min)", ...drv.map((r) => `${r.Fahrzeug};${r.Fahrer};${r.Fahrten};${r["Fahrzeit(min)"]}`), "", "Fahrten pro Route", "Route;Fahrten", ...rt.map((r) => `${r.Route};${r.Fahrten}`)];
      const blob = new Blob(["\uFEFF" + lines.join("\n")], { type: "text/csv;charset=utf-8" });
      const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = name + ".csv"; a.click();
      setTimeout(() => URL.revokeObjectURL(a.href), 2000);
    } else {
      const wbk = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wbk, XLSX.utils.aoa_to_sheet([["Tagesabschluss", fmtDate(day)], [], ...summary]), "Zusammenfassung");
      XLSX.utils.book_append_sheet(wbk, XLSX.utils.json_to_sheet(drv.length ? drv : [{ Hinweis: "keine Fahrten" }]), "Pro Fahrer");
      XLSX.utils.book_append_sheet(wbk, XLSX.utils.json_to_sheet(rt.length ? rt : [{ Hinweis: "keine Fahrten" }]), "Pro Route");
      XLSX.writeFile(wbk, name + ".xlsx");
    }
  } catch (e) { console.error("Report-Export", e); alert("Export nicht möglich in dieser Umgebung. Bitte CSV versuchen."); }
}
function exportRideRows(setup, dyn, order) {
  const ln = (id, c) => setup.locations.find((l) => l.id === id)?.short || c || "";
  let rides = (dyn.rides || []).filter((r) => r.status !== "cancelled");
  rides = rides.sort((a, b) => {
    if (order === "byDriver") {
      const da = setup.drivers.find((d) => d.id === a.assignedDriverId)?.vehicleId || "zzz";
      const db = setup.drivers.find((d) => d.id === b.assignedDriverId)?.vehicleId || "zzz";
      if (da !== db) return da.localeCompare(db);
    }
    return (a.dayKey + a.time).localeCompare(b.dayKey + b.time);
  });
  return rides.map((r) => {
    const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
    return {
      Tag: fmtDate(r.dayKey), Datum: r.date, Uhrzeit: r.time,
      Von: ln(r.fromId, r.fromCustom), Nach: ln(r.toId, r.toCustom), Zone: r.zone || "",
      DJ: r.djName || "", Personen: r.passengerCount, Passagiere: r.passengers || "",
      Flug: r.flightNo || "", Treffpunkt: r.meetingPoint || "", Notiz: r.notes || "",
      Fahrer: drv ? `${drv.firstName} ${drv.lastName}` : "", Fahrzeug: drv ? drv.vehicleId : "",
      Status: STATUS_LABEL[r.status] || r.status, "Dauer(min)": r.estDurationMin ?? "",
    };
  });
}
function exportRows(setup, dyn, order, fmt) {
  try {
    const rows = exportRideRows(setup, dyn, order);
    const ws = XLSX.utils.json_to_sheet(rows);
    const name = `open-beatz-shuttle-${order === "byDriver" ? "fahrerplan" : "fahrten"}-${todayISO()}`;
    if (fmt === "csv") {
      const csv = XLSX.utils.sheet_to_csv(ws);
      const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
      const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = name + ".csv"; a.click();
      setTimeout(() => URL.revokeObjectURL(a.href), 2000);
    } else {
      const wbk = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wbk, ws, "Fahrten");
      XLSX.writeFile(wbk, name + ".xlsx");
    }
  } catch (e) { console.error("Export", e); alert("Export nicht möglich in dieser Umgebung. Bitte CSV versuchen oder in echter Umgebung öffnen."); }
}
function printPlan(setup, dyn) {
  const rows = exportRideRows(setup, dyn, "byTime");
  const byDay = {};
  rows.forEach((r) => { (byDay[r.Tag] = byDay[r.Tag] || []).push(r); });
  const esc = (s) => String(s ?? "").replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
  let html = `<html><head><title>Shuttle Tagesplan</title><style>body{font-family:sans-serif;padding:20px;color:#111}h2{margin:18px 0 6px}table{border-collapse:collapse;width:100%;font-size:12px;margin-bottom:16px}th,td{border:1px solid #ccc;padding:4px 6px;text-align:left}th{background:#eee}</style></head><body><h1>Open Beatz · VIP Shuttle</h1>`;
  Object.entries(byDay).forEach(([day, list]) => {
    html += `<h2>${esc(day)}</h2><table><tr><th>Zeit</th><th>Von</th><th>Nach</th><th>Zone</th><th>DJ</th><th>Pers.</th><th>Flug</th><th>Fahrer</th><th>Fzg</th><th>Status</th></tr>`;
    list.forEach((r) => { html += `<tr><td>${esc(r.Uhrzeit)}</td><td>${esc(r.Von)}</td><td>${esc(r.Nach)}</td><td>${esc(r.Zone)}</td><td>${esc(r.DJ)}</td><td>${esc(r.Personen)}</td><td>${esc(r.Flug)}</td><td>${esc(r.Fahrer)}</td><td>${esc(r.Fahrzeug)}</td><td>${esc(r.Status)}</td></tr>`; });
    html += `</table>`;
  });
  html += `</body></html>`;
  const w = window.open("", "_blank");
  if (!w) { alert("Druckfenster wurde blockiert. Bitte Pop-ups erlauben oder Excel/CSV exportieren."); return; }
  w.document.write(html); w.document.close(); w.focus(); setTimeout(() => w.print(), 300);
}

/* --------------------------------- Modal --------------------------------- */
// GETEILTE Modal-Huelle. Haengt transitiv in ALLEN vier Rollen:
//   MissionControl -> AssignModal / RideForm / WhatsAppModal   (setzen mc)
//   DriverApp      -> IssueModal                               (setzt mc NICHT)
//   StageApp       -> StageIssueModal                          (setzt mc NICHT)
//   GuestApp       -> GuestIssueModal                          (setzt mc NICHT)
// Session 27a, Variante B: EINE Huelle mit Schalter statt eines zweiten McModal.
// Ohne mc rendert die Funktion zeichenidentisch wie vor 27a - die Classic-Zweige
// der Ternaeroperatoren ergeben exakt die alten className-Strings, und
// style={undefined} gibt React nicht aus. Belegt per Render-Test (IssueModal
// vorher/nachher, 2452 Zeichen). Wer hier etwas aendert, aendert den Fahrer-,
// Stage- und Gast-Dialog mit.
function Modal({ title, children, onClose, wide, mc }) {
  return (
    <div className="fixed inset-0 z-40 flex items-start justify-center bg-black/60 backdrop-blur-sm p-4 overflow-y-auto" onClick={onClose}>
      <div className={`${mc ? "mc-panel" : "bg-stone-900 border border-stone-800 rounded-2xl"} w-full ${wide ? "max-w-2xl" : "max-w-md"} my-8`} onClick={(e) => e.stopPropagation()}>
        <div className={`flex items-center justify-between px-5 py-3.5${mc ? "" : " border-b border-stone-800"}`}
          style={mc ? { borderBottom: "1px solid var(--mc-border)" } : undefined}>
          <h2 className={mc ? "text-[15px] font-semibold" : "font-medium text-stone-100"}
            style={mc ? { color: "var(--mc-text)" } : undefined}>{title}</h2>
          <button onClick={onClose} className={mc ? "mc-iconbtn" : "text-stone-500 hover:text-stone-300"}><X className="w-5 h-5" /></button>
        </div>
        <div className="p-5">{children}</div>
      </div>
    </div>
  );
}

/* ------------------------- Mission Control Beta UI ------------------------ */
// Neuer optionaler UI-Modus neben der Classic-Oberflaeche. Wird ausschliesslich
// im Dispo-Desktop-Zweig von App gerendert (nach der useMobileView-Pruefung,
// Handy behaelt Vorrang), gated ueber uiMode === "mission-control".
//
// Slice 1 (dieser Stand): reiner PASSTHROUGH auf Dashboard mit identischen Props.
// Es gibt hier bewusst noch KEINE eigene Glue, KEINE eigene Datenschicht und KEIN
// eigenes Layout. Damit bleibt Classic zu 100% erhalten und der Umschalter tauscht
// vorerst nur die Huelle (sichtbar am Umschalt-Button, der ueber onSetUiMode in den
// Dashboard-Kopf gereicht wird). Eigenes Shell/KPI-Layout und die duplizierte Glue
// nach Ansatz A folgen in Slice 2/3, ohne Classic anzufassen.
function MissionControl({ setup, dyn, session, updateDyn, updateSetup, onLogout, onPreviewGuest, onUndo, undoCount, onSwitchToMobile, onSetUiMode, offline, connIssue }) {
  // Session 5 (Slice 5.2): Mission-Control-Shell. Ansatz A - die Controller-
  // Glue ist eine EIGENE Kopie der Dashboard-Glue (bewusst dupliziert statt
  // Hook-Extraktion, Stabilitaet vor Eleganz). Der Inhaltsbereich rendert die
  // BESTEHENDEN Tab-Komponenten/Modals mit exakt denselben Props/Callbacks wie
  // Dashboard - Dashboard selbst bleibt unveraendert. Alle Schreibwege laufen
  // ueber updateDyn + logRide/setRideStatus/triggerPush, kein neues dyn-Feld.

  // ---- Duplizierte Glue (1:1 aus Dashboard) ----
  const me = (setup.dispatchers || []).find((p) => p.id === session?.dispatcherId);
  const meBy = `dispo:${session?.dispatcherId || ""}`;
  const push = usePushNotifications(session?.dispatcherId, "dispatcherState", updateDyn, setup.config.vapidPublicKey);
  const days = dayTabs(setup, dyn);
  const [day, setDay] = useState(days[0]?.key || "");
  useEffect(() => {
    if (days.length === 0) { if (day) setDay(""); return; }
    if (!days.some((d) => d.key === day)) setDay(days[0].key);
  }, [days, day]);

  const [tab, setTab] = useState("overview");
  const [filter, setFilter] = useState("all");
  const [q, setQ] = useState("");
  const [assignRide, setAssignRide] = useState(null);
  const [editRide, setEditRide] = useState(null);
  const [waRide, setWaRide] = useState(null);
  const [clock, setClock] = useState(nowHM());
  useEffect(() => { const t = setInterval(() => setClock(nowHM()), 20000); return () => clearInterval(t); }, []);
  const [boardRef, boardWidth] = useElementWidth();
  // Fokus-Bereich: eigene Breitenmessung (boardRef haengt am board-Container und
  // ist beim Direkteinstieg in "fokus" nie montiert -> waere 0). Plus der
  // Aufklapp-Zustand des Erledigt-Blocks. Rein presentational.
  const [focusRef, focusWidth] = useElementWidth();
  const [focusDoneOpen, setFocusDoneOpen] = useState(false);
  // Fokus-Ansicht: "prio" (Standard, Verhalten wie 0e8a951) oder "zeit".
  // Bewusst nur useState, keine Persistenz.
  const [focusView, setFocusView] = useState("prio");

  const [errToasts, setErrToasts] = useState([]);
  const notifyErr = useCallback((text) => {
    const id = Date.now() + Math.random();
    setErrToasts((t) => [{ id, text }, ...t].slice(0, 4));
    setTimeout(() => setErrToasts((cur) => cur.filter((x) => x.id !== id)), 8000);
  }, []);

  const dayRides = useMemo(() => (dyn.rides || [])
    .filter((r) => r.dayKey === day)
    .sort((a, b) => sortMin(a.time) - sortMin(b.time)), [dyn.rides, day]);

  const filtered = dayRides.filter((r) => {
    if (filter === "unassigned" && r.assignedDriverId) return false;
    if (filter === "active" && !["accepted", "enroute_pickup", "onboard"].includes(r.status)) return false;
    if (filter === "done" && r.status !== "done") return false;
    if (r.status === "cancelled" && filter !== "all") return false;
    if (q) {
      const hay = `${r.djName} ${r.passengers} ${r.flightNo} ${r.zone}`.toLowerCase();
      if (!hay.includes(q.toLowerCase())) return false;
    }
    return true;
  });

  // Teilpaket F2: Sammelfahrt-Vorschlaege (rein lesend). Plan-basiert -> now
  // spielt keine Rolle (C3 ist reine Planbewertung), daher stabiler Memo ohne
  // Tick. Nur Anzeige; kein Schreibweg, kein neues dyn-Feld.
  const [onlyGroup, setOnlyGroup] = useState(false);
  const ttEntriesMC = useMemo(() => normalizeTimetableEntries(TIMETABLE_RAW), []);
  const groupModel = useMemo(() => buildGroupRidePairCandidates({
    rides: dyn.rides, drivers: setup.drivers, setup, now: 0, timetableEntries: ttEntriesMC,
  }), [dyn.rides, setup, ttEntriesMC]);
  const groupPrimaryByRide = useMemo(() => {
    const m = new Map();
    (groupModel.primaries || []).forEach((c) => (c.rideIds || []).forEach((id) => { if (!m.has(id)) m.set(id, c); }));
    return m;
  }, [groupModel]);
  // Hinfahrt-Vorschlaege fuer den board-Tab: nur toFestival, nur mit
  // handlungsleitendem Primaervorschlag.
  const boardGroupPrimary = (r) => {
    if (!r || rideFestivalDirection(r) !== "toFestival") return null;
    const c = groupPrimaryByRide.get(r.id);
    return c && GROUP_RIDE_ACTIONABLE.has(c.status) ? c : null;
  };
  const boardGroupCount = dayRides.filter((r) => boardGroupPrimary(r)).length;

  const kpi = {
    total: dayRides.filter((r) => r.status !== "cancelled").length,
    unassigned: dayRides.filter((r) => !r.assignedDriverId && r.status !== "cancelled").length,
    pending: dayRides.filter((r) => r.status === "planned").length,
    active: dayRides.filter((r) => ["accepted", "enroute_pickup", "onboard"].includes(r.status)).length,
    done: dayRides.filter((r) => r.status === "done").length,
  };

  const locName = (id, txt) => setup.locations.find((l) => l.id === id)?.short || txt || "—";

  const emCases = emergencyCases(setup, dyn, day);
  const emCrit = emCases.filter((c) => c.sev === "critical").length;
  const emCount = emCases.length;
  const msgOpen = openMessages(dyn).length;

  const [moreOpen, setMoreOpen] = useState(false); // Slice 5.3: "Mehr"-Blatt der Mobil-Leiste

  // Session 6: kurzes visuelles Feedback, wenn sich eine Fahrt gerade geaendert hat
  // (Zuteilen/Bearbeiten/Status ueber die bestehenden Dialoge -> updatedAt steigt;
  // auch Aenderungen anderer Leitstellen-Geraete). Rein praesentational: kein
  // Schreibweg, keine Logik-/Statusaenderung. Beim ersten Laden flasht nichts
  // (prev ist dann undefined). Zaehler erlaubt ueberlappende Flashes sauber.
  const seenUpdatedRef = useRef({});
  const [flashIds, setFlashIds] = useState({});
  useEffect(() => {
    const prev = seenUpdatedRef.current;
    const fresh = [];
    const seen = {};
    (dyn.rides || []).forEach((r) => {
      const u = r.updatedAt || 0;
      seen[r.id] = u;
      if (prev[r.id] != null && u > prev[r.id]) fresh.push(r.id);
    });
    seenUpdatedRef.current = seen;
    if (fresh.length) {
      setFlashIds((f) => { const n = { ...f }; fresh.forEach((id) => { n[id] = (n[id] || 0) + 1; }); return n; });
      fresh.forEach((id) => setTimeout(() => setFlashIds((f) => {
        const n = { ...f }; if (n[id] > 1) n[id] -= 1; else delete n[id]; return n;
      }), 1600));
    }
  }, [dyn.rides]);

  // ---- Rollenabhaengige Nav (Slice 5.1) ----
  const navItems = mcNavForRole(session?.role);
  // Ist der aktive Tab fuer die Rolle nicht (mehr) erlaubt, auf den ersten
  // erlaubten zurueckfallen. Schuetzt zusaetzlich davor, dass jemals ein
  // gesperrter Tab sichtbar wird (Stage-Read-only-Garantie).
  useEffect(() => {
    if (navItems.length && !navItems.some((n) => n.tab === tab)) setTab(navItems[0].tab);
  }, [navItems, tab]);

  // ---- Ableitung fuer die untere Mobil-Leiste (Slice 5.3) ----
  // Primaere Buttons: die MC_MOBILE_PRIMARY-Tabs, aber nur soweit die Rolle
  // sie ueberhaupt sehen darf (Schnitt mit navItems), in fester Reihenfolge.
  // "Mehr" sammelt alle uebrigen rollen-erlaubten Punkte (MC_NAV-Reihenfolge).
  const mobilePrimary = MC_MOBILE_PRIMARY
    .map((k) => navItems.find((n) => n.tab === k))
    .filter(Boolean);
  const mobileMore = navItems.filter((n) => !MC_MOBILE_PRIMARY.includes(n.tab));
  const moreActive = mobileMore.some((n) => n.tab === tab); // aktiver Tab liegt unter "Mehr"
  const moreBadge = mobileMore.reduce((s, n) => s + (n.tab === "emergency" ? emCount : n.tab === "messages" ? msgOpen : 0), 0);
  const moreCrit = mobileMore.some((n) => n.tab === "emergency") && emCrit > 0;

  const liveActive = hasSupabase() && !offline && !connIssue;
  const roleLabel = ({ dispo: "Leitstelle", stage: "Stage Manager", driver: "Fahrer" })[session?.role] || "";

  const navBtnStyle = (isActive) => isActive
    ? { background: "var(--mc-hover)", color: "var(--mc-text)" }
    : { color: "var(--mc-text-secondary)" };

  return (
    <div className="mc-scope min-h-screen" style={{ background: "var(--mc-bg)", color: "var(--mc-text)" }}>
      <MissionStyles />

      {/* Fehler-Hinweise (fehlgeschlagenes Speichern kleinerer Aktionen) */}
      {errToasts.length > 0 && (
        <div className="fixed left-1/2 -translate-x-1/2 z-50 px-3 space-y-1.5 w-full max-w-md" style={{ top: "max(0.75rem, env(safe-area-inset-top))" }}>
          {errToasts.map((t) => (
            <div key={t.id} onClick={() => setErrToasts((cur) => cur.filter((x) => x.id !== t.id))}
              className="bg-red-600 text-white text-sm px-3.5 py-2.5 rounded-xl shadow-lg flex items-center gap-2 cursor-pointer">
              <AlertTriangle className="w-4 h-4 shrink-0" /><span className="flex-1">{t.text}</span><X className="w-4 h-4 shrink-0 opacity-70" />
            </div>
          ))}
        </div>
      )}

      {/* ---- Obere Statusleiste ---- */}
      <header className="sticky top-0 z-20 backdrop-blur" style={{ background: "color-mix(in srgb, var(--mc-bg) 92%, transparent)", borderBottom: "1px solid var(--mc-border)", paddingTop: "env(safe-area-inset-top)" }}>
        <div className="px-4 py-2.5 flex items-center gap-3">
          <div className="flex items-center gap-2.5 shrink-0">
            <span className="ob-pulse inline-block w-2 h-2 rounded-full bg-orange-500 shrink-0" />
            <img src={OB_HORIZ} alt="Open Beatz" style={obInvert} className="h-7 w-auto shrink-0" />
            <div className="hidden md:block text-[10px] font-mono tracking-[0.15em] leading-tight pl-2.5" style={{ color: "var(--mc-text-secondary)", borderLeft: "1px solid var(--mc-border)" }}>MISSION CONTROL</div>
            <span className="text-[9px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wide" style={{ background: "var(--mc-st-assigned-soft)", color: "var(--mc-st-assigned)" }}>Beta</span>
          </div>
          <div className="flex items-center gap-1.5 text-sm font-mono" style={{ color: "var(--mc-text-muted)" }}><Clock className="w-4 h-4" />{clock}</div>
          <div className="flex-1" />
          <LiveIndicator active={liveActive} label={liveActive ? "Live" : offline ? "Offline" : "Sync"} className="hidden sm:inline-flex" />
          {(roleLabel || me) && <span className="hidden md:inline text-xs" style={{ color: "var(--mc-text-muted)" }}>{roleLabel}{me ? ` · ${me.name}` : ""}</span>}
          {push.status !== "unconfigured" && (
            <button onClick={push.enable} title={push.status === "active" ? `${PUSH_STATUS_LABEL[push.status]} · antippen zum erneuten Synchronisieren` : PUSH_STATUS_LABEL[push.status]}
              className="hidden sm:flex items-center gap-1.5 text-[11px] px-1.5" style={{ color: "var(--mc-text-muted)" }}>
              <span className={`w-2 h-2 rounded-full shrink-0 ${push.status === "active" ? "bg-emerald-400" : push.status === "denied" || push.status === "error" ? "bg-red-400" : "bg-stone-600"}`} />
              Push{push.status === "idle" ? " · antippen" : ""}
            </button>
          )}
          <button onClick={onUndo} disabled={undoCount === 0} title={undoCount > 0 ? "Letzte Änderung rückgängig machen" : "Nichts zum Rückgängigmachen"}
            className="flex items-center gap-1.5 text-sm px-2.5 py-1.5 rounded-lg disabled:cursor-not-allowed"
            style={undoCount > 0 ? { color: "var(--mc-text-secondary)" } : { color: "var(--mc-text-muted)", opacity: 0.5 }}>
            <RefreshCw className="w-4 h-4 -scale-x-100" /><span className="hidden lg:inline">Rückgängig{undoCount > 1 ? ` (${undoCount})` : ""}</span>
          </button>
          {onSwitchToMobile && (
            <button onClick={onSwitchToMobile} title="Zur schlanken Handy-Ansicht wechseln" className="p-2 rounded-lg hover:bg-white/5" style={{ color: "var(--mc-text-muted)" }}><Smartphone className="w-4 h-4" /></button>
          )}
          {/* "Zu Classic": Session 19 ausgeblendet ueber onSetUiMode={null} aus
              dem App-Root, NICHT geloescht. Seit Session 23 gibt es kein Classic
              und keinen uiMode mehr, der Knopf ist damit endgueltig unerreichbar
              und wechselte auch nichts mehr. Er faellt in einer eigenen kleinen
              Scheibe zusammen mit onSetUiMode/onSwitchToMobile aus der
              MissionControl-Signatur, nicht hier nebenbei. */}
          {onSetUiMode && (
            <button onClick={() => onSetUiMode("classic")} title="Zurück zur Classic-Oberfläche"
              className="flex items-center gap-1.5 text-xs px-2.5 py-1.5 rounded-lg hover:bg-white/5"
              style={{ color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
              <RotateCcw className="w-3.5 h-3.5" /><span className="hidden md:inline">Zu Classic</span>
            </button>
          )}
          <button onClick={onLogout} className="p-2 rounded-lg hover:bg-white/5" style={{ color: "var(--mc-text-muted)" }}><LogOut className="w-5 h-5" /></button>
        </div>

        {/* Tage + KPIs */}
        <div className="px-4 pb-2.5 flex items-center gap-3 flex-wrap" style={{ borderTop: "1px solid var(--mc-border)" }}>
          <div className="flex gap-1.5 pt-2.5">
            {days.length === 0 && <span className="text-sm" style={{ color: "var(--mc-text-muted)" }}>Noch keine Tage – Fahrten importieren oder anlegen.</span>}
            {days.map((d) => (
              <button key={d.key} onClick={() => setDay(d.key)}
                className="px-3 py-1.5 rounded-lg text-sm"
                style={day === d.key ? { background: "var(--mc-text)", color: "var(--mc-bg)", fontWeight: 500 } : { background: "var(--mc-inset)", color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
                {d.label}
              </button>
            ))}
          </div>
          <div className="flex-1" />
          <div className="flex gap-2 pt-2.5">
            {[["Fahrten", kpi.total, null], ["Offen", kpi.unassigned, kpi.unassigned ? "assigned" : null], ["Anstehend", kpi.pending, "new"], ["Aktiv", kpi.active, "enroute"], ["Erledigt", kpi.done, "done"]].map(([l, v, st]) => (
              <div key={l} className="px-3 py-1.5 rounded-lg text-center min-w-[68px]" style={{ background: "var(--mc-panel)", border: "1px solid var(--mc-border)" }}>
                <div className="text-[10px] uppercase tracking-wide" style={{ color: "var(--mc-text-muted)" }}>{l}</div>
                <div className="text-lg font-semibold leading-none mt-0.5" style={{ color: st && MC_STATUS[st] ? `var(--mc-st-${MC_STATUS[st].key})` : "var(--mc-text)" }}><MissionCount value={v} /></div>
              </div>
            ))}
          </div>
        </div>
      </header>

      {/* ---- Rumpf: linke Nav + Hauptinhalt ---- */}
      <div className="flex items-stretch">
        {/* Linke Hauptnavigation (nur Desktop ab md; darunter uebernimmt die
            untere Mobil-Leiste). "block" statt "flex", damit die vertikalen
            Nav-Gruppen erhalten bleiben. */}
        <nav className="hidden md:block shrink-0 w-56 py-3 self-stretch" style={{ borderRight: "1px solid var(--mc-border)", background: "var(--mc-panel)" }}>
          {MC_NAV_GROUPS.map((g) => {
            const items = navItems.filter((n) => n.group === g);
            if (items.length === 0) return null;
            return (
              <div key={g} className="px-3 mb-3">
                <div className="mc-eyebrow px-2 mb-1">{g}</div>
                <div className="space-y-0.5">
                  {items.map((it) => {
                    const Icon = it.icon;
                    const isActive = tab === it.tab;
                    const badge = it.tab === "emergency" ? emCount : it.tab === "messages" ? msgOpen : 0;
                    const crit = it.tab === "emergency" && emCrit > 0;
                    return (
                      <button key={it.tab} onClick={() => setTab(it.tab)}
                        className={`w-full flex items-center gap-2.5 px-2.5 py-2 rounded-lg text-sm text-left transition-colors ${isActive ? "" : "hover:bg-white/5"}`}
                        style={navBtnStyle(isActive)}>
                        <Icon className="w-4 h-4 shrink-0" />
                        <span className="flex-1 truncate">{it.label}</span>
                        {badge > 0 && (
                          <span className="min-w-[1.1rem] h-[1.1rem] px-1 inline-flex items-center justify-center rounded-full text-[10px] font-bold"
                            style={it.tab === "emergency"
                              ? (crit ? { background: "var(--mc-st-problem)", color: "#fff" } : { background: "var(--mc-st-assigned)", color: "var(--mc-bg)" })
                              : { background: "var(--mc-st-new)", color: "#fff" }}>
                            {badge}
                          </span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </nav>

        {/* Hauptinhalt = bestehende Tabs/Board/Modals (identische Props wie Dashboard) */}
        <main className="flex-1 min-w-0 px-5 py-5 pb-24 md:pb-5">
          {(() => {
            const withIssues = (dyn.rides || []).filter((r) => rideHasOpenIssue(r) && r.status !== "cancelled");
            if (withIssues.length === 0) return null;
            const setIssueState = async (rideId, st) => {
              const res = await updateDyn((d) => {
                const rr = d.rides.find((x) => x.id === rideId);
                if (!rr) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
                // Nur die offenen Issues, deren Zustand sich wirklich aendert.
                // Sind alle schon im Zielzustand (anderer hat es bereits gesetzt)
                // -> echter No-op, kein rev+1 und kein doppelter Log-Eintrag.
                const zuAendern = (rr.issues || []).filter((i) => issueOpen(i) && i.state !== st);
                if (zuAendern.length === 0) return NO_CHANGE;
                zuAendern.forEach((i) => { i.state = st; });
                logRide(rr, st === "done" ? "problem_done" : "problem_progress", meBy);
                return d;
              });
              if (!res || !res.ok) notifyErr(res?.error || "Problemstatus konnte nicht gespeichert werden, bitte erneut versuchen.");
            };
            const critical = withIssues.filter((r) => (r.issues || []).some((i) => issueOpen(i) && CRITICAL_ISSUES.includes(i.type)));
            return (
              <div className="mb-4 rounded-xl border border-red-500/40 bg-red-500/10 p-3">
                <div className="text-sm text-red-200 font-medium mb-2 flex items-center gap-2">
                  <AlertTriangle className="w-4 h-4" />{withIssues.length} offene Problem-Meldung{withIssues.length > 1 ? "en" : ""}
                  {critical.length > 0 && <span className="text-[10px] bg-red-500 text-white px-1.5 py-0.5 rounded-full uppercase tracking-wide">{critical.length}× kritisch</span>}
                </div>
                <div className="space-y-1.5">
                  {withIssues.map((r) => {
                    const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
                    const iss = (r.issues || []).filter(issueOpen);
                    const inProgress = iss.every((i) => i.state === "progress");
                    const isCrit = iss.some((i) => CRITICAL_ISSUES.includes(i.type));
                    return (
                      <div key={r.id} className={`flex items-center flex-wrap gap-x-3 gap-y-1 text-sm rounded-lg px-3 py-2 ${isCrit ? "bg-red-500/15 border border-red-500/30" : "bg-stone-950/40"}`}>
                        <span className="font-mono text-stone-300">{r.time}</span>
                        <span className="text-stone-300">{drv ? `${drv.firstName} ${drv.lastName[0]}. (${drv.vehicleType === "Van" ? "Van" : "Car"})` : "kein Fahrer"}</span>
                        <span className="text-orange-300 font-medium truncate max-w-[140px]">{r.djName || locName(r.fromId, r.fromCustom)}</span>
                        <span className="text-red-300 truncate flex items-center gap-1.5">
                          {isCrit && <span className="text-[9px] bg-red-500 text-white px-1 rounded uppercase">!</span>}
                          {iss.map((i) => i.type + (i.note ? `: ${i.note}` : "")).join(" · ")}
                        </span>
                        <span className="text-[10px] text-stone-500">{iss[0] && fmtClock(iss[0].at)}</span>
                        <span className={`text-[10px] px-1.5 py-0.5 rounded ${inProgress ? "bg-amber-500/20 text-amber-300" : "bg-red-500/20 text-red-300"}`}>{inProgress ? "in Bearbeitung" : "offen"}</span>
                        <div className="ml-auto flex items-center gap-1.5 shrink-0">
                          {/* setDay MUSS mit: der Banner ist taguebergreifend (7968, kein dayKey-Filter),
                              der Probleme-Tab dagegen tagesgefiltert (emergencyCases, 5450). Ohne setDay
                              landet man auf einem leeren Tab, wenn das Problem an einem anderen Tag haengt.
                              Gleiches Muster wie "oeffnen" direkt darunter. */}
                          <button onClick={() => { setDay(r.dayKey); setTab("emergency"); }} className="text-xs text-orange-300 hover:text-orange-200">Notfall</button>
                          <button onClick={() => { setDay(r.dayKey); setEditRide(r); }} className="text-xs text-stone-400 hover:text-stone-200">öffnen</button>
                          {!inProgress && <button onClick={() => setIssueState(r.id, "progress")} className="text-xs bg-amber-600/80 hover:bg-amber-600 text-white px-2 py-1 rounded">in Arbeit</button>}
                          <button onClick={() => setIssueState(r.id, "done")} className="text-xs bg-stone-800 hover:bg-stone-700 text-stone-200 px-2 py-1 rounded">erledigt</button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })()}
          {tab === "board" && (() => {
            const twoCol = boardWidth >= 640;  // Liste + Fahrer
            const narrow = boardWidth > 0 && boardWidth < 560; // Karten stapeln
            const cols = twoCol ? "minmax(300px,2fr) minmax(160px,1fr)" : "1fr";
            const ridesLoaded = Array.isArray(dyn.rides);
            const boardRides = onlyGroup ? filtered.filter((r) => boardGroupPrimary(r)) : filtered;
            return (
            <div ref={boardRef} className="grid gap-5" style={{ gridTemplateColumns: cols }}>
              {/* Fahrtenliste */}
              <section>
                {/* Filterleiste + Suche + Neu */}
                <div className="flex items-center gap-2 mb-3 flex-wrap">
                  <div className="flex gap-0.5 p-1 rounded-[var(--mc-r)]" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
                    {[["all", "Alle"], ["unassigned", "Offen"], ["active", "Aktiv"], ["done", "Erledigt"]].map(([f, l]) => (
                      <button key={f} onClick={() => setFilter(f)}
                        className="px-2.5 py-1 rounded-[var(--mc-r-sm)] text-sm transition-colors"
                        style={filter === f ? { background: "var(--mc-hover)", color: "var(--mc-text)", fontWeight: 500 } : { color: "var(--mc-text-secondary)" }}>{l}</button>
                    ))}
                  </div>
                  <div className="relative flex-1 min-w-[160px] max-w-xs">
                    <Search className="w-4 h-4 absolute left-2.5 top-2.5 pointer-events-none" style={{ color: "var(--mc-text-muted)" }} />
                    <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="DJ, Gast, Flug…"
                      className="mc-input w-full pl-8 pr-8 py-2 text-sm" />
                    {q && <button onClick={() => setQ("")} aria-label="Suche leeren" className="absolute right-2 top-2.5" style={{ color: "var(--mc-text-muted)" }}><X className="w-4 h-4" /></button>}
                  </div>
                  {boardGroupCount > 0 && (
                    <button onClick={() => setOnlyGroup((v) => !v)} title="Nur Fahrten mit Sammelfahrt-Vorschlag zeigen"
                      className="text-xs px-2 py-1 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1 transition-colors"
                      style={onlyGroup ? { background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" } : { color: "var(--mc-text-secondary)", border: "1px solid var(--mc-border)" }}>
                      <Users className="w-3.5 h-3.5" />Sammelfahrt {boardGroupCount}
                    </button>
                  )}
                  <span className="text-xs font-mono tabular-nums hidden sm:inline" style={{ color: "var(--mc-text-muted)" }}>{boardRides.length}/{dayRides.filter((r) => r.status !== "cancelled").length}</span>
                  <button onClick={() => setEditRide({ _new: true, dayKey: day, date: day })}
                    className="mc-btn-primary ml-auto text-sm px-3 py-2 flex items-center gap-1.5">
                    <Plus className="w-4 h-4" />Fahrt
                  </button>
                </div>

                {/* Ladezustand (defensiv, falls Fahrten noch nicht bereitstehen) */}
                {!ridesLoaded && <LoadingState label="Fahrten werden geladen" />}

                {ridesLoaded && (
                <div className="space-y-2">
                  {boardRides.length === 0 && onlyGroup && (
                    <EmptyState icon={Users} title="Keine Hinfahrt mit Sammelfahrt-Vorschlag."
                      action={<button onClick={() => setOnlyGroup(false)} className="text-xs px-3 py-1.5 rounded-[var(--mc-r)]" style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>Filter aufheben</button>} />
                  )}
                  {boardRides.length === 0 && !onlyGroup && (() => {
                    const es = rideListEmpty({ total: dayRides.length, query: q, filterLabel: filter === "all" ? null : ({ unassigned: "Offen", active: "Aktiv", done: "Erledigt" }[filter]) });
                    return (
                      <EmptyState icon={Route} title={es.text}
                        action={
                          es.reset === "search" ? <button onClick={() => setQ("")} className="text-xs px-3 py-1.5 rounded-[var(--mc-r)]" style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>Suche zurücksetzen</button>
                          : es.reset === "filter" ? <button onClick={() => setFilter("all")} className="text-xs px-3 py-1.5 rounded-[var(--mc-r)]" style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>Alle anzeigen</button>
                          : <button onClick={() => setEditRide({ _new: true, dayKey: day, date: day })} className="mc-btn-primary text-xs px-3 py-1.5 flex items-center gap-1.5"><Plus className="w-3.5 h-3.5" />Fahrt anlegen</button>
                        } />
                    );
                  })()}
                  {boardRides.map((r) => {
                    const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
                    const cancelled = r.status === "cancelled";
                    const stripeKey = mcRideStatusKey(r.status, !!r.assignedDriverId);
                    const flashing = !!flashIds[r.id];
                    return (
                      <div key={r.id} className="mc-ride-card group relative flex items-stretch overflow-hidden"
                        style={{ opacity: cancelled ? 0.6 : 1, boxShadow: flashing ? "0 0 0 2px var(--mc-st-new), var(--mc-shadow)" : undefined }}>
                        {/* Statusstreifen */}
                        <span className="w-1 shrink-0 self-stretch" style={{ background: `var(--mc-st-${stripeKey})` }} aria-hidden="true" />
                        <div className="flex-1 min-w-0 px-4 py-3">
                        <div className={`flex ${narrow ? "flex-wrap" : "items-center"} gap-x-4 gap-y-2`}>
                          {/* Zeit */}
                          <div className="text-center min-w-[52px]">
                            <div className="font-mono text-lg font-semibold leading-none tabular-nums" style={{ color: "var(--mc-text)" }}>{r.time}</div>
                            <div className="text-[10px] mt-1 font-mono" style={{ color: r.estDurationMin == null ? "var(--mc-st-assigned)" : "var(--mc-text-muted)" }}>{r.estDurationMin != null ? `${r.estDurationMin}′` : "?′"}</div>
                          </div>
                          <div className="w-px self-stretch hidden sm:block" style={{ background: "var(--mc-border)" }} />
                          {/* Hauptinfo */}
                          <div className="flex-1 min-w-0">
                            {r.djName && <div className="text-base font-semibold truncate mb-0.5" style={{ color: "var(--mc-text)" }}>{r.djName}</div>}
                            <div className="flex items-center gap-2 text-sm flex-wrap">
                              <span style={{ color: "var(--mc-text-secondary)" }}>{locName(r.fromId, r.fromCustom)}</span>
                              <ArrowRight className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-text-muted)" }} />
                              <span className="font-medium truncate" style={{ color: "var(--mc-text)" }}>{locName(r.toId, r.toCustom)}</span>
                              {r.zone && <ZoneChip zone={r.zone} className="shrink-0" />}
                              {rideHasOpenIssue(r) && <span className="text-[10px] px-1.5 py-0.5 rounded shrink-0 inline-flex items-center gap-0.5" style={{ background: "var(--mc-st-problem-soft)", color: "var(--mc-st-problem)" }}><AlertTriangle className="w-2.5 h-2.5" />Problem</span>}
                              {flightDelayed(r) && <span className="text-[10px] px-1.5 py-0.5 rounded shrink-0 inline-flex items-center gap-0.5" style={{ background: "var(--mc-st-problem-soft)", color: "var(--mc-st-problem)" }}><Plane className="w-2.5 h-2.5" />Flug {flightStyle(r.flightStatus).l}</span>}
                            </div>
                            <div className="flex items-center gap-3 mt-1 text-xs flex-wrap" style={{ color: "var(--mc-text-muted)" }}>
                              <span className="inline-flex items-center gap-1"><Users className="w-3 h-3" />{r.passengerCount}</span>
                              {r.flightNo && <span className="inline-flex items-center gap-1" style={{ color: flightDelayed(r) ? "var(--mc-st-problem)" : "var(--mc-st-new)", fontWeight: flightDelayed(r) ? 500 : 400 }}><Plane className="w-3 h-3" />{r.flightNo}{r.flightStatus ? ` · ${flightStyle(r.flightStatus).l}` : ""}{flightDelayed(r) && " ⚠"}</span>}
                              {r.onDemand && <span style={{ color: "var(--mc-st-assigned)" }}>on demand</span>}
                            </div>
                          </div>
                          {/* Status */}
                          <div className="shrink-0"><StatusBadge status={stripeKey} label={STATUS_LABEL[r.status] || r.status || "—"} /></div>
                          {/* Fahrer */}
                          <div className={`${narrow ? "w-full" : "w-[150px]"} shrink-0`}>
                            {drv ? (
                              <button onClick={() => setAssignRide(r)} title="Fahrer ändern" className="w-full text-left rounded-[var(--mc-r)] px-1.5 py-1 -mx-1.5 hover:bg-white/5 transition-colors">
                                <div className="text-sm flex items-center gap-1.5" style={{ color: "var(--mc-text)" }}>
                                  <span className="w-2 h-2 rounded-full shrink-0" style={{ background: drv.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }} />
                                  {drv.firstName} {drv.lastName[0]}.
                                </div>
                                <div className="text-[10px] font-mono pl-3.5" style={{ color: "var(--mc-text-muted)" }}>{drv.vehicleType === "Van" ? "Van" : "Car"}</div>
                              </button>
                            ) : (
                              <button onClick={() => setAssignRide(r)}
                                className="mc-btn-assign w-full text-sm px-2.5 py-1.5 flex items-center justify-center gap-1">
                                <Navigation className="w-3.5 h-3.5" />Zuteilen
                              </button>
                            )}
                          </div>
                          {/* Aktionen */}
                          <div className="flex items-center gap-0.5 shrink-0 ml-auto">
                            <button onClick={() => setWaRide(r)} title="WhatsApp-Text" className="mc-iconbtn"><MessageSquare className="w-4 h-4" /></button>
                            <button onClick={() => setEditRide(r)} title="Fahrt öffnen" className="mc-iconbtn"><ChevronRight className="w-5 h-5" /></button>
                          </div>
                        </div>
                        {(() => { const gc = boardGroupPrimary(r); return gc ? (
                          <GroupSuggestionNote candidate={gc} thisRideId={r.id} rides={dyn.rides}
                            onOpenPartner={(pr) => setEditRide(pr)} onOpenAssign={() => setAssignRide(r)} />
                        ) : null; })()}
                        </div>
                      </div>
                    );
                  })}
                </div>
                )}
              </section>

              {/* Fahrer-Live-Spalte */}
              <section>
                <div className="mc-eyebrow mb-3 flex items-center gap-2"><Radio className="w-3.5 h-3.5" />Fahrer live</div>
                <div className="space-y-1.5">
                  {setup.drivers.map((d) => {
                    const s = computeDriverStats(setup, dyn, d.id, day);
                    return <DriverRow key={d.id} setup={setup} driver={d} stats={s} />;
                  })}
                </div>
              </section>
            </div>
            );
          })()}

          {/* ---- Fokus-Bereich (eigener Nav-Punkt, Idee B) ------------------ *
           * Priorisiert statt chronologisch. REIN PRAESENTATIONAL: keine eigene
           * Zuteilungs-, Status- oder Filterlogik. Quelle fuer "braucht
           * Aufmerksamkeit" ist ausschliesslich das bereits berechnete emCases
           * (emergencyCases), alle Aktionen laufen ueber genau dieselben Handler
           * wie im Fahrten-Tab (setAssignRide/setEditRide/setWaRide). Der
           * Fahrten-Tab bleibt unberuehrt.
           * ----------------------------------------------------------------- */}
          {tab === "fokus" && (() => {
            const twoCol = focusWidth >= 640;
            const cols = twoCol ? "minmax(300px,2fr) minmax(150px,1fr)" : "1fr";
            const ridesLoaded = Array.isArray(dyn.rides);

            // emCases kann mehrere Faelle pro Fahrt liefern (z.B. Problem UND
            // Flugalarm). Pro Fahrt gewinnt der erste Eintrag, denn emCases ist
            // bereits critical-vor-warn und darin nach Zeit sortiert.
            const attnCase = new Map();
            emCases.forEach((c) => { if (c.r && !attnCase.has(c.r.id)) attnCase.set(c.r.id, c); });

            // Jede Fahrt des Tages landet in genau einem Eimer; die Reihenfolge
            // der Pruefungen IST die Zuordnungsregel. Summe der vier Eimer ist
            // immer dayRides.length.
            const bOpen = [], bRun = [], bDone = [];
            dayRides.forEach((r) => {
              if (r.status === "done" || r.status === "cancelled") { bDone.push(r); return; }
              if (attnCase.has(r.id)) return;              // steht in bAttn
              if (!r.assignedDriverId) { bOpen.push(r); return; }
              bRun.push(r);
            });
            // bAttn in emCases-Reihenfolge (critical zuerst, dann nach Zeit).
            const bAttn = [];
            emCases.forEach((c) => { if (c.r && attnCase.get(c.r.id) === c) bAttn.push(c.r); });

            // Zeit-Ansicht (Idee A): dieselbe Menge dayRides, andere Partition.
            // Grenzen in sortMin-Space. sortMin (Z. 717) schiebt 00:00-05:59 um
            // +1440, die Nacht landet dadurch automatisch am Ende, ohne Sonderfall.
            // Erledigte/Stornierte bleiben wie in der Prio-Ansicht aussen vor und
            // stehen unten im gemeinsamen Aufklapper: Summe der vier Zeitbloecke
            // plus bDone ist immer dayRides.length.
            const TIME_BUCKETS = [["Vormittag", "bis 12:00", 720], ["Nachmittag", "bis 18:00", 1080], ["Abend", "bis 24:00", 1440], ["Nacht", "ab 00:00", Infinity]];
            const tBuckets = TIME_BUCKETS.map(() => []);
            dayRides.forEach((r) => {
              if (r.status === "done" || r.status === "cancelled") return;  // steht in bDone
              const m = sortMin(r.time);
              const i = TIME_BUCKETS.findIndex(([, , max]) => m < max);
              tBuckets[i < 0 ? TIME_BUCKETS.length - 1 : i].push(r);        // unlesbare Zeit -> Nacht
            });

            const head = (label, n, color) => (
              <div className="mc-eyebrow mb-2 flex items-center gap-2" style={{ color }}>
                {label}<span className="font-mono tabular-nums">{n}</span>
              </div>
            );
            const hint = (text) => (
              <div className="text-sm px-3 py-2 rounded-[var(--mc-r-sm)]"
                style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)", color: "var(--mc-text-muted)" }}>{text}</div>
            );

            // Grosse Karte (Aufmerksamkeit + offen). ca = zugehoeriger emCases-
            // Eintrag oder null.
            const bigCard = (r, ca) => {
              const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
              const stripeKey = mcRideStatusKey(r.status, !!r.assignedDriverId);
              const flashing = !!flashIds[r.id];
              const CIcon = ca ? (CASE_ICON[ca.type] || AlertTriangle) : null;
              const crit = !!ca && ca.sev === "critical";
              return (
                <div key={r.id} className="mc-ride-card group relative flex items-stretch overflow-hidden"
                  style={{ boxShadow: flashing ? "0 0 0 2px var(--mc-st-new), var(--mc-shadow)" : undefined,
                           borderColor: crit ? "var(--mc-st-problem)" : undefined }}>
                  <span className="w-1 shrink-0 self-stretch" style={{ background: ca ? "var(--mc-st-problem)" : `var(--mc-st-${stripeKey})` }} aria-hidden="true" />
                  <div className="flex-1 min-w-0 px-4 py-3">
                    <div className="flex items-center gap-x-4 gap-y-2 flex-wrap">
                      <div className="font-mono text-lg font-semibold leading-none tabular-nums min-w-[52px] text-center" style={{ color: "var(--mc-text)" }}>{r.time}</div>
                      <div className="flex-1 min-w-0">
                        {r.djName && <div className="text-base font-semibold truncate mb-0.5" style={{ color: "var(--mc-text)" }}>{r.djName}</div>}
                        <div className="flex items-center gap-2 text-sm flex-wrap">
                          <span style={{ color: "var(--mc-text-secondary)" }}>{locName(r.fromId, r.fromCustom)}</span>
                          <ArrowRight className="w-3.5 h-3.5 shrink-0" style={{ color: "var(--mc-text-muted)" }} />
                          <span className="font-medium truncate" style={{ color: "var(--mc-text)" }}>{locName(r.toId, r.toCustom)}</span>
                          {r.zone && <ZoneChip zone={r.zone} className="shrink-0" />}
                          <span className="inline-flex items-center gap-1 text-xs" style={{ color: "var(--mc-text-muted)" }}><Users className="w-3 h-3" />{r.passengerCount}</span>
                          {r.flightNo && <span className="inline-flex items-center gap-1 text-xs" style={{ color: flightDelayed(r) ? "var(--mc-st-problem)" : "var(--mc-st-new)" }}><Plane className="w-3 h-3" />{r.flightNo}</span>}
                        </div>
                      </div>
                      <div className="shrink-0"><StatusBadge status={stripeKey} label={STATUS_LABEL[r.status] || r.status || "—"} /></div>
                      <div className="shrink-0 w-[140px]">
                        {drv ? (
                          <button onClick={() => setAssignRide(r)} title="Fahrer ändern" className="w-full text-left rounded-[var(--mc-r)] px-1.5 py-1 -mx-1.5 hover:bg-white/5 transition-colors">
                            <div className="text-sm flex items-center gap-1.5" style={{ color: "var(--mc-text)" }}>
                              <span className="w-2 h-2 rounded-full shrink-0" style={{ background: drv.vehicleType === "Van" ? "var(--mc-st-assigned)" : "var(--mc-st-new)" }} />
                              {drv.firstName} {drv.lastName[0]}.
                            </div>
                          </button>
                        ) : (
                          <button onClick={() => setAssignRide(r)}
                            className="mc-btn-assign w-full text-sm px-2.5 py-1.5 flex items-center justify-center gap-1">
                            <Navigation className="w-3.5 h-3.5" />Zuteilen
                          </button>
                        )}
                      </div>
                      <div className="flex items-center gap-0.5 shrink-0 ml-auto">
                        <button onClick={() => setWaRide(r)} title="WhatsApp-Text" className="mc-iconbtn"><MessageSquare className="w-4 h-4" /></button>
                        <button onClick={() => setEditRide(r)} title="Fahrt öffnen" className="mc-iconbtn"><ChevronRight className="w-5 h-5" /></button>
                      </div>
                    </div>
                    {ca && (
                      <div className="mt-2 text-xs px-2.5 py-1.5 rounded-[var(--mc-r-sm)] inline-flex items-center gap-1.5"
                        style={{ background: "var(--mc-st-problem-soft)", color: "var(--mc-st-problem)" }}>
                        <CIcon className="w-3.5 h-3.5 shrink-0" />{ca.label}
                      </div>
                    )}
                    {(() => { const gc = boardGroupPrimary(r); return gc ? (
                      <GroupSuggestionNote candidate={gc} thisRideId={r.id} rides={dyn.rides}
                        onOpenPartner={(pr) => setEditRide(pr)} onOpenAssign={() => setAssignRide(r)} />
                    ) : null; })()}
                  </div>
                </div>
              );
            };

            // Dichte Zeile (laeuft gerade + erledigt + Zeit-Ansicht). Zweiter
            // Parameter ca ist der zugehoerige emCases-Eintrag oder null. Ohne ca
            // ist das Ergebnis identisch zu 0e8a951 (Prio-Ansicht unveraendert).
            const slimRow = (r, ca) => {
              const drv = setup.drivers.find((d) => d.id === r.assignedDriverId);
              const stripeKey = mcRideStatusKey(r.status, !!r.assignedDriverId);
              const CIcon = ca ? (CASE_ICON[ca.type] || AlertTriangle) : null;
              return (
                <div key={r.id} className="flex items-center gap-3 px-3 py-2 rounded-[var(--mc-r-sm)] overflow-hidden"
                  style={{ background: "var(--mc-panel)", border: "1px solid var(--mc-border)", opacity: r.status === "cancelled" ? 0.6 : 1 }}>
                  <span className="w-0.5 self-stretch shrink-0" style={{ background: ca ? "var(--mc-st-problem)" : `var(--mc-st-${stripeKey})` }} aria-hidden="true" />
                  <span className="font-mono text-sm tabular-nums shrink-0" style={{ color: "var(--mc-text)" }}>{r.time}</span>
                  {ca && <span title={ca.label} className="shrink-0 inline-flex"><CIcon className="w-3.5 h-3.5" style={{ color: "var(--mc-st-problem)" }} /></span>}
                  <span className="text-sm truncate flex-1 min-w-0" style={{ color: "var(--mc-text)" }}>
                    {r.djName || "—"}<span style={{ color: "var(--mc-text-muted)" }}> · {locName(r.fromId, r.fromCustom)} → {locName(r.toId, r.toCustom)}</span>
                  </span>
                  {drv && <span className="text-xs shrink-0 hidden sm:inline" style={{ color: "var(--mc-text-muted)" }}>{drv.firstName} {drv.lastName[0]}.</span>}
                  <span className="text-xs shrink-0" style={{ color: `var(--mc-st-${stripeKey})` }}>{STATUS_LABEL[r.status] || r.status || "—"}</span>
                  <button onClick={() => setEditRide(r)} title="Fahrt öffnen" className="mc-iconbtn shrink-0"><ChevronRight className="w-4 h-4" /></button>
                </div>
              );
            };

            // Erledigt-Aufklapper: in beiden Ansichten identisch, deshalb einmal
            // definiert statt dupliziert. Verhalten und Markup unveraendert
            // gegenueber 0e8a951, nutzt weiterhin focusDoneOpen und bDone.
            const doneBlock = () => (
              <div>
                <button onClick={() => setFocusDoneOpen((v) => !v)}
                  aria-expanded={focusDoneOpen}
                  className="w-full flex items-center gap-2 px-3 py-2.5 rounded-[var(--mc-r)] text-sm transition-colors hover:bg-white/5"
                  style={{ background: "var(--mc-panel)", border: "1px solid var(--mc-border)", color: "var(--mc-text)" }}>
                  <ChevronRight className="w-4 h-4 shrink-0 transition-transform" style={{ transform: focusDoneOpen ? "rotate(90deg)" : "none", color: "var(--mc-text-muted)" }} />
                  Erledigt<span className="font-mono tabular-nums" style={{ color: "var(--mc-text-muted)" }}>{bDone.length}</span>
                </button>
                {focusDoneOpen && <div className="space-y-1.5 mt-2">{bDone.map((r) => slimRow(r))}</div>}
              </div>
            );

            return (
            <div ref={focusRef} className="grid gap-5" style={{ gridTemplateColumns: cols }}>
              <section>
                {/* Ansichts-Umschalter. Optik 1:1 von der Filterleiste im
                    Fahrten-Tab. Rein presentational, kein Schreibweg. */}
                <div className="flex gap-0.5 p-1 mb-3 w-fit rounded-[var(--mc-r)]" style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
                  {[["prio", "Priorität"], ["zeit", "Nach Zeit"]].map(([v, l]) => (
                    <button key={v} onClick={() => setFocusView(v)} aria-pressed={focusView === v}
                      className="px-2.5 py-1 rounded-[var(--mc-r-sm)] text-sm transition-colors"
                      style={focusView === v ? { background: "var(--mc-hover)", color: "var(--mc-text)", fontWeight: 500 } : { color: "var(--mc-text-secondary)" }}>{l}</button>
                  ))}
                </div>
                {!ridesLoaded && <LoadingState label="Fahrten werden geladen" />}
                {ridesLoaded && dayRides.length === 0 && (
                  <EmptyState icon={Crosshair} title="Für diesen Tag sind keine Fahrten geplant."
                    action={<button onClick={() => setEditRide({ _new: true, dayKey: day, date: day })} className="mc-btn-primary text-xs px-3 py-1.5 flex items-center gap-1.5"><Plus className="w-3.5 h-3.5" />Fahrt anlegen</button>} />
                )}
                {ridesLoaded && dayRides.length > 0 && focusView === "prio" && (
                  <div className="space-y-5">
                    <div>
                      {head("Braucht Aufmerksamkeit", bAttn.length, "var(--mc-st-problem)")}
                      {bAttn.length === 0 ? hint("Nichts Kritisches offen.")
                        : <div className="space-y-2">{bAttn.map((r) => bigCard(r, attnCase.get(r.id)))}</div>}
                    </div>
                    <div>
                      {head("Offen, noch Zeit", bOpen.length, "var(--mc-st-assigned)")}
                      {bOpen.length === 0 ? hint("Alle anstehenden Fahrten haben einen Fahrer.")
                        : <div className="space-y-2">{bOpen.map((r) => bigCard(r, null))}</div>}
                    </div>
                    <div>
                      {head("Läuft gerade", bRun.length, "var(--mc-st-enroute)")}
                      {bRun.length === 0 ? hint("Gerade ist keine Fahrt unterwegs.")
                        : <div className="space-y-1.5">{bRun.map((r) => slimRow(r))}</div>}
                    </div>
                    {doneBlock()}
                  </div>
                )}
                {ridesLoaded && dayRides.length > 0 && focusView === "zeit" && (
                  <div className="space-y-5">
                    {tBuckets.every((b) => b.length === 0)
                      ? hint("Keine anstehenden Fahrten.")
                      : TIME_BUCKETS.map(([label, span], i) => (tBuckets[i].length === 0 ? null : (
                        <div key={label}>
                          {head(`${label} (${span})`, tBuckets[i].length, "var(--mc-text-secondary)")}
                          <div className="space-y-1.5">{tBuckets[i].map((r) => slimRow(r, attnCase.get(r.id) || null))}</div>
                        </div>
                      )))}
                    {doneBlock()}
                  </div>
                )}
              </section>

              {/* Fahrer-Live-Spalte: identisch zum Fahrten-Tab, gleiche Quelle. */}
              <section>
                <div className="mc-eyebrow mb-3 flex items-center gap-2"><Radio className="w-3.5 h-3.5" />Fahrer live</div>
                <div className="space-y-1.5">
                  {setup.drivers.map((d) => {
                    const s = computeDriverStats(setup, dyn, d.id, day);
                    return <DriverRow key={d.id} setup={setup} driver={d} stats={s} />;
                  })}
                </div>
              </section>
            </div>
            );
          })()}

          {tab === "overview" && <MissionOverviewTab setup={setup} dyn={dyn} day={day} setTab={setTab}
            onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }} onAssign={(r) => setAssignRide(r)} />}
          {tab === "timeline" && <MissionTimelinePage setup={setup} dyn={dyn} day={day} updateDyn={updateDyn} by={meBy} onUndo={onUndo} onErr={notifyErr}
            onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }} onAssign={(r) => setAssignRide(r)} />}
          {tab === "timetable" && <TimetableTab />}
          {tab === "rideslist" && <RidesListTab setup={setup} dyn={dyn} day={day} />}
          {tab === "returns" && <MissionReturnsTab setup={setup} dyn={dyn} day={day} updateDyn={updateDyn} by={meBy} onErr={notifyErr}
            onAssign={(r) => setAssignRide(r)} onWhatsApp={(r) => setWaRide(r)} onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }}
            onNewReturn={(artistName) => setEditRide({ _new: true, dayKey: day, date: day, djName: artistName, fromId: "festival", toId: "" })} />}
          {tab === "emergency" && <MissionEmergencyTab setup={setup} dyn={dyn} day={day} updateDyn={updateDyn} by={meBy} onErr={notifyErr}
            onAssign={(r) => setAssignRide(r)} onWhatsApp={(r) => setWaRide(r)} onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }} />}
          {tab === "messages" && <MissionMessagesInbox dyn={dyn} updateDyn={updateDyn} by={meBy} />}
          {tab === "flights" && <FlightTab setup={setup} dyn={dyn} day={day} updateDyn={updateDyn} by={meBy} onErr={notifyErr} onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }} />}
          {tab === "map" && <MapTab setup={setup} dyn={dyn} day={day} SchematicComponent={MissionSchematicMap} glideMarkers onEdit={(r) => { setDay(r.dayKey); setEditRide(r); }} />}
          {tab === "drivers" && <MissionDriversTab setup={setup} dyn={dyn} day={day} />}
          {tab === "settings" && <SettingsTab setup={setup} dyn={dyn} day={day} updateSetup={updateSetup} updateDyn={updateDyn} onPreviewGuest={onPreviewGuest} />}
        </main>
      </div>

      {/* ---- Untere Mobil-Navigation (nur schmal, md:hidden) --------------- *
          Gleiche Rollenfilterung wie die Desktop-Nav (mcNavForRole). Feste
          Primaer-Buttons + "Mehr" fuer den Rest. z-30: liegt unter den Modals
          (Modal = z-40, ChatPanel = z-50), damit ein offenes Modal die Leiste
          sauber ueberdeckt. Der Chat-FAB wird per --mc-fab-lift darueber gehoben. */}
      {navItems.length > 0 && (
        <>
          {/* "Mehr"-Blatt: liegt ueber der Leiste, schliesst bei Klick daneben */}
          {moreOpen && mobileMore.length > 0 && (
            <div className="md:hidden fixed inset-0 z-30" onClick={() => setMoreOpen(false)}>
              <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" />
              <div className="absolute left-0 right-0 p-3" style={{ bottom: "calc(56px + env(safe-area-inset-bottom))" }} onClick={(e) => e.stopPropagation()}>
                <div className="mc-sheet-in mx-auto max-w-md rounded-2xl overflow-hidden" style={{ background: "var(--mc-panel-raised)", border: "1px solid var(--mc-border)", boxShadow: "var(--mc-shadow-lg)" }}>
                  <div className="px-4 py-2.5 flex items-center justify-between" style={{ borderBottom: "1px solid var(--mc-border)" }}>
                    <span className="mc-eyebrow">Mehr</span>
                    <button onClick={() => setMoreOpen(false)} aria-label="Schließen" className="p-1 rounded-lg hover:bg-white/5" style={{ color: "var(--mc-text-muted)" }}><X className="w-4 h-4" /></button>
                  </div>
                  <div className="grid grid-cols-3 gap-1 p-2">
                    {mobileMore.map((it) => {
                      const Icon = it.icon;
                      const isActive = tab === it.tab;
                      const badge = it.tab === "emergency" ? emCount : it.tab === "messages" ? msgOpen : 0;
                      const crit = it.tab === "emergency" && emCrit > 0;
                      return (
                        <button key={it.tab} onClick={() => { setTab(it.tab); setMoreOpen(false); }}
                          className="relative flex flex-col items-center gap-1.5 px-2 py-3 rounded-xl text-xs"
                          style={isActive ? { background: "var(--mc-hover)", color: "var(--mc-text)" } : { color: "var(--mc-text-secondary)" }}>
                          <Icon className="w-5 h-5" />
                          <span className="truncate max-w-full">{it.label}</span>
                          {badge > 0 && (
                            <span className="absolute top-1.5 right-1.5 min-w-[1.05rem] h-[1.05rem] px-1 inline-flex items-center justify-center rounded-full text-[10px] font-bold"
                              style={it.tab === "emergency"
                                ? (crit ? { background: "var(--mc-st-problem)", color: "#fff" } : { background: "var(--mc-st-assigned)", color: "var(--mc-bg)" })
                                : { background: "var(--mc-st-new)", color: "#fff" }}>
                              {badge}
                            </span>
                          )}
                        </button>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Feste untere Leiste */}
          <nav className="md:hidden fixed bottom-0 left-0 right-0 z-30 flex items-stretch"
            style={{ background: "color-mix(in srgb, var(--mc-bg) 94%, transparent)", borderTop: "1px solid var(--mc-border)", backdropFilter: "blur(8px)", WebkitBackdropFilter: "blur(8px)", paddingBottom: "env(safe-area-inset-bottom)" }}>
            {mobilePrimary.map((it) => {
              const Icon = it.icon;
              const isActive = tab === it.tab;
              const label = MC_MOBILE_LABEL[it.tab] || it.label;
              return (
                <button key={it.tab} onClick={() => { setTab(it.tab); setMoreOpen(false); }}
                  className="mc-navbtn relative flex-1 flex flex-col items-center justify-center gap-0.5 py-2 text-[11px]"
                  style={isActive ? { color: "var(--mc-text)" } : { color: "var(--mc-text-muted)" }}>
                  {isActive && <span className="mc-nav-ind absolute top-0 left-1/4 right-1/4 h-0.5 rounded-full" style={{ background: "var(--mc-st-new)" }} />}
                  <Icon className="w-5 h-5" />
                  <span className="leading-none truncate max-w-full">{label}</span>
                </button>
              );
            })}
            {mobileMore.length > 0 && (
              <button onClick={() => setMoreOpen((v) => !v)} aria-expanded={moreOpen}
                className="mc-navbtn relative flex-1 flex flex-col items-center justify-center gap-0.5 py-2 text-[11px]"
                style={(moreActive || moreOpen) ? { color: "var(--mc-text)" } : { color: "var(--mc-text-muted)" }}>
                {moreActive && <span className="mc-nav-ind absolute top-0 left-1/4 right-1/4 h-0.5 rounded-full" style={{ background: "var(--mc-st-new)" }} />}
                <MoreHorizontal className="w-5 h-5" />
                <span className="leading-none">Mehr</span>
                {moreBadge > 0 && (
                  <span className="absolute top-1 right-[26%] w-2 h-2 rounded-full" style={{ background: moreCrit ? "var(--mc-st-problem)" : "var(--mc-st-assigned)" }} />
                )}
              </button>
            )}
          </nav>
        </>
      )}

      {assignRide && (
        <div className="mc-modal-fade">
        <AssignModal setup={setup} dyn={dyn} ride={assignRide}
          onClose={() => setAssignRide(null)}
          onAssign={async (driverId) => {
            // before aus dem gerenderten Stand fuer den Push-Vergleich (nach dem
            // Save nicht mehr rekonstruierbar). Im Mutator selbst bleibt der frische
            // DB-Vergleich fuer die Log-Entscheidung.
            const beforeDriver = (dyn.rides || []).find((x) => x.id === assignRide.id)?.assignedDriverId ?? null;
            const res = await updateDyn((d) => {
              const r = d.rides.find((x) => x.id === assignRide.id);
              if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
              const changed = r.assignedDriverId !== driverId;
              // Derselbe Fahrer ist bereits zugewiesen -> echter No-op (idempotent):
              // frueher schrieb dieser Pfad nur r.updatedAt und erhoehte rev+1, ohne
              // fachliche Aenderung. Jetzt kein Schreiben, kein Push (changed=false).
              if (!changed) return NO_CHANGE;
              const drvName = (id) => { const dr = setup.drivers.find((x) => x.id === id); return dr ? `${dr.firstName} ${dr.lastName[0]}. (${dr.vehicleType === "Van" ? "Van" : "Car"})` : "—"; };
              logRide(r, r.assignedDriverId ? "reassigned" : "assigned", meBy, driverId ? `→ ${drvName(driverId)}` : "Zuteilung entfernt");
              r.assignedDriverId = driverId;
              if ((!driverId || changed) && r.status !== "planned") setRideStatus(r, "planned", meBy);
              else r.updatedAt = Date.now();
              return d;
            });
            if (!res || !res.ok) return res; // Modal bleibt offen, zeigt Fehler, kein Push
            setAssignRide(null);
            // Push erst NACH bestaetigtem Save (nie im Mutator, der bei CAS-Retry mehrfach laeuft).
            const saved = (res.value.rides || []).find((x) => x.id === assignRide.id);
            if ((beforeDriver ?? null) !== (driverId ?? null) && driverId && saved) triggerPush(driverId, "Neue Fahrt zugeteilt", `${saved.time} · ${saved.djName || "Fahrt"}`, `ride-${saved.id}`);
            return res;
          }} />
        </div>
      )}

      {editRide && (
        <div className="mc-modal-fade">
        <RideForm setup={setup} ride={editRide}
          onClose={() => setEditRide(null)}
          onSave={async (data) => {
            if (!editRide._new) {
              const live = dyn.rides.find((x) => x.id === editRide.id);
              if (live && editRide.updatedAt && live.updatedAt && live.updatedAt !== editRide.updatedAt) {
                const lastLog = (live.log || [])[(live.log || []).length - 1];
                const who = lastLog ? byLabel(setup, lastLog.by) : "jemand anderes";
                const what = lastLog ? (LOG_LABEL[lastLog.event] || lastLog.event) : "eine Änderung";
                const ok = window.confirm(`Diese Fahrt wurde inzwischen von ${who} geändert (${what}, ${fmtClock(live.updatedAt)} Uhr).\n\nStatus, Fahrer und Problemmeldungen bleiben in jedem Fall erhalten. Trotzdem mit deinen übrigen Eingaben speichern?`);
                if (!ok) return { ok: false, cancelled: true };
              }
            }
            // Stabile ID VOR dem Mutator (CAS-Retry-sicher). before-Stand fuer den
            // Push-Vergleich festhalten (nach dem Save nicht mehr rekonstruierbar).
            const newId = editRide._new ? ("r" + Date.now() + Math.random().toString(36).slice(2, 6)) : null;
            const beforeRide = editRide._new ? null : (dyn.rides || []).find((x) => x.id === editRide.id);
            const res = await updateDyn((d) => {
              if (editRide._new) {
                const nr = { id: newId, assignedDriverId: null, ...data };
                logRide(nr, "created", meBy, "");
                setRideStatus(nr, "planned", meBy);
                d.rides.push(nr);
              } else {
                const r = d.rides.find((x) => x.id === editRide.id);
                // Fahrt inzwischen komplett geloescht -> Konflikt (die updatedAt-
                // Vorpruefung oben deckt nur "veraendert", nicht "weg" ab).
                if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr.");
                const timeChanged = data.time !== r.time || data.date !== r.date;
                const routeChanged = data.fromId !== r.fromId || data.toId !== r.toId || data.fromCustom !== r.fromCustom || data.toCustom !== r.toCustom;
                const meetChanged = (data.meetingPoint || "") !== (r.meetingPoint || "");
                if (timeChanged) logRide(r, "time", meBy, `${r.time} → ${data.time}`);
                if (routeChanged) logRide(r, "route", meBy, "Route geändert");
                if ((data.flightStatus || "") !== (r.flightStatus || "")) logRide(r, "flight", meBy, `Flug: ${flightStyle(data.flightStatus).l}`);
                const { status, assignedDriverId, issues, log, statusHistory, acceptedAt, enrouteAt, onboardAt, doneAt, cancelledAt, plannedAt, id, ...safeData } = data;
                Object.assign(r, safeData);
              }
              return d;
            });
            if (!res || !res.ok) return res; // Modal bleibt offen (RideForm zeigt saveErr), kein Push
            setEditRide(null);
            // Push erst NACH bestaetigtem Save (nie im Mutator). Nur bei bestehender
            // Fahrt mit geaenderter Zeit/Route/Treffpunkt; alles aus dem bestaetigten Stand.
            if (!editRide._new && beforeRide) {
              const saved = (res.value.rides || []).find((x) => x.id === editRide.id);
              if (saved) {
                const timeChanged = data.time !== beforeRide.time || data.date !== beforeRide.date;
                const routeChanged = data.fromId !== beforeRide.fromId || data.toId !== beforeRide.toId || data.fromCustom !== beforeRide.fromCustom || data.toCustom !== beforeRide.toCustom;
                const meetChanged = (data.meetingPoint || "") !== (beforeRide.meetingPoint || "");
                if ((timeChanged || routeChanged || meetChanged) && saved.assignedDriverId) {
                  triggerPush(saved.assignedDriverId, "Fahrt geändert", `${saved.djName || "Fahrt"} · ${saved.time}${meetChanged ? " · neuer Treffpunkt" : ""}`, `ride-${saved.id}`);
                }
              }
            }
            return res;
          }}
          onDelete={editRide._new ? null : async () => {
            const res = await updateDyn((d) => { const r = d.rides.find((x) => x.id === editRide.id); if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr."); setRideStatus(r, "cancelled", meBy); return d; });
            if (res && res.ok) setEditRide(null);
            return res;
          }} />
        </div>
      )}

      {waRide && (
        <div className="mc-modal-fade">
        <WhatsAppModal ride={waRide} setup={setup} onClose={() => setWaRide(null)}
          onCopied={(which) => updateDyn((d) => { const r = d.rides.find((x) => x.id === waRide.id); if (!r) return dynConflict("RIDE_GONE", "Diese Fahrt existiert nicht mehr."); logRide(r, "whatsapp", meBy, which); return d; })} />
        </div>
      )}

      {/* liftOffset ueber CSS-Var: auf schmal ueber die Mobil-Leiste, ab md 0 */}
      <ChatPanel setup={setup} dyn={dyn} day={day} updateDyn={updateDyn} by={meBy} liftOffset="var(--mc-fab-lift)" />
    </div>
  );
}

/* ======================================================================== *
 *  Mission Control Design System (Session 3)
 *  Enterprise-Dark: ruhig, hochwertig, nachttauglich. KEINE Fachlogik.
 *  Alle Tokens sind unter .mc-scope gescopt und koennen Classic technisch
 *  nicht erreichen. Basiskomponenten sind rein praesentational.
 * ======================================================================== */

// Zentrale, konsistente Statusfarben (eine Quelle der Wahrheit).
// Semantische UI-Zustaende, NICHT an ride.status gekoppelt (das kommt spaeter).
const MC_STATUS = {
  new:      { label: "Neu",        key: "new" },      // Blau
  assigned: { label: "Zugewiesen", key: "assigned" }, // Gelb/Orange
  enroute:  { label: "Unterwegs",  key: "enroute" },  // Violett
  done:     { label: "Erledigt",   key: "done" },     // Gruen
  problem:  { label: "Problem",    key: "problem" },  // Rot
  idle:     { label: "Inaktiv",    key: "idle" },     // Grau
};

// Reine Zuordnung Fahrt-Status -> MC_STATUS-Farbschluessel (fuer Statusstreifen +
// Status-Badge in der Mission-Control-Fahrtenansicht). AENDERT KEINE Statuslogik,
// nur die farbliche Gruppierung fuer die Darstellung. Der echte Status-Text kommt
// weiter aus STATUS_LABEL. Problem-Meldungen werden separat als rote Chips gezeigt,
// damit der Streifen den tatsaechlichen Fahrt-Status behaelt.
//   planned (ohne Fahrer) = new (blau)   | planned (mit Fahrer)/accepted = assigned
//   enroute_pickup/onboard = enroute     | done = done | cancelled = idle
function mcRideStatusKey(status, hasDriver) {
  switch (status) {
    case "cancelled": return "idle";
    case "done": return "done";
    case "onboard":
    case "enroute_pickup": return "enroute";
    case "accepted": return "assigned";
    case "planned": return hasDriver ? "assigned" : "new";
    default: return "idle";
  }
}

/* ---- Mission-Control-Navigation (Session 5, Slice 5.1) ----------------- *
 * Reine Datenstruktur + Rollenfilter. Wird in DIESEM Slice noch NICHT
 * gerendert (MissionControl bleibt Passthrough). Jeder Eintrag zeigt auf
 * einen BESTEHENDEN Dashboard-Tab-Key (siehe Nav-Array im Dashboard) -
 * es werden keine neuen Views erfunden und keine Tabs entfernt. Die Gruppen
 * dienen nur der spaeteren Desktop-Darstellung; die Mobile-Leiste (Slice 5.3)
 * nutzt eine Teilmenge derselben Items. Icons sind bereits importierte
 * lucide-react-Komponenten, keine neuen Imports.
 * ----------------------------------------------------------------------- */

// Kanonische Gruppen-Reihenfolge (fuer die Desktop-Nav in Slice 5.2).
const MC_NAV_GROUPS = ["MISSION CONTROL", "FAHRTEN", "BETRIEB", "PLANUNG & KOMMUNIKATION", "SYSTEM"];

// Flaches Item-Array; jedes Item traegt sein group-Feld selbst.
const MC_NAV = [
  // MISSION CONTROL
  { tab: "overview",  label: "Mission Control", icon: LayoutGrid,    group: "MISSION CONTROL" },
  { tab: "map",       label: "Karte",           icon: MapIcon,       group: "MISSION CONTROL" },
  // FAHRTEN
  { tab: "board",     label: "Fahrten",         icon: Route,         group: "FAHRTEN" },
  { tab: "fokus",     label: "Fokus",           icon: Crosshair,     group: "FAHRTEN" },
  { tab: "returns",   label: "Rückfahrten",     icon: Moon,          group: "FAHRTEN" },
  { tab: "flights",   label: "Flughafen",       icon: Plane,         group: "FAHRTEN" },
  // BETRIEB
  { tab: "drivers",   label: "Fahrer",          icon: Users,         group: "BETRIEB" },
  { tab: "emergency", label: "Probleme",        icon: Siren,         group: "BETRIEB" },
  // PLANUNG & KOMMUNIKATION
  { tab: "timeline",  label: "Timeline",        icon: Gauge,         group: "PLANUNG & KOMMUNIKATION" },
  { tab: "timetable", label: "Timetable",       icon: Clock,         group: "PLANUNG & KOMMUNIKATION" },
  { tab: "rideslist", label: "Fahrtenliste",    icon: Eye,           group: "PLANUNG & KOMMUNIKATION" },
  { tab: "messages",  label: "Chat",            icon: MessageSquare, group: "PLANUNG & KOMMUNIKATION" },
  // SYSTEM
  { tab: "settings",  label: "Einstellungen",   icon: Settings,      group: "SYSTEM" },
];

// Pro Rolle exakt der erlaubte Satz an Tab-Keys. Quelle ist ausschliesslich
// session.role (dispo|stage|driver) - KEINE neue, unabhaengige Rollenlogik.
//   dispo  = komplette Nav (null = alle)
//   stage  = strikt nur Live-Ansicht (overview) + Probleme melden (emergency),
//            damit die Stage-Read-only-Garantie unangetastet bleibt
//   driver = minimal (overview), falls je in den Shell geroutet
// Unbekannte/fehlende Rolle => leer (sicherer Default, zeigt nichts).
const MC_ROLE_TABS = {
  dispo:  null,
  stage:  ["overview", "emergency"],
  driver: ["overview"],
};

function mcNavForRole(role) {
  const allow = MC_ROLE_TABS[role];
  if (allow === null) return MC_NAV.slice();            // dispo: alles
  if (!Array.isArray(allow)) return [];                 // unbekannte Rolle: nichts
  return MC_NAV.filter((it) => allow.includes(it.tab)); // stage/driver: Teilmenge
}

/* ---- Mobile-Leiste (Session 5, Slice 5.3) ----------------------------- *
 * Diese Tabs bekommen in der unteren Leiste je einen eigenen Button, in
 * genau dieser Reihenfolge. "overview" heisst mobil "Live" (kuerzeres
 * Label), sonst gilt das MC_NAV-Label. Alle uebrigen rollen-erlaubten
 * Punkte wandern unter "Mehr". Der Rollenfilter kommt weiterhin
 * ausschliesslich aus mcNavForRole - KEINE zweite Rollenquelle. Fuer eine
 * reduzierte Rolle (z.B. stage = nur overview+emergency) erscheint dann
 * nur "Live" + "Mehr" (mit den Problemen darunter), die Stage-Read-only-
 * Garantie bleibt also unberuehrt.
 * ----------------------------------------------------------------------- */
const MC_MOBILE_PRIMARY = ["overview", "board", "returns", "drivers"];
const MC_MOBILE_LABEL = { overview: "Live" }; // sonst MC_NAV-Label

function MissionStyles() {
  return (
    <style>{`
      /* ---- Design-Tokens (nur unter .mc-scope aktiv) ---- */
      .mc-scope {
        /* Flaechen */
        --mc-bg: #0a0c10;
        --mc-panel: #12151b;
        --mc-panel-raised: #171b22;
        --mc-inset: #0d0f14;
        --mc-hover: #1c212a;
        /* Rahmen */
        --mc-border: #232a34;
        --mc-border-strong: #323c49;
        /* Text */
        --mc-text: #e7ebf0;
        --mc-text-secondary: #9aa4b2;
        /* 27a-3: von #616d7c auf #828d9c. Der alte Ton hatte auf Panel nur
           3.47 Kontrast, AA fuer Fliesstext braucht 4.5. Jetzt 5.43. Haengt an
           ueber 80 Textstellen (Uhrzeiten, Log, Hinweise). Nicht #7c8797
           nehmen, das ist exakt --mc-st-idle. */
        --mc-text-muted: #828d9c;
        /* Statusfarben: Akzent + weiche Fuellung */
        --mc-st-new: #4b90f6;       --mc-st-new-soft: rgba(75,144,246,0.30);
        --mc-st-assigned: #f5a524;  --mc-st-assigned-soft: rgba(245,165,36,0.30);
        --mc-st-enroute: #9a7cf7;   --mc-st-enroute-soft: rgba(154,124,247,0.30);
        --mc-st-done: #34d399;      --mc-st-done-soft: rgba(52,211,153,0.30);
        --mc-st-problem: #f26d6d;   --mc-st-problem-soft: rgba(242,109,109,0.30);
        --mc-st-idle: #7c8797;      --mc-st-idle-soft: rgba(124,135,151,0.30);
        /* Markenfarbe (Session 27a-2). BEWUSST ein anderer Ton als
           --mc-st-assigned (#f5a524): Orange = Marke, Hauptaktion, Fokus,
           beste Wahl. Amber = Status "zugeteilt" und Warnungen ("knapp").
           Die beiden duerfen nie zusammenfallen, sonst heisst Orange in einer
           Liste wieder vier Dinge gleichzeitig (das war das Classic-Problem). */
        --mc-brand: #ea580c;        --mc-brand-soft: rgba(249,115,22,0.16);
        --mc-brand-hover: #f97316;  --mc-brand-on: #ffffff;
        /* Kraeftige Fuellung, NUR fuer die Timeline-Balken. Bewusst getrennt von
           -soft: dort steht die Akzentfarbe als TEXT drauf (Badges), deshalb ist
           -soft bei 0.31 gedeckelt. Auf den Balken steht weisser Text, der traegt 0.45. */
        --mc-st-new-fill: rgba(75,144,246,0.45);
        --mc-st-assigned-fill: rgba(245,165,36,0.45);
        --mc-st-enroute-fill: rgba(154,124,247,0.45);
        --mc-st-done-fill: rgba(52,211,153,0.45);
        --mc-st-problem-fill: rgba(242,109,109,0.45);
        --mc-st-idle-fill: rgba(124,135,151,0.45);
        /* Tiefe / Schatten (subtil) */
        --mc-shadow-sm: 0 1px 2px rgba(0,0,0,0.40);
        --mc-shadow: 0 2px 10px rgba(0,0,0,0.35), 0 1px 2px rgba(0,0,0,0.40);
        --mc-shadow-lg: 0 14px 40px rgba(0,0,0,0.48);
        --mc-ring-inset: inset 0 1px 0 rgba(255,255,255,0.035);
        /* Radien */
        --mc-r-sm: 6px; --mc-r: 10px; --mc-r-lg: 14px; --mc-r-pill: 999px;
        /* Abstaende */
        --mc-space-1: 4px; --mc-space-2: 8px; --mc-space-3: 12px;
        --mc-space-4: 16px; --mc-space-5: 24px; --mc-space-6: 32px;
        /* Animationszeiten (Transitions) */
        --mc-dur-fast: 120ms; --mc-dur: 200ms; --mc-dur-slow: 340ms;
        --mc-ease: cubic-bezier(0.4, 0, 0.2, 1);
        /* Mikroanimationen (Keyframes, Slice 9): schnell 160 / normal 240 / langsam 380 ms */
        --mc-anim-fast: 160ms; --mc-anim: 240ms; --mc-anim-slow: 380ms;
        /* Fokus */
        --mc-focus: 0 0 0 2px var(--mc-bg), 0 0 0 4px rgba(249,115,22,0.55);
        /* Disabled */
        --mc-disabled-opacity: 0.45;
        /* Chat-FAB-Lift: auf schmal ueber die untere Mobil-Leiste heben (Slice 5.3),
           ab md wieder 0 (siehe Media-Query unten) */
        --mc-fab-lift: calc(56px + env(safe-area-inset-bottom));
        /* Typografie */
        --mc-font: system-ui, -apple-system, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
        --mc-font-mono: ui-monospace, "SF Mono", "JetBrains Mono", Menlo, Consolas, monospace;

        background: var(--mc-bg);
        color: var(--mc-text);
        font-family: var(--mc-font);
      }

      .mc-scope :focus-visible { outline: none; box-shadow: var(--mc-focus); }

      /* Panel */
      .mc-panel {
        background: var(--mc-panel);
        border: 1px solid var(--mc-border);
        border-radius: var(--mc-r-lg);
        box-shadow: var(--mc-shadow), var(--mc-ring-inset);
        animation: mc-panel-in var(--mc-anim) var(--mc-ease) both;
      }
      /* Effekt 1: Panels erscheinen weich beim Mount (Tab-Wechsel/Erststart) */
      @keyframes mc-panel-in {
        from { opacity: 0; transform: translateY(6px); }
        to   { opacity: 1; transform: translateY(0); }
      }

      /* SectionHeader-Eyebrow */
      .mc-eyebrow { font-size: 11px; letter-spacing: 0.08em; text-transform: uppercase; color: var(--mc-text-muted); }

      /* StatusBadge */
      .mc-badge {
        display: inline-flex; align-items: center; gap: 6px;
        padding: 3px 9px; border-radius: var(--mc-r-pill);
        font-size: 12px; font-weight: 500; line-height: 1; white-space: nowrap;
        /* Effekt 3: weicher Uebergang, wenn sich die Statusklasse (Farbe/Fuellung) aendert */
        transition: color var(--mc-anim) var(--mc-ease), background-color var(--mc-anim) var(--mc-ease);
      }
      .mc-badge .mc-dot { width: 6px; height: 6px; border-radius: 999px; background: currentColor; }
      .mc-badge--new      { color: var(--mc-st-new);      background: var(--mc-st-new-soft); }
      .mc-badge--assigned { color: var(--mc-st-assigned); background: var(--mc-st-assigned-soft); }
      .mc-badge--enroute  { color: var(--mc-st-enroute);  background: var(--mc-st-enroute-soft); }
      .mc-badge--done     { color: var(--mc-st-done);     background: var(--mc-st-done-soft); }
      .mc-badge--problem  { color: var(--mc-st-problem);  background: var(--mc-st-problem-soft); }
      .mc-badge--idle     { color: var(--mc-st-idle);     background: var(--mc-st-idle-soft); }
      .mc-badge--brand    { color: var(--mc-brand-on);    background: var(--mc-brand); }

      /* MetricCard */
      .mc-metric {
        background: var(--mc-inset);
        border: 1px solid var(--mc-border);
        border-radius: var(--mc-r);
        padding: var(--mc-space-4);
      }
      .mc-metric-label { font-size: 11px; letter-spacing: 0.06em; text-transform: uppercase; color: var(--mc-text-muted); }
      .mc-metric-value { font-size: 28px; font-weight: 600; color: var(--mc-text); font-variant-numeric: tabular-nums; line-height: 1.05; }
      .mc-metric-unit  { font-size: 13px; font-weight: 500; color: var(--mc-text-secondary); }

      /* IconButton */
      .mc-iconbtn {
        display: inline-flex; align-items: center; justify-content: center;
        width: 34px; height: 34px; border-radius: var(--mc-r);
        color: var(--mc-text-secondary);
        background: transparent; border: 1px solid transparent; cursor: pointer;
        transition: background var(--mc-dur) var(--mc-ease), color var(--mc-dur) var(--mc-ease), border-color var(--mc-dur) var(--mc-ease);
      }
      .mc-iconbtn:hover { background: var(--mc-hover); color: var(--mc-text); border-color: var(--mc-border); }
      .mc-iconbtn--active { background: var(--mc-hover); color: var(--mc-text); border-color: var(--mc-border-strong); }
      .mc-iconbtn:disabled { opacity: var(--mc-disabled-opacity); cursor: not-allowed; }
      .mc-iconbtn:disabled:hover { background: transparent; color: var(--mc-text-secondary); border-color: transparent; }

      /* Fahrtenkarte (Board) - Grundflaeche + Hover-Zustand + Flash via inline box-shadow */
      .mc-ride-card {
        background: var(--mc-panel);
        border: 1px solid var(--mc-border);
        border-radius: var(--mc-r-lg);
        transition: background var(--mc-dur) var(--mc-ease), border-color var(--mc-dur) var(--mc-ease), box-shadow var(--mc-dur) var(--mc-ease), transform var(--mc-anim-fast) var(--mc-ease);
      }
      /* Effekt 2: Karte hebt sich minimal beim Hover (nur transform, kein Layout-Shift) */
      .mc-ride-card:hover { background: var(--mc-panel-raised); border-color: var(--mc-border-strong); transform: translateY(-1px); }

      /* Sucheingabe */
      .mc-input {
        background: var(--mc-inset);
        border: 1px solid var(--mc-border);
        color: var(--mc-text);
        border-radius: var(--mc-r);
      }
      .mc-input::placeholder { color: var(--mc-text-muted); }
      .mc-input:focus { outline: none; border-color: var(--mc-brand); box-shadow: 0 0 0 3px var(--mc-brand-soft); }

      /* Primaerer Button (Speichern, Neue Fahrt, Verschieben, Kopieren).
         Session 27a-2: Markenorange statt Weiss. Die Klasse haengt auch am
         "Neue Fahrt"-Knopf der Shell und am "Verschieben" der Timeline - das
         ist Absicht, sonst waere der Knopf weiss und der Dialog dahinter
         orange. Deren Code ist unveraendert, nur diese Regel. */
      .mc-btn-primary {
        background: var(--mc-brand); color: var(--mc-brand-on);
        border-radius: var(--mc-r); font-weight: 500;
        transition: background var(--mc-dur) var(--mc-ease);
      }
      .mc-btn-primary:hover { background: var(--mc-brand-hover); }

      /* Zuteilen-Button (unbesetzte Fahrt) - blauer Akzent */
      .mc-btn-assign {
        background: var(--mc-st-new-soft); color: var(--mc-st-new);
        border-radius: var(--mc-r);
        transition: background var(--mc-dur) var(--mc-ease);
      }
      .mc-btn-assign:hover { background: color-mix(in srgb, var(--mc-st-new) 22%, transparent); }

      /* Chat-FAB (rund, Marke). Eigene Klasse statt .mc-btn-primary, weil die
         den Radius auf var(--mc-r) setzt und damit rounded-full plattmachen
         wuerde. Session 27b-2. */
      .mc-fab {
        background: var(--mc-brand); color: var(--mc-brand-on);
        border-radius: var(--mc-r-pill);
        box-shadow: var(--mc-shadow);
        transition: background var(--mc-dur) var(--mc-ease);
      }
      .mc-fab:hover { background: var(--mc-brand-hover); }

      /* Zurueckhaltender Zweit-Knopf neben einer Hauptaktion ("Verwerfen").
         Basis ist --mc-hover, damit er sich auch auf --mc-panel-raised noch
         absetzt. Session 27b-2. */
      .mc-btn-quiet {
        background: var(--mc-hover); color: var(--mc-text-secondary);
        border-radius: var(--mc-r);
        transition: background var(--mc-dur) var(--mc-ease), color var(--mc-dur) var(--mc-ease);
      }
      .mc-btn-quiet:hover { background: var(--mc-border); color: var(--mc-text); }

      /* Hinweisbox (Import-Zusammenfassung, Warnungen). Session 27b.
         BEWUSST NICHT --mc-st-*-soft: das steht auf 30 Prozent und ist als
         Badge-Fuellung gedacht. Flaechig ueber mehrere Zeilen ist 30 Prozent
         zu laut (genau der Rueckbau aus 27a-3 am Flug-Block). Hier 12 Prozent
         Flaeche, 28 Prozent Rahmen: die Box traegt die Bedeutung ueber Farbe,
         schreit aber nicht. Text steht in der vollen Statusfarbe. */
      .mc-note {
        border-radius: var(--mc-r); padding: 6px 10px;
        border: 1px solid transparent;
      }
      .mc-note--warn {
        color: var(--mc-st-assigned);
        background: color-mix(in srgb, var(--mc-st-assigned) 12%, transparent);
        border-color: color-mix(in srgb, var(--mc-st-assigned) 28%, transparent);
      }
      .mc-note--error {
        color: var(--mc-st-problem);
        background: color-mix(in srgb, var(--mc-st-problem) 12%, transparent);
        border-color: color-mix(in srgb, var(--mc-st-problem) 28%, transparent);
      }

      /* Destruktiver Knopf ("Alle Fahrten loeschen"). Gleiche Zurueckhaltung wie
         .mc-note: die Farbe warnt, die Flaeche bleibt ruhig. Session 27b. */
      .mc-btn-danger {
        color: var(--mc-st-problem);
        background: color-mix(in srgb, var(--mc-st-problem) 12%, transparent);
        border: 1px solid color-mix(in srgb, var(--mc-st-problem) 28%, transparent);
        border-radius: var(--mc-r);
        transition: background var(--mc-dur) var(--mc-ease);
      }
      .mc-btn-danger:hover { background: color-mix(in srgb, var(--mc-st-problem) 22%, transparent); }

      /* LiveIndicator (ruhiger Puls, kein Gaming) */
      @keyframes mc-pulse-ring {
        0%   { box-shadow: 0 0 0 0 rgba(52,211,153,0.45); }
        70%  { box-shadow: 0 0 0 6px rgba(52,211,153,0); }
        100% { box-shadow: 0 0 0 0 rgba(52,211,153,0); }
      }
      .mc-live-dot { width: 8px; height: 8px; border-radius: 999px; background: var(--mc-st-done); animation: mc-pulse-ring 2.4s ease-out infinite; }
      .mc-live-dot--off { background: var(--mc-st-idle); animation: none; }

      /* Effekt 4: neu gemeldete Probleme pulsieren genau EINMAL kurz rot
         (iteration 1 -> kein Dauerblinken). Roter Ring ueber box-shadow, analog
         zum bestehenden mc-pulse-ring; ohne fill-mode faellt die Karte danach
         auf ihren Grundzustand (kein Ring) zurueck. Unter prefers-reduced-motion
         schaltet der .mc-scope-*-Block unten die Animation ohnehin ab. */
      @keyframes mc-flash-problem {
        0%   { box-shadow: 0 0 0 0 color-mix(in srgb, var(--mc-st-problem) 55%, transparent); }
        70%  { box-shadow: 0 0 0 7px color-mix(in srgb, var(--mc-st-problem) 0%, transparent); }
        100% { box-shadow: 0 0 0 0 color-mix(in srgb, var(--mc-st-problem) 0%, transparent); }
      }
      .mc-scope .mc-flash-problem { animation: mc-flash-problem 1.1s var(--mc-ease) 1; }

      /* Effekt 8: MC-Modals oeffnen weich. Nur weiches OEFFNEN; Schliessen bleibt
         hart (eine Exit-Animation braeuchte verzoegertes Unmount = Zustandslogik,
         bewusst out of scope). Der Wrapper animiert AUSSCHLIESSLICH opacity
         (transform wuerde die position:fixed-Kinder des geteilten Modal-Chassis
         brechen) und sitzt selbst auf der bestehenden Modal-Ebene (fixed, z-40,
         siehe Stacking-Kommentar im Shell), damit die opacity<1-Phase das
         Stacking gegenueber Nav (z-30) und Toast/ChatPanel (z-50) nicht
         veraendert. reduced-motion deckt der .mc-scope-*-Block unten ab. */
      @keyframes mc-modal-in { from { opacity: 0; } to { opacity: 1; } }
      .mc-modal-fade { position: fixed; inset: 0; z-index: 40; animation: mc-modal-in var(--mc-anim) var(--mc-ease) both; }

      /* Effekt 9: Mobil-Navigation reagiert fluessig */
      .mc-navbtn { transition: color var(--mc-anim-fast) var(--mc-ease); }
      @keyframes mc-nav-ind-in { from { opacity: 0; transform: scaleX(0.35); } to { opacity: 1; transform: scaleX(1); } }
      .mc-nav-ind { animation: mc-nav-ind-in var(--mc-anim-fast) var(--mc-ease) both; transform-origin: center; }
      @keyframes mc-sheet-in { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      .mc-sheet-in { animation: mc-sheet-in var(--mc-anim) var(--mc-ease) both; }

      /* Effekt 7: neue Timeline-Eintraege blenden weich ein. NUR opacity und
         fill-mode backwards, damit die Inline-Opacity beim Draggen (0.25) danach
         wieder greift und die Positionierung (left/width) unberuehrt bleibt. */
      @keyframes mc-entry-in { from { opacity: 0; } to { opacity: 1; } }
      .mc-scope .mc-tl-block { animation: mc-entry-in var(--mc-anim) var(--mc-ease) backwards; }

      @media (prefers-reduced-motion: reduce) {
        .mc-live-dot { animation: none; }
        /* Alle MC-Mikroanimationen und Transitions aus; Elemente stehen sofort im Endzustand */
        .mc-scope *, .mc-scope *::before, .mc-scope *::after { animation: none !important; transition: none !important; }
      }

      /* Ab md gibt es keine untere Mobil-Leiste mehr -> Chat-FAB nicht mehr anheben. */
      @media (min-width: 768px) {
        .mc-scope { --mc-fab-lift: 0px; }
      }
    `}</style>
  );
}

// --- Basiskomponenten (rein praesentational, keine Fachlogik) ---

function SectionHeader({ title, subtitle, eyebrow, icon: Icon, actions, className = "" }) {
  return (
    <div className={`flex items-start justify-between gap-3 ${className}`}>
      <div className="min-w-0">
        {eyebrow && <div className="mc-eyebrow mb-1">{eyebrow}</div>}
        <div className="flex items-center gap-2">
          {Icon && <Icon className="w-4 h-4" style={{ color: "var(--mc-text-secondary)" }} />}
          <h2 className="text-[15px] font-semibold truncate" style={{ color: "var(--mc-text)" }}>{title}</h2>
        </div>
        {subtitle && <p className="text-xs mt-0.5" style={{ color: "var(--mc-text-secondary)" }}>{subtitle}</p>}
      </div>
      {actions && <div className="flex items-center gap-1.5 shrink-0">{actions}</div>}
    </div>
  );
}

function MissionPanel({ title, subtitle, eyebrow, icon, actions, header, children, className = "", bodyClassName = "", padded = true }) {
  const showHeader = header || title;
  return (
    <section className={`mc-panel ${className}`}>
      {showHeader && (
        <div className="px-4 py-3" style={{ borderBottom: "1px solid var(--mc-border)" }}>
          {header || <SectionHeader title={title} subtitle={subtitle} eyebrow={eyebrow} icon={icon} actions={actions} />}
        </div>
      )}
      <div className={`${padded ? "p-4" : ""} ${bodyClassName}`}>{children}</div>
    </section>
  );
}

function StatusBadge({ status = "idle", label, dot = true, className = "" }) {
  const s = MC_STATUS[status] || MC_STATUS.idle;
  return (
    <span className={`mc-badge mc-badge--${s.key} ${className}`}>
      {dot && <span className="mc-dot" />}
      {label || s.label}
    </span>
  );
}

function MetricCard({ label, value, unit, icon: Icon, status, hint, className = "" }) {
  const accent = status && MC_STATUS[status] ? `var(--mc-st-${MC_STATUS[status].key})` : "var(--mc-text-secondary)";
  return (
    <div className={`mc-metric ${className}`}>
      <div className="flex items-center justify-between">
        <span className="mc-metric-label">{label}</span>
        {Icon && <Icon className="w-4 h-4" style={{ color: accent }} />}
      </div>
      <div className="mt-2 flex items-baseline gap-1.5">
        <span className="mc-metric-value">{value}</span>
        {unit && <span className="mc-metric-unit">{unit}</span>}
      </div>
      {hint && <div className="mt-1 text-xs" style={{ color: "var(--mc-text-muted)" }}>{hint}</div>}
    </div>
  );
}

function IconButton({ icon: Icon, label, onClick, active = false, disabled = false, className = "", type = "button" }) {
  return (
    <button type={type} onClick={onClick} disabled={disabled} title={label} aria-label={label}
      className={`mc-iconbtn ${active ? "mc-iconbtn--active" : ""} ${className}`}>
      {Icon && <Icon className="w-[18px] h-[18px]" />}
    </button>
  );
}

function EmptyState({ icon: Icon, title, hint, action, className = "" }) {
  return (
    <div className={`flex flex-col items-center justify-center text-center px-6 py-10 ${className}`}>
      {Icon && (
        <div className="mb-3 flex items-center justify-center w-11 h-11 rounded-full"
          style={{ background: "var(--mc-inset)", border: "1px solid var(--mc-border)" }}>
          <Icon className="w-5 h-5" style={{ color: "var(--mc-text-muted)" }} />
        </div>
      )}
      <div className="text-sm font-medium" style={{ color: "var(--mc-text)" }}>{title}</div>
      {hint && <div className="text-xs mt-1 max-w-xs" style={{ color: "var(--mc-text-secondary)" }}>{hint}</div>}
      {action && <div className="mt-4">{action}</div>}
    </div>
  );
}

function LoadingState({ label = "Wird geladen", className = "" }) {
  return (
    <div className={`flex items-center justify-center gap-2.5 px-6 py-10 ${className}`}>
      <RefreshCw className="w-4 h-4 animate-spin" style={{ color: "var(--mc-text-secondary)" }} />
      <span className="text-sm" style={{ color: "var(--mc-text-secondary)" }}>{label}…</span>
    </div>
  );
}

function ErrorState({ title = "Fehler", message, onRetry, className = "" }) {
  return (
    <div className={`flex flex-col items-center justify-center text-center px-6 py-10 ${className}`}>
      <div className="mb-3 flex items-center justify-center w-11 h-11 rounded-full" style={{ background: "var(--mc-st-problem-soft)" }}>
        <AlertTriangle className="w-5 h-5" style={{ color: "var(--mc-st-problem)" }} />
      </div>
      <div className="text-sm font-medium" style={{ color: "var(--mc-text)" }}>{title}</div>
      {message && <div className="text-xs mt-1 max-w-sm break-words" style={{ color: "var(--mc-text-secondary)" }}>{message}</div>}
      {onRetry && (
        <button onClick={onRetry} className="mt-4 text-xs px-3 py-1.5 rounded-lg"
          style={{ background: "var(--mc-hover)", color: "var(--mc-text)", border: "1px solid var(--mc-border)" }}>
          Erneut versuchen
        </button>
      )}
    </div>
  );
}

function LiveIndicator({ active = true, label = "Live", className = "" }) {
  return (
    <span className={`inline-flex items-center gap-2 ${className}`}>
      <span className={`mc-live-dot ${active ? "" : "mc-live-dot--off"}`} />
      <span className="text-[11px] font-semibold tracking-wide uppercase"
        style={{ color: active ? "var(--mc-st-done)" : "var(--mc-text-muted)" }}>{label}</span>
    </span>
  );
}

// Effekt 6: KPI-Zahlen zaehlen beim ersten Mount sanft hoch (0 -> Ziel, easeOutCubic).
// Rein anzeigend, keine Datenlogik. Spaetere Wertaenderungen werden direkt uebernommen
// (kein erneutes Hochzaehlen). prefers-reduced-motion -> sofort der Zielwert.
function prefersReducedMotion() {
  return typeof window !== "undefined" && typeof window.matchMedia === "function"
    && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}
function useCountUp(target, duration = 650) {
  const isNum = typeof target === "number" && isFinite(target);
  const reduce = prefersReducedMotion();
  const [val, setVal] = useState(isNum && !reduce ? 0 : target);
  const doneRef = useRef(!isNum || reduce);
  const rafRef = useRef(0);
  useEffect(() => {
    if (!isNum) { setVal(target); return; }
    if (doneRef.current) { setVal(target); return; } // schon animiert -> Aenderungen direkt setzen
    doneRef.current = true;
    if (reduce || target === 0) { setVal(target); return; }
    const now0 = () => (typeof performance !== "undefined" && performance.now ? performance.now() : Date.now());
    const t0 = now0();
    const tick = (now) => {
      const p = Math.min(1, (now - t0) / duration);
      const eased = 1 - Math.pow(1 - p, 3);
      setVal(Math.round(target * eased));
      if (p < 1) rafRef.current = requestAnimationFrame(tick);
      else setVal(target);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); };
  }, [target, isNum, reduce]);
  return isNum ? val : target;
}
function MissionCount({ value, className = "", style }) {
  const shown = useCountUp(value);
  return <span className={className} style={style}>{shown}</span>;
}
